/****** Object:  UserDefinedFunction [dbo].[AccountCustomisationApprovers]    Script Date: 21-09-2024 20:36:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
create function [dbo].[AccountCustomisationApprovers](@Customer_Info_Id int)
RETURNS varchar(100)    
AS    
BEGIN    
       DECLARE @ApproverID VARCHAR(100)    
         SELECT @ApproverID=  STUFF((SELECT  ', ' + ApproverADID    
         FROM TBL_OVI_Account_Customisation_Approver     
         WHERE Account_Customisation_Customer_Details_ID=@Customer_Info_Id and ApproverADID IS NOT NULL    
         FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')    
         , 1, LEN(','), '')    
    
        return @ApproverID    
END
GO
/****** Object:  UserDefinedFunction [dbo].[fn_GetDrillDown]    Script Date: 21-09-2024 20:36:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

  
Create  FUNCTION [dbo].[fn_GetDrillDown](@LUserID varchar(20),@LUserRole varchar(20),@BusinessCode varchar(20))    
RETURNS varchar(500)     
    AS   
    BEGIN  
        declare @strSQL varchar(max)=null --,  @LUserID varchar(20) ='J0322',@LUserRole varchar(20)='RM',@BusinessCode varchar(20)='Tractor'  
     If @BusinessCode='HCV'                          
  Begin                  
  if(@LUserRole='TSM')                
  begin                
  set @LUserRole='RM'                
  end                 
                
  if @LUserRole='BH'                      
  Set @strSQL =' Isnull(HB.ZH,Isnull(HB.RH,isnull(HB.SH,isnull(HB.ASM,HB.RM)))) as [EMPCode]'          
  Else If @LUserRole='ZH'                          
  Set @strSQL =' Isnull(HB.RH,isnull(HB.SH,isnull(HB.ASM,HB.RM))) as [EMPCode]'                          
  Else If @LUserRole='RH'                          
  Set @strSQL =' isnull(HB.SH,isnull(HB.ASM,HB.RM)) as [EMPCode]'                          
  Else If @LUserRole='SH'                          
  Set @strSQL =' isnull(HB.ASM,HB.RM) as [EMPCode]'                          
  Else If @LUserRole='ASM' OR @LUserRole='RM'                          
  Set @strSQL =' isnull(HB.RM,''RM'') as [EMPCode]'                          
  End                          
               
  -- RM_TSM,ASM,RSM,ZSM,NSM,BH                    
 Else If @BusinessCode='LCV'                          
 Begin                          
  if @LUserRole='BH'                      
  Set @strSQL =' Isnull(HB.NSM,Isnull(HB.ZSM,isnull(HB.RSM,isnull(HB.ASM,HB.RM)))) as [EMPCode]'                           
  Else If @LUserRole='NSM'                          
  Set @strSQL =' Isnull(HB.ZSM,isnull(HB.RSM,isnull(HB.ASM,HB.RM))) as [EMPCode]'                          
  Else If @LUserRole='ZSM'                          
  Set @strSQL =' isnull(HB.RSM,isnull(HB.ASM,HB.RM)) as [EMPCode]'                          
  Else If @LUserRole='RSM'                          
  Set @strSQL =' isnull(HB.ASM,HB.RM) as [EMPCode]'                          
  Else If @LUserRole='ASM' OR @LUserRole='RM'                          
  Set @strSQL =' isnull(HB.RM,''RM'') as [EMPCode]'                          
 End                     
                     
  -- RM,ASM,SH,RH,CH,BH                    
 Else If @BusinessCode='UCV'                          
 Begin                          
  if @LUserRole='BH'                      
  Set @strSQL =' Isnull(HB.CH,Isnull(HB.RH,isnull(HB.SH,isnull(HB.ASM,HB.RM)))) as [EMPCode]'                           
  Else If @LUserRole='CH'                          
  Set @strSQL =' Isnull(HB.RH,isnull(HB.SH,isnull(HB.ASM,HB.RM))) as [EMPCode]'                          
  Else If @LUserRole='RH'                          
  Set @strSQL =' isnull(HB.SH,isnull(HB.ASM,HB.RM)) as [EMPCode]'                          
  Else If @LUserRole='SH'                          
  Set @strSQL =' isnull(HB.ASM,HB.RM) as [EMPCode]'                          
  Else If @LUserRole='ASM' OR @LUserRole='RM'                          
  Set @strSQL =' isnull(HB.RM,''RM'') as [EMPCode]'                          
 End                          
                    
 -- RM,ASM,SH,RH,NSM,BH                    
 Else if @BusinessCode='CERL'                          
  Begin                          
   if @LUserRole='BH'                      
   Set @strSQL =' Isnull(HB.NSM,Isnull(HB.RH,isnull(HB.SH,isnull(HB.ASM,HB.RM)))) as [EMPCode]'                          
   Else If @LUserRole='NSM'                          
   Set @strSQL =' Isnull(HB.RH,isnull(HB.SH,isnull(HB.ASM,HB.RM))) as [EMPCode]'                          
   Else If @LUserRole='RH'                          
   Set @strSQL =' isnull(HB.SH,isnull(HB.ASM,HB.RM)) as [EMPCode]'                          
   Else If @LUserRole='SH'                          
   Set @strSQL =' isnull(HB.ASM,HB.RM) as [EMPCode]'                          
   Else If @LUserRole='ASM' OR @LUserRole='RM'                          
   Set @strSQL =' isnull(HB.RM,''RM'') as [EMPCode]'                          
  End                          
                          
  --RM,TL,SH,SRH,HWC,BH                       
  Else If @BusinessCode='IFG'                          
  Begin                 
        if(@LUserRole='UH')                
  begin                
  set @LUserRole='TL'                
  end                 
  else if(@LUserRole='RH')                
  begin                
  set @LUserRole='SH'                
  end                
                
   if @LUserRole='BH'                      
   Set @strSQL =' Isnull(HB.HWC,Isnull(HB.SRH,isnull(HB.SH,isnull(HB.TL,HB.RM)))) as [EMPCode]'                          
   Else If @LUserRole='HWC'                          
   Set @strSQL =' Isnull(HB.SRH,isnull(HB.SH,isnull(HB.TL,HB.RM))) as [EMPCode]'                          
   Else If @LUserRole='SRH'                          
   Set @strSQL =' isnull(HB.SH,isnull(HB.TL,HB.RM)) as [EMPCode]'                          
   Else If @LUserRole='SH'                          
   Set @strSQL =' isnull(HB.TL,HB.RM) as [EMPCode]'                          
   Else If @LUserRole='TL' OR @LUserRole='RM'                          
   Set @strSQL =' isnull(HB.RM,''RM'') as [EMPCode]'                          
  End                          
                          
  -- BH,BM,NSM,SH,ASM,RM                          
  Else If @BusinessCode='TRACTOR'                          
  Begin                     
  if(@LUserRole='SM')                
  begin                
  set @LUserRole='RM'                
  end                  
                
   if @LUserRole='BH'                      
   Set @strSQL =' Isnull(HB.BM,Isnull(HB.NSM,isnull(HB.SH,isnull(HB.ASM,HB.RM))))  as [EMPCode]'                          
   Else If @LUserRole='BM'                          
   Set @strSQL =' Isnull(HB.NSM,isnull(HB.SH,isnull(HB.ASM,HB.RM))) as [EMPCode]'                          
   Else If @LUserRole='NSM'                           
   Set @strSQL =' isnull(HB.SH,isnull(HB.ASM,HB.RM)) as [EMPCode]'                          
   Else If @LUserRole='SH'                          
   Set @strSQL =' isnull(HB.ASM,HB.RM) as [EMPCode]'                          
   Else If @LUserRole='ASM' OR @LUserRole='RM'                          
   Set @strSQL =' HB.RM as [EMPCode]'                          
  End                          
                          
  -- RM,ASM,SH,RH,NSM,BH                        
  Else If @BusinessCode='BRANCH'                          
  Begin                          
   if @LUserRole='BH'                      
  Set @strSQL =' Isnull(HB.NSM,Isnull(HB.RH,Isnull(HB.SH,Isnull(HB.ASM,HB.RM)))) as [EMPCode]'                          
   Else if @LUserRole='NSM'                       
  Set @strSQL =' Isnull(HB.RH,Isnull(HB.SH,Isnull(HB.ASM,HB.RM))) as [EMPCode]'                          
  Else if @LUserRole='RH'                       
  Set @strSQL =' Isnull(HB.SH,Isnull(HB.ASM,HB.RM)) as [EMPCode]'                      
   Else If @LUserRole='SH'                          
  Set @strSQL =' Isnull(HB.ASM,HB.RM) as [EMPCode]'                          
   Else If @LUserRole='ASM' OR @LUserRole='RM'                          
  Set @strSQL =' isnull(HB.RM,''RM'') as [EMPCode]'                          
  End                          
                 
   Else  If @BusinessCode='CV-WC'                          
  Begin                  
  if(@LUserRole='TSM')                
  begin                
  set @LUserRole='RM'                
  end                 
                
  if @LUserRole='BH'                      
  Set @strSQL =' Isnull(HB.ZH,Isnull(HB.RH,isnull(HB.SH,isnull(HB.ASM,HB.RM)))) as [EMPCode]'            
  Else If @LUserRole='ZH'                          
  Set @strSQL =' Isnull(HB.RH,isnull(HB.SH,isnull(HB.ASM,HB.RM))) as [EMPCode]'                          
  Else If @LUserRole='RH'                          
  Set @strSQL =' isnull(HB.SH,isnull(HB.ASM,HB.RM)) as [EMPCode]'                          
  Else If @LUserRole='SH'                          
  Set @strSQL =' isnull(HB.ASM,HB.RM) as [EMPCode]'                     
  Else If @LUserRole='ASM' OR @LUserRole='RM'                          
  Set @strSQL =' isnull(HB.RM,''RM'') as [EMPCode]'                          
  End         
    
  
    Else If @BusinessCode='TRACTOR-WC'                          
  Begin                     
  if(@LUserRole='SM')                
  begin                
  set @LUserRole='RM'                
  end                  
                
   if @LUserRole='BH'                      
   Set @strSQL =' Isnull(HB.BM,Isnull(HB.NSM,isnull(HB.SH,isnull(HB.ASM,HB.RM))))  as [EMPCode]'                          
   Else If @LUserRole='BM'                          
   Set @strSQL =' Isnull(HB.NSM,isnull(HB.SH,isnull(HB.ASM,HB.RM))) as [EMPCode]'                          
   Else If @LUserRole='NSM'                           
   Set @strSQL =' isnull(HB.SH,isnull(HB.ASM,HB.RM)) as [EMPCode]'                          
   Else If @LUserRole='SH'                          
   Set @strSQL =' isnull(HB.ASM,HB.RM) as [EMPCode]'                          
   Else If @LUserRole='ASM' OR @LUserRole='RM'                          
   Set @strSQL =' HB.RM as [EMPCode]'                          
  End    
  --select  @strSQL  
  --exec(@strSQL)  
        RETURN  @strSQL ;   
    END
GO
/****** Object:  UserDefinedFunction [dbo].[fn_GetDrillDownEmpcode]    Script Date: 21-09-2024 20:36:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE  FUNCTION [dbo].[fn_GetDrillDownEmpcode](@LUserID varchar(20),@LUserRole varchar(20),@BusinessCode varchar(20))    
RETURNS @returnDynamicTable TABLE 
(
    strSQL  nvarchar(max) NULL, 
    BusinessID nvarchar(50) NULL,
	 strTable nvarchar(max) NULL,
	  strGroupBy nvarchar(max) NULL
)  
    AS   
    BEGIN  
        declare @strSQL varchar(max)=null ,@BusinessID varchar(max)=null,@strTable varchar(max)=null,@strGroupBy varchar(max)=null
     if @BusinessCode='TRACTOR'                            
  Begin       
   set @BusinessID ='1' 
	   set @strTable =' tbl_PMS_Hierarchy_Tractor HB left join tbl_PMS_Manpower_Profile MP    
	   on (SupervisorEmpCode=HB.RM or SupervisorEmpCode=HB.ASM or SupervisorEmpCode=HB.SH or SupervisorEmpCode=HB.NSM or  SupervisorEmpCode=HB.BM ) and  HB.BH=''R0374'''  
		set @strGroupBy='HB.RM,HB.ASM,HB.SH,HB.NSM,HB.BM'  


   -- BH,BM,NSM,SH,ASM,RM        
    if @LUserRole='BH'     
   
    Set @strSQL ='(Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where BH ='''+ @LUserID +'''    
     Union    
     Select distinct ASM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  BH ='''+ @LUserID +'''    
     union    
     Select distinct SH as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  BH ='''+ @LUserID +'''    
     union    
     Select distinct NSM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  BH ='''+ @LUserID +'''    
     union    
     Select distinct BM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  BH ='''+ @LUserID +'''    
     union    
     Select distinct BH as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  BH ='''+ @LUserID +''')'               
         
    Else If @LUserRole='BM'                            
    Set @strSQL ='(Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where BM ='''+ @LUserID +'''    
     Union    
     Select distinct ASM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  BM ='''+ @LUserID +'''    
     union    
     Select distinct SH as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  BM ='''+ @LUserID +'''    
     union    
     Select distinct NSM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  BM ='''+ @LUserID +'''    
     union    
     Select distinct BM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  BH ='''+ @LUserID +''')'                            
    Else If @LUserRole='NSM'                            
    Set @strSQL ='(Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where NSM ='''+ @LUserID +'''    
     Union    
     Select distinct ASM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  NSM ='''+ @LUserID +'''    
     union    
     Select distinct SH as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  NSM ='''+ @LUserID +'''    
     union    
     Select distinct NSM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  NSM ='''+ @LUserID +''') '                            
    Else If @LUserRole='SH'                            
    Set @strSQL ='(Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where SH ='''+ @LUserID +'''    
     Union    
     Select distinct ASM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  SH ='''+ @LUserID +'''    
     union    
     Select distinct SH as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  SH ='''+ @LUserID +''') '      
         
    Else If @LUserRole='ASM'                          
    Set @strSQL =' (Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where ASM ='''+ @LUserID +'''    
     Union    
     Select distinct ASM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where  ASM ='''+ @LUserID +'''    
     )'       
 Else If @LUserRole='RM' or @LUserRole='SO'                          
    Set @strSQL =' (Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_TRACTOR where RM ='''+ @LUserID +''')'    
    
  End                            
  Else if @BusinessCode='IFG'                               
   Begin    
		set @BusinessID ='3' 
		set @strTable =' tbl_PMS_Hierarchy_IFG HB left join tbl_PMS_Manpower_Profile MP    
	  on (SupervisorEmpCode=HB.RM or SupervisorEmpCode=HB.TL or SupervisorEmpCode=HB.SH or SupervisorEmpCode=HB.SRH or  SupervisorEmpCode=HB.HWC ) and  HB.BH=''R0374'''  
	   set @strGroupBy='HB.RM,HB.TL,HB.SH,HB.SRH,HB.HWC'  


		   if(@LUserRole='UH')              
		  begin              
		  set @LUserRole='TL'              
		  end               
		  else if(@LUserRole='RH')              
		  begin              
		  set @LUserRole='SH'              
		  end 
		   -- BH,HWC,SRH,SH,TL,RM    
			if @LUserRole='BH'                        
			Set @strSQL ='(Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_IFG where BH ='''+ @LUserID +'''    
			 Union    
			 Select distinct TL as [EMPCode] from tbl_PMS_Hierarchy_IFG where BH ='''+ @LUserID +'''    
			 union    
			 Select distinct SH as [EMPCode] from tbl_PMS_Hierarchy_IFG where BH ='''+ @LUserID +'''    
			 union    
