		set @strGroupBy='HB.RM,HB.ASM,HB.SH,HB.RH,HB.ZH'  

    if @LUserRole='BH'                        
    Set @strSQL ='(Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where BH ='''+ @LUserID +'''    
     Union    
     Select distinct ASM as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where BH ='''+ @LUserID +'''    
     union    
     Select distinct SH as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where BH ='''+ @LUserID +'''    
     union    
     Select distinct RH as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where BH ='''+ @LUserID +'''    
     union    
     Select distinct ZH as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where BH ='''+ @LUserID +'''    
     union    
     Select distinct BH as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where BH ='''+ @LUserID +''')'               
    Else If @LUserRole='ZH'                            
    Set @strSQL ='(Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where ZH ='''+ @LUserID +'''    
     Union    
     Select distinct ASM as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where ZH ='''+ @LUserID +'''    
     union    
     Select distinct SH as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where ZH ='''+ @LUserID +'''    
     union    
     Select distinct RH as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where ZH ='''+ @LUserID +'''    
     union    
     Select distinct ZH as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where ZH ='''+ @LUserID +''')'                            
    Else If @LUserRole='RH'                            
    Set @strSQL ='(Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where RH ='''+ @LUserID +'''    
     Union    
     Select distinct ASM as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where RH ='''+ @LUserID +'''    
     union    
     Select distinct SH as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where RH ='''+ @LUserID +'''    
     union    
     Select distinct RH as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where RH ='''+ @LUserID +''') '                            
    Else If @LUserRole='SH'                            
    Set @strSQL ='(Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where SH ='''+ @LUserID +'''    
     Union    
     Select distinct ASM as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where SH ='''+ @LUserID +'''    
     union    
     Select distinct SH as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where SH ='''+ @LUserID +''') '      
         
    Else If @LUserRole='ASM'                          
    Set @strSQL =' (Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where ASM ='''+ @LUserID +'''    
     Union    
     Select distinct ASM as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where ASM ='''+ @LUserID +''')'       
 Else If @LUserRole='RM'                          
    Set @strSQL =' (Select distinct RM as [EMPCode] from tbl_PMS_Hierarchy_CV_WC where RM ='''+ @LUserID +''')'    
    
  End     
	  INSERT @returnDynamicTable
        SELECT @strSQL, @BusinessID,@strTable,@strGroupBy
		    RETURN;
    END
GO
/****** Object:  UserDefinedFunction [dbo].[fn_GetGroupByEmpcode]    Script Date: 21-09-2024 20:36:47 ******/
