-- select replace (dbo.fn_GetGroupByEmpcode('S3534','NSM','TRACTOR'),'HT.','HT.')
CREATE  FUNCTION [dbo].[fn_GetGroupByEmpcode](@LUserID varchar(20),@LUserRole varchar(20),@BusinessCode varchar(20))    
RETURNS  varchar(500)
 AS   
 BEGIN  
 declare @strSQL varchar(max)=null, @strGroupBy varchar(max)=null
 if @BusinessCode='TRACTOR'                            
 Begin       
	-- BH,BM,NSM,SH,ASM,RM        
	if @LUserRole='BH'     
		set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.NSM,HT.BM '  
	Else If @LUserRole='BM'                            
		set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.NSM'                  
	Else If @LUserRole='NSM'                            
		set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH'                           
	Else If @LUserRole='SH'                            
		set @strGroupBy=' Group by HT.RM,HT.ASM'       
	Else If @LUserRole='ASM'                          
		set @strGroupBy=' Group by HT.RM'  
 
 End                            
 Else if @BusinessCode='IFG'                               
 Begin    
	if(@LUserRole='UH')              
	begin              
	set @LUserRole='TL'              
	end               
	else if(@LUserRole='RH')              
	begin              
	set @LUserRole='SH'              
	end 

	-- BH,HWC,SRH,SH,TL,RM    
	if @LUserRole='BH'                        
		set @strGroupBy=' Group by HT.RM,HT.TL,HT.SH,HT.SRH,HT.HWC'  
	Else If @LUserRole='HWC'                            
		set @strGroupBy=' Group by HT.RM,HT.TL,HT.SH,HT.SRH' 	 
	Else If @LUserRole='SRH'                            
		set @strGroupBy=' Group by HT.RM,HT.TL,HT.SH' 	 
	Else If @LUserRole='SH'                            
		set @strGroupBy=' Group by HT.RM,HT.TL' 	 
	Else If @LUserRole='TL'                          
		set @strGroupBy=' Group by HT.RM' 	 
	End     
  Else if @BusinessCode='CERL'                               
  Begin    
  --BH,NSM,RH,SH,ASM,RM
    if @LUserRole='BH'     
       Set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH,HT.NSM'     
    Else If @LUserRole='NSM'                            
       Set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH'     
    Else If @LUserRole='RH'                            
       Set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH'                         
    Else If @LUserRole='SH'                            
       Set @strGroupBy=' Group by HT.RM,HT.ASM'
    Else If @LUserRole='ASM'                          
       Set @strGroupBy=' Group by HT.RM'
  End      
  Else if @BusinessCode='LCV'                               
  Begin      
	
  -- BH,NSM,ZSM,RSM,ASM,RM    
    if @LUserRole='BH'                        
       set @strGroupBy=' Group by HT.RM,HT.ASM,HT.RSM,HT.ZSM,HT.NSM'  
    Else If @LUserRole='NSM'                            
      set @strGroupBy=' Group by HT.RM,HT.ASM,HT.RSM,HT.ZSM'                          
    Else If @LUserRole='ZSM'                            
      set @strGroupBy=' Group by HT.RM,HT.ASM,HT.RSM'                        
    Else If @LUserRole='RSM'                            
      set @strGroupBy=' Group by HT.RM,HT.ASM'       
    Else If @LUserRole='ASM'                          
      set @strGroupBy=' Group by HT.RM' 
    
  End      
  Else if @BusinessCode='BRANCH'                               
  Begin      
	
  -- BH,NSM,RH,SH,ASM,RM    
    if @LUserRole='BH'                        
      set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH,HT.NSM'       
    Else If @LUserRole='NSM'                            
     set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH,HT.NSM'                             
    Else If @LUserRole='RH'                            
      set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH,HT.NSM'  
    Else If @LUserRole='SH'                            
      set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH,HT.NSM'  
    Else If @LUserRole='ASM'                          
      set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH,HT.NSM'  
 
  End      
  Else if @BusinessCode='HCV'                               
  Begin      
  -- BH,ZH,RH,SH,ASM,RM   
    if @LUserRole='BH'                        
     set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH,HT.ZH'  
    Else If @LUserRole='ZH'                            
      set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH'  
    Else If @LUserRole='RH'                            
      set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH'                          
    Else If @LUserRole='SH'                            
      set @strGroupBy=' Group by HT.RM,HT.ASM'                          
    Else If @LUserRole='ASM'                          
     set @strGroupBy=' Group by HT.RM'                          
  End      
  Else if @BusinessCode='UCV'                               
  Begin      
   -- BH,CH,RH,SH,ASM,RM    
	
    if @LUserRole='BH'                        
      set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH,HT.CH'  
    Else If @LUserRole='CH'                            
      set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH'  
    Else If @LUserRole='RH'                            
      set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH' 
    Else If @LUserRole='SH'                            
      set @strGroupBy=' Group by HT.RM,HT.ASM'      
    Else If @LUserRole='ASM'                          
     set @strGroupBy=' Group by HT.RM' 
  End 
  Else if @BusinessCode='TRACTOR-WC'                            
  Begin         
   -- BH,BM,NSM,SH,ASM,RM        
    
   if @LUserRole='BH'     
     set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.NSM,HT.BM'        
   Else If @LUserRole='BM'                            
     set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.NSM'        
   Else If @LUserRole='NSM'                            
     set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH'        
   Else If @LUserRole='SH'                            
     set @strGroupBy=' Group by HT.RM,HT.ASM'             
   Else If @LUserRole='ASM'                          
     set @strGroupBy=' Group by HT.RM'        
  End   
  Else if @BusinessCode='CV-WC'                               
  Begin      
  -- BH,ZH,RH,SH,ASM,RM    
  
   if @LUserRole='BH'                        
     set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH,HT.ZH'  
   Else If @LUserRole='ZH'                            
     set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH,HT.RH'  
   Else If @LUserRole='RH'                            
     set @strGroupBy=' Group by HT.RM,HT.ASM,HT.SH'  
   Else If @LUserRole='SH'                            
    set @strGroupBy=' Group by HT.RM,HT.ASM'  
    Else If @LUserRole='ASM'                          
     set @strGroupBy=' Group by HT.RM'  
  End     
   
      RETURN @strGroupBy;
  END
GO
