create function [dbo].[fn_GetSupervisor](@Empcode varchar(50),@SupervisorRole varchar(50))
RETURNS varchar(50)
AS 
BEGIN
 DECLARE @SupervisorID VARCHAR(50)
 select @SupervisorID=SupervisorCode from TBL_OVI_RM_Hierarchy_Mapping
 where EmpCode=@Empcode and SupervisorRole like @SupervisorRole

 return @SupervisorID
END
GO
