CREATE  FUNCTION [dbo].[fn_GetTriggerName] (      
 @TriggerId varchar(100)      
)      
RETURNS  Varchar(200)  AS      
BEGIN      
 DECLARE @return_value Varchar(200) ;      
      
 select @return_value = Trigger_ID +' - ' + Trigger_name from RFA_TriggerMaster where Trigger_ID= @TriggerId;      
 --SET @return_value =  CASE WHEN @TriggerId = 1 THEN ''              
       
    RETURN @return_value      
END 
GO
/****** Object:  UserDefinedFunction [dbo].[fn_month_name_to_number]    Script Date: 21-09-2024 20:36:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


create function [dbo].[fn_month_name_to_number] (@monthname varchar(25))
returns int as
begin
	declare @monthno as int;
	select @monthno =
	case @monthname
	when 'January' then 1
	when 'February' then 2
	when 'March' then 3
	when 'April' then 4
	when 'May' then 5
	when 'June' then 6
	when 'July' then 7
	when 'August' then 8
	when 'September' then 9
	when 'October' then 10
	when 'November' then 11
	when 'December' then 12
	end
	return @monthno
end
GO
/****** Object:  UserDefinedFunction [dbo].[fn_month_number_to_name]    Script Date: 21-09-2024 20:36:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[fn_month_number_to_name] (@monthnumber int)
RETURNS VARCHAR(50)
AS BEGIN
    DECLARE @monthname VARCHAR(50)

   SELECT  @monthname= DATENAME( MONTH, DATEADD( MONTH,@monthnumber, -1))


    RETURN @monthname
END
GO
