 -- select * from fn_TPMS_GetHierarchy('R0374','BH','CERL')
CREATE  FUNCTION [dbo].[fn_TPMS_GetHierarchy](@LUserID varchar(20),@LUserRole varchar(20),@BusinessCode varchar(20))    
RETURNS @returnDynamicTable TABLE 
(
    
    strSQL varchar(max) NULL,
	strcolumn  varchar(max) NULL
	
)     
    AS   
    BEGIN  
	    declare @strSQL varchar(max)=null ,@strcolumn varchar(max)=null--,@strTable varchar(max)=null,@strGroupBy varchar(max)=null
      --  declare @strSQL varchar(max)=null --,  @LUserID varchar(20) ='J0322',@LUserRole varchar(20)='L6',@BusinessCode varchar(20)='Tractor'  
     If @BusinessCode='HCV'                          
  Begin                  
       set @strcolumn='Select distinct K.RM as L6,K.ASM as L5,k.SH as L4,K.RH as L3,K.ZH as L2,K.BH as L1 from tbl_PMS_Hierarchy_HCV '      
                
  if @LUserRole='BH'                      
  Set @strSQL =' Isnull(HT.L2,Isnull(HT.L3,isnull(HT.L4,isnull(HT.L5,HT.L6)))) as [EMPCode]'          
  Else If @LUserRole='ZH'                          
  Set @strSQL =' Isnull(HT.L3,isnull(HT.L4,isnull(HT.L5,HT.L6))) as [EMPCode]'                          
  Else If @LUserRole='RH'                          
  Set @strSQL =' isnull(HT.L4,isnull(HT.L5,HT.L6)) as [EMPCode]'                          
  Else If @LUserRole='SH'                          
  Set @strSQL =' isnull(HT.L5,HT.L6) as [EMPCode]'                          
  Else If @LUserRole='ASM' OR @LUserRole='RM'                          
  Set @strSQL =' isnull(HT.L6,''L6'') as [EMPCode]'                          
  End                          
               
  -- L6_TSM,L5,RSM,ZSM,NSM,BH                    
 Else If @BusinessCode='LCV'                          
 Begin                          
 set @strcolumn='Select distinct K.RM as L6,K.ASM as L5,k.RSM as L4,K.ZSM as L3,K.NSM as L2,K.BH as L1  from tbl_PMS_Hierarchy_LCV '      

  if @LUserRole='BH'                      
  Set @strSQL =' Isnull(HT.L2,Isnull(HT.L3,isnull(HT.L4,isnull(HT.L5,HT.L6)))) as [EMPCode]'                           
  Else If @LUserRole='NSM'                          
  Set @strSQL =' Isnull(HT.L3,isnull(HT.L4,isnull(HT.L5,HT.L6))) as [EMPCode]'                          
  Else If @LUserRole='ZSM'                          
  Set @strSQL =' isnull(HT.L4,isnull(HT.L5,HT.L6)) as [EMPCode]'                          
  Else If @LUserRole='RSM'                          
  Set @strSQL =' isnull(HT.L5,HT.L6) as [EMPCode]'                          
  Else If @LUserRole='ASM' OR @LUserRole='RM'                          
  Set @strSQL =' isnull(HT.L6,''L6'') as [EMPCode]'                          
 End                     
                     
  -- L6,L5,SH,RH,CH,BH                    
 Else If @BusinessCode='UCV'                          
 Begin                          
 set @strcolumn='Select distinct K.RM as L6,K.ASM as L5,k.SH as L4,K.RH as L3,K.CH as L2,K.BH as L1  from tbl_PMS_Hierarchy_UCV '      
  if @LUserRole='BH'                      
  Set @strSQL =' Isnull(HT.L2,Isnull(HT.L3,isnull(HT.L4,isnull(HT.L5,HT.L6)))) as [EMPCode]'                           
  Else If @LUserRole='CH'                          
  Set @strSQL =' Isnull(HT.L3,isnull(HT.L4,isnull(HT.L5,HT.L6))) as [EMPCode]'                          
  Else If @LUserRole='RH'                          
  Set @strSQL =' isnull(HT.L4,isnull(HT.L5,HT.L6)) as [EMPCode]'                          
  Else If @LUserRole='SH'                          
  Set @strSQL =' isnull(HT.L5,HT.L6) as [EMPCode]'                          
  Else If @LUserRole='ASM' OR @LUserRole='RM'                          
  Set @strSQL =' isnull(HT.L6,''L6'') as [EMPCode]'                          
 End                          
                    
 -- L6,L5,SH,RH,NSM,BH                    
 Else if @BusinessCode='CERL'                          
  Begin                      
  set @strcolumn='Select distinct K.RM as L6,K.ASM as L5,k.SH as L4,K.RH as L3,K.NSM as L2,K.BH as L1  from tbl_PMS_Hierarchy_CERL '      
   if @LUserRole='BH'                      
   Set @strSQL =' Isnull(HT.L2,Isnull(HT.L3,isnull(HT.L4,isnull(HT.L5,HT.L6)))) as [EMPCode]'                          
   Else If @LUserRole='NSM'                          
   Set @strSQL =' Isnull(HT.L3,isnull(HT.L4,isnull(HT.L5,HT.L6))) as [EMPCode]'                          
   Else If @LUserRole='RH'                          
   Set @strSQL =' isnull(HT.L4,isnull(HT.L5,HT.L6)) as [EMPCode]'                          
   Else If @LUserRole='SH'                          
   Set @strSQL =' isnull(HT.L5,HT.L6) as [EMPCode]'                          
   Else If @LUserRole='ASM' OR @LUserRole='RM'                          
   Set @strSQL =' isnull(HT.L6,''L6'') as [EMPCode]'                          
  End                          
                          
  --L6,TL,SH,SRH,HWC,BH                       
  Else If @BusinessCode='IFG'                          
  Begin                 
                 
                set @strcolumn='Select distinct K.RM as L6,K.TL as L5,k.SH as L4,K.SRH as L3,K.HWC as L2,K.BH as L1  from tbl_PMS_Hierarchy_IFG '      
   if @LUserRole='BH'                      
   Set @strSQL =' Isnull(HT.L2,Isnull(HT.L3,isnull(HT.L4,isnull(HT.L5,HT.L6)))) as [EMPCode]'                          
   Else If @LUserRole='HWC'                          
   Set @strSQL =' Isnull(HT.L3,isnull(HT.L4,isnull(HT.L5,HT.L6))) as [EMPCode]'                          
   Else If @LUserRole='SRH'                          
   Set @strSQL =' isnull(HT.L4,isnull(HT.L5,HT.L6)) as [EMPCode]'                          
   Else If @LUserRole='SH'                          
   Set @strSQL =' isnull(HT.L5,HT.L6) as [EMPCode]'                          
   Else If @LUserRole='TL' OR @LUserRole='RM'                          
   Set @strSQL =' isnull(HT.L6,''L6'') as [EMPCode]'                          
  End                          
                          
  -- BH,BM,NSM,SH,L5,L6                          
  Else If @BusinessCode='TRACTOR'                          
