                set @strcolumn='Select distinct K.RM as L6,K.ASM as L5,k.SH as L4,K.NSM as L3,K.BM as L2,K.BH as L1  from tbl_PMS_Hierarchy_Tractor '      
                
   if @LUserRole='BH'                      
