   Else If @LUserRole='BM'                          
   Set @strSQL =' Isnull(HT.L3,isnull(HT.L4,isnull(HT.L5,HT.L6))) as [EMPCode]'                          
   Else If @LUserRole='NSM'                           
   Set @strSQL =' isnull(HT.L4,isnull(HT.L5,HT.L6)) as [EMPCode]'                          
   Else If @LUserRole='SH'                          
