     	  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode where A.Account_Customisation_Customer_Details_ID=@CustomerId and A.LevelNumber<@NextLevelNo
              FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')
