     ELSE IF(@Identflag='SentBack')
     BEGIN
     select @CCEmailId=STUFF((SELECT  ', ' + B.EmpEmail from TBL_OVI_Account_Customisation_Approver A 
     	  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode where A.Account_Customisation_Customer_Details_ID=@CustomerId and A.LevelNumber=1 
              FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')
              , 1, LEN(','), '')
     END

END
ELSE
BEGIN
    IF(@Identflag='Request')
    BEGIN
    select @CCEmailId=STUFF((SELECT  ', ' + B.EmpEmail from TBL_OVI_Aprrover A 
    	  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode where A.Customer_Info_Id=@CustomerId and A.LevelNumber=1
             FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')
             , 1, LEN(','), '')
    END
    ELSE IF(@Identflag='Approved')
    BEGIN
    select @CCEmailId=STUFF((SELECT  ', ' + B.EmpEmail from TBL_OVI_Aprrover A 
    	  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode where A.Customer_Info_Id=@CustomerId and A.LevelNumber=1
             FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')
             , 1, LEN(','), '')
    END
    ELSE IF(@Identflag='SentBack')
    BEGIN
    select @CCEmailId=STUFF((SELECT  ', ' + B.EmpEmail from TBL_OVI_Aprrover A 
    	  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode where A.Customer_Info_Id=@CustomerId and A.LevelNumber=1 
             FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')
             , 1, LEN(','), '')
    END
	ELSE IF(@Identflag='Reject')
    BEGIN
    select @CCEmailId=STUFF((SELECT  ', ' + B.EmpEmail from TBL_OVI_Aprrover A 
    	  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode where A.Customer_Info_Id=@CustomerId and A.LevelNumber<@NextLevelNo 
             FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')
             , 1, LEN(','), '')
    END
END
return @CCEmailId
END
