/****** Object:  UserDefinedFunction [dbo].[Split]    Script Date: 21-09-2024 20:36:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[Split](@String varchar(8000), @Delimiter char(1))        
returns @temptable TABLE (items varchar(8000))        
as        
begin        
    declare @idx int        
    declare @slice varchar(8000)        
       
    select @idx = 1        
        if len(@String)<1 or @String is null  return        
       
    while @idx!= 0        
    begin        
        set @idx = charindex(@Delimiter,@String)        
        if @idx!=0        
            set @slice = left(@String,@idx - 1)        
        else        
            set @slice = @String        
           
        if(len(@slice)>0)   
            insert into @temptable(Items) values(@slice)        
  
        set @String = right(@String,len(@String) - @idx)        
        if len(@String) = 0 break        
    end    
return        
end  


GO
/****** Object:  UserDefinedFunction [dbo].[SplitString]    Script Date: 21-09-2024 20:36:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[SplitString]  
(      
    @Input NVARCHAR(MAX),  
    @Character CHAR(1)  
)  
RETURNS @Output TABLE (  
    Item NVARCHAR(1000)  
)  
AS  
BEGIN  
    DECLARE @StartIndex INT, @EndIndex INT  
   
    SET @StartIndex = 1  
   
    WHILE CHARINDEX(@Character, @Input) > 0  
    BEGIN  
        SET @EndIndex = CHARINDEX(@Character, @Input)  
           
        INSERT INTO @Output(Item)  
        SELECT SUBSTRING(@Input, @StartIndex, @EndIndex - 1)  
           
        SET @Input = SUBSTRING(@Input, @EndIndex + 1, LEN(@Input))  
    END  
   
    -- Check if the remaining input is not empty and insert it
    IF LEN(@Input) > 0
    BEGIN
        INSERT INTO @Output(Item)  
        SELECT @Input
    END
   
    RETURN  
END
GO
/****** Object:  UserDefinedFunction [dbo].[yearfrac]    Script Date: 21-09-2024 20:36:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
create function [dbo].[yearfrac] (@d1 datetime, @d2 datetime) returns float
as
begin
return convert(numeric(18,2),abs(datediff(d, @d1, @d2)) / 365.00)
end
GO
