/****** Object:  StoredProcedure [dbo].[Csp_ACR_Churnutilaccwise_New]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE Proc  [dbo].[Csp_ACR_Churnutilaccwise_New] 
                  

                  
As                  
Begin                
Declare @Sflag as int              
Declare @cnt as int                  
set @cnt = -1                  
set @Sflag = 0        

            
 Declare @IColumb as varchar(max) 
 Declare @IClmn as varchar(max)              
 Declare @OClmn as varchar(max)      
 set   @IColumb=''  
 set   @OClmn=''              
 set   @IClmn=''           
    
While(@cnt != -14)                  
Begin                  
    --print(@cnt)          
 --print(substring(Datename(month, dateadd(month,@cnt,getdate()) ),1,3) + datename(year,dateadd(month,@cnt,getdate())))        
      
 Declare @CntFlag as int                        
 Declare @sql as varchar(max)                  
 Declare  @Iname as varchar(50)                  
 Declare  @Oname as varchar(50)                  
 Declare  @Iflag as int                  
 Declare  @Oflag as int                  
 Declare  @Tflag as int  
      
 set @CntFlag = 1                  
 set @Tflag  = 0                  
     
 set @Iname = substring(Datename(month, dateadd(month,@cnt,getdate()) ),1,3) + datename(year,dateadd(month,@cnt,getdate())) +'_NetCredit'                  
 set @Oname = substring(Datename(month, dateadd(month,@cnt,getdate()) ),1,3) + datename(year,dateadd(month,@cnt,getdate())) +'_Util'                  
 Select @Iflag  = dbo.fnChkCName('Tra_ChurnNetCreditHistory',@Iname)                  
 select @Oflag  = dbo.fnChkCName('Tra_ChurnNetCreditHistory',@Oname)                  
 set @Tflag = @Iflag +  @Oflag              
                
 IF @Tflag = 2                  
 Begin        
-- Print('M1') 
 --Print(@cnt)               
 --Print(@Tflag)       
 --Print (@Iname)        
 --Print(@Oname)                 
  IF @cnt = -13                  
  Begin                  
   set @IColumb = @IColumb +'''' + substring(Datename(month, dateadd(month,@cnt,getdate()) ),1,3) + datename(year,dateadd(month,@cnt,getdate())) + ''''                  
   set @IClmn = @IClmn + @Iname               
   set @OClmn = @OClmn + @Oname                 
  End                  
   Else if @cnt = -1                  
  --Else if @cnt = -2                  
  Begin                  
   set @IColumb = '''' + substring(Datename(month, dateadd(month,@cnt,getdate()) ),1,3) + datename(year,dateadd(month,@cnt,getdate())) + ''','                  
   set @IClmn = @Iname  + ','               
   set @OClmn = @Oname  + ','        
   set @CntFlag = 0    
   set @Sflag  = 1                 
  End         
   Else  if @cnt = -2 and  @CntFlag = 1      
 Begin      
     
 if @Sflag = 1    
  Begin    
   set @IColumb = @IColumb + '''' + substring(Datename(month, dateadd(month,@cnt,getdate()) ),1,3) + datename(year,dateadd(month,@cnt,getdate())) + ''','                  
   set @IClmn = @IClmn + @Iname  + ','               
   set @OClmn = @OClmn + @Oname  + ','        
   set @CntFlag = 0          
  End    
 Else    
  Begin    
   set @IColumb = '''' + substring(Datename(month, dateadd(month,@cnt,getdate()) ),1,3) + datename(year,dateadd(month,@cnt,getdate())) + ''','                  
   set @IClmn = @Iname  + ','               
   set @OClmn = @Oname  + ','        
   set @CntFlag = 0         
  End    
 End              
  Else                  
  Begin                  
   set @IColumb = @IColumb + '''' + substring(Datename(month, dateadd(month,@cnt,getdate()) ),1,3) + datename(year,dateadd(month,@cnt,getdate())) + ''','                  
   set @IClmn = @IClmn  + @Iname + ','              
   set @OClmn = @OClmn  + @Oname + ','              
  End                    
                  
 End                  
 set @cnt = @cnt -1                  
                   
End                  
         
--       print('--Start--')           
--Print(@IColumb)                
--Print(@OClmn)              
--Print(@IClmn)   
--print('--Hello--')             
              
Declare @sqlt1 varchar(max)              
              
set @sqlt1 = 'select Account_no,Mnt,Netcr,Limit                   
From                   
(                  
select Account_no,' + @IClmn + ',Limit  from Tra_ChurnNetCreditHistory  ) p                  
Unpivot                  
(                  
Netcr For Mnt in (' + @IClmn + ')                  
)                  
as unpvt '         
        
--Print(@sqlt1)           
              
Declare @sqlt2 varchar(max)              
              
set @sqlt2 = 'select Account_no,Mnt,Netcr,Limit                   
From                   
(                  
select Account_no,' + @OClmn + ',Limit from Tra_ChurnNetCreditHistory ) p                  
Unpivot                  
(                  
Netcr For Mnt in (' + @OClmn + ')                  
)                  
as unpvt '              
              
           
--Print(@sqlt2)              
              
Create table #Temp                  
(                  
 Account_no varchar(50),                  
 Mnt varchar(25),       
 Netcr varchar(50), 
 limit varchar(50)                 
-- Outcr varchar(50)                  
)                  
--                      
insert into #Temp(Account_no,Mnt,Netcr,limit)                
exec(@sqlt1)              
              
              
Create table #Temp2                  
(                  
 Account_no varchar(50),                  
 Mnt varchar(25),                  
 Outcr varchar(50), 
 limit varchar(50)                  
)                 
              
insert into #Temp2(Account_no,Mnt,Outcr,limit)               
exec(@sqlt2)              
              
update #Temp              
set Mnt = substring(mnt,1,7)              
              
update #Temp2                  
set Mnt = substring(mnt,1,7)                   
              
--select * from #Temp              
--select * from #Temp2              
              
set @sql = 'select               
    distinct(T1.Account_no) as ''Accno'',              
    T1.Mnt as ''Month End'',              
    round( convert(float, T1.Netcr)/100000,2) as ''Total Credits Rs. In Lacs'',            
 round( convert(float, T2.Outcr)/100000,2) as ''Utilization'' ,T1.limit              
    --,'''' as ''No of credits in the Account''             
   from #Temp as T1 inner join #Temp2 as T2                  
   on T1.Mnt = T2.Mnt                  
   and T1.Account_no = T2.Account_no                  
   and T1.Mnt in (' + @IColumb + ') order by T1.Mnt'              
              
--print(@sql)              

Create table #temp_danny
(Accno varchar(100),
[Month End] varchar(100),
[Total Credits Rs. In Lacs] varchar(100),
Utilization varchar(100),
limit varchar(50)

)


Insert into #temp_danny
exec(@sql)   

delete from  [OneViewIndicator].[dbo].tbl_netcredit_utlization

insert into  [OneViewIndicator].[dbo].tbl_netcredit_utlization
Select SME_Client_ID,(SUBSTRING([Month End],1,3) + ' ' + 
SUBSTRING([Month End],4,5)) as [Month End], sum(cast([Total Credits Rs. In Lacs]as float )) 'net credits', sum(cast(Utilization as float)),limit from #temp_danny  
c inner join [10.226.204.81].[RepotDB].[dbo].Mst_Name_Match_Dtl d on c.Accno=d.Account_No
group by SME_Client_ID,[Month End], [Total Credits Rs. In Lacs], Utilization ,limit
order by cast((SUBSTRING([Month End],1,3) + ' ' + SUBSTRING([Month End],4,5)) as datetime) desc            
             
--print('---By-----')   
Drop table #Temp                  
Drop table #Temp2               
              
              
End




