CREATE procedure [dbo].[CustomerPageLables]
@LS_ID varchar(50)
as
begin
select 
LS_ID, isnull (CustomerName, 'NA') 'CustomerName', isnull (Branch_ID, 'NA')'Branch_ID', isnull (case when Email='0' then 'NA' else Email End , 'NA') 'EMAIL', 
isnull (PhoneNumber, 'NA') 'Phonenumber', isnull (Line_Of_Activity, 'NA') 'Line_Of_Activity', isnull(PSL_Category,'NA')'PSL_Category',
 isnull(Industry, 'NA') 'Industry', isnull(RAM_Rating,'NA')'RAM_Rating', isnull(Constitution,'NA')'Constitution', Isnull(Convert(Varchar(20),CONVERT(date,Businesss_Vintage,102),106),'NA') 'Businesss_Vintage',
 isnull (CITY, 'NA')'CITY', isnull(REGION, 'NA') 'REGION', isnull(STATE, 'NA')'STATE', isnull(LCHU,'NA')'LCHU', isnull (Watchlist, 'NA')'Watchlist', 
 isnull ([Exit], 'NA') 'Exit', isnull (Plan_Available, 'NA')'Plan_Available',isnull (Account_Vintage, 'NA')  'Account_Vintage', isnull(SPT, 'NO') 'SPT', 
 isnull(IRR, 'NA') 'IRR', isnull (Self_funding, 'NA') 'Self_funding_ratio'
 from Customer where LS_ID = @LS_ID order by CustomerName asc
end
