/****** Object:  StoredProcedure [dbo].[Get_Branch]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE Procedure [dbo].[Get_Branch]
@flag varchar(100)=null,
@Branch_Name varchar(100)=Null
as
begin
Declare @FBCount float,@NFBCount float,@TotalFBNFB float,@FBO float,@NFBO float,@TotalFBONFBO float
select @FBCount=SUM(CAST([LIMIT AMT (INR)] as INT))from WC where [FLEXCUBE BRANCH]=@Branch_Name and [FACILITY_NAME]='CASH CREDIT' 
select @NFBCount=SUM(CAST([LIMIT AMT (INR)] as INT))from WC where [FLEXCUBE BRANCH]=@Branch_Name and [FACILITY_NAME]!='CASH CREDIT'
select @FBO=SUM(CAST([FUND_OUTSTANDING AMT (INR)] as INT))from WC where [FLEXCUBE BRANCH]=@Branch_Name 
select @NFBO=SUM(CAST([NON_FUND_OUTSTANDING AMT (INR)] as INT))from WC where [FLEXCUBE BRANCH]=@Branch_Name 
set @TotalFBNFB=isNull(@FBCount,0)+isNull(@NFBCount,0)
set @TotalFBONFBO=ISNULL(@FBO,0)+isNull(@NFBO,0)
--select @TotalFBNFB,@FBCount,@NFBCount
if(@flag='GetAll')
begin
select distinct [FLEXCUBE BRANCH] as'FLEXCUBE_BRANCH' from WC
end
else if(@flag='GetData')
begin
if(@Branch_Name='District')
begin

select  [FLEXCUBE BRANCH] as 'Branch Name',COUNT([FLEXCUBE BRANCH]) as'Customer' from WC group by [FLEXCUBE BRANCH]
select @FBCount as 'FB',@NFBCount as 'NFB',@TotalFBNFB as 'Total'
select @FBO as 'FB O/S',@NFBO as 'NF O/S',@TotalFBONFBO as 'Total O/s'
end
else
begin
select  [FLEXCUBE BRANCH]  as 'Branch Name',COUNT([FLEXCUBE BRANCH]) as'Customer' from WC where [FLEXCUBE BRANCH]=@Branch_Name 
group by [FLEXCUBE BRANCH]
select @FBCount as 'FB',@NFBCount as 'NFB',@TotalFBNFB as 'Total'
select @FBO as 'FB O/S',@NFBO as 'NF O/S',@TotalFBONFBO as 'Total O/s'
end
end
end
GO
