/****** Object:  StoredProcedure [dbo].[Get_PSL_Classification]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE Procedure [dbo].[Get_PSL_Classification]
as
begin
select [Section],Count([Section])'# of Customers',(Sum(CONVERT(decimal(18,2),[OS in Cr]))) as 'Amount (in cr)', Sum(CONVERT(decimal(18,2),[OS in Cr])) * 100.0 / (select Sum(CONVERT(decimal(18,2),[OS in Cr]))  from TBL_OVI_BBGPSL) as '%'
from TBL_OVI_BBGPSL
group by [Section] order by Sum(CONVERT(decimal(18,2),[OS in Cr])) * 100.0 / (select Sum(CONVERT(decimal(18,2),[OS in Cr])) from TBL_OVI_BBGPSL);

--select [Section], Count([Section])'# of Customers',Sum(CONVERT(decimal(18,2),[OS in Cr]))as '%' from TBL_OVI_BBGPSL  group by [Section]  order by Sum(CONVERT(decimal(18,2),[OS in Cr]))
--select jsonData = JSON_QUERY((select Sum(CONVERT(decimal(18,2),[OS in Cr])) * 100.0 / (select Sum(CONVERT(decimal(18,2),[OS in Cr]))  from TBL_OVI_BBGPSL)as 'Count',[Section], Count([Section])'# of Customers' from TBL_OVI_BBGPSL  group by [Section] order by  Sum(CONVERT(decimal(18,2),[OS in Cr])) * 100.0 / (select Sum(CONVERT(decimal(18,2),[OS in Cr]))  from TBL_OVI_BBGPSL) for json path  ))

select Sum(CONVERT(decimal(18,2),[OS in Cr])) * 100.0 / (select Sum(CONVERT(decimal(18,2),[OS in Cr]))  from TBL_OVI_BBGPSL)as 'Count',[Section], Count([Section])'# of Customers' from TBL_OVI_BBGPSL  group by [Section] order by  Sum(CONVERT(decimal(18,2),[OS in Cr])) * 100.0 / (select Sum(CONVERT(decimal(18,2),[OS in Cr]))  from TBL_OVI_BBGPSL)





end
