CREATE procedure [dbo].[getCross_Sell_Completed]
@ls_id varchar(100)
as 
begin

select distinct Cross_Sell_ID, Cross_Sell_name, ls_id, Cross_Sell_Entry_id, Cross_Sell_completion_days, Cross_Sell_start_date, Cross_Sell_supervisor ,Cross_Sell_start_date,
