/****** Object:  StoredProcedure [dbo].[getCrossSell]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[getCrossSell]  
@ls_id varchar(100),
@empid varchar(100),
@dept varchar(100) =''
as 
begin

if(@dept !='Credit')
	Begin

	select distinct n.Cross_Sell_ID, Cross_Sell_name, n.ls_id, n.Cross_Sell_Entry_id, Cross_Sell_completion_days, Cross_Sell_start_date, Cross_Sell_supervisor ,n.Cross_Sell_start_date,
	case when Cross_Sell_Entry_remarks_id is null then 'Pending' else (case when Cross_Sell_supervisor_approved is null then 'Pending at supervisor' else Cross_Sell_supervisor_approved end) end 'status'  from 
	Cross_Sell_entry n  left join Cross_Sell_entry_rmarks r on r.Cross_Sell_Entry_id = n.Cross_Sell_Entry_id 
	where (Cross_Sell_supervisor_approved is null  or Cross_Sell_supervisor_approved ='Pending' ) and n.ls_id = @ls_id and (Cross_Sell_rm =@empid or Cross_Sell_supervisor =@empid)
	and Cross_Sell_status is null
	union
	select distinct n.Cross_Sell_ID, Cross_Sell_name, n.ls_id, n.Cross_Sell_Entry_id, Cross_Sell_completion_days, Cross_Sell_start_date, Cross_Sell_ACM ,n.Cross_Sell_start_date,
	case when Cross_Sell_Entry_remarks_id is null then 'Pending' else (case when Cross_Sell_ACM_approved is null then 'Pending at CM' else Cross_Sell_ACM_approved end) end 'status'  from 
	Cross_Sell_Entry n  inner join Cross_Sell_entry_rmarks r on r.Cross_Sell_Entry_id = n.Cross_Sell_Entry_id 
	where (Cross_Sell_Cm_approved is null  or Cross_Sell_Cm_approved ='Pending' ) and n.ls_id = @ls_id and (Cross_Sell_rm =@empid or Cross_Sell_supervisor =@empid ) and n.Cross_Sell_Cm <>''
	and Cross_Sell_supervisor_approved is not null
	union
	select distinct n.Cross_Sell_ID, Cross_Sell_name, n.ls_id, n.Cross_Sell_Entry_id, Cross_Sell_completion_days, Cross_Sell_start_date, Cross_Sell_ACm ,n.Cross_Sell_start_date,
	case when Cross_Sell_Entry_remarks_id is null then 'Pending' else (case when Cross_Sell_ACM_approved is null then 'Pending at ACM' else Cross_Sell_ACM_approved end) end 'status'  from 
	Cross_Sell_Entry n  inner join Cross_Sell_entry_rmarks r on r.Cross_Sell_Entry_id = n.Cross_Sell_Entry_id 
	where (Cross_Sell_ACM_approved is null  or Cross_Sell_ACM_approved ='Pending' )  and Cross_Sell_CM_approved is not null   and n.ls_id = @ls_id and (Cross_Sell_rm =@empid or Cross_Sell_supervisor =@empid ) and n.Cross_Sell_Cm <>''
	and Cross_Sell_status is not null
	
	End
Else
	Begin

	select distinct n.Cross_Sell_ID, Cross_Sell_name, n.ls_id, n.Cross_Sell_Entry_id, Cross_Sell_completion_days, Cross_Sell_start_date, Cross_Sell_ACm 'Cross_Sell_Supervisor',n.Cross_Sell_start_date,
	case when Cross_Sell_Entry_remarks_id is null then 'Pending' else (case when Cross_Sell_ACM_approved is null then 'Pending at CM' else Cross_Sell_ACM_approved end) end 'status'  from 
	Cross_Sell_Entry n  inner join Cross_Sell_entry_rmarks r on r.Cross_Sell_Entry_id = n.Cross_Sell_Entry_id 
	where (Cross_Sell_Cm_approved is null  or Cross_Sell_Cm_approved ='Pending' ) and Cross_Sell_supervisor_approved is not null and n.ls_id = @ls_id and (Cross_Sell_Cm =@empid or Cross_Sell_ACM =@empid )

	End
end
GO
/****** Object:  StoredProcedure [dbo].[Getcustomers_details]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[Getcustomers_details] 
@RM_ID varchar(50)
as
begin
select A.LS_ID,	Branch_ID,	CustomerName, isnull(Fund, '0')'Fund',
isnull (NonFund,'0') 'NonFund',	case when B.ABC_Category='NPA' then 'NPA' else isnull (DPD, '0') END as DPD, ISNULL(Account_Status, 'NA')'Account_Status', isnull(Avg_Monthly_Util, '0') 'Avg_Monthly_Util', isnull (Avg_Churn, '0') 'Avg_Churn',	isnull(Houskeep_Defferal,'NA')'Houskeep_Defferal', ISNULL(convert(varchar,(cast(Date_of_renewal as DATE)),106), 'NA')'Date_of_renewal',
ISNULL(convert(varchar, next_stck_Stmt_due_date, 102 ),'NA')'next_stck_Stmt_due_date' , ISNULL(Risk_Item_Pending,'NA')'Risk_Item_Pending',ISNULL(Cross_Sell_Item_Pending,'NA')'Cross_Sell_Item_Pending', isnull (industry ,'NA') 'industry', isnull (RM_ID ,'NA') 'RM_ID'
, TH_ID, CH_ID, ZH_ID, CM_ID, ACM_ID, RH_ID, RCH_ID, SPT,Customer_Account_linkage  
 
	From customer A left join(select * from  Account_History_Latest_ASR where ABC_Category='NPA') B on A.LS_ID=B.LS_ID  where (RM_ID = @RM_ID or CM_ID =@RM_ID)
	group by 
	A.LS_ID,	Branch_ID,	CustomerName, Fund,
NonFund,B.ABC_Category,DPD, Account_Status, Avg_Monthly_Util,Avg_Churn,	Houskeep_Defferal, convert(varchar,(cast(Date_of_renewal as DATE)),106),
convert(varchar, next_stck_Stmt_due_date, 102 ) , Risk_Item_Pending,Cross_Sell_Item_Pending, industry 
, RM_ID
, TH_ID, CH_ID, ZH_ID, CM_ID, ACM_ID, RH_ID, RCH_ID, SPT,Customer_Account_linkage order by CustomerName

end
GO
