/****** Object:  StoredProcedure [dbo].[GetRecords]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[GetRecords]    
(    
@PageIndex INT = 1
      ,@PageSize INT = 10
      ,@RecordCount INT OUTPUT  
)    
as    
begin    
SET NOCOUNT ON;
      SELECT ROW_NUMBER() OVER
      (
            ORDER BY Id ASC
      )AS RowNumber
	  ,Id
      ,EmpCode
		,EmpName
		,EmpDesignation
      
     into #Results
      FROM tbl_PMS_Hierarchy_Master
     
      SELECT @RecordCount = COUNT(*)
      FROM #Results
           
      SELECT * FROM #Results
      WHERE RowNumber BETWEEN(@PageIndex -1) * @PageSize + 1 AND(((@PageIndex -1) * @PageSize + 1) + @PageSize) - 1
     
      DROP TABLE #Results
  
end 
GO
/****** Object:  StoredProcedure [dbo].[getriskrelated]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[getriskrelated]  
@ls_id varchar(100),
@empid varchar(100),
@dept varchar(100) =''
as 
begin
--select distinct n.Trigger_ID, trigger_name, n.ls_id, n.Trigger_Entry_id, Trigger_completion_days, trigger_start_date, Trigger_supervisor ,s.Trigger_table_run_on_date_Change, status  from 
--(select t.trigger_id, d.Trigger_name, t.ls_id, d.Trigger_completion_days,Trigger_Entry_id, trigger_start_date, Trigger_supervisor from Trigger_Entry t inner join tbl_trigger_defination d 
--on d.Trigger_ID = t.trigger_id) n inner join
--tbl_Trigger_Source_manger s on s.Trigger_ID = n.trigger_id left join trigger_entry_rmarks r on r.Trigger_Entry_id = n.Trigger_Entry_id where (status is null  or status ='Pending' )and n.ls_id = @ls_id
if(@dept !='Credit')
	Begin

	select distinct n.Trigger_ID, trigger_name, n.ls_id, n.Trigger_Entry_id, Trigger_completion_days, trigger_start_date, Trigger_supervisor ,n.Trigger_start_date,
	case when Trigger_Entry_remarks_id is null then 'Pending' else (case when Trigger_supervisor_approved is null then 'Pending at supervisor' else Trigger_supervisor_approved end) end 'status'  from 
	Trigger_Entry n  left join trigger_entry_rmarks r on r.Trigger_Entry_id = n.Trigger_Entry_id 
	where (Trigger_supervisor_approved is null  or Trigger_supervisor_approved ='Pending' ) and n.ls_id = @ls_id and (Trigger_rm =@empid or Trigger_supervisor =@empid)
	and Trigger_status is null
	union
	select distinct n.Trigger_ID, trigger_name, n.ls_id, n.Trigger_Entry_id, Trigger_completion_days, trigger_start_date, Trigger_ACM ,n.Trigger_start_date,
	case when Trigger_Entry_remarks_id is null then 'Pending' else (case when Trigger_ACM_approved is null then 'Pending at CM' else Trigger_ACM_approved end) end 'status'  from 
	Trigger_Entry n  inner join trigger_entry_rmarks r on r.Trigger_Entry_id = n.Trigger_Entry_id 
	where (Trigger_Cm_approved is null  or Trigger_Cm_approved ='Pending' ) and n.ls_id = @ls_id and (Trigger_rm =@empid or Trigger_supervisor =@empid ) and n.Trigger_Cm <>''
	and Trigger_supervisor_approved is not null
	union
	select distinct n.Trigger_ID, trigger_name, n.ls_id, n.Trigger_Entry_id, Trigger_completion_days, trigger_start_date, Trigger_ACm ,n.Trigger_start_date,
	case when Trigger_Entry_remarks_id is null then 'Pending' else (case when Trigger_ACM_approved is null then 'Pending at ACM' else Trigger_ACM_approved end) end 'status'  from 
	Trigger_Entry n  inner join trigger_entry_rmarks r on r.Trigger_Entry_id = n.Trigger_Entry_id 
	where (Trigger_ACM_approved is null  or Trigger_ACM_approved ='Pending' )  and Trigger_CM_approved is not null   and n.ls_id = @ls_id and (Trigger_rm =@empid or Trigger_supervisor =@empid ) and n.Trigger_Cm <>''
	and Trigger_status is not null
	
	End
Else
	Begin

	select distinct n.Trigger_ID, trigger_name, n.ls_id, n.Trigger_Entry_id, Trigger_completion_days, trigger_start_date, Trigger_ACm 'Trigger_Supervisor',n.Trigger_start_date,
	case when Trigger_Entry_remarks_id is null then 'Pending' else (case when Trigger_ACM_approved is null then 'Pending at CM' else Trigger_ACM_approved end) end 'status'  from 
	Trigger_Entry n  inner join trigger_entry_rmarks r on r.Trigger_Entry_id = n.Trigger_Entry_id 
	where (Trigger_Cm_approved is null  or Trigger_Cm_approved ='Pending' ) and Trigger_supervisor_approved is not null and n.ls_id = @ls_id and (Trigger_Cm =@empid or Trigger_ACM =@empid )

	End
end
GO
