/****** Object:  StoredProcedure [dbo].[OneviewIndicatorReports]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[OneviewIndicatorReports]
@LSID varchar(50)
as 

declare @First_time_7_dpd_date varchar(100)
declare @First_time_30_dpd_date varchar(100)
declare @Current_Watchlist varchar(100)
declare @No_of_times_last_6_Watchlist varchar(100)
declare @Watchlist_Months varchar(800)
declare @Current_Low_Churning varchar(100) 
declare @No_times_Last_6_Churn varchar(100)
declare @Low_Churn_Months varchar(100)
declare @Exit1 varchar(100)
declare @Plan_Avb varchar(100)
declare @Plan1 varchar(500)



--CREATE TABLE #OneviewIndicatorReports
--(
--[First_time_7_dpd_date] varchar(100),
--[First_time_30_dpd_date] varchar(100), 
--[Current_Watchlist] varchar(100), 
--[No_of_times_last_6_Watchlist] varchar(100),
--[Watchlist_Months] varchar(100),
--[Current_Low_Churning] varchar(100),  
--[No_times_Last_6_Churn] varchar(100),
--[Low_Churn_Months] varchar(100),
--[Exit1] varchar(100),  
--[Plan_Avb] varchar(100),
--[Plan1] varchar(500)
--)

set @Current_Watchlist = (SELECT top 1 'Y' AS [status] FROM TbleUpload_WatchList WHERE convert(dateTIME,[Month],101) IN
(select max(convert(datetime,[Month],101)) as mnt  from TbleUpload_WatchList)
AND [SME_Client_ID]= @LSID)

if  @Current_Watchlist IS  null
	
	BEGIN
	
		set @Current_Watchlist='N'
	
	END

set @First_time_7_dpd_date=(select Replace(Substring(convert(varchar(50),min(convert(datetime,DATE_OF_TOD,101)),113),0,12),' ','/')as 'DATE OF TOD'    
From [repotdb].dbo.Tra_DDLHistory  where convert(numeric(18),DPD)>=7 and SME_Client_ID=@LSID)  

if @First_time_7_dpd_date is not null
	begin
		set @First_time_7_dpd_date=  convert(varchar(50),DATEADD(day,7,@First_time_7_dpd_date),106)
	end

else
BEGIN
	
		set @First_time_7_dpd_date = 'N'
	
	END

set @First_time_30_dpd_date =(select Replace(Substring(convert(varchar(50),min(convert(datetime,DATE_OF_TOD,101)),113),0,12),' ','/')as 'DATE OF TOD'    
From [repotdb].dbo.Tra_DDLHistory  where convert(numeric(18),DPD)>=30 and SME_Client_ID=@LSID )


if @First_time_30_dpd_date is not null
	begin
		set @First_time_30_dpd_date= convert(varchar(50),DATEADD(day,30,@First_time_30_dpd_date),106)
	end

	else
BEGIN
	
		set @First_time_30_dpd_date='N'
	
	END

DECLARE @Record_Id numeric(18)

---------=================START EXIT PLAN LOGIC

	IF EXISTS(SELECT top 1 * FROM Mst_Exit WHERE [LasterSoft_id] =@LSID)
		BEGIN
			SET @Exit1='YES'
			SELECT top 1 @Record_Id=ID FROM Mst_Exit WHERE [LasterSoft_id] =@LSID
		END
	ELSE
		BEGIN
			SET @Exit1='NO'
			SET @Plan_Avb='NO'
			SET @Plan1='NO'
		
		END
		
---------=================END EXIT PLAN LOGIC

	IF @Exit1='YES'
		begin
				IF EXISTS(SELECT top 1 * FROM [Tra_planOfAction] WHERE [Record_Id] =@Record_Id)
					BEGIN
						SET @Plan_Avb='YES'
						SET @Plan1=(select top 1 [Plan_Of_Action] from [Tra_planOfAction] where [Record_Id]=@Record_Id)
			
					END
				ELSE
					BEGIN
						SET @Plan_Avb='NO'
						SET @Plan1='NO'
					END	
		

--------============final update of all logic

UPDATE TblOneViewInd_report
SET First_time_7_dpd_date		=@First_time_7_dpd_date
,First_time_30_dpd_date			=@First_time_30_dpd_date
,Current_Watchlist				=@Current_Watchlist
,No_of_times_last_6_Watchlist	=@No_of_times_last_6_Watchlist
,Watchlist_Months				=@Watchlist_Months
,Current_Low_Churning			=@Current_Low_Churning
,No_times_Last_6_Churn			=@No_times_Last_6_Churn
,Low_Churn_Months				=@Low_Churn_Months
,Exit1							=@Exit1
,Plan_Avb						=@Plan_Avb
,Plan1							=@Plan1
,ls_id  						=@lsid

end

GO
