/****** Object:  StoredProcedure [dbo].[OVI_PROC_DAILY_USAGE_CRD_REPORT]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
Create Proc [dbo].[OVI_PROC_DAILY_USAGE_CRD_REPORT]  
AS  
BEGIN  

 
--Credit OVI Usage MIS
 
 
 
select Distinct EmpCode, EmpName, 'Login' as Activity,Convert(varchar,LoginTime,23) as Activity_Date from LoginAttempts ALT 
where Convert(date,LoginTime,102) BETWEEN Convert(date,'2023-09-01',102)  and Convert(date,GETDATE(),102)
and flag = 'Successful'
group by EmpCode,EmpName,Convert(varchar,LoginTime,23) ORDER BY Convert(varchar,LoginTime,23) DESC
 
 
 
select Distinct Emp_Code, Activity, Activity_Details, Convert(varchar,Activity_Date,23) as Date  from Activity_Log_Tracker 
where Convert(date,Activity_Date,102) BETWEEN Convert(date,'2023-09-01',102)  and Convert(date,GETDATE(),102)
--Convert(date,Activity_Date,102) = Convert(date,GETDATE()-1,102)
and Activity in ('Account Summary Report','Account Statement Report') ORDER BY Date dESC
 
 
 
select Distinct Emp_Code, Activity, Activity_Details, Convert(varchar,Activity_Date,23) as Date  
from Activity_Log_Tracker 
where Convert(date,Activity_Date,102) BETWEEN Convert(date,'2023-09-01',102)  and Convert(date,GETDATE(),102)
--Convert(date,Activity_Date,102) = Convert(date,GETDATE()-1,102)
and Activity in ('Account Conduct Report') ORDER BY Convert(varchar,Activity_Date,23)  dESC
 
 
 
select Distinct Emp_Code, Activity, Activity_Details, Convert(varchar,Activity_Date,103) as Date  
from Activity_Log_Tracker 
where Convert(date,Activity_Date,102) BETWEEN Convert(date,'2023-09-01',102)  and Convert(date,GETDATE(),102)
--Convert(date,Activity_Date,102) = Convert(date,GETDATE()-1,102)
and Activity in ('Exit CM List', 'Exit Details', 'Exit Details RM', 'Exit Report')
END
GO
/****** Object:  StoredProcedure [dbo].[OVI_PROC_DAILY_USAGE_REPORT]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE Proc [dbo].[OVI_PROC_DAILY_USAGE_REPORT]  
AS  
BEGIN  

select Emp_Code, EmpName,Activity,Convert(varchar,Activity_Date,23) as Activity_Date from Activity_Log_Tracker ALT, UserMaster UM  
where Module_Name='OneViewIndicator-RM'  and Activity = 'Login successfully' and ALT.Emp_Code = UM.EmpCode
and Convert(date,Activity_Date,102) BETWEEN Convert(date,'2023-09-01',102)  and Convert(date,GETDATE(),102) 
--Convert(date,Activity_Date,102) = Convert(date,GETDATE()-1,102)
group by Activity,Emp_Code,EmpName,Convert(varchar,Activity_Date,23) order by Activity_Date desc --Convert(varchar,Activity_Date,103) desc
 
 
 
select Customer_Name, CustomerType, Proposal_Number, Request_Number, CreatedBy as EmpCode, EmpName, Convert(varchar,CreatedOn,103) as Date 
from TBL_OVI_Asset_Pricing_Customer_Info C,UserMaster UM 
Where Convert(date,CreatedOn,102) BETWEEN Convert(date,'2023-09-01',102)  and Convert(date,GETDATE(),102) 
--Convert(date,CreatedOn,102) = Convert(date,GETDATE()-1,102) 
and UM.EmpCode = C.CreatedBy order by CreatedOn desc
-------------------------------------------------------------------------------------------------------------------------------  
END
GO
