/****** Object:  StoredProcedure [dbo].[proc_checkExpiryStatus]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[proc_checkExpiryStatus]
 
 @appName as varchar(50),

 @date as datetime=null

AS

begin

set @date =GETDATE()
if  @date>=(select enddate from  tblExpiryDt where AppName=@appName)

begin

Update tblExpiryDt
set status='Expired : ' + convert(varchar,enddate,106)
where AppName=@appName

select top 1 status from tblExpiryDt where AppName = @appName 

--select 'Expired'

end
else
begin
if  @date >=(select dateadd(month,-1,enddate) from  tblExpiryDt where AppName=@appName)
begin


Update tblExpiryDt
set status='Message : ' + CONVERT(VARCHAR,enddate,106)
where AppName=@appName

select top 1 status from tblExpiryDt where AppName = @appName 

end
else
begin
select 'Process'

Update tblExpiryDt
set status='Process'
where AppName=@appName

end
end
end

GO
