CREATE procedure [dbo].[RMloginreport]
as
select EmpCode,EmpName,BranchCode,ProfileId,LastLoginDate,LastLogoutDate ,'BBG' 'Department'
 from UserMaster u inner join (select distinct Rm_ID from Rm_lsID_upload_BBG) b on u.EmpCode=b.Rm_ID
 where LastLoginDate is not null 
union 
select  EmpCode,EmpName,BranchCode,ProfileId,LastLoginDate,LastLogoutDate ,'EEG' 'Department' 
from UserMaster u inner join (select distinct Rm_ID from Rm_lsID_upload_EEG) b on u.EmpCode=b.Rm_ID
 where LastLoginDate is not null  
union
select  EmpCode,EmpName,BranchCode,ProfileId,LastLoginDate,LastLogoutDate ,'Other' 'Department' 
from UserMaster where EmpCode not in ( 
select distinct Rm_ID from Rm_lsID_upload_BBG
union
select distinct Rm_ID from Rm_lsID_upload_EEG) and LastLoginDate is not null  
order by LastLoginDate desc
GO
