/****** Object:  StoredProcedure [dbo].[SCHEDULER_ERROR_LOG_NEW]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SCHEDULER_ERROR_LOG_NEW]
@TYPE VARCHAR(100)='',
@VLAUE VARCHAR(200)=''
AS
BEGIN
  
  IF(@TYPE='MACROI_COUNT')
     BEGIN
          select count(1) from SchedulerErrorLog where status = 'Pass' and date = cast (getdate() as date) and tblname = 'MACROI'
	END

	ELSE IF(@TYPE='Log_MCROI')
     BEGIN
        insert into SchedulerErrorLog values ('MCROI', cast (getdate() as date), 'Fail')
	 END

	 ELSE IF(@TYPE='Log_CollateralDetailsCount')
     BEGIN
        select count(1) from SchedulerErrorLog where status = 'Fail' and date = cast (getdate() as date) and tblname = 'Collateral_Details'
	 END

	 ELSE IF(@TYPE='Log_CollateralDetails')
     BEGIN
        insert into SchedulerErrorLog values ('Collateral_Details', cast (getdate() as date), 'Fail')
	 END

	 ELSE IF(@TYPE='ClientDetailsCount')
     BEGIN
        select count(1) from SchedulerErrorLog where status = 'Pass' and date = cast (getdate() as date) and tblname = 'Client_Details'
	 END

	 ELSE IF(@TYPE='Client_Details')
     BEGIN
        insert into SchedulerErrorLog values ('Client_Details', cast (getdate() as date), 'Fail')
	 END

	 ELSE IF(@TYPE='Facility_Detailscount')
     BEGIN
        select count(1) from SchedulerErrorLog where status = 'Pass' and date = cast (getdate() as date) and tblname = 'Facility_Details'
	 END

	 ELSE IF(@TYPE='Facility_Details')
     BEGIN
             insert into SchedulerErrorLog values ('Facility_Details', cast (getdate() as date), 'Fail')
	 END


	  ELSE IF(@TYPE='StockDetailsCount')
     BEGIN
          select count(1) from SchedulerErrorLog where status = 'Pass' and date = cast (getdate() as date) and tblname = 'Stock_Details'
	 END


	  ELSE IF(@TYPE='Stock_Details')
     BEGIN
        insert into SchedulerErrorLog values ('Stock_Details', cast (getdate() as date), 'Fail')
	 END

	  ELSE IF(@TYPE='Vintage_DetailsCount')
     BEGIN
        select count(1) from SchedulerErrorLog where status = 'Pass' and date = cast (getdate() as date) and tblname = 'Account_Vintage'
	 END

	  ELSE IF(@TYPE='Disbursed_DetailsCount')
     BEGIN
         select count(1) from SchedulerErrorLog where status = 'Pass' and date = cast (getdate() as date) and tblname = 'Facility_Disbursed_Details'
	 END

	  ELSE IF(@TYPE='Facility_Disbursed_Details')
     BEGIN
        insert into SchedulerErrorLog values ('Facility_Disbursed_Details', cast (getdate() as date), 'Fail')
	 END

	  ELSE IF(@TYPE='FinancialDetailsCount')
     BEGIN
          select count(1) from SchedulerErrorLog where status = 'Pass' and date = cast (getdate() as date) and tblname = 'Financial_Details'
	 END

	

END
GO
