/****** Object:  StoredProcedure [dbo].[Select_Account_History_Latest_ASR]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[Select_Account_History_Latest_ASR]
@LS_ID varchar(50)
as 
begin
select [Month] , isnull(Sales, '0')'Sales', isnull(Net_Credits, '0') 'Net_Credits', isnull(churn, '0')'churn', 
isnull(cast(Utilization as decimal(10,2)), '0')'Utilization', isnull(I_W_Check_Return, '0')'I_W_Check_Return', isnull(cast(Max_DPD as decimal(10,0)),'0')'Max_DPD', 
isnull(Cast(Max_TOD as decimal(10,0)), '0')'Max_TOD', isnull(Whether_LCHU, 'NO')'Whether_LCHU', isnull(Whether_Watchlist, 'NO')'Whether_Watchlist', ISNULL(LC_BG_Devolved, 'NO')'LC_BG_Devolved',
ISNULL(ABC_Category, 'Not Available')'ABC_Category', CONVERT(float,(REPLACE(REPLACE(ISNULL(Behavior_Score, 0), 'Not Available',0), 'NPA', 0))) 'Behavior_Score', monthnumber,Date  from Account_History_Latest_ASR where LS_ID = @LS_ID
union 
select 'Total/Average/Count', sum(Convert(decimal (18,2), Sales)), sum(Convert(decimal(18,2),Net_Credits)), 
sum(convert (Decimal(18,2),churn)) /count(Convert(int,monthnumber)),
sum(convert(decimal(18,2),Utilization )) / count(Convert(int,MonthNumber)),
sum(convert(int,I_W_Check_Return))/count(convert(int,I_W_Check_Return)),
sum(convert(decimal(18,2),Max_DPD))/count(convert(decimal(18,2),Max_DPD)), 
sum(convert(decimal(18,2),Max_TOD))/count(convert(decimal(18,2),Max_TOD)), '', '' , '' , 
MAX(ABC_Category)'ABC', Round(AVG (CONVERT(float,(REPLACE(REPLACE(ISNULL(Behavior_Score, 0), 'Not Available',0), 'NPA', 0)))),0) 'Behavior_Score', 0,''   from Account_History_Latest_ASR where LS_ID = @ls_id
order by Date desc 
end
GO
