/****** Object:  StoredProcedure [dbo].[Select_Action_Items_Pending_ACM]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[Select_Action_Items_Pending_ACM]  
@supervisorId varchar(100)
As
Begin

--select d.trigger_id, d.trigger_entry_id,  d.LS_ID, d.RM_ID, d.Supervisor_id, d.Trigger_DRP_Option_id ,D.RM_NAME, CustomerName, Trigger_name, 
--Convert(varchar,Trigger_completion_days,23) 
--'Trigger_completion_days',convert(varchar,Trigger_date_change,23) 'Trigger_date_change', n.Action  ,Trigger_status
--from (select m.trigger_id, m.trigger_entry_id, m.LS_ID, m.RM_ID, m.Supervisor_id, m.Trigger_DRP_Option_id ,m.RM_NAME, CustomerName, Trigger_name, 
--Convert(varchar,Trigger_completion_days,23) 
--'Trigger_completion_days',convert(varchar,Trigger_date_change,23) 'Trigger_date_change' , Trigger_status 
--from (select e.Trigger_ID,e.Trigger_Entry_id, t.LS_ID, RM_ID, trigger_drp_option_id, Supervisor_id, t.RM_NAME,CUSTOMERNAME, Trigger_status from 
--(select ls_Id, c.RM_ID, l.RM_Name, CustomerName, Supervisor_id from customer c 
--inner join Landing_Page_Summary l on l.rm_id = c.Rm_id) t inner join Trigger_Entry e
--on e.LS_id = t.ls_id) m  left join tbl_trigger_defination d on d.Trigger_ID = m.trigger_id) d left join trigger_drp_option n on n.Trigger_DRP_Option_id = d.Trigger_DRP_Option_id
--where Supervisor_id  =@supervisorid and trigger_status is null or trigger_status='Rejected' order by rm_name


select distinct d.trigger_id, d.trigger_entry_id,  d.LS_ID, d.Trigger_rm RM_ID, d.Trigger_supervisor Supervisor_id, r.Trigger_DRP_Option_id ,d.RM_NAME, CustomerName, d.Trigger_name, 
Convert(varchar,d.Trigger_completion_days,23),
Convert(varchar,Feedback_date,23)'Trigger_completion_days' 
,Convert(varchar,Trigger_start_date,23) 'Trigger_start_date',n.Action, Trigger_status, replace(replace(isnull(s.trigger_rm_action, ''), '<', 'less than '), '>', 'greater than ') trigger_rm_action, replace(replace(isnull(s.trigger_cm_action, ''), '<', 'less than '), '>', 'greater than ') trigger_cm_action
from [trigger_entry] d inner join Trigger_Entry_rmarks r 
on r.Trigger_Entry_id=d.Trigger_Entry_id 
inner join trigger_drp_option n 
on n.Trigger_DRP_Option_id = r.Trigger_DRP_Option_id 
inner join tbl_trigger_defination s 
on d.trigger_ID = s.Trigger_ID
where d.Trigger_ACM=@supervisorId and d.Trigger_status is not null and r.Trigger_Cm_approved is not null

end
GO
