Create procedure [dbo].[Select_Action_Items_Pending_CM]  
@CMId varchar(100)
As
Begin

		select distinct d.trigger_id, d.trigger_entry_id,  d.LS_ID, d.Trigger_rm RM_ID, d.Trigger_supervisor Supervisor_id, r.Trigger_DRP_Option_id ,d.RM_NAME, CustomerName, 
		Trigger_name, Convert(varchar,Trigger_completion_days,23),Convert(varchar,Feedback_date,23)'Trigger_completion_days',
		Convert(varchar,Trigger_start_date,23) 'Trigger_start_date',n.Action, Trigger_status
		from [trigger_entry] d inner join Trigger_Entry_rmarks r 
		on r.Trigger_Entry_id=d.Trigger_Entry_id 
		inner join trigger_drp_option n 
		on n.Trigger_DRP_Option_id = r.Trigger_DRP_Option_id 
		where d.Trigger_CM=@CMId 
		and d.Trigger_status is not null 
		and r.Trigger_supervisor_approved is not null

end
