Convert(varchar,Cross_Sell_completion_days,23),
Convert(varchar,Feedback_date,23)'Cross_Sell_Completion_Days' 
,Convert(varchar,Cross_Sell_start_date,23) 'Cross_Sell_start_date',n.Action, Cross_Sell_status, replace(replace(isnull(s.trigger_rm_action, ''), '<', 'less than '), '>', 'greater than ') trigger_rm_action, replace(replace(isnull(s.trigger_cm_action, ''), '<', 'less than '), '>', 'greater than ') trigger_cm_action
from [Cross_Sell_entry] d inner join Cross_Sell_Entry_rmarks r 
on r.Cross_Sell_Entry_id=d.Cross_Sell_Entry_id 
inner join trigger_drp_option n 
on n.Trigger_DRP_Option_id = r.Cross_Sell_DRP_Option_id 
inner join tbl_trigger_defination s 
on d.Cross_Sell_ID = s.Trigger_ID
where d.Cross_Sell_ACM=@supervisorId 
and d.Cross_Sell_status is not null 
and r.Cross_Sell_Cm_approved is not null


end
GO
