CREATE PROCEDURE [dbo].[Sp_addCustomerVisitInfo]  
@LeadID int=NULL,  
@VisitType int=NULL,  
@TravelledBy int=NULL,  
@Distance Decimal(15,3)=NULL,  
@LeadCLosureSTatus int=NULL,  
@NextVisitDate Datetime=NULL,  
@ActualVisitDate Datetime=NULL,  
@Remarks Varchar(500)=NULL,  
@LoginUser varchar(20)=NULL  
AS  
BEGIN  
INSERT INTO Visit  
(  
LeadID,  
VisitType,  
TravelledBy,  
Distance,  
LeadCLosureSTatus,  
NextVisitDate,  
ActualVisitDate,  
Remarks,  
CreationDate,  
LoginUser  
)  
VALUES  
(  
@LeadID,  
@VisitType,  
@TravelledBy,  
@Distance,  
@LeadCLosureSTatus,  
@NextVisitDate,  
@ActualVisitDate,  
@Remarks,  
GETDATE(),  
@LoginUser  
)  
END
GO
/****** Object:  StoredProcedure [dbo].[SP_AllTriggerExecution]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
	-- EXEC SP_AllTriggerExecution 2,'November',2021,'a17640'		
CREATE Procedure [dbo].[SP_AllTriggerExecution]                              
(                              
 @TriggerID int=null,                              
 @Month  varchar(20)=null,                              
 @Year Int=null,                              
 @Lusr as varchar(20)=null -- User Id                              
)                              
AS                               
BEGIN               
              
  --// This id contains string type of Id from MasterTable.              
  Declare @_TriggerID Varchar(30)= null , @_TriggerName  varchar(250)=null;              
              
  SELECT @_TriggerID = Trigger_ID , @_TriggerName = Trigger_name from RFA_TriggerMaster where id = @TriggerID ;              
              
  IF(@TriggerID=1)                              
  BEGIN                              
		EXEC SP_TriggerExecution_1A @Month,@Year,@Lusr ,@TriggerID;                              
  END                   
  ELSE IF(@TriggerID = 4) -- Trigger3            
  BEGIN                
		EXEC SP_TriggerExecution_3 @Month , @Year , @Lusr , @TriggerID , @_TriggerName;                
  END           
  ELSE IF(@TriggerID = 2) -- Trigger 1B            
  BEGIN                
		EXEC SP_TriggerExecution_1B @Month , @Year , @Lusr , @TriggerID , @_TriggerName;                
  END           
                      
     -- Change status pending to Executed after Executon is done.                     
  IF NOT EXISTS(Select top(1) id from RFA_MonthWiseTriggerStatus where TriggerId = @TriggerID and TMonth = @Month and TYear = @Year)                    
  BEGIN      
  print 1
		Insert into RFA_MonthWiseTriggerStatus (TriggerId , CreatedOn , TStatus , TMonth , TYear)                    
		Values(@TriggerID , GETDATE() , 'Executed' , @Month , @Year)                    
   END                    
   ELSE                    
   BEGIN  
    print 2
		update a                            
		set a.TStatus ='Executed'                            
		, a.TMonth =FORMAT(GETDATE(),'MMMM')                     
		,a.CreatedOn = GETDATE()                    
		from                            
		RFA_MonthWiseTriggerStatus a(nolock)                            
		inner join RFA_TriggerMaster b(nolock)                            
		on a.TriggerId = b.id                            
		where b.id = @TriggerID     
		and [TMonth] = @Month  
		and [TYear] = @Year  
   END                        
END 

select * from RFA_MonthWiseTriggerStatus
GO
/****** Object:  StoredProcedure [dbo].[SP_API_Search]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE Procedure [dbo].[SP_API_Search](
 @searchText varchar(1000)=null
 ,@action varchar(50)=null
 ,@id int =null
)
AS
BEGIN
	if(@action ='getAll')
	BEGIN
	
	select A.TBL_API_Main_ID,A.PRODUCT_PROCESSOR_URL_UAT  as ServiceURL,A.SERVICE_DESC,SERVICE_MIDDLEWARE.Value as SERVICE_TYPE 
	,A.COD_SERVICE_ID,A.SERVICE_SIGNATURE,
	SERVICE_PROVIDER.Value as SERVICE_PROVIDER
	,A.PRODUCT_PROCESSOR_WSDL , DOMAIN_NAME.Value as DOMAIN_NAME
	from TBL_API_Main A
	left join TBL_API_Master_Values SERVICE_MIDDLEWARE
	on A.NAM_SERVICE_MIDDLEWARE = SERVICE_MIDDLEWARE.Id And SERVICE_MIDDLEWARE.API_Master_ID=1
	left join TBL_API_Master_Values SERVICE_INTERFACE_TYPE 
	on a.SERVICE_INTERFACE_TYPE = SERVICE_INTERFACE_TYPE.Id and SERVICE_INTERFACE_TYPE.API_Master_ID=2
	left join TBL_API_Master_Values SERVICE_CATEGORY 
	on a.SERVICE_CATEGORY = SERVICE_CATEGORY.Id and SERVICE_CATEGORY.API_Master_ID=3
	left join TBL_API_Master_Values SERVICE_PROVIDER 
	on a.SERVICE_PROVIDER = SERVICE_PROVIDER.Id and SERVICE_PROVIDER.API_Master_ID=4

	left join TBL_API_Master_Values SERVICE_TYPE 
	on a.SERVICE_TYPE = SERVICE_TYPE.Id and SERVICE_TYPE.API_Master_ID=5

	left join TBL_API_Master_Values NAM_CONTAINER 
	on a.NAM_CONTAINER = NAM_CONTAINER.Id and NAM_CONTAINER.API_Master_ID=6

	left join TBL_API_Master_Values NAM_DOMAIN 
	on a.NAM_DOMAIN = NAM_DOMAIN.Id and NAM_DOMAIN.API_Master_ID=7

	left join TBL_API_Master_Values DOMAIN_NAME 
	on a.DOMAIN_NAME = DOMAIN_NAME.Id and DOMAIN_NAME.API_Master_ID=8

	Where (A.COD_SERVICE_ID like '%'+ @searchText +'%' OR  A.SERVICE_SIGNATURE like '%'+ @searchText +'%'
		OR  SERVICE_MIDDLEWARE.Value like '%'+ @searchText +'%'  OR  SERVICE_PROVIDER.Value like '%'+ @searchText +'%'
		OR  A.PRODUCT_PROCESSOR_WSDL like '%'+ @searchText +'%' OR  DOMAIN_NAME.Value like '%'+ @searchText +'%')
	END
	ELSE IF(@action='getOne')
	BEGIN
		select A.TBL_API_Main_ID,A.PRODUCT_PROCESSOR_URL_UAT  as ServiceURL,A.SERVICE_DESC,SERVICE_MIDDLEWARE.Value as SERVICE_TYPE 
	,A.COD_SERVICE_ID,A.SERVICE_SIGNATURE,
	SERVICE_PROVIDER.Value as SERVICE_PROVIDER
	,A.PRODUCT_PROCESSOR_WSDL , DOMAIN_NAME.Value as DOMAIN_NAME
	from TBL_API_Main A
	left join TBL_API_Master_Values SERVICE_MIDDLEWARE
	on A.NAM_SERVICE_MIDDLEWARE = SERVICE_MIDDLEWARE.Id And SERVICE_MIDDLEWARE.API_Master_ID=1
	left join TBL_API_Master_Values SERVICE_INTERFACE_TYPE 
	on a.SERVICE_INTERFACE_TYPE = SERVICE_INTERFACE_TYPE.Id and SERVICE_INTERFACE_TYPE.API_Master_ID=2
	left join TBL_API_Master_Values SERVICE_CATEGORY 
	on a.SERVICE_CATEGORY = SERVICE_CATEGORY.Id and SERVICE_CATEGORY.API_Master_ID=3
	left join TBL_API_Master_Values SERVICE_PROVIDER 
	on a.SERVICE_PROVIDER = SERVICE_PROVIDER.Id and SERVICE_PROVIDER.API_Master_ID=4

	left join TBL_API_Master_Values SERVICE_TYPE 
	on a.SERVICE_TYPE = SERVICE_TYPE.Id and SERVICE_TYPE.API_Master_ID=5

	left join TBL_API_Master_Values NAM_CONTAINER 
	on a.NAM_CONTAINER = NAM_CONTAINER.Id and NAM_CONTAINER.API_Master_ID=6

	left join TBL_API_Master_Values NAM_DOMAIN 
	on a.NAM_DOMAIN = NAM_DOMAIN.Id and NAM_DOMAIN.API_Master_ID=7

	left join TBL_API_Master_Values DOMAIN_NAME 
	on a.DOMAIN_NAME = DOMAIN_NAME.Id and DOMAIN_NAME.API_Master_ID=8
	where A.TBL_API_Main_ID =@id
	END
END
GO
/****** Object:  StoredProcedure [dbo].[SP_API_Search_Temp]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


-- exec SP_API_Search_Temp '','getAll',''


CREATE Procedure [dbo].[SP_API_Search_Temp](
 @searchText varchar(1000)=null
 ,@action varchar(50)=null
 ,@id int =null
 , @whereClause varchar(max)= null  
)
AS
BEGIN
	if(@action ='getAll')
	BEGIN
	select A.TBL_API_Main_ID,A.PRODUCT_PROCESSOR_URL_UAT  as ServiceURL,A.SERVICE_DESC,SERVICE_MIDDLEWARE.Value as SERVICE_TYPE
	,A.COD_SERVICE_ID,A.SERVICE_SIGNATURE,
	SERVICE_PROVIDER.Value as SERVICE_PROVIDER
	,A.PRODUCT_PROCESSOR_WSDL , DOMAIN_NAME.Value as DOMAIN_NAME,A.fileName
	from TBL_API_Main A
	left join TBL_API_Master_Values SERVICE_MIDDLEWARE
	on A.NAM_SERVICE_MIDDLEWARE = SERVICE_MIDDLEWARE.Id And SERVICE_MIDDLEWARE.API_Master_ID=1
	left join TBL_API_Master_Values SERVICE_INTERFACE_TYPE 
	on a.SERVICE_INTERFACE_TYPE = SERVICE_INTERFACE_TYPE.Id and SERVICE_INTERFACE_TYPE.API_Master_ID=2
	left join TBL_API_Master_Values SERVICE_CATEGORY 
	on a.SERVICE_CATEGORY = SERVICE_CATEGORY.Id and SERVICE_CATEGORY.API_Master_ID=3
	left join TBL_API_Master_Values SERVICE_PROVIDER 
	on a.SERVICE_PROVIDER = SERVICE_PROVIDER.Id and SERVICE_PROVIDER.API_Master_ID=4

	left join TBL_API_Master_Values SERVICE_TYPE 
	on a.SERVICE_TYPE = SERVICE_TYPE.Id and SERVICE_TYPE.API_Master_ID=5

	left join TBL_API_Master_Values NAM_CONTAINER 
	on a.NAM_CONTAINER = NAM_CONTAINER.Id and NAM_CONTAINER.API_Master_ID=6

	left join TBL_API_Master_Values NAM_DOMAIN 
	on a.NAM_DOMAIN = NAM_DOMAIN.Id and NAM_DOMAIN.API_Master_ID=7

	left join TBL_API_Master_Values DOMAIN_NAME 
	on a.DOMAIN_NAME = DOMAIN_NAME.Id and DOMAIN_NAME.API_Master_ID=8

	Where (A.COD_SERVICE_ID like '%'+ @searchText +'%' OR  A.SERVICE_SIGNATURE like '%'+ @searchText +'%'
		OR  SERVICE_MIDDLEWARE.Value like '%'+ @searchText +'%'  OR  SERVICE_PROVIDER.Value like '%'+ @searchText +'%'
		OR  A.PRODUCT_PROCESSOR_WSDL like '%'+ @searchText +'%' OR  DOMAIN_NAME.Value like '%'+ @searchText +'%'OR  A.fileName like '%'+ @searchText +'%')
		
	END
	ELSE IF(@action='Filter')
	BEGIN
	Declare @query varchar(max) = N'';

	  SET @query =' select A.TBL_API_Main_ID,A.PRODUCT_PROCESSOR_URL_UAT  as ServiceURL,A.SERVICE_DESC,SERVICE_MIDDLEWARE.Value as SERVICE_TYPE,A.SERVICE_INTERFACE_TYPE,A.SERVICE_CATEGORY
	,A.COD_SERVICE_ID,A.SERVICE_SIGNATURE,
	SERVICE_PROVIDER.Value as SERVICE_PROVIDER
	,A.PRODUCT_PROCESSOR_WSDL , DOMAIN_NAME.Value as DOMAIN_NAME,A.fileName
	   INTO #tmp_DynamicTable  from TBL_API_Main A
	left join TBL_API_Master_Values SERVICE_MIDDLEWARE
	on A.NAM_SERVICE_MIDDLEWARE = SERVICE_MIDDLEWARE.Id And SERVICE_MIDDLEWARE.API_Master_ID=1
	left join TBL_API_Master_Values SERVICE_INTERFACE_TYPE 
	on a.SERVICE_INTERFACE_TYPE = SERVICE_INTERFACE_TYPE.Id and SERVICE_INTERFACE_TYPE.API_Master_ID=2
	left join TBL_API_Master_Values SERVICE_CATEGORY 
	on a.SERVICE_CATEGORY = SERVICE_CATEGORY.Id and SERVICE_CATEGORY.API_Master_ID=3
	left join TBL_API_Master_Values SERVICE_PROVIDER 
	on a.SERVICE_PROVIDER = SERVICE_PROVIDER.Id and SERVICE_PROVIDER.API_Master_ID=4

	left join TBL_API_Master_Values SERVICE_TYPE 
	on a.SERVICE_TYPE = SERVICE_TYPE.Id and SERVICE_TYPE.API_Master_ID=5

	left join TBL_API_Master_Values NAM_CONTAINER 
	on a.NAM_CONTAINER = NAM_CONTAINER.Id and NAM_CONTAINER.API_Master_ID=6

	left join TBL_API_Master_Values NAM_DOMAIN 
	on a.NAM_DOMAIN = NAM_DOMAIN.Id and NAM_DOMAIN.API_Master_ID=7

	left join TBL_API_Master_Values DOMAIN_NAME 
	on a.DOMAIN_NAME = DOMAIN_NAME.Id and DOMAIN_NAME.API_Master_ID=8
	     
	 select * into #tmp_finalTable from  #tmp_DynamicTable '
	  SET @query += ' Select * From #tmp_finalTable where  ' + @whereClause + '      
	     Drop table #tmp_DynamicTable ; Drop table #tmp_finalTable ;'  
	print @query
	EXEC(@query); 
	END

	ELSE IF(@action='getOne')
	BEGIN
		select A.TBL_API_Main_ID,A.PRODUCT_PROCESSOR_URL_UAT  as ServiceURL,A.SERVICE_DESC,SERVICE_MIDDLEWARE.Value as SERVICE_TYPE 
	,A.COD_SERVICE_ID,A.SERVICE_SIGNATURE,
	SERVICE_PROVIDER.Value as SERVICE_PROVIDER
	,A.PRODUCT_PROCESSOR_WSDL , DOMAIN_NAME.Value as DOMAIN_NAME,A.fileName
	from TBL_API_Main A
	left join TBL_API_Master_Values SERVICE_MIDDLEWARE
	on A.NAM_SERVICE_MIDDLEWARE = SERVICE_MIDDLEWARE.Id And SERVICE_MIDDLEWARE.API_Master_ID=1
	left join TBL_API_Master_Values SERVICE_INTERFACE_TYPE 
	on a.SERVICE_INTERFACE_TYPE = SERVICE_INTERFACE_TYPE.Id and SERVICE_INTERFACE_TYPE.API_Master_ID=2
	left join TBL_API_Master_Values SERVICE_CATEGORY 
	on a.SERVICE_CATEGORY = SERVICE_CATEGORY.Id and SERVICE_CATEGORY.API_Master_ID=3
	left join TBL_API_Master_Values SERVICE_PROVIDER 
	on a.SERVICE_PROVIDER = SERVICE_PROVIDER.Id and SERVICE_PROVIDER.API_Master_ID=4

	left join TBL_API_Master_Values SERVICE_TYPE 
	on a.SERVICE_TYPE = SERVICE_TYPE.Id and SERVICE_TYPE.API_Master_ID=5

	left join TBL_API_Master_Values NAM_CONTAINER 
	on a.NAM_CONTAINER = NAM_CONTAINER.Id and NAM_CONTAINER.API_Master_ID=6

	left join TBL_API_Master_Values NAM_DOMAIN 
	on a.NAM_DOMAIN = NAM_DOMAIN.Id and NAM_DOMAIN.API_Master_ID=7

	left join TBL_API_Master_Values DOMAIN_NAME 
	on a.DOMAIN_NAME = DOMAIN_NAME.Id and DOMAIN_NAME.API_Master_ID=8
	where A.TBL_API_Main_ID =@id
	
	END
END
GO
