CREATE PROCEDURE [dbo].[sp_APIA_JIRA] --7939,'OBPINT','',9175          
 @IntegrationId INT = null            
,@JIRAFlag VARCHAR(100) = null   
,@JIRAId VARCHAR(100) = null  
,@ServiceID VARCHAR(100) = null  

AS BEGIN            
  
  IF(@JIRAFlag='APIGATE')        
  BEGIN        
   SELECT 
		JIRA_Type,
		Project,
		Description,
		Issue_Type,
		Priority,
		GETDATE() AS ConceptApprovalDate,
		R12_Change_Id,
		(SELECT BusinessJustification FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS BusinessJustification,
		GETDATE() AS RDDiscussionCompletionDate,
		GETDATE() AS ConceptReceiptDate,
		GETDATE() AS AuditApprovalReceivedForCNRaise,
		GETDATE() AS ComplianceApprovalReceivedForCNRaised,
		GETDATE() AS ConceptDiscussionDate1,
		GETDATE() AS ConceptDiscussionDate2,
		GETDATE() AS ConceptDiscussionDate3,
		'Parag Rao' AS ExecutiveSponsor,
		--(SELECT ExecutiveSponsor FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS ExecutiveSponsor,
		Application_Name,
		Enhancement_Type,
		'Raunaq Singh' AS BusinessSponsor,
		--(SELECT BusinessSponsor FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS BusinessSponsor,
		Business_Group,
		Project_Impacting_Ops,
		Impacted_Operations_Unit,
		Benefit,
		Regulatory_Requirement,
		Interface_Requirement,
		Size_Of_Enhancement,
		RD_Prioritization,
		BTG_BSG_UH_Name,
		Audit_Sign_Off_Category,
		BTG_BSG_SUPERVISOR,
		Application_Type,
		BTG_TEAM_LEAD
	FROM [dbo].[tbl_API_ADDA_JIRAFields]  WHERE JIRA_Type = 'APIGATE' AND Status = 1
  END
  ELSE IF(@JIRAFlag='APIINT')        
  BEGIN  
  SELECT 
		JIRA_Type,
		Project,
		Description,
		Issue_Type,
		Size_Of_Enhancement,
		(SELECT PlannedGoLiveDate FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS PlannedGoLiveDate,
		Executor1_TimeSpent,
		BTG_BSG_UH_Name,
		Executor1
  FROM [dbo].[tbl_API_ADDA_JIRAFields]  WHERE JIRA_Type = 'APIINT' AND Status = 1
  END
  ELSE IF(@JIRAFlag='SOAENHN')
  BEGIN
	SELECT
		JIRA_Type,
		Project,
		Issue_Type,
		(SELECT ProjectManagerBTG FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS ProjectManagerBTG,
		(SELECT ExecutiveSponsor FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS ExecutiveSponsor,
		BusinessUnit,
		(SELECT ProjectName FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS ProjectName,
		(SELECT ConsumerApplication FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS SourceSystem,
		(SELECT ProducerApplication FROM TBL_APIA_ServiceDetails WHERE ServiceID = @ServiceID) AS DestinationSystem,
		GETDATE() AS RDDiscussionDate,
		(SELECT Volume FROM TBL_APIA_ServiceDetails WHERE ServiceID = @ServiceID) AS TPS,
		(SELECT COUNT(ServiceID) FROM TBL_APIA_ServiceDetails WHERE IntegrationId = @IntegrationId AND Existing_New_Id = 1) AS ExistingServiceCount,
		(SELECT COUNT(ServiceID) FROM TBL_APIA_ServiceDetails WHERE IntegrationId = @IntegrationId AND Existing_New_Id = 2) AS NewServiceCount,
		(SELECT PlannedGoLiveDate FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS PlannedGoLiveDate,
		(SELECT
			CASE 
				WHEN Existing_New_Id = 1 THEN 'Existing'
				ELSE 'New' 
			END 
		FROM TBL_APIA_ServiceDetails WHERE ServiceID = @ServiceID) AS Service ,
		ProjectType
	FROM [dbo].[tbl_API_ADDA_JIRAFields]  WHERE JIRA_Type = 'SOAENHN' AND Status = 1
  END
  IF(@JIRAFlag='OBPENH')
  BEGIN
	SELECT
		JIRA_Type,
		Project,
		Description,
		Issue_Type,
		Priority,
		GETDATE() AS ConceptApprovalDate,
		(SELECT PlannedGoLiveDate FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS PlannedGoLiveDate,
		R12_Change_Id,
		(SELECT ProjectManagerBTG FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS BusinessSPoC,
		(SELECT BusinessJustification FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS BusinessJustification,
		(SELECT ConsumerApplication FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS SourceSystem,
		(SELECT ProducerApplication FROM TBL_APIA_ServiceDetails WHERE ServiceID = @ServiceID) AS DestinationSystem,
		Executor1_TimeSpent,
		10 AS customfield_13001,
		(SELECT Volume FROM TBL_APIA_ServiceDetails WHERE ServiceID = @ServiceID) AS TPS,
		'Parag Rao' AS ExecutiveSponsor,
		--(SELECT ExecutiveSponsor FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS ExecutiveSponsor,
		Project_Impacting_Ops,
		Impacted_Operations_Unit,
		Regulatory_Requirement,
		(SELECT
			CASE 
				WHEN Middleware_Name_ID = 82 THEN 'SOA'
				WHEN Middleware_Name_ID = 83 THEN 'OBP'
				WHEN Middleware_Name_ID = 84 THEN 'APIGW' 
			END  
		FROM TBL_APIA_ServiceDetails WHERE ServiceID = @ServiceID) AS InterfaceRequirement,
		RD_Prioritization,
		Size_Of_Enhancement,
		BTG_TEAM_LEAD,
		Enhancement_Type,
		Application_Name,
		Business_Group,
		'Sujatha Mohan' AS BusinessSponsor,
		--(SELECT BusinessSponsor FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS BusinessSponsor,
		(SELECT
			CASE 
				WHEN Existing_New_Id = 1 THEN 'Existing'
				ELSE 'New' 
			END 
		FROM TBL_APIA_ServiceDetails WHERE ServiceID = @ServiceID) AS Service ,
		BTG_BSG_SUPERVISOR,
		BTG_BSG_UH_Name,
		Audit_Sign_Off_Category,
		Benefit,
		'329 - UPI and IMPS Payments' AS CostCenterCode,
		--(SELECT CostCenterCode FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS CostCenterCode,
		Developer_Name,
		Developer_Team_Lead,
		Executor1,
		'Aditi Mehta' AS customfield_13000,
		Application_Type
	FROM [dbo].[tbl_API_ADDA_JIRAFields]  WHERE JIRA_Type = 'OBPENH' AND Status = 1
  END
  ELSE IF(@JIRAFlag='OBPINT')
  BEGIN
	SELECT
		JIRA_Type,
		Project,
		Description,
		Issue_Type,
		(SELECT Volume FROM TBL_APIA_ServiceDetails WHERE ServiceID = @ServiceID) AS TPS,
		Project_Impacting_Ops,
		Impacted_Operations_Unit,
		'Parag Rao' AS ExecutiveSponsor,
		--(SELECT ExecutiveSponsor FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS ExecutiveSponsor,
		'Sujatha Mohan' AS BusinessSponsor
		--(SELECT BusinessSponsor FROM TBL_APIA_Integration WHERE IntegrationId = @IntegrationId) AS BusinessSponsor,
	FROM [dbo].[tbl_API_ADDA_JIRAFields]  WHERE JIRA_Type = 'OBPINT' AND Status = 1
  END
  ELSE IF(@JIRAFlag='InsertJIRAId')
  BEGIN
	UPDATE TBL_APIA_ServiceDetails SET JIRAId = @JIRAId WHERE ServiceID = @ServiceID 
  END
END 
GO
/****** Object:  StoredProcedure [dbo].[sp_APIA_NewAPIIntegration]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[sp_APIA_NewAPIIntegration]            
 @IntegrationId int=null            
,@ProjectManagerBTG varchar(100)=null            
,@ProjectManagerIT varchar(100)=null            
,@ProjectName varchar(100)=null            
,@ProjectId varchar(100)=null            
,@PlannedGoLiveDate datetime=null            
,@BusinessJustification varchar(max)  =null          
,@BusinessSponsor varchar(100)=null            
,@ExecutiveSponsor varchar(100)=null            
,@CostCenterCode varchar(100)=null            
,@UserJourneyDocumentFileName varchar(100)=null            
,@Feedback varchar(500)=null            
,@Status int=0            
,@CreatedBy varchar(100)=null           
,@UpdatedBy varchar(100)=null            
,@IdentFlag varchar(50)            
,@ServiceName varchar(100)=null          
,@Purpose varchar(100)=null          
,@Existing_New varchar(100)=null          
,@ConsumerApplication varchar(100)=null          
,@ProducerApplication varchar(100)=null          
,@Is_APIGW_Request bit =null          
,@Rest_Soap varchar(100)=null          
,@Transformation varchar(100)=null          
,@Volume varchar(100)=null          
,@UpdateFlag varchar(100)=null          
,@ServiceID varchar(100)=null          
,@Assign Varchar(50)=null        
,@AssignFrom Varchar(50)='USER'       
,@Existing_New_Id int=0        
,@Rest_SOAP_Id int=0        
,@ServiceType_Id int=0        
,@APIType_Id int=0        
,@APICategory_Id int=0        
,@APIRiskScore_Id int=0        
,@PartnerRiskScore_Id int=0        
,@DomainName_Id int=0      
,@IsActive bit=1     
,@FeedbackId int=0    
,@servicenameId int=0,    
@ConsumerDC_Id int=null,    
@ProducerDC_Id int=null,    
@Platform varchar(200)=null,    
@QValue1 int=0,    
@QValue2 int=0,    
@QValue3 int=0,    
@QValue4 int=0,    
@QValue5 int=0,    
@RiskScore FLOAT(4)=0,    
@Classification varchar(10)=null,
@BTGUSER VARCHAR(50)=null,
@ITUSER VARCHAR(50)=null,
@ITARCHITECTURE VARCHAR(50)=null,
@ChannelID VARCHAR(50)=null,
@ContainerName VARCHAR(50)=null,
@InternalServiceName VARCHAR(50)=null,
@ExternalServiceName VARCHAR(50)=null,
@ExternalServiceText VARCHAR(Max)=null,
@HostAppID int=null,
@ConsumerDC VARCHAR(50)=null,
@ProducerDC VARCHAR(50)=null,
@HostApptext VARCHAR(50)=null,
@QID int=null,
@OptionsID int=null,
@RDConceptNoteFileName varchar(100)=null,
@ExpectedAPISpecificationFileName varchar(100)=null,
@SequenceDiagramFileName varchar(100)=null,
@ConsumerId INT = 0,
@flagPl varchar(10)=null,
@createdAt datetime=null,
@ConsumerApplicationId INT = 0,
@FullName varchar (50)=null,
@MiddlewareNameId INT = 0
AS BEGIN            
  IF(@IdentFlag='AddNewIntegration')            
  BEGIN    
  SET IDENTITY_INSERT TBL_APIA_Integration ON

  DECLARE @NewID INT=0
  SET @NewID=(SELECT MAX(IntegrationId)+1 FROM TBL_APIA_Integration)

  INSERT INTO TBL_APIA_Integration(ProjectManagerBTG,ProjectManagerIT,ProjectName,ProjectId,PlannedGoLiveDate,            
  BusinessJustification,BusinessSponsor,ExecutiveSponsor,CostCenterCode,UserJourneyDocumentPath,Status,CreatedAt,CreatedBy,Assign,AssignFrom, ConsumerApplication,RDConceptNote,ConsumerApplicationId,IntegrationId)            
  VALUES(@ProjectManagerBTG,@ProjectManagerIT,@ProjectName,@ProjectId,@PlannedGoLiveDate,@BusinessJustification,            
  @BusinessSponsor,@ExecutiveSponsor,@CostCenterCode,@UserJourneyDocumentFileName,@Status,GETDATE(),@CreatedBy,@Assign,@AssignFrom, @ConsumerApplication,@RDConceptNoteFileName,@ConsumerApplicationId,@NewID)  
 SET IDENTITY_INSERT TBL_APIA_Integration OFF

  SET @IntegrationId=  (SELECT SCOPE_IDENTITY() AS IntegrationId)    
  SET @Feedback = 'New Integration  Created  By User'    
  IF(@IntegrationId <> 0  or @IntegrationId <> null) 
  BEGIN
        INSERT INTO tbl_API_ADDA_Feedback (Integration_Id,Feedback_Details,Status,Created_By,Created_Date,IsActive,AssignTo,AssignFrom)     
      VALUES(@IntegrationId,@Feedback,@Status,@CreatedBy,GETDATE(),@IsActive,@Assign,@AssignFrom) 
  END
 
   
      
    SELECT @IntegrationId AS IntegrationId;    
    
 --SELECT SCOPE_IDENTITY() AS IntegrationId;    
 -- SELECT MAX(IntegrationId) AS IntegrationId FROM TBL_APIA_Integration          
          
  END   
  ELSE IF @IdentFlag='BTGProjectMgr' 
	BEGIN
		SELECT ISNULL(EmpName,'') AS ProjectManagerBTG,ISNULL(EmpCode,'') AS IntegrationId  FROM [dbo].[UserMaster] WITH(NOLOCK)
	END
  ELSE IF @IdentFlag='feedbacktouser' 
	BEGIN
		IF(@AssignFrom='BTGUSER')  
		Begin
		SELECT 
			IntegrationId,
		   'API' + REPLACE(CONVERT(varchar, CreatedAt, 106), ',', '') + CAST(IntegrationId AS varchar) AS 'APIADDAID', 
			TBL_APIA_Integration.projectname, 
			TBL_APIA_Integration.projectid, 
			TBL_APIA_Integration.ProjectManagerBTG,
			TBL_APIA_Integration.ProjectManagerIT,
			--TBL_APIA_Integration.status,
			IsNull(In_Platform,'') as 'Platform',
			statusDescription AS Status
    
		FROM 
			TBL_APIA_Integration
		JOIN 
			tbl_API_ADDA_Feedback ON TBL_APIA_Integration.integrationid = tbl_API_ADDA_Feedback.Integration_id
	   INNER JOIN
			TBL_API_statusMaster AS SM ON SM.statusCode = TBL_APIA_Integration.Status
		WHERE 
			tbl_API_ADDA_Feedback.assignto = 'User' and tbl_API_ADDA_Feedback.AssignFrom='BTGUSER' and statusDescription = 'Feedback by BTG User'
			AND tbl_API_ADDA_Feedback.Created_Date = (
				SELECT MAX(Created_Date) 
				FROM tbl_API_ADDA_Feedback 
				WHERE Integration_id = TBL_APIA_Integration.integrationid
			);

		End
		IF(@AssignFrom='ITUSER')  
		Begin
			SELECT 
			IntegrationId,
		   'API' + REPLACE(CONVERT(varchar, CreatedAt, 106), ',', '') + CAST(IntegrationId AS varchar) AS 'APIADDAID', 
			TBL_APIA_Integration.projectname, 
			TBL_APIA_Integration.projectid, 
			TBL_APIA_Integration.ProjectManagerBTG,
			TBL_APIA_Integration.ProjectManagerIT,
			--TBL_APIA_Integration.status,
			IsNull(In_Platform,'') as 'Platform',
			statusDescription AS Status
    
		FROM 
			TBL_APIA_Integration
		JOIN 
			tbl_API_ADDA_Feedback ON TBL_APIA_Integration.integrationid = tbl_API_ADDA_Feedback.Integration_id
	   INNER JOIN
			TBL_API_statusMaster AS SM ON SM.statusCode = TBL_APIA_Integration.Status
		WHERE 
			tbl_API_ADDA_Feedback.assignto = 'User' and tbl_API_ADDA_Feedback.AssignFrom='ITUSER' and statusDescription = 'Feedback by IT User'
			AND tbl_API_ADDA_Feedback.Created_Date = (
				SELECT MAX(Created_Date) 
				FROM tbl_API_ADDA_Feedback 
				WHERE Integration_id = TBL_APIA_Integration.integrationid
			);

		End
		IF(@AssignFrom='ITArchitech')  
		Begin
			SELECT 
			IntegrationId,
		   'API' + REPLACE(CONVERT(varchar, CreatedAt, 106), ',', '') + CAST(IntegrationId AS varchar) AS 'APIADDAID', 
			TBL_APIA_Integration.projectname, 
			TBL_APIA_Integration.projectid, 
			TBL_APIA_Integration.ProjectManagerBTG,
			TBL_APIA_Integration.ProjectManagerIT,
			--TBL_APIA_Integration.status,
			IsNull(In_Platform,'') as 'Platform',
			statusDescription AS Status
    
		FROM 
			TBL_APIA_Integration
		JOIN 
			tbl_API_ADDA_Feedback ON TBL_APIA_Integration.integrationid = tbl_API_ADDA_Feedback.Integration_id
	   INNER JOIN
			TBL_API_statusMaster AS SM ON SM.statusCode = TBL_APIA_Integration.Status
		WHERE 
			tbl_API_ADDA_Feedback.assignto = 'User' and tbl_API_ADDA_Feedback.AssignFrom='ITArchitech' and statusDescription = 'Feedback by IT Architech'
			AND tbl_API_ADDA_Feedback.Created_Date = (
				SELECT MAX(Created_Date) 
				FROM tbl_API_ADDA_Feedback 
				WHERE Integration_id = TBL_APIA_Integration.integrationid
			);
		End
	END
  ELSE IF(@IdentFlag='GetNewIntegrationDetails') 
  BEGIN          
        
  IF(@AssignFrom='USER')        
   BEGIN         
  Select   
  A.IntegrationId,    
  'API' +replace (convert(varchar, A.CreatedAt, 106) ,' ','')+ Cast(A.IntegrationId AS varchar)  as 'APIADDAID',    
  ProjectName,    
  ProjectId,    
  ProjectManagerBTG,    
  ProjectManagerIT,     
  statusDescription as Status,    
  Assign,    
  AssignFrom,    
  Status as workflowstatus ,    
  IsNull(In_Platform,'') as 'Platform'
  ,ISNULL(stuff ((Select ', ' +  JIRAId from TBL_APIA_ServiceDetails where IntegrationId=A.IntegrationId order by IntegrationId FOR XML PATH ('')), 1, 2, ''),'') as [JIRAID]
  from TBL_APIA_Integration  A  
  Inner Join TBL_API_statusMaster As SM on SM.statusCode=Status 
  where A.CreatedBy=@CreatedBy
  ORDER BY A.IntegrationId DESC         
  END        
  ELSE IF(@AssignFrom<>'USER')        
   BEGIN         
  Select     
  A.IntegrationId,    
    'API' +replace (convert(varchar, A.CreatedAt, 106) ,' ','')+ Cast(A.IntegrationId AS varchar)  as 'APIADDAID',    
  ProjectName,    
  ProjectId,    
  ProjectManagerBTG,    
  ProjectManagerIT,      
  statusDescription as Status,    
  Assign,    
  AssignFrom, 
  Status as workflowstatus,    
  IsNull(In_Platform,'') as 'Platform',
  ISNULL(stuff ((Select ', ' +  JIRAId from TBL_APIA_ServiceDetails where IntegrationId=A.IntegrationId order by IntegrationId FOR XML PATH ('')), 1, 2, ''),'') as [JIRAID]  from TBL_APIA_Integration A    
  Inner Join TBL_API_statusMaster As SM on SM.statusCode=Status      
  order by A.IntegrationId desc     
    
    
  END        
        
 END           
        
  ELSE IF(@IdentFlag='AddServiceDetails')          
  BEGIN  
  


	  --If( @Platform  !='External')
	  --BEGIN
   
		
If(@flagPl='All')
		   BEGIN
              UPDATE TBL_APIA_Integration set In_Platform= 'Internal' WHERE IntegrationId=@IntegrationId
			END 
  ELSE IF(@flagPl='single' and @Platform='Internal & External')
  BEGIN 
      UPDATE TBL_APIA_Integration set In_Platform= 'Internal' WHERE IntegrationId=@IntegrationId
	  SET @flagPl='All'
  END 
 ELSE 
  BEGIN
	UPDATE TBL_APIA_Integration set In_Platform= @Platform WHERE IntegrationId=@IntegrationId
END
      --IF(@Purpose!=null and @Purpose!='')
		--Begin
			INSERT INTO TBL_APIA_ServiceDetails(IntegrationId,ServiceName,Purpose,Existing_New,ConsumerApplication,ProducerApplication,Is_APIGW_Request,Rest_Soap,Transformation,Volume,CreatedBy,CreatedAt      
			 ,Existing_New_Id      
			,Rest_SOAP_Id      
			,ServiceType_Id      
			,APIType_Id      
			,APICategory_Id      
			,APIRiskScore_Id      
			,PartnerRiskScore_Id      
			,DomainName_Id,     
			ConsumerDC_Id,    
			ProducerDC_Id,    
			Platform,    
			QValue1,    
			QValue2,    
			QValue3,    
			QValue4,    
			QValue5,    
			RiskScore,
			InternalServiceName,
			ExternalServiceName ,
			ConsumerDC,
			ProducerDC,
			ExpectedServiceSpecificationDocument,
			Classification,
			Middleware_Name_ID
			  )          
      
      
			values(      
			@IntegrationId,@ServiceName,@Purpose,@Existing_New,@ConsumerApplication,@ProducerApplication,@Is_APIGW_Request,@Rest_Soap,@Transformation,      
			@Volume,      
			@CreatedBy      
			,getdate()      
			,@Existing_New_Id      
			,@Rest_SOAP_Id      
			,@ServiceType_Id      
			,@APIType_Id      
			,@APICategory_Id      
			,@APIRiskScore_Id      
			,@PartnerRiskScore_Id     
			,@DomainName_Id,    
			@ConsumerDC_Id,    
			@ProducerDC_Id,    
			@Platform,    
			@QValue1,    
			@QValue2,    
			@QValue3,    
			@QValue4,    
			@QValue5,    
			@RiskScore,
			@InternalServiceName,
			@ExternalServiceName ,
			@ConsumerDC,
			@ProducerDC,
			@ExpectedAPISpecificationFileName,
			@Classification,0
			)  
		--End
	--  END

 --DECLARE @InternalCountS int
 --DECLARE @ExternalCountS int
 --DECLARE @InternalExternalCountS int

 --SET @InternalCountS = (select count(Platform) from TBL_APIA_ServiceDetails where Platform='Internal' and IntegrationId=@IntegrationId)
 --SET @ExternalCountS = (select count(Platform) from TBL_APIA_ServiceDetails where Platform='External' and IntegrationId=@IntegrationId)
 --SET @InternalExternalCountS = (select count(Platform) from TBL_APIA_ServiceDetails where Platform='Internal & External' and IntegrationId=@IntegrationId)


 If(@flagPl='All')--((@InternalCountS>0 AND @ExternalCountS>0) OR (@InternalCountS>0 AND @InternalExternalCountS>0) OR (@ExternalCountS>0 AND @InternalExternalCountS>0) )
 BEGIN
  If(@Platform ='Internal & External' Or @Platform ='External' Or  @Platform ='Internal')
	  BEGIN
	  Declare @IntegrationIdIE int
 
	  -------------------------------------------------------------------Add New Integration----Based On Internal & External--------------------------------------------------------------------------
 
	 IF((select Count(Parent_IntegrationId) from TBL_APIA_Integration where Parent_IntegrationId=@IntegrationId)=0)
	 BEGIN
		 INSERT INTO TBL_APIA_Integration(ProjectManagerBTG,ProjectManagerIT,ProjectName,ProjectId,PlannedGoLiveDate,            
		 BusinessJustification,BusinessSponsor,ExecutiveSponsor,CostCenterCode,UserJourneyDocumentPath,Status,CreatedAt,CreatedBy,Assign,AssignFrom, ConsumerApplication,Parent_IntegrationId,In_Platform,RDConceptNote,ConsumerApplicationId)            
		  select ProjectManagerBTG,ProjectManagerIT,ProjectName,ProjectId,PlannedGoLiveDate,BusinessJustification,            
		  BusinessSponsor,ExecutiveSponsor,CostCenterCode,UserJourneyDocumentPath,Status,GETDATE(),CreatedBy,Assign,AssignFrom, ConsumerApplication,@IntegrationId,'External',RDConceptNote, ConsumerApplicationId  From TBL_APIA_Integration  where   IntegrationId=@IntegrationId

	  SET @IntegrationIdIE=  (SELECT SCOPE_IDENTITY() AS IntegrationId) 


	  IF(@IntegrationIdIE <> 0  or @IntegrationIdIE <> null) 
     BEGIN
	    SET @Feedback = 'New Integration  Created  By User'  

        INSERT INTO tbl_API_ADDA_Feedback (Integration_Id,Feedback_Details,Status,Created_By,Created_Date,IsActive,AssignTo,AssignFrom)     
      VALUES(@IntegrationIdIE,@Feedback,1,@CreatedBy,GETDATE(),@IsActive,'BTGUSER','USER')  
    END

	  END
  ELSE
  BEGIN
    SET @IntegrationIdIE= (SELECT IntegrationId from TBL_APIA_Integration where Parent_IntegrationId=@IntegrationId and Parent_IntegrationId is not null)
  END 
    
  



  ---------------------------------------------Add Service-------Based On Internal & External---------------------------------------------------
--IF(@Purpose!=null and @Purpose!='')
--		Begin
		 INSERT INTO TBL_APIA_ServiceDetails(IntegrationId,ServiceName,Purpose,Existing_New,ConsumerApplication,ProducerApplication,Is_APIGW_Request,Rest_Soap,Transformation,Volume,CreatedBy,CreatedAt      
		,Existing_New_Id      
		,Rest_SOAP_Id      
		,ServiceType_Id      
		,APIType_Id      
		,APICategory_Id      
		,APIRiskScore_Id      
