  Left join [dbo].[tbl_API_Adda_Misccd] As APICate on APICate.CDValDesc=Main.API_CAT    AND   APICate.CDTP='API Category' 
  Left join [dbo].[tbl_API_Adda_Misccd] As DOMAINNAME on DOMAINNAME.CDValDesc=Main.DOMAIN_NAME    AND DOMAINNAME.CDTP='Domain Name'
  Left join [dbo].[tbl_API_Adda_Misccd] As RestSoap on RestSoap.CDValDesc=Main.SERVICE_INTERFACE_TYPE    AND   RestSoap.CDTP='Rest_Soap'
