 ,RiskScore    
 ,Classification 
 ,InternalServiceName 
 ,ExternalServiceName
  ,ConsumerDC
  ,ProducerDC
  )          
  values(@IntegrationId,@ServiceName,@Purpose,@Existing_New,@ConsumerApplication,@ProducerApplication,@Is_APIGW_Request,@Rest_Soap,@Transformation,@Volume,@CreatedBy,getdate()      
,@Existing_New_Id      
,@Rest_SOAP_Id      
,@ServiceType_Id      
,@APIType_Id      
,@APICategory_Id      
,@APIRiskScore_Id      
,@PartnerRiskScore_Id      
,@DomainName_Id    
,@ConsumerDC_Id    
,@ProducerDC_Id    
,@Platform    
