---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE PROCEDURE [dbo].[sp_APIA_NewExceptionManagement]                    
    (      
  @CaseId VARCHAR(100) =NULL,      
  @ExceptionId VARCHAR(100)=NULL, 
  @OriginalOnboardingGASID VARCHAR(100) = NULL,      
  @ExceptionRequestor VARCHAR(100) = NULL,      
  @APIProjectName VARCHAR(200) = NULL,      
  @APIProjectDescription VARCHAR(500) = NULL,      
  @PartnersToBeIntegrated VARCHAR(500) = NULL,      
  @ProductAPIToBeConsumed VARCHAR(500) = NULL,      
  @RequestedException VARCHAR(500) = NULL,      
  @ReasonForException VARCHAR(500) = NULL,      
  @StartDate varchar(100) = NULL,      
  @EndDate varchar(100) = NULL,      
  @HowExceptionToBeImplemented VARCHAR(500) = NULL,      
  @IdentFlag VARCHAR(100),      
  @ImpactOnBank VARCHAR(100) = NULL,      
  @ExceptionLevel VARCHAR(100) = NULL,
  @currentUser varchar(100) = NULL,
  @ExceptionCaseID VARCHAR(100) = NULL,		     
  @ApproverUserID VARCHAR(100) = NULL,   
  @ApproverType VARCHAR(100) = NULL,      
  @ApproverLevel VARCHAR(100) = NULL,
  @BusinessVerticalHead varchar(100) = null,
  @BusinessGroupHead varchar(100) = NULL,
  @CIOGroup VARCHAR(100) = NULL,
  @ITDRMVerticalHead VARCHAR(100) = NULL,
  @ITDRMGroupHead VARCHAR(100) = NULL,
  @CISOGroup VARCHAR(100) = NULL,
  @ITVerticalHead VARCHAR(100) = NULL,
  @BSGVerticalHead VARCHAR(100) = NULL,
  @ComplianceVerticalHead VARCHAR(100) = NULL,
  @ISGVerticalHead VARCHAR(100) = NULL,
  @APEXSteeringCommittee VARCHAR(100) = NULL,
  @ExceptionXMl xml=NULL,
  @FileUpload varchar(100)=null,
  @PartnerToBeIntegrated varchar(500)=null,
  @CreatedBy varchar(100)=null,
  @CretaedDate varchar(100)=null,
  @updateBy varchar(100)=null,
  @UpdatedDate varchar(100)=null,
  @ApproverSequence int=null,
  @OroginalOnboardingGasID VARCHAR(100) = NULL,
  @Approver_Level varchar(100)=null,
  @Last4Digits INT=null
    )      
AS       
BEGIN                    
    IF (@IdentFlag = 'ExceptionManagement')                    
    BEGIN         
		 DECLARE @CaseUniqueno int    
		 DECLARE @UniqueString varchar(100) 
		SET @ExceptionId=(SELECT CaseId FROM tbl_APIA_ExceptionManagement WHERE OriginalOnboardingGASID=@ExceptionId OR ID=@ExceptionId)
		IF ISNULL(@ExceptionId,'')<>''
		BEGIN
			UPDATE tbl_APIA_ExceptionManagement
			SET OriginalOnboardingGASID=@CaseId,
				ExceptionRequestor=@ExceptionRequestor,
				APIProjectName=@APIProjectName,
				APIProjectDescription=@APIProjectDescription,
				PartnersToBeIntegrated=@PartnersToBeIntegrated,
				RequestedException=@RequestedException,
				ReasonForException=@ReasonForException,
				StartDate=@StartDate,
				EndDate=@EndDate,
				HowExceptionToBeImplemented=@HowExceptionToBeImplemented,
				ImpactOnBank=@ImpactOnBank,
				ExceptionLevel=@ExceptionLevel,
				updateBy=@currentUser,
				updatedDate=GETDATE()
				--FileUpload=@FileUpload
				
			WHERE CaseId=@ExceptionId OR ID=cast(@CaseId as int)

			select @ExceptionId  AS OriginalOnboardingGASID
		END
		ELSE
		BEGIN
			INSERT INTO tbl_APIA_ExceptionManagement      
			(      
			   OriginalOnboardingGASID,      
			   ExceptionRequestor,      
			   APIProjectName,      
			   APIProjectDescription,    
			   PartnersToBeIntegrated,      
			   ProductAPIToBeConsumed,      
			   RequestedException,      
			   ReasonForException,      
			   StartDate,      
			   EndDate,      
			   HowExceptionToBeImplemented,      
			   ImpactOnBank,      
			   ExceptionLevel,
			   createdBy,
			   createdDate      
					)      
					VALUES      
					(      
			   @OriginalOnboardingGASID,      
			   @ExceptionRequestor,      
			   @APIProjectName,      
			   @APIProjectDescription,      
			   @PartnersToBeIntegrated,      
			   @ProductAPIToBeConsumed,      
			   @RequestedException,      
			   @ReasonForException,      
			   @StartDate,      
			   @EndDate,      
			   @HowExceptionToBeImplemented,      
			   @ImpactOnBank,      
			   @ExceptionLevel,
			   @currentUser,
			   GETDATE()      
					)  
		   
			 --set @CaseUniqueno=scope_identity()   
			 set @CaseUniqueno=(SELECT MAX(ID) FROM tbl_APIA_ExceptionManagement) 
    
			 SET @UniqueString='APIGW'+convert(varchar(100),@CaseUniqueno) 

			 INSERT INTO tbl_APIA_Exception_Audit_Log 
				 (
					CaseID ,
					ApprovalID ,
					[Status] ,
					createdBy ,
					[createdDate] 
				 )	

				 VALUES
				 (
					@CaseUniqueno,
					 @ApproverUserID,
					'created',
					@currentUser,
					GETDATE()      
				  )   
    
			 update tbl_APIA_ExceptionManagement    
			 SET CaseId='APIGW'+REPLACE(CONVERT(VARCHAR,ISNULL(createdDate,GETDATE()),3),'/','')+(CASE WHEN LEN(ID)=1 THEN '0000' 
										WHEN LEN(ID)=2 THEN '000' WHEN LEN(ID)=3 THEN '00' WHEN LEN(ID)=4 THEN '0' END)+
										CAST(ID AS VARCHAR)--@UniqueString    
			 where ID= @CaseUniqueno    
		
			SET @UniqueString=(SELECT TOP 1 CaseId FROM tbl_APIA_ExceptionManagement ORDER BY createdDate  DESC)
			 select @UniqueString  AS OriginalOnboardingGASID  
		END
	END      
	ELSE IF @IdentFlag = 'GetExceptionLevel'       
	BEGIN      
		SELECT       
			ISNULL(apiid, '') AS APIId,      
			ISNULL(ImpactOnbank, '') AS ImpactOnBank,      
			ISNULL(Level, '') AS Level      
		FROM      
			tbl_APIA_ExceptionLevel      
		WHERE       
			ImpactOnBank LIKE '%'+@ImpactOnBank+'%'      
    END     
	 ELSE IF (@IdentFlag = 'LevelNumber1')    
	 begin  
 
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=1 and ApproverType='Business' and ApproverLevel='VH'  
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=1 and ApproverType='Business' and ApproverLevel='GH'  
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=1 and ApproverType='CIO' and ApproverLevel='GH' 
	   END   
		ELSE IF (@IdentFlag = 'LevelNumber2')    
	 begin  
 
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=2 and ApproverType='Business' and ApproverLevel='VH'  
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=2 and ApproverType='ITDRM' and ApproverLevel='VH'  
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=2 and ApproverType='Business' and ApproverLevel='GH' 
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=2 and ApproverType='CIO' and ApproverLevel='GH'  
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=2 and ApproverType='ITDRM' and ApproverLevel='GH'  
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=2 and ApproverType='CISO' and ApproverLevel='GH' 
	   END
	   ELSE IF (@IdentFlag = 'LevelNumber3')
	   begin  
	    select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=3 and ApproverType='IT' and ApproverLevel='VH'
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=2 and ApproverType='BSG' and ApproverLevel='VH' 
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=2 and ApproverType='Business' and ApproverLevel='VH'
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=2 and ApproverType='Compliance' and ApproverLevel='VH'
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=2 and ApproverType='ITDRM' and ApproverLevel='VH'
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=2 and ApproverType='ISG' and ApproverLevel='VH'
		select * from tbl_APIA_MstExceptionApprovalMetrix where ExceptionLevel=3 and ApproverType='APEX IT Steering Committee' and ApproverLevel='VH'
	   END 
	ELSE IF @IdentFlag='GetNewCaseId'
	BEGIN
		SELECT top 1 CaseId AS CaseID FROM tbl_APIA_ExceptionManagement ORDER BY createdDate desc 
	END 
	ELSE IF @IdentFlag='UserExceptionList'
	Begin
	SELECT 
		    PO.ID AS CaseId,
			PO.CaseId AS OriginalOnboardingGASID,
			--PO.OriginalOnboardingGASID AS OriginalOnboardingGASID,
			APIProjectName AS PartnerName,
			ApproverLevel as ApproverLevel,
			CASE
			    WHEN PEx.ApproverLevel = 'VH' THEN 'Pending'
			    WHEN PEx.ApproverLevel = 'GH' THEN 'VH Pending'
			    ELSE ISNULL(PEx.Status, 'Null') -- Use the original status if none of the conditions are met
			END AS Status,
			ISNULL(CONVERT(VARCHAR, PO.createdBy, 105), '') AS CreatedBy,
			ISNULL(CONVERT(VARCHAR, PO.createdDate, 105), '') AS DateCreated,
			ISNULL(CONVERT(VARCHAR, PO.updatedDate, 105), '') AS DateUpdated
			FROM 
			    tbl_APIA_ExceptionManagement PO WITH (NOLOCK)
			LEFT JOIN 
			    tbl_APIA_Exception_Audit_Log AU WITH (NOLOCK) ON AU.CASEID = AU.ID
			LEFT JOIN 
			tbl_APIA_PartnerExceptionApprovalList PEx WITH (NOLOCK) ON PEx.ExceptionCaseID = PO.CaseId
			ORDER BY 
			    PO.createdDate DESC;
	End
	ELSE IF @IdentFlag='ExceptionLevels'
	BEGIN
			INSERT INTO tbl_APIA_PartnerExceptionApprovalList      
				(      
	       ExceptionCaseID,      
		   ApproverUserID,    
		   [Status],    
		   ApproverType,      
		   ApproverLevel,      
		   CreatedBy,
		    DateCreated
	            )  
			SELECT @ExceptionCaseID,@BusinessVerticalHead,'Created','Business','VH',@currentUser,GETDATE() UNION
			SELECT @ExceptionCaseID,@BusinessGroupHead,'Created','Business','GH',@currentUser,GETDATE() UNION			
			SELECT @ExceptionCaseID,@CIOGroup,'Created','CIO','GH',@currentUser,GETDATE() UNION
			SELECT @ExceptionCaseID,@ITDRMVerticalHead,'Created','ITDRM','VH',@currentUser,GETDATE() UNION
			SELECT @ExceptionCaseID,@ITDRMGroupHead,'Created','ITDRM','GH',@currentUser,GETDATE() UNION
			SELECT @ExceptionCaseID,@CISOGroup,'Created','CISO','FH',@currentUser,GETDATE() UNION
			SELECT @ExceptionCaseID,@ITVerticalHead,'Created','IT','VH',@currentUser,GETDATE() UNION
			SELECT @ExceptionCaseID,@BSGVerticalHead,'Created','BSG','VH',@currentUser,GETDATE() UNION
			SELECT @ExceptionCaseID,@ComplianceVerticalHead,'Created','Compliance','VH',@currentUser,GETDATE() UNION
			SELECT @ExceptionCaseID,@ISGVerticalHead,'Created','ISG','VH',@currentUser,GETDATE() UNION
			SELECT @ExceptionCaseID,@APEXSteeringCommittee,'Created','APEX','VH',@currentUser,GETDATE()  
	END 
	ELSE IF @IdentFlag='SaveExceptionLevel'
	BEGIN
		INSERT INTO tbl_APIA_PartnerExceptionApprovalList(ExceptionCaseID,ApproverUserID,Status,ApproverType,
			ApproverLevel,DateCreated,DateApproved,CreatedBy,ExceptionLevel,CaseID)
		SELECT TBL.COL.value('ExceptionCaseID[1]','VARCHAR(100)') AS ExceptionCaseID,
			   TBL.COL.value('ApproverUserID[1]','VARCHAR(100)') AS ApproverUserID,
			   TBL.COL.value('Status[1]','VARCHAR(100)') AS Status,
			   TBL.COL.value('ApproverType[1]','VARCHAR(100)') AS ApproverType,
			   TBL.COL.value('ApproverLevel[1]','VARCHAR(100)') AS ApproverLevel,
			   GETDATE() AS DateCreated,GETDATE() AS DateApproved,
			   TBL.COL.value('CreatedBy[1]','VARCHAR(100)') AS CreatedBy,
			   TBL.COL.value('ExceptionLevel[1]','VARCHAR(100)') AS ExceptionLevel,
			   TBL.COL.value('CaseID[1]','VARCHAR(100)') AS CaseID
		FROM @ExceptionXMl.nodes('/ExceptionLevels/lstAddExceptionlevelDetails/AddExceptionlevelDetails') AS TBL(COL)
	END
	ELSE IF @IdentFlag='GetExceptionDeatil'
	BEGIN
	
		SELECT ID,caseID,ExceptionRequestor,APIProjectName,APIProjectDescription,
			PartnersToBeIntegrated,ProductAPIToBeConsumed,RequestedException,ReasonForException,
			StartDate,EndDate,HowExceptionToBeImplemented,ImpactOnBank,ExceptionLevel
		FROM tbl_APIA_ExceptionManagement 
		--WHERE ID=4217  WHERE CaseId=@ExceptionId OR ID=cast(@CaseId as int)
		WHERE ID=@ExceptionId 
	END
	ELSE IF @IdentFlag='BackExceptionDeatil'
	BEGIN
	
		SELECT ID,caseID,ExceptionRequestor,APIProjectName,APIProjectDescription,
			PartnersToBeIntegrated,ProductAPIToBeConsumed,RequestedException,ReasonForException,
			StartDate,EndDate,HowExceptionToBeImplemented,ImpactOnBank,ExceptionLevel
		FROM tbl_APIA_ExceptionManagement 
		--WHERE ID=4217  WHERE CaseId=@ExceptionId OR ID=cast(@CaseId as int)
		WHERE caseID=@ExceptionId
	END
	ELSE IF @IdentFlag='GetExceptionLevel'
	BEGIN
		
		select Pex.ExceptionCaseID,Pex.ApproverUserID,mst.ApproverName,mst.ExceptionLevel,Pex.ApproverLevel from tbl_APIA_PartnerExceptionApprovalList Pex
		left join 
		tbl_APIA_MstExceptionApprovalMetrix mst with(nolock) on mst.ApproverUserID=Pex.ApproverUserID
		where Pex.ExceptionCaseID=@ExceptionCaseID
	END
	ELSE IF @IdentFlag='GetExceptionLevelData'
	BEGIN
		SELECT ApproverUserID,ApproverType,ApproverLevel,ExceptionLevel 
		FROM tbl_APIA_PartnerExceptionApprovalList 
		WHERE ExceptionCaseID=@ExceptionId AND ExceptionLevel=@ExceptionLevel
	END
	ELSE IF @IdentFlag='GetApprovalTrailList'
	BEGIN
		SELECT 
		    PO.ID AS ID,
		    PO.CaseId AS OriginalOnboardingGASID,
		    APIProjectName AS PartnerName,
			ApproverUserID AS ApproverId,
			PEx.status,
		    CASE
		        WHEN PEx.ApproverLevel = 'VH' THEN 'Pending'
		        WHEN PEx.ApproverLevel = 'GH' THEN 'VH Pending'
		        ELSE ISNULL(AU.Status, '')
		    END AS Status,
		    ISNULL(CONVERT(VARCHAR, PO.createdBy, 105), '') AS CreatedBy,
		    ISNULL(CONVERT(VARCHAR, PO.createdDate, 105), '') AS DateCreated,
		    ISNULL(CONVERT(VARCHAR, PO.updatedDate, 105), '') AS DateUpdated
		FROM 
		    tbl_APIA_ExceptionManagement PO WITH (NOLOCK)
		LEFT JOIN 
		    tbl_APIA_Exception_Audit_Log AU WITH (NOLOCK) ON AU.CASEID = AU.ID
		LEFT JOIN 
		    tbl_APIA_PartnerExceptionApprovalList PEx WITH (NOLOCK) ON PEx.ExceptionCaseID = PO.CaseId
		WHERE 
		    PEx.approverUserID = @ApproverUserID--'G1499'
		    -- Add additional conditions if needed
		ORDER BY 
		    PO.createdDate DESC;
	END;
	ELSE IF @IdentFlag='GetEditLevelDeatil'
	BEGIN	
		SELECT DISTINCT T.ApproverType,T.ApproverUserID,S.ApproverUserID+'_'+S.ApproverName as ApproverName,T.ApproverType+'_'+S.ApproverLevel as Approver_Level,S.ApproverLevel
		FROM tbl_APIA_ExceptionManagement U
		LEFT JOIN tbl_APIA_PartnerExceptionApprovalList T WITH(NOLOCK) ON T.ExceptionCaseID=U.CaseId 
		LEFT JOIN tbl_APIA_MstExceptionApprovalMetrix S WITH (NOLOCK) ON T.ApproverUserID=S.ApproverUserID AND T.ApproverType=S.ApproverType  AND S.ApproverLevel=T.ApproverLevel  
		WHERE U.CaseId=@ExceptionId
		--'APIGW18012404308'
	END;
	ELSE IF @IdentFlag='ViewExceptionDeatil'
	BEGIN
	
		SELECT ID,caseID,ExceptionRequestor,APIProjectName,APIProjectDescription,
			PartnersToBeIntegrated,ProductAPIToBeConsumed,RequestedException,ReasonForException,
			StartDate,EndDate,HowExceptionToBeImplemented,ImpactOnBank,ExceptionLevel
		FROM tbl_APIA_ExceptionManagement 
		--WHERE ID=4217  WHERE CaseId=@ExceptionId OR ID=cast(@CaseId as int)
		WHERE ID=@ExceptionId 
	END
	--ELSE IF @IdentFlag = 'SaveAllDetails_Level1'       
	--BEGIN      
	--	insert into tbl_APIA_SaveExceptionLevel1(CaseID,OroginalOnboardingGasID,ExceptionRequestor,aPIProjectName,APIProjectDescription,PartnerToBeIntegrated,ProductAPITOBEConsumed,RequestedException,
	--	ReasonForException,StartDate,EndDate,HowExceptiontobeImplemented,ImpactOnBank,ExceptionLevel,CreatedBy,CretaedDate,updateBy,UpdatedDate,ApproverSequence,FileUpload,BusinessVerticalHead,
	--	BusinessGroupHead,CIOGroup)
	--	values(
