/****** Object:  StoredProcedure [dbo].[SP_BulkRejectFeedback]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE Procedure [dbo].[SP_BulkRejectFeedback]          
(          
@action varchar(75)=null          
,@LsId int =null          
,@TriggerId int = null          
,@FeedbackId int =null        
,@UserId varchar(30) = null 
,@rejectedReason varchar(max)=null
)          
AS          
BEGIN          
 Declare @UserType varchar(100)=null;                
 SELECT @UserType = [Role] from RFATrigger_UserMapping where EmpId=@UserId;          
          
  select @FeedbackId = FeedbackId         
  , @TriggerId = TriggerId        
  from Feedback a(nolock) where LsId=@LsId;        
        
 --IF(@UserType='Cluster Head')                    
 --BEGIN           
 -- Delete from CMFeedback where LsId = @LsId and TriggerId = @TriggerId  ;          
            
 -- Insert into FeedbackStatus(FeedbackId,[Status],CreditManager)          
 -- Values(@FeedbackId , 2 ,@UserId)          
          
 -- UPDATE Feedback set IsRejected =1           
 -- where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @FeedbackId          
          
 -- select 'FeedbackRejected'  as Msg;          
 --END          
 --ELSE        
 IF(@UserType='Circle Head')                    
 BEGIN        
   --select  @rejectedReason = rejectedReason from ACHFeedback where LsId = @LsId and TriggerId = @TriggerId  ;    
  Delete from ACHFeedback where LsId = @LsId and TriggerId = @TriggerId  ;          
            
  Insert into FeedbackStatus(FeedbackId,[Status],AreaCreditHead,CreatedOn)          
  Values(@FeedbackId , 4 ,@UserId,GETDATE())          
          
  UPDATE CMFeedback set IsRejected =1  , rejectedReason =@rejectedReason   
  where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @FeedbackId          
          
  select 'FeedbackRejected' as Msg;          
 END          
 ELSE IF(@UserType='Unit Head' OR @UserType='Business Head')                    
 BEGIN   
    --select  @rejectedReason = rejectedReason from RCHFeedback where LsId = @LsId and TriggerId = @TriggerId  ;    
  Delete from RCHFeedback where LsId = @LsId and TriggerId = @TriggerId  ;          
            
  Insert into FeedbackStatus(FeedbackId,[Status],RegionalCreditHead,CreatedOn)          
  Values(@FeedbackId , 6 ,@UserId,GETDATE())          
          
  UPDATE ACHFeedback set IsRejected =1  ,rejectedReason = @rejectedReason       
  where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @FeedbackId          
          
  select 'FeedbackRejected' as Msg;          
 END          
END
GO
