CREATE proc [dbo].[Sp_CaptureProductivity]
@System as varchar(250)= NULL,
@Region as varchar(100)= NULL,
@BranchCode as varchar(50) = NULL,
@empCode as varchar(10)= NULL,
@role as varchar(150) =NULL,
@Mnemonic_Code as varchar(50) = NULL,
@Mnemonic_Description as varchar(MAX) = NULL,
@Count as varchar(50) = NULL,
@CoreSystem as varchar(250) = NULL
as 
begin

		insert into tbl_ProductivityDetails
		select @System,@Region Region,'' [State],'' City,
				@BranchCode BranchCode,
				'' BranchName,
				getdate() Event_Date,
				'' userID,
				@empCode EmpCode,
				'' User_Name,
				@role User_Type,
				@Mnemonic_Code Mnemonic_Code,
				@Mnemonic_Description Mnemonic_Description,
				1 'Count',
				getdate() LoginDateTime,
				getdate() LogoutDateTime,
				@CoreSystem CoreSystem

end
