CREATE Procedure [dbo].[SP_checkPolicyStatus]  
(  
@FeedbackId INT  
,@LsId INT  =null  
,@TriggerId INT =null  
,@Month varchar(30)=null  
,@Year INT =null  
,@UserId varchar(30)=null  
)  
AS  
BEGIN  
  
  select top(1)FeedbackId ,@LsId as LsId,@Month as [Month] ,@Year as [Year] ,@TriggerId as TriggerId  ,  
  Msg = case when [Status] = 90 then 'Approved'
		 when [Status] = 91 then 'Rejected'
		else 'In-Workflow' end  
  from FeedbackStatus   
  where FeedbackId = @FeedbackId   
  order by FeedbackStatusId desc
  --and LsId = @LsId   
  --and [Month] = @Month   
  --and [Year] = @Year  
  --order by CreatedOn desc  
  
  
END  

