/****** Object:  StoredProcedure [dbo].[sp_checkStatus]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[sp_checkStatus]
AS
BEGIN

	DECLARE @TriggerId int -- database name 
	DECLARE @Month varchar(30) = FORMAT(GETDATE(),'MMMM') , @Year int = FORMAT(GETDATE(),'yyyy');
	
	DECLARE db_cursor CURSOR FOR 
	SELECT id 
	FROM RFA_TriggerMaster
	
	OPEN db_cursor  
	FETCH NEXT FROM db_cursor INTO @TriggerId  
	
	WHILE @@FETCH_STATUS = 0  
	BEGIN  
	       
		   --select @TriggerId;
	
		   IF NOT EXISTS(select id from RFA_MonthWiseTriggerStatus where TriggerId = @TriggerId and TMonth = @Month  and TYear = @Year )
		   BEGIN
				INSERT INTO RFA_MonthWiseTriggerStatus (TriggerId ,  CreatedOn , TStatus , TMonth , TYear)
				Values ( @TriggerId , GETDATE(), 'Pending' , @Month , @Year )
		   END
	
	      FETCH NEXT FROM db_cursor INTO @TriggerId 
	END 
	
	CLOSE db_cursor  
	DEALLOCATE db_cursor 

END
GO
/****** Object:  StoredProcedure [dbo].[SP_Corpository_Delete_Add]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
--  SP_Get_Checked_TriggerOutput 'TriggerLevel_Output','17','04',2022,'A17614'  
-- exec SP_GetTriggerOutput 'TriggerLevel_Output','',17,'04',2022,'A17614'   
--exec SP_Corpository_Delete_Add '05-2022','Delete_Corpository_triggers',''  
  
  
  
CREATE procedure [dbo].[SP_Corpository_Delete_Add]                        
(                        
@CreatedOn varchar(50)=null,                        
@Action varchar(100)=null,            
@EmpCode varchar(50)=null            
)                        
AS                        
BEGIN                        
 IF (@Action='Delete_Corpository_triggers')                        
 BEGIN                        
 --print 1                        
  delete from RFA_Corpository_Output where FORMAT(CreatedOn,'MM-yyyy')=@CreatedOn                        
  delete from RFA_Corpository_Output_TriggerLevel where FORMAT(CreatedOn,'MM-yyyy')=@CreatedOn                        
  delete from RFA_Corpository_Output_PANLevel where FORMAT(CreatedOn,'MM-yyyy')=@CreatedOn                        
                        
  select 1 as Msg;                        
 END                        
 ELSE IF (@Action='Add_Corpository_triggers')                        
 BEGIN                        
    
  --delete from RFA_Corpository_Output where FORMAT(CreatedOn,'MM-yyyy')=@CreatedOn                        
  --delete from RFA_Corpository_Output_TriggerLevel where FORMAT(CreatedOn,'MM-yyyy')=@CreatedOn                        
  --delete from RFA_Corpository_Output_PANLevel where FORMAT(CreatedOn,'MM-yyyy')=@CreatedOn   
    
 insert into RFA_Corpository_Output_TriggerLevel([Sr.No],[Name of Company],[Company PAN],[Change Reported],                        
 [Description],[Event Date],[Event Identification Date],[Flag],[TRIGGER_ID],[CreatedOn])                        
 select [Sr No],[Name of Company],[Company PAN],[Change Reported],                        
 [Description],[Event Date],[Event Identification Date],[Flag],[RBI Trigger],[CreatedOn]                       
 from RFA_Corpository_Output                       
 WHERE Format([CreatedOn],'MM-yyyy') = @CreatedOn                         
                        
                         
  UPDATE t1                        
  SET t1.LSCLIENTID = t2.LSCLIENTID,t1.Segment=t2.[Segment Name (BBG/EEG/CV/CE/HCF/INF)],t1.[Final Retail/CLTU]=t2.[Final Retail/CLTU],                        
  t1.[Credit Manager]=t2.[Credit Manager],t1.[Area Credit Manager]=t2.[Area Credit Manager],t1.[Regional Credit Head]=t2.[Regional Credit Head],                        
  t1.REGION=t2.Region,t1.CITY=t2.City,t1.STATE=t2.State,t1.RELATIONSHIP_MANAGER=t2.[Relationship Manager],t1.UnitHead=t2.[Unit Head/Regional Sales Manager]                      
  FROM RFA_Corpository_Output_TriggerLevel AS t1                        
  INNER JOIN RFA_CustomerScoping AS t2                        
  ON t1.[Company PAN] = t2.PAN_NO                        
  WHERE Format(t1.[CreatedOn],'MM-yyyy') = @CreatedOn                        
                          
                        
  insert into RFA_Corpository_Output_PANLevel (PAN_NO,TRIGGER_ID,CreatedOn)                        
  select distinct([Company PAN]),[RBI Trigger],[CreatedOn]                       
  from RFA_Corpository_Output                        
  WHERE Format([CreatedOn],'MM-yyyy') = @CreatedOn                      
                          
  UPDATE a                        
  SET a.LSCLIENTID = b.LSCLIENTID,a.CUSTOMER_NAME=b.[Customer Name], a.Segment=b.[Segment Name (BBG/EEG/CV/CE/HCF/INF)],a.[Final Retail/ CLTU]=b.[Final Retail/CLTU],                        
  a.[Credit Manager]=b.[Credit Manager],a.[Area Credit Manager]=b.[Area Credit Manager],a.[Regional Credit Head]=b.[Regional Credit Head],                        
  a.REGION=b.Region,a.CITY=b.City,a.STATE=b.State,a.RELATIONSHIP_MANAGER=b.[Relationship Manager],a.UnitHead=b.[Unit Head/Regional Sales Manager]                        
  FROM RFA_Corpository_Output_PANLevel AS a                        
  INNER JOIN RFA_CustomerScoping AS b                        
  ON a.PAN_NO = b.PAN_NO                        
  WHERE Format(a.[CreatedOn],'MM-yyyy') = @CreatedOn                        
                        
  select  [Company PAN], [RBI Trigger] , CT = COUNT(distinct [Description])                         
  INTO #tmp_PANCount                        
  from RFA_Corpository_Output                         
  WHERE Format(CreatedOn,'MM-yyyy') = @CreatedOn                        
  group by [Company PAN], [RBI Trigger]                        
                        
  UPDATE c                        
  SET c.[Count of triggers] = d.CT                        
  FROM RFA_Corpository_Output_PANLevel AS c                    
  INNER JOIN #tmp_PANCount AS d                        
  ON c.PAN_NO = d.[Company PAN]                        
  WHERE Format(c.[CreatedOn],'MM-yyyy') = @CreatedOn                     
                    
  declare @monthnumber int;                    
  select @monthnumber=SUBSTRING(@CreatedOn, 1, 2)                    
                    
  delete from RFATriggerPublish                   
  where [Month]=dbo.fn_month_number_to_name(@monthnumber)                   
  and year=SUBSTRING(@CreatedOn, 4, 7)                     
                      
  insert into RFATriggerPublish(LSID,CustomerName,TriggerName,RaisedOn,IsRectified,RM_Id,[Month],[Year],RFATriggerId,IsCorpository)                    
  select LSCLIENTID,CUSTOMER_NAME,dbo.fn_GetTriggerName(a.TRIGGER_ID),GETDATE(),0,RELATIONSHIP_MANAGER                  
  ,Format([CreatedOn],'MMMM'),Format([CreatedOn],'yyyy'),b.id,1                    
  from RFA_Corpository_Output_PANLevel  a      
  inner join RFA_TriggerMaster B      
  on a.TRIGGER_ID = B.Trigger_ID      
  where Format([CreatedOn],'MM-yyyy')= @CreatedOn                  
  and ISNUMERIC(LSCLIENTID)=1                    
                    
   --EXEC sp_UserMapping '100',@CreatedOn ,null;                 
                  
  ---update monthwise status---                
                
  Delete RFA_MonthWiseTriggerStatus                
  where TriggerId in (                
  select Distinct m.id                
  from RFA_Corpository_Output l inner join RFA_TriggerMaster m on l.[RBI Trigger]=m.Trigger_ID                
  where Format(CreatedOn,'MM-yyyy') = @CreatedOn                
  )                
  AND TMonth =dbo.fn_month_number_to_name(@monthnumber) and TYear=SUBSTRING(@CreatedOn, 4, 7)                
                
                
                
  INSERT INTO RFA_MonthWiseTriggerStatus (TriggerId , CreatedOn , TStatus , TMonth , TYear)                
  select Distinct b.id , GETDATE() , 'Published' , Format([CreatedOn],'MMMM') ,Format([CreatedOn],'yyyy')                
  from RFA_Corpository_Output   a      
   inner join RFA_TriggerMaster B      
  on a.[RBI Trigger] = B.Trigger_ID      
  where Format(CreatedOn,'MM-yyyy') = @CreatedOn         
        
  ---update file status--                
  select a.triggerId,a.RecordId as FileId                
  INTO #tmp_TriggerFiles                
  from RFA_FileMaster a                
  INNER JOIN RFA_FileStatus b                
  on a.RecordId = b.fileId                
  Where b.file_Month =dbo.fn_month_number_to_name(@monthnumber)       
  AND b.file_Year=SUBSTRING(@CreatedOn, 4, 7)                
  AND a.triggerId IN (                
  select Distinct t.id                
  from RFA_Corpository_Output s inner join RFA_TriggerMaster t on s.[RBI Trigger]=t.Trigger_ID              
  where Format(CreatedOn,'MM-yyyy') = @CreatedOn                
  )                
                  
  Delete From RFA_FileStatus where RecordID IN (                
  select FileId from #tmp_TriggerFiles                
  ) AND file_Month =dbo.fn_month_number_to_name(@monthnumber) AND file_Year=SUBSTRING(@CreatedOn, 4, 7)                
                  
                  
                  
  INSERT INTO RFA_FileStatus(file_Month , file_Year , fileId , fileStatus , CreatedOn)                
  select dbo.fn_month_number_to_name(@monthnumber) , SUBSTRING(@CreatedOn, 4, 7) , RecordId ,'Upload', GETDATE() from RFA_FileMaster a                
  where a.triggerId in (                
  select Distinct b.id        
  from RFA_Corpository_Output a      
   inner join RFA_TriggerMaster B      
  on a.[RBI Trigger] = B.Trigger_ID      
  where Format(CreatedOn,'MM-yyyy') = @CreatedOn                
  )                
   insert into Activity_Log_Tracker(Emp_Code,Form_Name,Module_Name,Total_Count,Activity,Activity_Details,Activity_Date) values            
  (@EmpCode,'RFAdashboard.aspx','Corpository Triggers',1,'Upload','Corpository output file Uploaded',GETDATE())             
                
                
  drop table #tmp_TriggerFiles                
                          
  drop table #tmp_PANCount                        
                          
  select 1 as Msg;                        
 END                        
END  
      
GO
