CREATE procedure [dbo].[SP_Display_CorpositoryData]      
(      
@Action varchar(100),          
@Trigger_Id varchar(500)=null,                
@month varchar(30) =null,           
@year int =null,              
@EmpCode varchaR(50)=NULL      
)      
AS       
BEGIN      

  select distinct [Company PAN],LSCLIENTID,[Name of Company]
  ,Description,FORMAT([Event Date],'dd-MM-yyyy') as [Event Date],  
  Segment ,CreatedOn
  from RFA_Corpository_Output_TriggerLevel  a
  Inner join RFA_TriggerMaster b
  on a.TRIGGER_ID = b.TRIGGER_ID
  where b.id=@Trigger_Id       
  and Format(a.CreatedOn,'MM-yyyy')= CONVERT(varchar, @month) +'-'+ CONVERT(varchar, @year)      
         
END
