CREATE procedure [dbo].[Sp_EmailEx_Dashboard]                   
@LUSRID varchar(50)=Null,
@flag varchar(50)=Null  

as                                                                                      
BEGIN   
 if(@flag='dashboardCount')
 Begin
   


  select b.EmpCode, b.EmpName,b.EmpDesignation, sum(case when status='open'  then 1 else 0 end) as [Ticket_Open]
  ,sum(case when status='Close'  then 1 else 0 end) as [Ticket_Close]
  ,sum(case when status='WP'  then 1 else 0 end) as [Ticket_WP]
  from Tbl_EmailEx_SaveTicket a
  inner join Tbl_EmailEx_EmployeeMaster b on a.AssignTo=b.EmpCode
  where AssignTo in (select Empcode from Tbl_EmailEx_EmployeeMaster where SupervisorEmpCode=@LUSRID) group by b.EmpName,b.EmpDesignation,b.EmpCode

 -- select EmpName,EmpDesignation from Tbl_EmailEx_EmployeeMaster where EmpCode=@LUSRID
 --select count(id)as 'Count_Open'  from Tbl_EmailEx_SaveTicket where AssignTo = @LUSRID and status='Open'
 --select count(id)  as'Count_Close' from Tbl_EmailEx_SaveTicket where AssignTo = @LUSRID and status='Close'
 --select count(id) as 'Count_WP' from Tbl_EmailEx_SaveTicket where AssignTo = @LUSRID and status='WP'
 End
 if(@flag='DashboardList')
 begin
 select b.AppName,a.AssignTo,a.status,CONVERT(date,a.Duedate,105) as Targetdate,DATEDIFF(day, Duedate,GETDATE()) AS Aging from Tbl_EmailEx_SaveTicket a
 inner join Tbl_EmailEx_ApplicationMaster b on  a.AppID=b.AppID  where A.AssignTo=@LUSRID
 end
END
