/****** Object:  StoredProcedure [dbo].[SP_FeedbackActivityTrail]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
   -- exec SP_FeedbackActivityTrail '1394568','A17614','November',2021    
    
CREATE Procedure [dbo].[SP_FeedbackActivityTrail]        
(        
 @LsId int         
,@UserId  varchar(30)=null        
,@month varchar(30)=null    
,@year int = null     
)        
AS        
BEGIN        
-- 2537354        
  Declare @feedbackId int = null  ;        
        
  select @feedbackId = FeedbackId from Feedback where LsId = @LsId and feedbackMonth = @month and feedbackYear = @year;        
    
        
  CREATE TABLE #Activity (id INT identity(1,1),FeedbackStatusId int, FeedbackId int , FeedbackStatus int,FeedbackMsg varchar(100),      
  ActivityDate datetime , RejectedReason varchar(max) , UserId varchar(30) , UserName varchar(250)  , feedbackMonth varchar(30), feedbackYear Int)     
  
  INSERT INTO #Activity (FeedbackStatusId,FeedbackId,FeedbackStatus,FeedbackMsg)
  select a.FeedbackStatusId,  a.FeedbackId,a.Status,b.Msg 
	from  FeedbackStatus a(nolock)
	inner join FeedbackMsg b(nolock)
	on a.[Status] = b.[Status]
	Where FeedbackId=@feedbackId
	order by FeedbackStatusId asc
        
  CREATE TABLE #RMActivity (id INT identity(1,1), FeedbackId int        
  , FeedbackStatus int,FeedbackStatusId int , CreatedOn datetime,        
  Msg varchar(100),isRejected bit,reason varchar(max), UserId varchar(30)    
   , feedbackMonth varchar(30), feedbackYear Int)        
            
        
  INSERT INTO #RMActivity (FeedbackId , FeedbackStatus , FeedbackStatusId , CreatedOn, Msg,isRejected,reason,UserId,feedbackMonth,feedbackYear)        
  select a.FeedbackId , a.[Status] ,a.FeedbackStatusId,a.CreatedOn,b.Msg,isnull(c.isRejected,0),c.rejectedReason ,a.RM       
   ,c.feedbackMonth,c.feedbackYear    
    from FeedbackStatus a(nolock)        
    inner join FeedbackMsg b(nolock)        
    on a.[Status] = b.[Status]        
    left join Feedback c(nolock)        
    on a.FeedbackId = c.FeedbackId        
    where a.FeedbackId = @feedbackId and a.[Status] in (0)        
      
        
  INSERT INTO #RMActivity (FeedbackId , FeedbackStatus , FeedbackStatusId , CreatedOn, Msg,isRejected,reason,UserId,feedbackMonth,feedbackYear)        
  select  a.FeedbackId , a.[Status] ,a.FeedbackStatusId,a.CreatedOn,b.Msg,isnull(c.isRejected,0),c.rejectedReason,a.CreditManager       
   ,c.feedbackMonth,c.feedbackYear    
    from FeedbackStatus a(nolock)        
    inner join FeedbackMsg b(nolock)        
    on a.[Status] = b.[Status]        
    left join CMFeedback c(nolock)        
    on a.FeedbackId = c.FeedbackId        
    where a.FeedbackId = @feedbackId and a.[Status] in (1,2)        
       
          
  INSERT INTO #RMActivity (FeedbackId , FeedbackStatus , FeedbackStatusId , CreatedOn, Msg,isRejected,reason,UserId,feedbackMonth,feedbackYear)        
  select  a.FeedbackId , a.[Status] ,a.FeedbackStatusId,a.CreatedOn,b.Msg,isnull(c.isRejected,0),c.rejectedReason  ,a.AreaCreditHead       
   ,c.feedbackMonth,c.feedbackYear    
    from FeedbackStatus a(nolock)        
    inner join FeedbackMsg b(nolock)        
    on a.[Status] = b.[Status]        
    left join ACHFeedback c(nolock)        
    on a.FeedbackId = c.FeedbackId        
    where a.FeedbackId = @feedbackId and a.[Status] in (3,4)        
      
        
  INSERT INTO #RMActivity (FeedbackId , FeedbackStatus , FeedbackStatusId , CreatedOn, Msg,isRejected,reason,UserId,feedbackMonth,feedbackYear)        
  select  a.FeedbackId , a.[Status] ,a.FeedbackStatusId,a.CreatedOn,b.Msg,isnull(c.isRejected,0),c.rejectedReason,a.RegionalCreditHead      
  ,c.feedbackMonth,c.feedbackYear    
    from FeedbackStatus a(nolock)        
    inner join FeedbackMsg b(nolock)        
    on a.[Status] = b.[Status]        
    left join RCHFeedback c(nolock)        
    on a.FeedbackId = c.FeedbackId        
    where a.FeedbackId = @feedbackId and a.[Status] in (5,6)        
     
	   Update a       
      set a.RejectedReason = isnull(b.reason,'')  ,a.UserId = b.UserId    
	  ,a.feedbackMonth = b.feedbackMonth , a.feedbackYear = b.feedbackYear
	  ,a.ActivityDate = b.CreatedOn
      from #Activity a      
      inner join #RMActivity b      
      on a.FeedbackStatusId = b.FeedbackStatusId      

     Update a       
      set a.RejectedReason = b.PolicyTeamComment , a.ActivityDate = b.CreateOn
	  ,a.UserId = b.CreatedBy , a.feedbackMonth =  b.[Month] , a.feedbackYear = b.[Year]
      from #Activity a      
      inner join PolicyReviewLogs b      
      on a.FeedbackStatus = b.PolicyStatus  


          
	update a      
	set a.UserName = ' By -: '+ b.EmpName +' [ '+b.EmpCode+' ] '      
	  from #Activity   a(nolock)      
	left join UserMaster b(nolock)      
	on a.UserId = b.EmpCode      
   
	update a set a.UserName = ' By Supervisor -: '+ c.EmpName +' [ '+c.EmpCode+' ] ' 
	from #Activity   a(nolock)  
	INNER JOIN EmployeeMaster b(nolock)
	on a.UserId = b.SupervisorEmployeeCode
	left join UserMaster c(nolock)      
	on a.UserId = c.EmpCode    

  
	select FeedbackStatusId,id,FeedbackId,isnull(FeedbackMsg,'') as FeedbackMsg      
	,isnull(FeedbackStatus,'') as FeedbackStatus      
	,isnull(RejectedReason,'') as   RejectedReason      
	,ActivityDate = case when FeedbackMsg='Feedback pending' then '' else  isnull(Format(ActivityDate,'dd-MMM-yyyy'),'') end   
	,UserId , ISNULL(UserName,'') as UserName      
	,feedbackMonth , feedbackYear    
	from #Activity a(nolock)  
	
    
	

  drop table #Activity        
  drop table #RMActivity        
       
END
GO
/****** Object:  StoredProcedure [dbo].[SP_FeedbackBulkApprove]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
--exec SP_FeedbackBulkApprove '','5423808',0,0,'R0862'      
CREATE Procedure [dbo].[SP_FeedbackBulkApprove](      
@Action varchar(50)=null,      
@LsId int =null      
,@Triggerid int = null      
,@FeedbackId int =null      
,@UserId varchar(30)=null    
,@rejectedReason varchar(max)=null
)      
AS      
BEGIN      
  Declare @Role varchar(100)=null ;                    
  select @Role = [Role] from RFATrigger_UserMapping where EmpId=@UserId         
      
   select @FeedbackId = FeedbackId       
   , @TriggerId = TriggerId      
   from CMFeedback a(nolock) where LsId=@LsId;      
 select @Role      
       
  IF(@Role='Circle Head')                  
  BEGIN        
    IF NOT EXISTS(SELECT * FROM ACHFeedback where LsId=@LsId)                        
    BEGIN                  
    INSERT INTO ACHFeedback(                    
      FeedbackId                    
     ,ActionProposedId                    
     ,NoActionProposedReasonId                    
     ,RFARecommendationId                    
     ,FraudClassificationNonClassfication                    
     ,ReasonForRFARecommendation                    
     ,IsRejectedByPolicyTeam                    
     ,LsId                    
     ,TriggerId                    
     ,CMFeedbackId                  
    ,ModifiedBy              
    ,ModifiedDate  ,feedbackMonth , feedbackYear      
    )      
    select       
     FeedbackId      
     ,ActionProposedId      
     ,NoActionProposedReasonId                    
     ,RFARecommendationId                    
     ,FraudClassificationNonClassfication                
     ,ReasonForRFARecommendation                    
     ,IsRejectedByPolicyTeam                    
     ,LsId                    
     ,TriggerId        
     ,CMFeedbackId      
    ,@UserId 
    ,GETDATE()       ,feedbackMonth , feedbackYear      
    from CMFeedback      
    where LsId = @LsId      
               
      INSERT INTO FeedbackStatus(FeedbackId,[Status],AreaCreditHead,CreatedOn)                      
      VALUES(@FeedbackId,3,@UserId,GETDATE());                      
             
    UPDATE CMFeedback set IsRejected =0          
    where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @FeedbackId          
            
   UPDATE ACHFeedback set IsRejected = 0          
   where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @FeedbackId          
       
   SELECT @FeedbackId as Id , 'Feedback saved successfully.' as Msg;        
   END      
   END      
   ELSE IF(@Role ='Unit Head' OR @Role='Business Head')               
   BEGIN             
   print 1      
   IF NOT EXISTS(select * from RCHFeedback (nolock) where LsId=@LsId)                    
   BEGIN             
    print 12      
    INSERT INTO RCHFeedback(                    
      FeedbackId                    
     ,ActionProposedId                    
     ,NoActionProposedReasonId                    
     ,RFARecommendationId                    
     ,FraudClassificationNonClassfication                    
     ,ReasonForRFARecommendation                    
     ,IsRejectedByPolicyTeam                    
     ,LsId                    
