      UPDATE RCHFeedback set IsRejected = 0          
      where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @FeedbackId          
             
      SELECT @FeedbackId as Id , 'Feedback saved successfully.' as Msg;       
   END      
  END      
END      
