/****** Object:  StoredProcedure [dbo].[sp_FeedbackUpdate]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


--  alter table Feedback add feedbackMonth varchar(30),feedbackYear int
--alter table CMFeedback add feedbackMonth varchar(30),feedbackYear int
--alter table ACHFeedback add feedbackMonth varchar(30),feedbackYear int
--alter table RCHFeedback add feedbackMonth varchar(30),feedbackYear int


CREATE Procedure [dbo].[sp_FeedbackUpdate](                          
@Action varchar(30)                          
,@Id int=null                          
,@ActionProposedId int = null                          
,@NoActionProposedReasonId int = null                          
,@FraudClassificationNonClassfication varchar(500)=null                          
,@ReasonForRFARecommendation varchar(500)=null                          
,@RFARecommendationId int =null                          
,@TriggerId int =null                          
,@UserId varchar(25) =null                          
,@PolicyTeamId varchar(25)=null                          
,@IsRecommendedForReview bit = null                          
,@LsId int = null                          
,@IsRejectedByPolicyTeam bit =null                      
,@ACHFeedbackId int =null                    
,@CMFeedbackId int =null                  
,@IsSendForReview bit = null          
,@rejectReason varchar(500)=null 
,@month varchar(30)=null
,@year int = null
)                          
AS                          
BEGIN                          
                      
 Declare @Role varchar(50)=null;                      
 select @Role = [Role] from RFATrigger_UserMapping where EmpId=@UserId                      
    
	IF(@Role  IS NULL)
	BEGIN
		IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='RM')
		BEGIN
			SET @Action ='RMFeedback';
		END
		ELSE IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='CM')
		BEGIN
			SET @Role ='Cluster Head';
		END
	END
                      
 IF(@Action='RMFeedback')                          
 BEGIN                          
  IF NOT EXISTS(SELECT * FROM Feedback where FeedbackId=@Id)                          
  BEGIN                          
    INSERT INTO Feedback(                          
      RelationshipManagerId                          
     ,TriggerId                          
     ,ActionProposedId                          
     ,NoActionProposedReasonId                          
     ,RFARecommendationId                          
     ,FraudClassificationNonClassfication                          
     ,ReasonForRFARecommendation                          
     ,IsRecommendedForReview                          
     ,PolicyTeamId                          
     ,CreatedBy                          
     ,CreatedOn                          
     ,LsId           
  ,rejectedReason 
  ,feedbackMonth
  ,feedbackYear
    )                          
    VALUES(                          
     @UserId                          
     ,@TriggerId                          
     ,@ActionProposedId                          
     ,@NoActionProposedReasonId                          
     ,@RFARecommendationId                          
     ,@FraudClassificationNonClassfication                          
     ,@ReasonForRFARecommendation                          
     ,ISNULL(@IsRecommendedForReview,0)                          
     ,@PolicyTeamId                          
     ,@UserId                          
     ,GETDATE()                          
     ,@LsId       
  ,@rejectReason    
  ,@month
  ,@year
    )                          
                              
    SET @Id = SCOPE_IDENTITY();                          
                         
    INSERT INTO FeedbackStatus(FeedbackId,[Status],RM,CreatedOn)                        
    VALUES(@Id,0,@UserId,GETDATE());                        
                   
    UPDATE Feedback set IsRejected = 0, rejectedReason=''            
 where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
            
    SELECT @Id as Id , 'Feedback saved successfully.' as Msg;                 
                        
  END                          
  ELSE                          
  BEGIN                          
    UPDATE Feedback                          
    set ActionProposedId = @ActionProposedId                          
    ,NoActionProposedReasonId = @NoActionProposedReasonId                          
    ,RFARecommendationId = @RFARecommendationId                          
    ,FraudClassificationNonClassfication = @FraudClassificationNonClassfication                          
    ,ReasonForRFARecommendation = @ReasonForRFARecommendation                          
    ,IsRecommendedForReview = ISNULL(@IsRecommendedForReview,0)                          
    ,ModifiedBy = @UserId                          
    ,ModifiedDate = GETDATE()        
    ,rejectedReason = @rejectReason      
    WHERE FeedbackId = @Id                 
    and LsId = @LsId   and TriggerId = @TriggerId
	and feedbackMonth = @month and feedbackYear = @year	;                          
       
       INSERT INTO FeedbackStatus(FeedbackId,[Status],RM,CreatedOn)                        
    VALUES(@Id,0,@UserId,GETDATE());      
       
 UPDATE Feedback set IsRejected = 0   , rejectedReason=''         
 where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
            
    SELECT @Id as Id , 'Feedback updated successfully.' as Msg;                          
   END                          
 END                       
 ELSE IF(@Action='CH_ACH_BUFeedback')           
 BEGIN                      
 IF(@Role like'%Cluster Head%')                      
 BEGIN                      
 IF NOT EXISTS(select * from CMFeedback (nolock) where FeedbackId=@Id)                      
 BEGIN                      
   INSERT INTO CMFeedback(                      
     FeedbackId                      
    ,ActionProposedId                      
    ,NoActionProposedReasonId                      
    ,RFARecommendationId                      
    ,FraudClassificationNonClassfication                      
    ,ReasonForRFARecommendation                      
    ,IsRejectedByPolicyTeam                      
    ,LsId                      
    ,TriggerId                  
 ,IsSendForReview                
 ,ModifiedBy                
 ,ModifiedDate        
 ,rejectedReason    
 ,feedbackMonth
 ,feedbackYear
   )VALUES(                      
     @Id                      
     ,@ActionProposedId                      
     ,@NoActionProposedReasonId                      
     ,@RFARecommendationId                      
     ,@FraudClassificationNonClassfication                      
     ,@ReasonForRFARecommendation                      
     ,@IsRejectedByPolicyTeam                      
     ,@LsId                      
     ,@TriggerId                   
  ,@IsSendForReview                
  ,@UserId                
  ,GETDATE()          
  ,@rejectReason   
  ,@month
  ,@year
   )                      
                      
                      
                        
   INSERT INTO FeedbackStatus(FeedbackId,[Status],CreditManager,CreatedOn)                        
   VALUES(@Id,1,@UserId,GETDATE());                        
                      
   SET @Id = SCOPE_IDENTITY();              
               
   UPDATE Feedback set IsRejected =0   , rejectedReason=''          
   where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
                
 UPDATE CMFeedback set IsRejected = 0 , rejectedReason=''           
 where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
            
   SELECT @Id as Id , 'Feedback saved successfully.' as Msg;              
            
 END                      
   ELSE                       
  BEGIN                      
  UPDATE CMFeedback                       
  SET ActionProposedId = @ActionProposedId                      
  ,NoActionProposedReasonId = @NoActionProposedReasonId                      
  ,RFARecommendationId = @RFARecommendationId                      
  ,FraudClassificationNonClassfication = @FraudClassificationNonClassfication                      
  ,ReasonForRFARecommendation = @ReasonForRFARecommendation                      
  ,IsRejectedByPolicyTeam = @IsRejectedByPolicyTeam         
  ,rejectedReason = @rejectReason      
  where FeedbackId = @Id                      
  and LsId = @LsId and feedbackMonth = @month and feedbackYear = @year;                
             
  INSERT INTO FeedbackStatus(FeedbackId,[Status],CreditManager,CreatedOn)                        
   VALUES(@Id,1,@UserId,GETDATE());     
    
   UPDATE Feedback set IsRejected =0  , rejectedReason=''           
   where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
               
   UPDATE CMFeedback set IsRejected = 0  , rejectedReason=''          
 where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
         
  SELECT @Id as Id , 'Feedback updated successfully.' as Msg;               
            
             
            
 END                      
 END                    
 ELSE IF(@Role like'%Circle Head%')                    
 BEGIN                    
  IF NOT EXISTS(select * from ACHFeedback (nolock) where FeedbackId=@Id)                      
  BEGIN                      
   INSERT INTO ACHFeedback(                      
     FeedbackId                      
    ,ActionProposedId                      
    ,NoActionProposedReasonId                      
    ,RFARecommendationId                      
    ,FraudClassificationNonClassfication                      
    ,ReasonForRFARecommendation                      
    ,IsRejectedByPolicyTeam                      
    ,LsId                      
    ,TriggerId                      
    ,CMFeedbackId                    
 ,ModifiedBy                
 ,ModifiedDate       
 ,rejectedReason   , feedbackMonth , feedbackYear   
   )VALUES(                      
     @Id                      
     ,@ActionProposedId                      
     ,@NoActionProposedReasonId                      
     ,@RFARecommendationId                  
     ,@FraudClassificationNonClassfication                      
     ,@ReasonForRFARecommendation                      
     ,@IsRejectedByPolicyTeam                      
     ,@LsId                      
     ,@TriggerId                      
  ,@CMFeedbackId                    
  ,@UserId                
  ,GETDATE()           
  ,@rejectReason  ,@month , @year    
   )                      
                
   INSERT INTO FeedbackStatus(FeedbackId,[Status],AreaCreditHead,CreatedOn)                        
   VALUES(@Id,3,@UserId,GETDATE());                  
                      
  SET @Id = SCOPE_IDENTITY();              
              
  UPDATE CMFeedback set IsRejected =0    , rejectedReason=''        
   where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
            
   UPDATE ACHFeedback set IsRejected = 0  , rejectedReason=''          
 where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
            
  SELECT @Id as Id , 'Feedback saved successfully.' as Msg;                      
  END                      
  ELSE                       
  BEGIN                      
  UPDATE ACHFeedback                       
  SET ActionProposedId = @ActionProposedId                      
  ,NoActionProposedReasonId = @NoActionProposedReasonId                      
  ,RFARecommendationId = @RFARecommendationId                      
  ,FraudClassificationNonClassfication = @FraudClassificationNonClassfication                      
  ,ReasonForRFARecommendation = @ReasonForRFARecommendation                      
  ,IsRejectedByPolicyTeam = @IsRejectedByPolicyTeam              
  ,rejectedReason = @rejectReason      
  where FeedbackId = @Id                      
  and LsId = @LsId  and feedbackMonth = @month and feedbackYear = @year                    
        
  INSERT INTO FeedbackStatus(FeedbackId,[Status],AreaCreditHead,CreatedOn)                        
   VALUES(@Id,3,@UserId,GETDATE());           
    
   UPDATE CMFeedback set IsRejected =0   , rejectedReason=''          
   where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id       
       
   UPDATE ACHFeedback set IsRejected = 0  , rejectedReason=''          
 where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
            
  SELECT @Id as Id , 'Feedback updated successfully.' as Msg;                       
  END                      
 END                    
 ELSE IF(@Role like'%Unit Head%' OR @Role like'%Business Head%')                    
 BEGIN                    
  IF NOT EXISTS(select * from RCHFeedback (nolock) where FeedbackId=@Id)                      
  BEGIN                      
   INSERT INTO RCHFeedback(                      
     FeedbackId                      
    ,ActionProposedId                      
    ,NoActionProposedReasonId                      
    ,RFARecommendationId                      
    ,FraudClassificationNonClassfication     
    ,ReasonForRFARecommendation                      
    ,IsRejectedByPolicyTeam                      
    ,LsId                      
    ,TriggerId                      
    ,ACHFeedbackId                    
    ,CMFeedbackId                    
 ,ModifiedBy                
 ,ModifiedDate        
 ,rejectedReason , feedbackMonth , feedbackYear      
   )VALUES(                      
     @Id                      
     ,@ActionProposedId                      
     ,@NoActionProposedReasonId                      
     ,@RFARecommendationId                      
     ,@FraudClassificationNonClassfication                      
     ,@ReasonForRFARecommendation                      
     ,@IsRejectedByPolicyTeam                      
     ,@LsId                      
   ,@TriggerId                      
 ,@ACHFeedbackId                    
 ,@CMFeedbackId                    
 ,@UserId                
 ,GETDATE()           
 ,@rejectReason , @month , @year     
   )                      
                        
   INSERT INTO FeedbackStatus(FeedbackId,[Status],RegionalCreditHead,CreatedOn)                        
   VALUES(@Id,5,@UserId,GETDATE());                        
                      
   SET @Id = SCOPE_IDENTITY();                      
               
   UPDATE ACHFeedback set IsRejected =0   , rejectedReason=''          
   where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
            
   UPDATE RCHFeedback set IsRejected = 0  , rejectedReason=''          
   where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
            
   SELECT @Id as Id , 'Feedback saved successfully.' as Msg;                      
  END                      
  ELSE                       
  BEGIN                      
  UPDATE RCHFeedback                       
  SET ActionProposedId = @ActionProposedId                      
  ,NoActionProposedReasonId = @NoActionProposedReasonId                      
  ,RFARecommendationId = @RFARecommendationId                      
  ,FraudClassificationNonClassfication = @FraudClassificationNonClassfication                      
  ,ReasonForRFARecommendation = @ReasonForRFARecommendation                      
  ,IsRejectedByPolicyTeam = @IsRejectedByPolicyTeam           
  ,rejectedReason = @rejectReason      
  where FeedbackId = @Id                      
  and LsId = @LsId  and feedbackMonth =@month  and feedbackYear = @year                    
           
    INSERT INTO FeedbackStatus(FeedbackId,[Status],RegionalCreditHead,CreatedOn)                        
   VALUES(@Id,5,@UserId,GETDATE());     
    
      UPDATE ACHFeedback set IsRejected =0  , rejectedReason=''           
   where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
            
    UPDATE RCHFeedback set IsRejected = 0   , rejectedReason=''         
 where TriggerId = @TriggerId and LsId = @LsId and FeedbackId = @Id            
            
            
  SELECT @Id as Id , 'Feedback updated successfully.' as Msg;                       
  END                      
 END                    
 END                      

  Insert into [Activity_Log_Tracker] Values(@UserId,'trigger_count_details.aspx','feedback update',1,'Upload','Feedback updated',getdate())  ;
 delete from PolicyFeedback where FeedbackId = @Id and LsId = @LsId and [Month] = @month and [Year] = @year;

END 
GO
/****** Object:  StoredProcedure [dbo].[sp_fetch_ApproverCode]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE Procedure [dbo].[sp_fetch_ApproverCode]
@Role as varchar(50)
As
Begin

if @Role = 'Supervisor'	
	Begin
		select distinct trigger_supervisor + '-' + CASe when  EmpName is null then 'NA' else replace(EmpName ,'-','') END 'trigger_supervisor'  from trigger_entry t left join UserMaster u on t.trigger_supervisor= u.EmpCode  where isnull(trigger_supervisor, '') <> ''
	End

if @Role = 'CM'	
	Begin
		select distinct trigger_cm  + '-' + CASe when  EmpName is null then 'NA' else replace(EmpName ,'-','') END 'trigger_cm' from trigger_entry t left join UserMaster u on t.trigger_supervisor= u.EmpCode where isnull(trigger_cm, '') <> ''
	End

if @Role = 'ACM'	
	Begin
		select distinct trigger_acm  + '-' + CASe when  EmpName is null then 'NA' else replace(EmpName ,'-','') END 'trigger_acm'  from trigger_entry t left join UserMaster u on t.trigger_supervisor= u.EmpCode where isnull(trigger_acm, '') <> ''  
	End
End

  
GO
