/****** Object:  StoredProcedure [dbo].[sp_Fetch_Cross_Sell_Data]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE Procedure [dbo].[sp_Fetch_Cross_Sell_Data]
@LS_ID varchar(20),
@Cross_Sell_Entry_Id int,
@Status varchar(100)
As
Begin

if @status = 'Pending'

Begin

select a.ls_id, a.customername, a.Cross_Sell_name, a.Cross_Sell_start_date, a.Cross_Sell_completion_days, '' Actual_Completion_Date, '' action, b.remarks, b.Forward_to, '' Trigger_RM_Action, '' Trigger_CM_Action
from Cross_Sell_Entry a left join Cross_Sell_entry_rmarks b 
on a.Cross_Sell_Entry_id = b.Cross_Sell_Entry_id 
where a.ls_id = @LS_ID
and a.Cross_Sell_Entry_id = @Cross_Sell_Entry_Id
order by b.Cross_Sell_Entry_remarks_id desc

End

Else if @status = 'Pending at supervisor'

Begin

select a.ls_id, c.customername, c.Cross_Sell_name, c.Cross_Sell_start_date, c.Cross_Sell_completion_days, '' Actual_Completion_Date, d.action, a.remarks, a.Forward_to, e.Trigger_RM_Action, e.Trigger_CM_Action
from Cross_Sell_Entry_rmarks a inner join Cross_Sell_entry c
on a.LS_ID = c.LS_id
and a.Cross_Sell_Entry_id = c.Cross_Sell_Entry_id
inner join Trigger_DRP_Option d
on a.Cross_Sell_DRP_Option_id = d.Trigger_DRP_Option_id
and c.Cross_Sell_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.Cross_Sell_id
where a.ls_id = @LS_ID
and a.Cross_Sell_Entry_id = @Cross_Sell_Entry_Id
order by a.Cross_Sell_Entry_remarks_id desc

End

Else if @status = 'Pending at CM'

Begin

select a.ls_id, c.customername, c.Cross_Sell_name, c.Cross_Sell_start_date, c.Cross_Sell_completion_days, '' Actual_Completion_Date, d.action, a.remarks, a.Forward_to,a.Cross_Sell_Entry_remarks_id,a.Cross_Sell_DRP_Option_id, e.Trigger_RM_Action, e.Trigger_CM_Action
from Cross_Sell_Entry_rmarks a inner join Cross_Sell_entry c
on a.LS_ID = c.LS_id
and a.Cross_Sell_Entry_id = c.Cross_Sell_Entry_id
inner join Trigger_DRP_Option d
on a.Cross_Sell_DRP_Option_id = d.Trigger_DRP_Option_id
and c.Cross_Sell_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.Cross_Sell_id
where a.ls_id = @LS_ID
and a.Cross_Sell_Entry_id = @Cross_Sell_Entry_Id
union
select a.ls_id, c.customername, c.Cross_Sell_name, c.Cross_Sell_start_date, c.Cross_Sell_completion_days, '' Actual_Completion_Date, d.action, a.remarks, a.Forward_to,a.Cross_Sell_Entry_remarks_id,a.Cross_Sell_DRP_Option_id, e.Trigger_RM_Action, e.Trigger_CM_Action
from Cross_Sell_Entry_rmarks_history a inner join Cross_Sell_entry c
on a.LS_ID = c.LS_id
and a.Cross_Sell_Entry_id = c.Cross_Sell_Entry_id
inner join Trigger_DRP_Option d
on a.Cross_Sell_DRP_Option_id = d.Trigger_DRP_Option_id
and c.Cross_Sell_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.Cross_Sell_id
where a.ls_id = @LS_ID
and a.Cross_Sell_Entry_id = @Cross_Sell_Entry_Id
order by a.Cross_Sell_Entry_remarks_id desc

End
Else if @status = 'Pending at ACM'

Begin

select a.ls_id, c.customername, c.Cross_Sell_name, c.Cross_Sell_start_date, c.Cross_Sell_completion_days, '' Actual_Completion_Date, d.action, a.remarks, a.Forward_to,a.Cross_Sell_Entry_remarks_id,a.Cross_Sell_DRP_Option_id, e.Trigger_RM_Action, e.Trigger_CM_Action
from Cross_Sell_Entry_rmarks a inner join Cross_Sell_entry c
on a.LS_ID = c.LS_id
and a.Cross_Sell_Entry_id = c.Cross_Sell_Entry_id
inner join Trigger_DRP_Option d
on a.Cross_Sell_DRP_Option_id = d.Trigger_DRP_Option_id
and c.Cross_Sell_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.Cross_Sell_id
where a.ls_id = @LS_ID
and a.Cross_Sell_Entry_id = @Cross_Sell_Entry_Id
union
select a.ls_id, c.customername, c.Cross_Sell_name, c.Cross_Sell_start_date, c.Cross_Sell_completion_days, '' Actual_Completion_Date, d.action, a.remarks, a.Forward_to,a.Cross_Sell_Entry_remarks_id,a.Cross_Sell_DRP_Option_id, e.Trigger_RM_Action, e.Trigger_CM_Action
from Cross_Sell_Entry_rmarks_history a inner join Cross_Sell_entry c
on a.LS_ID = c.LS_id
and a.Cross_Sell_Entry_id = c.Cross_Sell_Entry_id
inner join Trigger_DRP_Option d
on a.Cross_Sell_DRP_Option_id = d.Trigger_DRP_Option_id
and c.Cross_Sell_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.Cross_Sell_id
where a.ls_id = @LS_ID
and a.Cross_Sell_Entry_id = @Cross_Sell_Entry_Id

order by a.Cross_Sell_Entry_remarks_id desc

End

Else if @status = 'Completed'

Begin

select a.ls_id, c.customername, c.Cross_Sell_name, c.Cross_Sell_start_date, c.Cross_Sell_completion_days, c.Actual_Completion_Date, d.action, a.remarks, a.Forward_to, e.Trigger_RM_Action, e.Trigger_CM_Action
from Cross_Sell_Entry_rmarks_history a inner join Cross_Sell_entry_History c
on a.LS_ID = c.LS_id
and a.Cross_Sell_Entry_id = c.Cross_Sell_Entry_id
inner join Trigger_DRP_Option d
on a.Cross_Sell_DRP_Option_id = d.Trigger_DRP_Option_id
and c.Cross_Sell_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.Cross_Sell_id
where a.ls_id = @LS_ID
and a.Cross_Sell_Entry_id = @Cross_Sell_Entry_Id
and a.Cross_Sell_user_role='Relationship Manager'
order by a.Cross_Sell_Entry_remarks_id desc

End

End


