/****** Object:  StoredProcedure [dbo].[sp_Fetch_MonthYear]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE Procedure [dbo].[sp_Fetch_MonthYear]
As
Begin

Declare @start_date date = dateadd(year, -1, getdate())
Declare @end_date date = getdate()

;with CTE as
(
Select  @start_date as startDate
union all
select DATEADD(month, 1, startDate)
from CTE
where DATEADD(month, 1, startDate) <= @end_date
)

select Left(DATENAME(Month, startDate), 3) + '-' + DATENAME(YEAR, startDate) 'MonthYear' from CTE 


End
GO
/****** Object:  StoredProcedure [dbo].[sp_Fetch_RiskRelated_Data]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE Procedure [dbo].[sp_Fetch_RiskRelated_Data]
@LS_ID varchar(20),
@Trigger_Entry_Id int,
@Status varchar(100)
As
Begin

if @status = 'Pending'

Begin

select a.ls_id, a.customername, a.trigger_name, a.trigger_start_date, a.trigger_completion_days, '' Actual_Completion_Date, '' action, b.remarks, b.Forward_to, e.Trigger_RM_Action, e.Trigger_CM_Action
from Trigger_Entry a left join trigger_entry_rmarks b 
on a.Trigger_Entry_id = b.Trigger_Entry_id 
inner join tbl_trigger_defination e
on e.trigger_id = a.trigger_id
where a.ls_id = @LS_ID
and a.Trigger_Entry_id = @Trigger_Entry_Id
order by b.Trigger_Entry_remarks_id desc

End

Else if @status = 'Pending at supervisor'

Begin

select a.ls_id, c.customername, c.trigger_name, c.trigger_start_date, c.trigger_completion_days, '' Actual_Completion_Date, d.action, a.remarks, a.Forward_to, e.Trigger_RM_Action, e.Trigger_CM_Action
from Trigger_Entry_rmarks a inner join trigger_entry c
on a.LS_ID = c.LS_id
and a.Trigger_Entry_id = c.Trigger_Entry_id
inner join Trigger_DRP_Option d
on a.Trigger_DRP_Option_id = d.Trigger_DRP_Option_id
and c.trigger_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.trigger_id
where a.ls_id = @LS_ID
and a.Trigger_Entry_id = @Trigger_Entry_Id
order by a.Trigger_Entry_remarks_id desc

End

Else if @status = 'Pending at CM'

Begin

select a.ls_id, c.customername, c.trigger_name, c.trigger_start_date, c.trigger_completion_days, '' Actual_Completion_Date, d.action, a.remarks, a.Forward_to,a.Trigger_Entry_remarks_id,a.Trigger_DRP_Option_id, e.Trigger_RM_Action, e.Trigger_CM_Action
from Trigger_Entry_rmarks a inner join trigger_entry c
on a.LS_ID = c.LS_id
and a.Trigger_Entry_id = c.Trigger_Entry_id
inner join Trigger_DRP_Option d
on a.Trigger_DRP_Option_id = d.Trigger_DRP_Option_id
and c.trigger_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.trigger_id
where a.ls_id = @LS_ID
and a.Trigger_Entry_id = @Trigger_Entry_Id

union

select a.ls_id, c.customername, c.trigger_name, c.trigger_start_date, c.trigger_completion_days, '' Actual_Completion_Date, d.action, a.remarks, a.Forward_to,a.Trigger_Entry_remarks_id,a.Trigger_DRP_Option_id, e.Trigger_RM_Action, e.Trigger_CM_Action
from Trigger_Entry_rmarks_history a inner join trigger_entry c
on a.LS_ID = c.LS_id
and a.Trigger_Entry_id = c.Trigger_Entry_id
inner join Trigger_DRP_Option d
on a.Trigger_DRP_Option_id = d.Trigger_DRP_Option_id
and c.trigger_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.trigger_id
where a.ls_id = @LS_ID
and a.Trigger_Entry_id = @Trigger_Entry_Id
order by a.Trigger_Entry_remarks_id desc

End
Else if @status = 'Pending at ACM'

Begin

select a.ls_id, c.customername, c.trigger_name, c.trigger_start_date, c.trigger_completion_days, '' Actual_Completion_Date, d.action, a.remarks, a.Forward_to,a.Trigger_Entry_remarks_id,a.Trigger_DRP_Option_id,e.Trigger_RM_Action, e.Trigger_CM_Action
from Trigger_Entry_rmarks a inner join trigger_entry c
on a.LS_ID = c.LS_id
and a.Trigger_Entry_id = c.Trigger_Entry_id
inner join Trigger_DRP_Option d
on a.Trigger_DRP_Option_id = d.Trigger_DRP_Option_id
and c.trigger_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.trigger_id
where a.ls_id = @LS_ID
and a.Trigger_Entry_id = @Trigger_Entry_Id
union
select a.ls_id, c.customername, c.trigger_name, c.trigger_start_date, c.trigger_completion_days, '' Actual_Completion_Date, d.action, a.remarks, a.Forward_to,a.Trigger_Entry_remarks_id,a.Trigger_DRP_Option_id,e.Trigger_RM_Action, e.Trigger_CM_Action
from Trigger_Entry_rmarks_history a inner join trigger_entry c
on a.LS_ID = c.LS_id
and a.Trigger_Entry_id = c.Trigger_Entry_id
inner join Trigger_DRP_Option d
on a.Trigger_DRP_Option_id = d.Trigger_DRP_Option_id
and c.trigger_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.trigger_id
where a.ls_id = @LS_ID
and a.Trigger_Entry_id = @Trigger_Entry_Id
order by a.Trigger_Entry_remarks_id desc

End

Else if @status = 'Completed'

Begin

select a.ls_id, c.customername, c.trigger_name, c.trigger_start_date, c.trigger_completion_days, c.Actual_Completion_Date, d.action, a.remarks, a.Forward_to, e.Trigger_RM_Action, e.Trigger_CM_Action
from Trigger_Entry_rmarks_history a inner join trigger_entry_History c
on a.LS_ID = c.LS_id
and a.Trigger_Entry_id = c.Trigger_Entry_id
inner join Trigger_DRP_Option d
on a.Trigger_DRP_Option_id = d.Trigger_DRP_Option_id
and c.trigger_id = d.Trigger_ID
inner join tbl_trigger_defination e
on e.trigger_id = c.trigger_id
where a.ls_id = @LS_ID
and a.Trigger_Entry_id = @Trigger_Entry_Id
and a.trigger_user_role='Relationship Manager'
order by a.Trigger_Entry_remarks_id desc

End

End


GO
