CREATE procedure [dbo].[Sp_GenerateCustomerLeadInfo](
@LeadID int ,
@CustomerID	int =null,
@LeadType	int =null,
@CustomerStatus	int =null,
@CustomerType	int =null,
@Units	int =null,
@DealSize	int =null,
@Business	int =null,
@Product	int =null, 
@CreationDate date,
@LoginUser varchar(20) =null,
@ModifiedDate date,
@ModifiedBy varchar(20)=null)
as
 begin
 if @LeadID ='0'
 begin
insert into LeadInformation(
CustomerID,	
LeadType,
CustomerStatus,
CustomerType,
Units,
DealSize,
Business,
Product, 
CreationDate,
LoginUser ,
ModifiedDate,
ModifiedBy )
values
(
@CustomerID,	
@LeadType	,
@CustomerStatus	,
@CustomerType	,
@Units	,
@DealSize,
@Business,
@Product, 
@CreationDate,
@LoginUser ,
@ModifiedDate,
@ModifiedBy



);
set @LeadID = SCOPE_IDENTITY();
select @LeadID  as LeadID  ;
end
else 
begin
update LeadInformation
set 
CustomerID=@CustomerID,	
LeadType=@LeadType,
CustomerStatus=@CustomerStatus,
CustomerType=@CustomerType,
Units=@Units,
DealSize=@DealSize,
Business=@Business,
Product=@Product, 
CreationDate=@CreationDate,
LoginUser=@LoginUser ,
ModifiedDate=@ModifiedDate,
ModifiedBy=@ModifiedBy
where LeadID=@LeadID
 



select @LeadID  as LeadID  ;
end
end

GO
