/****** Object:  StoredProcedure [dbo].[SP_Get_Checked_TriggerOutput]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
 --SP_Get_Checked_TriggerOutput 'TriggerLevel_Output','1A,29,30,36','05',2022,'A17614'
 
CREATE procedure [dbo].[SP_Get_Checked_TriggerOutput]  
(  
@Action varchar(100),    
@Trigger_Id varchar(500)=null,          
@month varchar(30) =null,     
@year int =null,        
@EmpCode varchaR(50)=NULL   
)  
AS  
BEGIN  
      
     IF(@Action ='PANLevel_Output')  
  BEGIN  
  
  Select Z.* from (  
     select TRIGGER_ID as Tid,  PAN_NO , LSCLIENTID , CUSTOMER_NAME , Segment , [Final Retail/ CLTU], [Credit Manager] , [Area Credit Manager] , [Regional Credit Head]    
     ,REGION , CITY , [STATE] , RELATIONSHIP_MANAGER , [Count of triggers]     
     ,TriggerID = 'RFA'+TRIGGER_ID+'/'+ CONVERT(varchar, @month) +'-'+ CONVERT(varchar, @year) +'/'+PAN_NO     
     , TriggerType = 'External'  
 -- into #Temp1  
     from RFA_Corpository_Output_PANLevel       
     where Format(CreatedOn,'MM-yyyy')= CONVERT(varchar, @month) +'-'+ CONVERT(varchar, @year)   
  
  UNION ALL  
  
  select Tid='1', PAN_NO , LS_ID , CUSTOMER_NAME , SEGMENT , [Final Retail/ CLTU] ='', CREDIT_MANAGER,AREA_CREDIT_MANAGER,RCH,Region,City      
     ,[STATE],RELATIONSHIP_MANAGER,[COUNT]=0, TRIGGERID = 'RFA1A/'+ CONVERT(varchar, @month) +'-'+ CONVERT(varchar, @year)   +'/'+PAN_NO        
     ,TriggerType = 'Internal'    
     from RFA_Trigger1A_Output1      
     WHERE [Month] = dbo.fn_month_number_to_name( CONVERT(int, @month))      
     AND [Year] =  @year   
  )Z  
  Where Convert(varchar, Z.Tid ) IN  
  (select * from SplitString(@Trigger_Id,','))   
 -- select * from #Temp1 where Tid in(REPLACE(@Trigger_Id,'''',''))  
  
  END  
   
  ELSE IF(@Action='TriggerLevel_Output')   
  BEGIN  
  
  select Y.* from(  
  select TRIGGER_ID as Tid,[Company PAN] , LSCLIENTID , [Name of Company] , Segment , [Final Retail/ CLTU]='', [Credit Manager] , [Area Credit Manager] , [Regional Credit Head]      
     ,REGION , CITY , [STATE] , RELATIONSHIP_MANAGER , [Count of triggers] =0    
     , TriggerID = 'RFA'+TRIGGER_ID+'/'+ CONVERT(varchar, @month) +'-'+ CONVERT(varchar, @year)   +'/'+[Company PAN]       
     , TriggerType = 'External'      
     from RFA_Corpository_Output_TriggerLevel   
  where  
     Format(CreatedOn,'MM-yyyy')= CONVERT(varchar, @month) +'-'+ CONVERT(varchar, @year)    
  
  UNION ALL  
    
  select  Tid='1', PAN_NO , LS_ID , CUSTOMER_NAME , SEGMENT , [Final Retail/ CLTU] ='', CREDIT_MANAGER,AREA_CREDIT_MANAGER,RCH,Region,City      
     ,[STATE],RELATIONSHIP_MANAGER,[COUNT]=0, TRIGGERID = 'RFA1A/'+ CONVERT(varchar, @month) +'-'+ CONVERT(varchar, @year)   +'/'+PAN_NO      
     , TriggerType = 'Internal'    
     from RFA_Trigger1A_Output1      
     WHERE [Month] = dbo.fn_month_number_to_name( CONVERT(int, @month))      
     AND [Year] =  @year  
  )Y  
  Where Convert(varchar, Y.Tid ) IN  
  (select * from SplitString(@Trigger_Id,','))   
    
  
  END  
  
 -- drop table #Temp1  
 -- drop table #Temp2  
  
END  
  
GO
/****** Object:  StoredProcedure [dbo].[SP_Get_RBI_Unclaimed_MIS_AGE_Amount_Data]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

  
CREATE procedure [dbo].[SP_Get_RBI_Unclaimed_MIS_AGE_Amount_Data]                         
@TYP_RBI_Unclaimed_Age_wise  TYP_RBI_Unclaimed_Age_wise readonly,                          
@reportDate date,                          
@Flag varchar(50),          
@JWT_Token varchar(1000)          
AS                           
BEGIN    
declare @reportDate_minus1Day date,@filename varchar(1000)  
declare @Month int  
set @reportDate_minus1Day = (select DATEADD(day, -1, @reportDate))  
set @Month = (select month(@reportDate))  
set @filename = (select case when @Month = 2 then 'Reporting_API_Data_Feb.csv' when @Month = 3 then 'Reporting_API_Data_Mar.csv'   
when @Month = 4 then 'Reporting_API_Data_APR.csv' when @Month = 5 then 'Reporting_API_Data_May.csv' when @Month = 6 then 'Reporting_API_Data_June.csv' when @Month = 7 then 'Reporting_API_Data_July.csv' else '' end )  
  
  
IF (@Flag = 'AGE')                          
BEGIN           
          
 IF EXISTS(Select JWT_Token_dd From tbl_JWT_Token where JWT_Token_dd=convert(varchar(1100),CONCAT(@JWT_Token,FORMAT(GETDATE(), 'ddMMyyyyhhmm'))))      -- and 1=2                                                                
 BEGIN                                                                      
  Select 'Invalid JWT_Token' as MSG--select Account_Holder_Name as accountHolderName,[address],bankName,urn from tbl_RBI_deposit                                                                                
 END                                                                      
 ELSE                                                                      
 BEGIN           
IF(@filename='')
BEGIN
Select ''
END
ELSE
BEGIN          
       select R.[MIN],R.[MAX],        
  case when numberOfAccounts is null then '0' else numberOfAccounts end as numberOfAccounts,        
  case when totalAmount is null then '0' else totalAmount end as totalAmount        
   from (               
     SELECT t1.[min], t1.[max], CAST(COUNT(t2.ID) AS varchar(50)) AS numberOfAccounts,CAST(SUM(t2.[Amount( in INR)]) AS varchar(50)) as totalAmount              
  --case when CAST(SUM(t2.[Amount( in INR)]) AS varchar(50)) is null then '0' else CAST(SUM(t2.[Amount( in INR)]) AS varchar(50)) end as totalAmount             
   FROM @TYP_RBI_Unclaimed_Age_wise AS t1                        
   LEFT JOIN TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 AS t2 ON   
     
   --[Date of transfer to DEA Fund] between dateadd(YEAR,-(case when t1.[max] = 'MAXIMUM' then (select year(min([Date of transfer to DEA Fund])) from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 where [Date of transfer to DEA Fund] <= @reportDate   
   ----and File_Names = @filename   
   --) else t1.[max] end    ), @reportDate) and  
   --dateadd(YEAR,-(case when t1.[min] ='MINIMUM' then 0 else t1.[min] end),@reportDate_minus1Day)  
   (convert(decimal(18,4),DATEDIFF(month,[Date of transfer to DEA Fund], dateadd(month,0,@reportDate)))/12) between case when t1.[Min]='MINIMUM' then 0 else convert(decimal(18,4),t1.[Min])+0.0001 end and   
case when t1.[max] = 'MAXIMUM' then 2000 else convert(decimal(18,4),t1.[Max]) end  
  
   --and File_Names = @filename   
     
   --DATEDIFF(YEAR, [Date of transfer to DEA Fund], @reportDate) > case when t1.[min] ='MINIMUM' then -1 else t1.[min] end                   
   --AND DATEDIFF  (YEAR, [Date of transfer to DEA Fund], @reportDate)<= case when t1.[max] = 'MAXIMUM' then DATEDIFF  (YEAR, [Date of transfer to DEA Fund], @reportDate) else t1.[max] end                  
   GROUP BY t1.[min], t1.[max] )A        
    right join @TYP_RBI_Unclaimed_Age_wise R on R.[min] = A.[min]        
                  
  --select CAST(convert(varchar, @reportDate, 34) as varchar(50) ) reportDate,CAST(CONVERT(varchar, @reportDate, 34) as varchar(50)) lastUpdatedOn            
     select top 1  CAST(CONVERT(varchar, max(created_on), 34) as varchar(50)) lastUpdatedOn,CAST(convert(varchar, @reportDate, 34) as varchar(50) ) reportDate  from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023  
	 --where File_Names = @filename  
  --convert(date,created_on) <= @reportDate and File_Names = @filename  
    
   Insert into tbl_JWT_Token values(@JWT_Token,GetDate(),convert(varchar(1100),CONCAT(@JWT_Token,FORMAT(GETDATE(), 'ddMMyyyyhhmm'))))      --,NEWID() 
END  
 END          
            
                        
END                    
IF (@Flag = 'AMOUNT')                      
BEGIN           
 IF EXISTS(Select JWT_Token_dd From tbl_JWT_Token where JWT_Token_dd=convert(varchar(1100),CONCAT(@JWT_Token,FORMAT(GETDATE(), 'ddMMyyyyhhmm'))))      -- and 1=2                                                                
 BEGIN                                                                      
  Select 'Invalid JWT_Token' as MSG--select Account_Holder_Name as accountHolderName,[address],bankName,urn from tbl_RBI_deposit                                                                                
 END                                                                      
 ELSE                                                                      
 BEGIN           
IF(@filename='')
BEGIN
Select ''
END
ELSE
BEGIN                   
   select A.[MIN],A.[MAX],        
  case when numberOfAccounts is null then '0' else numberOfAccounts end as numberOfAccount,        
  case when totalAmount is null then '0' else totalAmount end as totalAmount        
   from (                     
   SELECT t1.[min], t1.[max], CAST(COUNT(t2.ID) AS varchar(50)) AS numberOfAccounts,CAST(SUM(t2.[Amount( in INR)]) AS varchar(50)) as totalAmount               
  -- case when CAST(SUM(t2.[Amount( in INR)]) AS varchar(50)) is null then '0' else CAST(SUM(t2.[Amount( in INR)]) AS varchar(50)) end as totalAmount             
   FROM @TYP_RBI_Unclaimed_Age_wise AS t1             
  LEFT JOIN TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 AS t2   
    
  ON t2.[Amount( in INR)] between case when t1.[min]='MINIMUM' then -10000 else convert(decimal(18,4),t1.[Min])+0.0001 end and 
  case when t1.[Max]='MAXIMUM' then 99999999999 else convert(decimal(18,4),t1.[Max]) end
  --> case when t1.[min] ='MINIMUM' then -1 else t1.[min] end  AND t2.[Amount( in INR)] <=                   
  -- case when t1.[max] = 'MAXIMUM' then (select max([Amount( in INR)]) from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 where [Date of transfer to DEA Fund] <= @reportDate  --and File_Names = @filename  
  -- ) else t1.[max] end    
   where [Date of transfer to DEA Fund] <= @reportDate --and File_Names = @filename  
   GROUP BY t1.[min], t1.[max] )A        
    --right join @TYP_RBI_Unclaimed_Age_wise R on R.[min] = A.[min]        
             
                       
           
       --select top 1  CAST(CONVERT(varchar, created_on, 34) as varchar(50)) lastUpdatedOn,CAST(convert(varchar, @reportDate, 34) as varchar(50) ) reportDate  from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023     
    select top 1  CAST(CONVERT(varchar, max(created_on), 34) as varchar(50)) lastUpdatedOn,CAST(convert(varchar, @reportDate, 34) as varchar(50) ) reportDate  from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023  
	--where  File_Names = @filename  
    --convert(date,created_on) <= @reportDate and File_Names = @filename  
  
    Insert into tbl_JWT_Token values(@JWT_Token,GetDate(),convert(varchar(1100),CONCAT(@JWT_Token,FORMAT(GETDATE(), 'ddMMyyyyhhmm'))))   --,NEWID()       
END
 END          
                     
END     
  
  
             
END   
GO
/****** Object:  StoredProcedure [dbo].[SP_Get_RBI_Unclaimed_MIS_AGE_Amount_Data_Test]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[SP_Get_RBI_Unclaimed_MIS_AGE_Amount_Data_Test]          
@TYP_RBI_Unclaimed_Age_wise  TYP_RBI_Unclaimed_Age_wise readonly,          
@reportDate date,          
@Flag varchar(50)          
AS           
BEGIN          
IF (@Flag = 'AGE')          
BEGIN          
   --SELECT t1.[min], t1.[max], CAST(COUNT(t2.ID) AS varchar(50)) AS numberOfAccounts,CAST(SUM(t2.[Amount( in INR)]) AS varchar(50)) as totalAmount        
   --FROM @TYP_RBI_Unclaimed_Age_wise AS t1        
   --JOIN TBL_RBI_Unclaimed_MIS_Data AS t2 ON DATEDIFF(YEAR, [Date of transfer to DEA Fund], GETDATE()) > t1.[min]AND DATEDIFF  (YEAR, [Date of transfer to DEA Fund], GETDATE())<= t1.[max]        
   --GROUP BY t1.[min], t1.[max]    
     
     SELECT t1.[min], t1.[max], CAST(COUNT(t2.ID) AS varchar(50)) AS numberOfAccounts,CAST(SUM(t2.[Amount( in INR)]) AS varchar(50)) as totalAmount        
   FROM @TYP_RBI_Unclaimed_Age_wise AS t1        
   JOIN TBL_RBI_Unclaimed_MIS_Data AS t2 ON DATEDIFF(YEAR, [Date of transfer to DEA Fund], GETDATE()) > case when t1.[min] ='MINIMUM' then -1 else t1.[min] end   
   AND DATEDIFF  (YEAR, [Date of transfer to DEA Fund], GETDATE())<= case when t1.[max] = 'MAXIMUM' then DATEDIFF  (YEAR, [Date of transfer to DEA Fund], GETDATE()) else t1.[max] end  
   GROUP BY t1.[min], t1.[max]    
  
  select CAST(convert(varchar, @reportDate, 34) as varchar(50) ) reportDate,CAST(CONVERT(varchar, @reportDate, 34) as varchar(50)) lastUpdatedOn    
        
END    
IF (@Flag = 'AMOUNT')      
BEGIN    
   --SELECT t1.[min], t1.[max], CAST(COUNT(t2.ID) AS varchar(50)) AS numberOfAccounts,CAST(SUM(t2.[Amount( in INR)]) AS varchar(50)) as totalAmount        
   --FROM @TYP_RBI_Unclaimed_Age_wise AS t1        
   --JOIN TBL_RBI_Unclaimed_MIS_Data AS t2 ON t2.[Amount( in INR)] > t1.[min] AND t2.[Amount( in INR)] <= t1.[max]    
   --GROUP BY t1.[min], t1.[max]    
     
   SELECT t1.[min], t1.[max], CAST(COUNT(t2.ID) AS varchar(50)) AS numberOfAccounts,CAST(SUM(t2.[Amount( in INR)]) AS varchar(50)) as totalAmount        
   FROM @TYP_RBI_Unclaimed_Age_wise AS t1        
   JOIN TBL_RBI_Unclaimed_MIS_Data AS t2 ON t2.[Amount( in INR)] > case when t1.[min] ='MINIMUM' then -1 else t1.[min] end  AND t2.[Amount( in INR)] <=   
   case when t1.[max] = 'MAXIMUM' then (select max([Amount( in INR)]) from TBL_RBI_Unclaimed_MIS_Data) else t1.[max] end  
   GROUP BY t1.[min], t1.[max]    
       
   select CAST(convert(varchar, @reportDate, 34) as varchar(50) ) reportDate,CAST(CONVERT(varchar, @reportDate, 34) as varchar(50)) lastUpdatedOn    
END 
IF (@Flag = 'PINCODE')
BEGIN

   select distinct([State code]) from TBL_RBI_Unclaimed_MIS_Data
   select [State code],[Bank Branch Pincode],CAST(COUNT(ID) AS varchar(50)) AS numberOfAccounts,CAST(SUM([Amount( in INR)]) AS varchar(50)) as totalAmount from TBL_RBI_Unclaimed_MIS_Data
    group by [State code],[Bank Branch Pincode]

END
END



GO
/****** Object:  StoredProcedure [dbo].[SP_Get_RBI_Unclaimed_MIS_Consolidated_Data]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE PROCEDURE [dbo].[SP_Get_RBI_Unclaimed_MIS_Consolidated_Data]
	--declare 
	@TYP_RBI_Unclaimed_Age_wise TYP_RBI_Unclaimed_Age_wise readonly
	,@TYP_RBI_Unclaimed_Amount_wise TYP_RBI_Unclaimed_Age_wise readonly
	,@reportDate DATE
	,-- = '2023-11-03'    
	@JWT_Token VARCHAR(1000)
AS
BEGIN
	--select * from tbl_RBIUnclaimed_MIS_Repots_Activity_Log_Tracker order by id desc
	BEGIN TRY
		DECLARE @reportDate_minus1Day DATE
			,@filename VARCHAR(1000)
		DECLARE @Month INT

		SET @reportDate_minus1Day = (
				SELECT DATEADD(day, - 1, @reportDate)
				)
		SET @Month = (
				SELECT month(@reportDate)
				)
		SET @filename = (
				SELECT CASE 
						WHEN @Month = 2
							THEN 'Reporting_API_Data_Feb.csv'
						WHEN @Month = 3
							THEN 'Reporting_API_Data_Mar.csv'
						WHEN @Month = 4
							THEN 'Reporting_API_Data_APR.csv'
						WHEN @Month = 5
							THEN 'Reporting_API_Data_May.csv'
						WHEN @Month = 6
							THEN 'Reporting_API_Data_June.csv'
						WHEN @Month = 7
							THEN 'Reporting_API_Data_July.csv'
						ELSE ''
						END
				)

		DECLARE @TokenBody NVARCHAR(max)

		IF EXISTS (
				SELECT JWT_Token_dd
				FROM tbl_JWT_Token
				WHERE JWT_Token_dd = convert(VARCHAR(1100), CONCAT (
							@JWT_Token
							,FORMAT(GETDATE(), 'ddMMyyyyhhmm')
							))
				) -- and 1=2                                                                
		BEGIN
			SET @TokenBody = N'      
 {      
 "MSG":"Invalid JWT_Token"       
 }'

			SELECT @TokenBody AS Result
		END
		ELSE
		BEGIN
			IF OBJECT_ID(N'tempdb..#Age') IS NOT NULL
			BEGIN
				DROP TABLE #Age;
			END

			INSERT INTO tbl_JWT_Token
			VALUES (
				@JWT_Token
				,GetDate()
				,convert(VARCHAR(1100), CONCAT (
						@JWT_Token
						,FORMAT(GETDATE(), 'ddMMyyyyhhmm')
						))
				)

			DECLARE @data NVARCHAR(max)
			DECLARE @AmountData NVARCHAR(max) = ''
			DECLARE @BindData NVARCHAR(max) = ''
			DECLARE @BindDataN NVARCHAR(max) = ''
			DECLARE @AmountDataN NVARCHAR(max) = ''
			DECLARE @statecode VARCHAR(50)
				,@count INT
				,@cnt INT = 1
			DECLARE @MIN VARCHAR(50)
				,@MAX VARCHAR(50)
				,@Row_ID INT

			SET @count = (
					SELECT count(0)
					FROM @TYP_RBI_Unclaimed_Age_wise
					)
			SET @data = N'{                
"reportDate":"' + (
					SELECT convert(VARCHAR(50), @reportDate, 105)
					) + '",                
"lastUpdatedOn":"' + (
					SELECT TOP 1 CAST(CONVERT(VARCHAR, max(created_on), 34) AS VARCHAR(50)) lastUpdatedOn
					FROM TBL_RBI_Unclaimed_MIS_Data_Backup_12122023
						----where convert(date,created_on) <= @reportDate and File_Names = @filename )+'" ,      
						--where File_Names = @filename 
					) + '" ,   
"accountDetails":[{'

			CREATE TABLE #Age (
				Row_ID INT identity(1, 1)
				,[MIN] VARCHAR(50)
				,[MAX] VARCHAR(50)
				)

			INSERT INTO #Age (
				[MIN]
				,[MAX]
				)
			SELECT *
			FROM @TYP_RBI_Unclaimed_Age_wise

			IF EXISTS (
					SELECT 1
					FROM TBL_RBI_Unclaimed_MIS_Data_Backup_12122023
					WHERE Category = 'I'
					) --and [Date of transfer to DEA Fund]<= @reportDate)              
			BEGIN
				SET @BindData = N'              
"type":"I",              
"ageBucket":[{'

				WHILE (@cnt <= @count)
				BEGIN
					SELECT @MIN = [MIN]
						,@MAX = [MAX]
						,@Row_ID = Row_ID
					FROM #Age
					WHERE Row_ID = @cnt

					SET @AmountData = @AmountData + N' "min":"' + (@MIN) + '",              
"max":"' + (@MAX) + '",              
"amountBucket": ' + (
							SELECT JSON_QUERY((
										SELECT R.[min]
											,R.[max]
											,CASE 
												WHEN numberOfAccounts IS NULL
													THEN '0'
												ELSE numberOfAccounts
												END AS numberOfAccounts
											,CASE 
												WHEN totalAmount IS NULL
													THEN '0'
												ELSE totalAmount
												END AS totalAmount
										FROM (
											SELECT t1.[min]
												,t1.[max]
												,CAST(COUNT(t2.ID) AS VARCHAR(50)) AS numberOfAccounts
												,CAST(SUM(t2.[Amount( in INR)]) AS VARCHAR(50)) AS totalAmount
											FROM @TYP_RBI_Unclaimed_Amount_wise AS t1
											LEFT JOIN TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 AS t2 ON t2.[Amount( in INR)] BETWEEN CASE 
															WHEN t1.[min] = 'MINIMUM'
																THEN - 1
															ELSE convert(DECIMAL(18, 4), t1.[Min]) + 0.0001
															END
													AND CASE 
															WHEN t1.[Max] = 'MAXIMUM'
																THEN (
																		SELECT max([Amount( in INR)])
																		FROM TBL_RBI_Unclaimed_MIS_Data_Backup_12122023
																		WHERE [Date of transfer to DEA Fund] <= @reportDate
																		)
															ELSE convert(DECIMAL(18, 4), t1.[Max])
															END
											--t2.[Amount( in INR)] > case when t1.[min] ='MINIMUM' then -1 else t1.[min] end  AND t2.[Amount( in INR)] <=                   
											-- case when t1.[max] = 'MAXIMUM' then (select max([Amount( in INR)]) from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 where [Date of transfer to DEA Fund] <= @reportDate ) else t1.[max] end                
											WHERE Category = 'I'
												AND (convert(DECIMAL(18, 4), DATEDIFF(month, [Date of transfer to DEA Fund], dateadd(month, 0, @reportDate))) / 12) BETWEEN CASE 
															WHEN @MIN = 'MINIMUM'
																THEN 0
															ELSE convert(DECIMAL(18, 4), @MIN) + 0.0001
															END
													AND CASE 
															WHEN @MAX = 'MAXIMUM'
																THEN (
																		SELECT year(min([Date of transfer to DEA Fund]))
																		FROM TBL_RBI_Unclaimed_MIS_Data_Backup_12122023
																		WHERE [Date of transfer to DEA Fund] <= @reportDate
																		)
															ELSE convert(DECIMAL(18, 4), @MAX)
															END
											--[Date of transfer to DEA Fund] between dateadd(YEAR,-(case when @MAX = 'MAXIMUM' then (select year(min([Date of transfer to DEA Fund])) from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 where [Date of transfer to DEA Fund] <= @reportDate ) else @MAX end    ), @reportDate) and
											--dateadd(YEAR,-(case when @MIN ='MINIMUM' then -1 else @MIN end ), @reportDate_minus1Day)
											--and File_Names = @filename 
											GROUP BY t1.[min]
												,t1.[max]
											) A
										RIGHT JOIN @TYP_RBI_Unclaimed_Amount_wise R ON R.[min] = A.[min]
										FOR json path
										))
							)

					--print @BindData              
					IF (@cnt <> @count)
					BEGIN
						SET @AmountData = @AmountData + N'},{'
					END

					SET @cnt = @cnt + 1
				END

				SET @BindData = @BindData + @AmountData + N'}]}, {'

				PRINT '@BindData ' + @BindData

				SET @cnt = 1
			END

			IF EXISTS (
					SELECT *
					FROM TBL_RBI_Unclaimed_MIS_Data_Backup_12122023
					WHERE Category = 'N'
					) -- and [Date of transfer to DEA Fund]<= @reportDate)              
			BEGIN
				SET @cnt = 1
				SET @BindDataN = N'           
"type":"N",              
"ageBucket":[{'

				WHILE (@cnt <= @count)
				BEGIN
					SELECT @MIN = [MIN]
						,@MAX = [MAX]
						,@Row_ID = Row_ID
					FROM #Age
					WHERE Row_ID = @cnt

					SET @AmountDataN = @AmountDataN + N' "min":"' + (@MIN) + '",              
"max":"' + (@MAX) + '",              
"amountBucket": ' + (
							SELECT JSON_QUERY((
										SELECT R.[min]
											,R.[max]
											,CASE 
												WHEN numberOfAccounts IS NULL
													THEN '0'
												ELSE numberOfAccounts
												END AS numberOfAccounts
											,CASE 
												WHEN totalAmount IS NULL
													THEN '0'
												ELSE totalAmount
												END AS totalAmount
										FROM (
											SELECT t1.[min]
												,t1.[max]
												,CAST(COUNT(t2.ID) AS VARCHAR(50)) AS numberOfAccounts
												,CAST(SUM(t2.[Amount( in INR)]) AS VARCHAR(50)) AS totalAmount
											FROM @TYP_RBI_Unclaimed_Amount_wise AS t1
											LEFT JOIN TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 AS t2 ON
												--t2.[Amount( in INR)] > case when t1.[min] ='MINIMUM' then -1 else t1.[min] end  
												--AND t2.[Amount( in INR)] <= case when t1.[max] = 'MAXIMUM' then (select max([Amount( in INR)]) from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 where [Date of transfer to DEA Fund] <= @reportDate) else t1.[max] end  
												t2.[Amount( in INR)] BETWEEN CASE 
															WHEN t1.[min] = 'MINIMUM'
																THEN - 10000
															ELSE convert(DECIMAL(18, 4), t1.[Min]) + 0.0001
															END
													AND CASE 
															WHEN t1.[Max] = 'MAXIMUM'
																THEN (
																		select max([Amount( in INR)]) from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 
																		where [Date of transfer to DEA Fund] <= @reportDate
																		--SELECT year(min([Date of transfer to DEA Fund]))
																		--FROM TBL_RBI_Unclaimed_MIS_Data_Backup_12122023
																		--WHERE [Date of transfer to DEA Fund] <= @reportDate
																		)
															ELSE convert(DECIMAL(18, 4), t1.[Max])
															END
											WHERE Category = 'N'
												AND
												--[Date of transfer to DEA Fund] between dateadd(YEAR,-(case when @MAX = 'MAXIMUM' then (select year(min([Date of transfer to DEA Fund])) from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 where [Date of transfer to DEA Fund] <= @reportDate ) else @MAX end    ), @reportDate) and
												--dateadd(YEAR,-(case when @MIN ='MINIMUM' then 0 else @MIN end), @reportDate_minus1Day) 
												(convert(DECIMAL(18, 4), DATEDIFF(month, [Date of transfer to DEA Fund], dateadd(month, 0, @reportDate))) / 12) BETWEEN CASE 
															WHEN @MIN = 'MINIMUM'
																THEN 0
															ELSE convert(DECIMAL(18, 4), @MIN) + 0.0001
															END
													AND CASE 
															WHEN @MAX = 'MAXIMUM'
																THEN (
																		SELECT year(min([Date of transfer to DEA Fund]))
																		FROM TBL_RBI_Unclaimed_MIS_Data_Backup_12122023
																		WHERE [Date of transfer to DEA Fund] <= @reportDate
																		)
															ELSE convert(DECIMAL(18, 4), @MAX)
															END
											 --and File_Names = @filename 
											GROUP BY t1.[min]
												,t1.[max]
											) A
										RIGHT JOIN @TYP_RBI_Unclaimed_Amount_wise R ON R.[min] = A.[min]
										FOR json path
										))
							)

					--  Insert into tbl_RBIUnclaimed_MIS_Repots_Activity_Log_Tracker (APIName,Request,error,CreatedDate)       
					--select  'test conolidate 5',@AmountDataN,'',GETDATE()
					-- print @AmountDataN              
					IF (@cnt <> @count)
					BEGIN
						SET @AmountDataN = @AmountDataN + N'},{'
							--    Insert into tbl_RBIUnclaimed_MIS_Repots_Activity_Log_Tracker (APIName,Request,error,CreatedDate)       
							--select  'test conolidate 8',@cnt,@count,GETDATE()
					END

					SET @cnt = @cnt + 1
				END

				--  Insert into tbl_RBIUnclaimed_MIS_Repots_Activity_Log_Tracker (APIName,Request,error,CreatedDate)       
				--select  'test conolidate 9',@BindDataN,@AmountDataN,GETDATE()
				--print '@BindDataN 2' + @BindDataN
				--print '@AmountDataN 2' + @AmountDataN
				SET @BindDataN = @BindDataN + @AmountDataN + N'}]}]}'
					-- select @BindDataN              
			END

			-- select 10
			--SELECT @data + @BindData + @BindDataN AS Result
				-- Insert into tbl_RBIUnclaimed_MIS_Repots_Activity_Log_Tracker (APIName,Request,error,CreatedDate)       
				--select  'test conolidate 4',@BindDataN,'',GETDATE()
				DECLARE @ResultData Varchar(MAX)
				SET @ResultData=@data + @BindData + @BindDataN
				IF(@ResultData is null)
				BEGIN
					SELECT '[]' AS RESULT
				END
				ELSE
				BEGIN
					SELECT @data + @BindData + @BindDataN AS Result
				END
		END
	END TRY

	BEGIN CATCH
		INSERT INTO tbl_RBIUnclaimed_MIS_Repots_Activity_Log_Tracker (
			APIName
			,Request
			,error
			,CreatedDate
			)
		SELECT 'test conolidate'
			,ERROR_LINE()
			,ERROR_MESSAGE()
			,GETDATE()
	END CATCH
END
GO
/****** Object:  StoredProcedure [dbo].[SP_Get_RBI_Unclaimed_MIS_Consolidated_Data_SNAP]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
        
          
CREATE procedure [dbo].[SP_Get_RBI_Unclaimed_MIS_Consolidated_Data_SNAP]                                 
@TYP_RBI_Unclaimed_Age_wise  TYP_RBI_Unclaimed_Age_wise readonly,                                  
@reportDate date,                                  
@Flag varchar(50)=null,                  
@JWT_Token varchar(1000)                  
AS                                   
BEGIN            
declare @reportDate_minus1Day date,@filename varchar(1000)          
declare @Month int          
declare @Year int          
set @reportDate_minus1Day = (select DATEADD(day, -1, @reportDate))          
set @Month = (select month(@reportDate))          
set @Year = (select Year(@reportDate))          
         
                            
--IF (@Flag = 'SNAP')                              
--BEGIN                   
 IF EXISTS(Select JWT_Token_dd From tbl_JWT_Token where JWT_Token_dd=convert(varchar(1100),CONCAT(@JWT_Token,FORMAT(GETDATE(), 'ddMMyyyyhhmm'))))      -- and 1=2                                                                        
 BEGIN                                                                              
  Select 'Invalid JWT_Token' as MSG--select Account_Holder_Name as accountHolderName,[address],bankName,urn from tbl_RBI_deposit                                                                                        
 END                                                                              
 ELSE                                                                              
 BEGIN                   
                      
         
 DECLARE @MyTableName sysname;      
 DECLARE @DynamicSQL nvarchar(max);      
      
    SET @MyTableName = 'SnapShot_'+Cast(@Month as varchar(10))+'_'+Cast(@Year as varchar(10));      
 /*    
    SET @DynamicSQL = N'SELECT * FROM ' + QUOTENAME(@MyTableName) + '';      
          
    EXEC sp_executesql @DynamicSQL;      
                                    
    select top 1  CAST(CONVERT(varchar, max(created_on), 34) as varchar(50)) lastUpdatedOn,CAST(convert(varchar, @reportDate, 34) as varchar(50) ) reportDate  from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023     
 */    
   --'+CAST(convert(varchar, @reportDate, 34) as varchar(50) )+' reportDate,  
 SET @DynamicSQL = N'select top 1     
 CAST(CONVERT(varchar, max(created_on), 34) as varchar(50)) lastUpdatedOn,    
 accountDetails=(Select a.Category as type    
 ,ageBucket=(Select MinAge as min,MaxAge as max    
 ,amountBucket=(Select MinAmount as min,MaxAmount as max,numberOfAccounts,totalAmount From ' + QUOTENAME(@MyTableName) + ' c where c.Category=a.Category   
 and c.MinAge=b.MinAge and c.MaxAge=b.MaxAge group by c.MinAmount,c.MaxAmount,c.numberOfAccounts,c.totalAmount FOR JSON PATH)     
 From ' + QUOTENAME(@MyTableName) + ' b where b.Category=a.Category group by b.MinAge,b.MaxAge FOR JSON PATH)     
 from ' + QUOTENAME(@MyTableName) + ' a group by a.Category FOR JSON PATH)    
 from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 FOR JSON PATH;';    
    
 EXEC sp_executesql @DynamicSQL;      
    
    Insert into tbl_JWT_Token values(@JWT_Token,GetDate(),convert(varchar(1100),CONCAT(@JWT_Token,FORMAT(GETDATE(), 'ddMMyyyyhhmm'))))   --,NEWID()               
END                   
                             
--END             
          
          
                     
END 
