/****** Object:  StoredProcedure [dbo].[SP_Get_RBI_Unclaimed_MIS_Pincode_Data]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO






        
CREATE procedure [dbo].[SP_Get_RBI_Unclaimed_MIS_Pincode_Data]        
@ReportDate varchar(50),      
@JWT_Token varchar(1000)      
as         
begin       

declare @filename varchar(1000)
declare @Month int
set @Month = (select month(convert(date,@reportDate,105)))
set @filename = (select case when @Month = 2 then 'Reporting_API_Data_Feb.csv' when @Month = 3 then 'Reporting_API_Data_Mar.csv' 
when @Month = 4 then 'Reporting_API_Data_APR.csv' when @Month = 5 then 'Reporting_API_Data_May.csv' when @Month = 6 then 'Reporting_API_Data_June.csv' when @Month = 7 then 'Reporting_API_Data_July.csv' else '' end )


 declare @TokenBody nvarchar(max)      
 IF EXISTS(Select JWT_Token_dd From tbl_JWT_Token where JWT_Token_dd=convert(varchar(1100),CONCAT(@JWT_Token,FORMAT(GETDATE(), 'ddMMyyyyhhmm'))))      -- and 1=2                                                            
 BEGIN         
 set @TokenBody = N'      
 {      
 "MSG":"Invalid JWT_Token"       
 }'      
       
 select @TokenBody as Result      
  --Select 'Invalid JWT_Token' as MSG--select Account_Holder_Name as accountHolderName,[address],bankName,urn from tbl_RBI_deposit         
        
      
 END                                                                  
 ELSE                                                                  
 BEGIN       
 IF OBJECT_ID(N'tempdb..#pincodedata') IS NOT NULL                      
   BEGIN                      
    DROP TABLE #pincodedata;                      
   END          
           
   IF OBJECT_ID(N'tempdb..#statetemp') IS NOT NULL                      
   BEGIN                      
    DROP TABLE #statetemp;                      
   END          
           
DECLARE @data NVARCHAR(max)        
declare @Statedata nvarchar(max) =''        
declare @statecode varchar(50),@count int , @cnt int = 1        
        
set @count = (select count(distinct [State code]) from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 where [Date of transfer to DEA Fund]<=convert(date,@ReportDate,105) 
--and File_Names = @filename
)        
select * into #statetemp from (SELECT ROW_NUMBER() OVER (ORDER BY [State code]) row_num,[State code] FROM TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 where         
[Date of transfer to DEA Fund] < = convert(date,@ReportDate,105) --and File_Names = @filename         
group by [State code]        
)A         
        
select * into #pincodedata from (select  [State code],[Bank Branch Pincode],CAST(COUNT(ID) AS varchar(50)) AS numberOfAccount, CAST(SUM([Amount( in INR)]) AS varchar(50)) as totalAmount  from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 where [Date of transfer to DEA Fund]
    
 < = convert(date,@ReportDate,105) 
 --and File_Names = @filename 
 group by [State code],[Bank Branch Pincode])A        
        
        
SET @data = N'{        
"reportDate":"'+ @reportDate+'",        
"lastUpdatedOn":"'+(select top 1  CAST(CONVERT(varchar, max(created_on), 34) as varchar(50)) lastUpdatedOn  from TBL_RBI_Unclaimed_MIS_Data_Backup_12122023 
--where 
------convert(date,created_on) <= convert(date,@ReportDate,105) and File_Names = @filename)+'" , 
-- File_Names = @filename
 )+'" ,   
"stateGroup":[{'        
        
while (@cnt <= @count )        
begin        
set @statecode = (select [State code] from #statetemp where row_num =  @cnt)        
set @Statedata = @Statedata +  N'         
"stateCode" : "' + @statecode + '",        
"pinGroup": '+    (Select JSON_QUERY(( select [Bank Branch Pincode] as pinCode,numberOfAccount,totalAmount from #pincodedata where [State code] =  @statecode for json path)))    if(@cnt <> @count )  begin  set @Statedata = @Statedata + '}, {'  end        
  
    
 set @cnt = @cnt + 1        
 print @cnt        
 print @statecode        
end        
        
        
set @Statedata = @Statedata + '} ] }'        
         
        
if(@cnt = 1 )        
begin        
select '[]' as Result        
end        
else        
begin        
select @data + @Statedata  as Result        
      
        
end      
 Insert into tbl_JWT_Token values(@JWT_Token,GetDate(),convert(varchar(1100),CONCAT(@JWT_Token,FORMAT(GETDATE(), 'ddMMyyyyhhmm')))) --,NEWID()      
 END      
        
       
end
GO
