-- sp_getAccountLevelDetails 1,'1591957','November',2021,''      
CREATE Procedure [dbo].[sp_getAccountLevelDetails](      
@triggerId int ,      
@LsId varchar(25)=null,      
@month varchar(30)=null,      
@year int=null,      
@userId varchar(25)=null      
)      
AS      
BEGIN      
 --IF(@triggerId=1)      
 --BEGIN      
      select Distinct LS_ID  as Id
	  ,CUSTOMER_NAME
	 -- ,Format(b.RaisedOn,'MMM-yy') as RaisedOn    
	     ,RaisedOn = SUBSTRING(a.[Month],0,4)+'-' + CONVERT(varchar(10), a.[Year])   
		 ,b.TriggerName
		 ,b.RFATriggerId
   from RFA_Trigger1A_Output1   a(nolock)    
     Inner join RFATriggerPublish b(nolock)    
   on a.LS_ID = b.LSID    
   where  LS_ID= @LsId      
   and a.[Month]=@month      
   and a.[Year]=@year      
   and IsPublished=1      
    
	UNION   
 --END      
      
 --ELSE IF(@triggerId=2)      
 --BEGIN      
      select Distinct [LS/ID]  as Id , [Customer Name] as CUSTOMER_NAME 
	  --,Format(b.RaisedOn,'MMM-yy') as RaisedOn   
	    ,RaisedOn = SUBSTRING(a.[Month],0,4)+'-' + CONVERT(varchar(10), a.[Year])     
		 ,b.TriggerName,b.RFATriggerId
   from RFA_Trigger1B_Output1_BBG a(nolock)    
   Inner join RFATriggerPublish b(nolock)    
   on a.[LS/ID] = b.LSID    
   where  [LS/ID]= @LsId      
   and a.[Month]=@month      
   and a.[Year]=@year      
   and IsPublished=1      
      
   UNION       
      
   select Distinct LS_ID  as Id ,[Customer Name] as CUSTOMER_NAME     
   --,Format(b.RaisedOn,'MMM-yy') as RaisedOn    
     ,RaisedOn = SUBSTRING(a.[Month],0,4)+'-' + CONVERT(varchar(10), a.[Year])     
	  ,b.TriggerName,b.RFATriggerId
   from RFA_Trigger1B_Output1_CTG a(nolock)    
   Inner join RFATriggerPublish b(nolock)    
   on a.LS_ID = b.LSID    
   where  LS_ID= @LsId      
   and a.[Month]=@month      
   and a.[Year]=@year      
   and IsPublished=1      
      
   UNION       
      
   select Distinct LS_ID  as Id ,[Customer Name] as CUSTOMER_NAME
   --,Format(b.RaisedOn,'MMM-yy') as RaisedOn    
     ,RaisedOn = SUBSTRING(a.[Month],0,4)+'-' + CONVERT(varchar(10), a.[Year]) 
	  ,b.TriggerName,b.RFATriggerId
   from RFA_Trigger1B_Output1_INF   a(nolock)    
   Inner join RFATriggerPublish b(nolock)    
   on a.LS_ID = b.LSID    
   where  LS_ID= @LsId      
   and a.[Month]=@month      
   and a.[Year]=@year      
   and IsPublished=1      
      
 --END      
     UNION    
 --ELSE IF(@triggerId=4)      
 --BEGIN      
      select Distinct a.LSID as Id, CUSTOMER_NAME as CUSTOMER_NAME
	  --,Format(b.RaisedOn,'MMM-yy') as RaisedOn    
	    ,RaisedOn = SUBSTRING(a.[Month],0,4)+'-' + CONVERT(varchar(10), a.[Year])  
		 ,b.TriggerName,b.RFATriggerId
   from RFA_Trigger3_PAN_Output_BBG   a(nolock)    
   Inner join RFATriggerPublish b(nolock)    
   on a.LSID = b.LSID    
   where  a.LSID= @LsId      
   and a.[Month]=@month      
   and a.[Year]=@year      
   and IsPublished=1      

     UNION       
      
    select Distinct a.LSID as Id, CUSTOMER_NAME  as CUSTOMER_NAME 
	--,Format(b.RaisedOn,'MMM-yy') as RaisedOn    
	  ,RaisedOn = SUBSTRING(a.[Month],0,4)+'-' + CONVERT(varchar(10), a.[Year])  
	   ,b.TriggerName,b.RFATriggerId
   from RFA_Trigger3_PAN_Output_CTG  a(nolock)    
   Inner join RFATriggerPublish b(nolock)    
   on a.LSID = b.LSID    
   where  a.LSID= @LsId      
   and a.[Month]=@month      
   and a.[Year]=@year      
   and IsPublished=1     
 --END      
END 
