/****** Object:  StoredProcedure [dbo].[SP_GetCorpositoryTrigger]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- EXEC SP_GetCorpositoryTrigger '04',2022

CREATE procedure [dbo].[SP_GetCorpositoryTrigger]
(                  
@month varchar(30) =null                
,@year int =null                
)            
AS                    
BEGIN                
                
  select        
  a.id as Trigger_ID,a.Trigger_ID as T_Id,a.Trigger_name              
  ,a.Trigger_Type            
  ,[count]=0,b.TStatus             
  into #temp1               
  from RFA_TriggerMaster a inner join                 
  RFA_MonthWiseTriggerStatus b 
  on a.id=b.TriggerId                 
  where b.TMonth=dbo.fn_month_number_to_name(@month)                
  and TYear = @year              
  and (TStatus='Executed' or TStatus='Published')                
                
    select [RBI Trigger] ,CT= count(Z.[RBI Trigger])
    INTO #tmp_PANCount 
    from 
    (      
   		select [RBI Trigger] , [Description]
   		from RFA_Corpository_Output                     
   		WHERE Format(CreatedOn,'MM-yyyy') =  CONVERT(varchar, @month) +'-'+ CONVERT(varchar, @year)       
   		--and [RBI Trigger]='42'
   		group by [RBI Trigger] , [Description]
   )Z
	group by Z.[RBI Trigger]

  --select [RBI Trigger] ,[Description], CT = COUNT([RBI Trigger])                         
  --INTO #tmp_Count                        
  --from RFA_Corpository_Output                     
  --WHERE Format(CreatedOn,'MM-yyyy') = CONVERT(varchar, @month) +'-'+ CONVERT(varchar, @year)                        
  --group by [RBI Trigger] ,[Description]                
         
  --select [RBI Trigger] , CT = Count(CT)    
  --INTO #tmp_PANCount    
  --from #tmp_Count group by [RBI Trigger]    
             
  select 1 as [RBI Trigger] , CT = COUNT(PAN_NO)                         
  INTO #tmp_Trigger1A_PANCount                        
  from RFA_Trigger1A_Output1                         
  WHERE [Month] =  dbo.fn_month_number_to_name( CONVERT(int, @month))              
  and [Year] = @year                    
  --group by PAN_NO   ;            
            
  update t1                
  set                
  t1.[count]=t2.CT                 
  from #temp1 t1            
  inner join  #tmp_PANCount t2             
  on t1.T_Id=t2.[RBI Trigger]  ;                
              
  update t1                
  set                
  t1.[count]= t1.[count] + t2.CT                 
  from #temp1 t1            
  inner join  #tmp_Trigger1A_PANCount t2             
  on t1.Trigger_ID=t2.[RBI Trigger]  ;                 
                  
            
  select * from #temp1 where [count]>0              
                
  drop table #temp1                
  drop table #tmp_PANCount                
  drop table #tmp_Trigger1A_PANCount            
                   
END   

	 
GO
