CREATE procedure [dbo].[Sp_GetExistingDetails]
(@LeadID int =null)
as 
begin 
select c.CustomerID,c.CustomerName,c.City,m.value as mainCustomertype,B.[Business Group],B.LeadID,B.LeadType,B.CustomerStatus,B.CustomerType,B.Description from customerinfo c
inner join
(select A.BusinessGroup as [Business Group],PM.Value as LeadType,PM1.Value as CustomerStatus ,PM2.Value as CustomerType,Description,CustomerID,LeadID from

(select B.BusinessGroup,LeadType,L.LeadID,CustomerStatus,CustomerType,P.Description,CustomerID from leadinformation l
left outer join BusinessMaster B on l.Business=B.BusinessID
left outer join ProductMaster P on l.Product=P.ProductID)A
left join PMSDropDownMaster PM on A.LeadType=PM.KeyId
left join PMSDropDownMaster PM1 on A.CustomerStatus=PM1.KeyId
left join PMSDropDownMaster PM2 on A.CustomerType=PM2.KeyId)B
on B.CustomerID=c.CustomerID
left outer join PMSDropDownMaster M on c.CustomerType=m.keyid





 where B.LeadID= LTRIM(@LeadID);
end 







GO
