/****** Object:  StoredProcedure [dbo].[sp_getFeedback]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE Procedure [dbo].[sp_getFeedback](                
@Action varchar(30)                
,@TriggerId int =null                
,@LsId int = null                
,@UserId varchar(25) =null                
,@month varchar(30)= null
,@year int = null
)                
AS                
BEGIN                
 Declare @Role varchar(50)=null;              
 select @Role = [Role] from RFATrigger_UserMapping where EmpId=@UserId              
              
    IF(@Role  IS NULL)
	BEGIN
		IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='RM')
		BEGIN
			SET @Role ='Relationship Manager';
		END
		ELSE IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='CM')
		BEGIN
			SET @Role ='Cluster Head';
		END
	END
	
 IF(@Action='getFeedback')                
 BEGIN                
  IF(@Role like'%Relationship Manager%')              
  BEGIN              
   SELECT FeedbackId,                
     TriggerId                
    ,ActionProposedId                
    ,NoActionProposedReasonId                
    ,RFARecommendationId                
    ,FraudClassificationNonClassfication                
    ,ReasonForRFARecommendation                
    ,PolicyTeamId           
  ,0 as IsSendForReview    
  ,rejectedReason  ,feedbackMonth , feedbackYear
   from Feedback  (nolock)              
   WHERE LsId = @LsId                 
   and TriggerId = @TriggerId  and   feedbackMonth = @month and feedbackYear = @year             
   END              
   ELSE IF(@Role like'%Cluster Head%'  )              
   BEGIN         
  IF EXISTS(select * from CMFeedback where LsId= @LsId and TriggerId = @TriggerId and   feedbackMonth = @month and feedbackYear = @year )        
  BEGIN        
  SELECT FeedbackId,                
     TriggerId                
    ,ActionProposedId                
    ,NoActionProposedReasonId                
    ,RFARecommendationId                
     ,FraudClassificationNonClassfication                
     ,ReasonForRFARecommendation                
    ,0 as PolicyTeamId            
    ,IsSendForReview     
 ,rejectedReason  ,feedbackMonth , feedbackYear
        from CMFeedback  (nolock)              
        WHERE LsId = @LsId                 
        and TriggerId = @TriggerId   and   feedbackMonth = @month and feedbackYear = @year       
  END        
  ELSE         
  BEGIN        
        
     SELECT FeedbackId,                
     TriggerId                
    ,ActionProposedId                
    ,NoActionProposedReasonId                
    ,RFARecommendationId                
     ,FraudClassificationNonClassfication                
          ,ReasonForRFARecommendation                
          ,PolicyTeamId             
    ,0 as IsSendForReview   
 ,rejectedReason ,feedbackMonth , feedbackYear 
        from Feedback  (nolock)              
        WHERE LsId = @LsId                 
        and TriggerId = @TriggerId --and IsRejected = 0   
		and   feedbackMonth = @month and feedbackYear = @year
 END        
   END              
   ELSE IF(@Role like'%Circle Head%'  )              
   BEGIN           
 IF EXISTS(select * from ACHFeedback where LsId = @LsId and TriggerId = @TriggerId and   feedbackMonth = @month and feedbackYear = @year )        
 BEGIN        
  SELECT  FeedbackId,                
   TriggerId                
  ,ActionProposedId                
  ,NoActionProposedReasonId                
  ,RFARecommendationId                
  ,FraudClassificationNonClassfication                
        ,ReasonForRFARecommendation                
  ,CMFeedbackId          
  ,ACHFeedbackId          
  ,0 as IsSendForReview       
  ,rejectedReason  ,feedbackMonth , feedbackYear
  from ACHFeedback  (nolock)              
  WHERE LsId = @LsId                 
        and TriggerId = @TriggerId and   feedbackMonth = @month and feedbackYear = @year   
 END        
 ELSE        
 BEGIN        
        
        
  SELECT FeedbackId,                
    TriggerId                
   ,ActionProposedId                
   ,NoActionProposedReasonId                
   ,RFARecommendationId                
   ,FraudClassificationNonClassfication                
         ,ReasonForRFARecommendation               
   ,CMFeedbackId          
   ,0 as IsSendForReview    
   ,rejectedReason  ,feedbackMonth , feedbackYear
      from CMFeedback  (nolock)              
      WHERE LsId = @LsId   and   feedbackMonth = @month and feedbackYear = @year              
      and TriggerId = @TriggerId  --and IsRejected = 0            
  END        
   END              
   ELSE IF(@Role like'%Unit Head%' OR @Role like'%Business Head%')              
   BEGIN            
 IF EXISTS(select * from RCHFeedback where LsId= @LsId and TriggerId = @TriggerId and   feedbackMonth = @month and feedbackYear = @year )        
 BEGIN        
  SELECT  FeedbackId,                
    TriggerId                
   ,ActionProposedId                
   ,NoActionProposedReasonId                
   ,RFARecommendationId                
   ,FraudClassificationNonClassfication                
         ,ReasonForRFARecommendation                
   ,CMFeedbackId          
   ,ACHFeedbackId          
   ,0 as IsSendForReview    
   ,rejectedReason  ,feedbackMonth , feedbackYear
       from RCHFeedback  (nolock)              
       WHERE LsId = @LsId                 
       and TriggerId = @TriggerId  and   feedbackMonth = @month and feedbackYear = @year        
 END        
 ELSE        
 BEGIN        
        
  SELECT  FeedbackId,                
    TriggerId                
   ,ActionProposedId                
   ,NoActionProposedReasonId                
   ,RFARecommendationId                
   ,FraudClassificationNonClassfication                
         ,ReasonForRFARecommendation                
   ,CMFeedbackId          
   ,ACHFeedbackId          
   ,0 as IsSendForReview    
   ,rejectedReason  ,feedbackMonth , feedbackYear
       from ACHFeedback  (nolock)              
       WHERE LsId = @LsId   and   feedbackMonth = @month and feedbackYear = @year              
       and TriggerId = @TriggerId  --and IsRejected = 0          
  END        
   END              
  END                
END 
GO
/****** Object:  StoredProcedure [dbo].[SP_getFeedbackActivity]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

--exec SP_getFeedbackActivity '3479816','M12603' 

CREATE Procedure [dbo].[SP_getFeedbackActivity](
@LsId int
,@UserId varchar(25)=null
)
AS
BEGIN
	select 
	a.FeedbackId 
	, [Status] = case when  a.[Status] = 0 then 'RM Feedback taken' 
					  when  a.[Status] = 1 then 'CM Approved'
					  when  a.[Status] = 2 then 'CM Rejected'
					  when  a.[Status] = 3 then 'ACH Approved/Closed'
					  when  a.[Status] = 4 then 'ACH Rejected'
					  when  a.[Status] = 5 then 'RCH Approved/Closed'
					  else  'RCH Rejected' end 
	
	from FeedbackStatus a(nolock)
	inner join Feedback b(nolock)
	on a.FeedbackId=b.FeedbackId
	where b.LsId=@LsId 
	and CreatedBy=@UserId
	order by a.FeedbackStatusId asc
END
GO
/****** Object:  StoredProcedure [dbo].[SP_GetFeedbackForPolicyTeam]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
--exec SP_GetFeedbackForPolicyTeam  
  
CREATE Procedure [dbo].[SP_GetFeedbackForPolicyTeam]  
AS  
BEGIN  
  
 Create Table #tmpPolicyData (  
  FeedbackId int , CMFeedbackId Int ,ACHFeedbackId Int , RCHFeedbackId Int ,ActionProposedId Int  
 ,NoActionProposedReasonId Int ,RFARecommendationId Int,FraudClassificationNonClassfication varchar(500)  
 ,ReasonForRFARecommendation varchar(500) , IsRejectedByPolicyTeam bit ,LsId Int ,TriggerId Int ,IsSendForReview Bit  
 ,IsRejected bit,rejectedReason varchar(2000) , feedbackMonth varchar(30) ,feedbackYear Int , feedbackStatus varchar(100)  
 , [Status] INT  
 )   
   
   
 -- ------------------- RCHFeedback Insert ---------------  
 INSERT INTO #tmpPolicyData   
 select   
 FeedbackId   
 ,CMFeedbackId= 0  
 ,ACHFeedbackId =0   
 ,RCHFeedbackId   
 ,ActionProposedId  
 ,NoActionProposedReasonId  
 ,RFARecommendationId  
 ,FraudClassificationNonClassfication  
 ,ReasonForRFARecommendation  
 ,IsRejectedByPolicyTeam  
 ,LsId  
 ,TriggerId  
 ,IsSendForReview =0  
 ,IsRejected  
 ,rejectedReason  
 ,feedbackMonth  
 ,feedbackYear  
 ,'' as feedbackStatus  
 ,NULL as [Status]  
 from RCHFeedback  
   
 -- ------------------- ACHFeedback Insert ---------------  
 INSERT INTO  #tmpPolicyData  
 select   
 FeedbackId   
 ,CMFeedbackId= 0  
 ,ACHFeedbackId   
 ,RCHFeedbackId =0   
 ,ActionProposedId  
 ,NoActionProposedReasonId  
 ,RFARecommendationId  
 ,FraudClassificationNonClassfication  
 ,ReasonForRFARecommendation  
 ,IsRejectedByPolicyTeam  
 ,LsId  
 ,TriggerId  
 ,IsSendForReview =0  
 ,IsRejected  
 ,rejectedReason  
 ,feedbackMonth  
 ,feedbackYear   
 ,'' as feedbackStatus  
 ,NULL as [Status]  
 from ACHFeedback WHERE   
 FeedbackId NOT IN(  
  SELECT FeedbackId from RCHFeedback  
 )  
   
 -------------------------CMFeedback Insert ---------------  
   
 INSERT INTO #tmpPolicyData   
 select   
  FeedbackId   
 ,CMFeedbackId  
 ,ACHFeedbackId = 0  
 ,RCHFeedbackId =0   
 ,ActionProposedId  
 ,NoActionProposedReasonId  
 ,RFARecommendationId  
 ,FraudClassificationNonClassfication  
 ,ReasonForRFARecommendation  
 ,IsRejectedByPolicyTeam  
 ,LsId  
 ,TriggerId  
 ,IsSendForReview  
 ,IsRejected  
 ,rejectedReason  
 ,feedbackMonth  
 ,feedbackYear  
 ,'' as feedbackStatus  
 ,NULL as [Status]  
 from CMFeedback   
 WHERE FeedbackId NOT IN(  
  SELECT FeedbackId from ACHFeedback  
 )  
  
   
 -------------------------RM Feedback Insert For CM Process ---------------  
   
 INSERT INTO #tmpPolicyData   
 select   
  FeedbackId   
 ,CMFeedbackId = 0  
 ,ACHFeedbackId = 0  
 ,RCHFeedbackId =0   
 ,ActionProposedId  
 ,NoActionProposedReasonId  
 ,RFARecommendationId  
 ,FraudClassificationNonClassfication  
 ,ReasonForRFARecommendation  
 ,IsRejectedByPolicyTeam = 0  
 ,LsId  
 ,TriggerId  
 ,IsSendForReview =0  
 ,IsRejected  
 ,rejectedReason  
 ,feedbackMonth  
 ,feedbackYear  
 ,'' as feedbackStatus  
 ,NULL as [Status]  
 from Feedback   
 WHERE FeedbackId NOT IN(  
  SELECT FeedbackId from CMFeedback  
 )  
  
--------------- Curson Execution to set Feedback Msg ---------------------------  
 DECLARE @FeedbackId Int --   
   
 DECLARE db_cursor CURSOR FOR   
 SELECT FeedbackId   
 FROM #tmpPolicyData  
   
   
 OPEN db_cursor    
 FETCH NEXT FROM db_cursor INTO @FeedbackId    
   
 WHILE @@FETCH_STATUS = 0    
 BEGIN    
     
  SELECT top(1)   
  FeedbackStatusId , FeedbackId , b.[Status], Msg  
  INTO #tmpFeedback  
  FROM  FeedbackStatus a(NOLOCK)  
  INNER JOIN FeedbackMsg B(NOLOCK)  
  ON a.[Status] = b.[Status]  
  where a.FeedbackId = @FeedbackId  
  ORDER BY CreatedOn DESC  
   
  UPDATE a  
  set a.feedbackStatus = isnull(b.Msg,'')  
  ,a.[Status] = b.[Status]  
  FROM #tmpPolicyData a  
  inner join #tmpFeedback b   
  on a.FeedbackId = b.FeedbackId   
   
  drop table #tmpFeedback  
   
     FETCH NEXT FROM db_cursor INTO @FeedbackId   
 END   
   
 CLOSE db_cursor    
   
 DEALLOCATE db_cursor  
   
--------------- Curson Execution to set Feedback Msg ---------------------------  
  
select   Distinct
     a.FeedbackId  ,a.CMFeedbackId  
 ,a.ACHFeedbackId  ,a.RCHFeedbackId    
 ,a.ActionProposedId ,a.NoActionProposedReasonId  
 ,a.RFARecommendationId ,a.FraudClassificationNonClassfication  
 ,a.ReasonForRFARecommendation ,a.IsRejectedByPolicyTeam  
 ,a.LsId ,a.TriggerId,a.rejectedReason ,a.feedbackMonth  
 ,a.feedbackYear ,a.feedbackStatus ,a.[Status] ,b.CustomerName  
 ,b.TriggerName,RaisedOn= FORMAT(b.RaisedOn,'MMM-yyyy')  
from #tmpPolicyData a(nolock)  
inner join RFATriggerPublish b(nolock)  
on a.LsId = b.LSID and a.feedbackMonth = b.[Month] and a.feedbackYear = b.[Year]  
  
drop table #tmpPolicyData  
  
END  
  
GO
