Create procedure [dbo].[SP_LOGIN_LOGOUT_REPORT_SEGMENT]
as
begin
select b.rm_id , 'BBG'  as Segment, EmpName, BranchCode, ProfileId, lastlogindate, lastlogoutdate from Rm_lsID_upload_BBG b inner join (select * from usermaster where lastLogindate is not null) l on b.Rm_ID = l.EmpCode
union all
select e.rm_id , 'EEG' as Segment, EmpName, BranchCode, ProfileId, lastlogindate, LastLogoutDate from Rm_lsID_upload_EEG e inner join (select * from usermaster where lastLogindate is not null) l on e.Rm_ID = l.EmpCode
end
