-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_AssetPricing] (@CustomerId int = NULL                
, @CustomerName varchar(250) = NULL                    
, @IsPSL int = NULL                    
, @PSLType varchar(200) = NULL                    
, @IsWeakerSection int = NULL                    
, @Multiple_Banking int = NULL                    
, @IEC_No varchar(100) = NULL                    
, @Avg_Import_Volume varchar(100) = NULL                    
, @Overdue_IDPMS varchar(100) = NULL                    
, @Overdue_EDPMS varchar(100) = NULL                    
, @MTT_Transactions varchar(100) = NULL                    
, @Justification varchar(max) = NULL                    
, @CommercialType varchar(200) = NULL                    
, @CustomerType varchar(200) = NULL                    
, @RAROC varchar(100) = NULL                    
, @APR_PFY varchar(100) = NULL                    
, @APR_YTD varchar(100) = NULL                    
, @CTI varchar(100) = NULL                    
, @Vintage varchar(100) = NULL                    
, @CreatedBy varchar(30) = NULL                    
, @CreatedOn datetime = NULL                    
, @ProposalNumber int = NULL                    
, @ClientId int = NULL                    
, @ApprovalNo varchar(100) = NULL                    
, @IsFTB int = NULL                    
, @CreditProtectWaived int = NULL  
, @flag int = NULL
,@Remark varchar(max)=null
)                    
AS                    
BEGIN                    
  declare @EmpRole varchar(50),@Prop_Status int,@MaxLevelNo varchar(50)              
  select @EmpRole=EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@CreatedBy              
  IF EXISTS (SELECT                    
      AP_Customer_Info_ID                    
    FROM TBL_OVI_Asset_Pricing_Customer_Info                    
    WHERE AP_Customer_Info_ID = @CustomerId)                    
  BEGIN                    
    --Update            
 select @MaxLevelNo= max(LevelNumber) from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId           
    select @Prop_Status=[Status] from  TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId   
	
INSERT INTO TBL_OVI_Asset_Pricing_Customer_Info_History
SELECT *,@CreatedBy,GETDATE() FROM TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId   
   
    UPDATE TBL_OVI_Asset_Pricing_Customer_Info                    
    SET Customer_Name = @CustomerName,                    
        PSL = @IsPSL,                    
        PSLType = @PSLType,                    
        IsWeakerSection = @IsWeakerSection,                    
        Justification = @Justification,                       
        RAROC = @RAROC,                    
        [APR PFY] = @APR_PFY,                    
        [APR YTD] = @APR_YTD,                    
        IsFTB = @IsFTB,                    
        Vintage = @Vintage,                    
        IsMultipleBanking = @Multiple_Banking,                    
        IP_Approval_No = @ApprovalNo,                    
        CTI = @CTI,    
  CreatedOn=GETDATE(),  
  Month=FORMAT(GETDATE(), 'MM'),  
  Year=FORMAT(GETDATE(), 'yyyy'),  
  CreditProtectWaived = @CreditProtectWaived,  
  flag=@flag  
    WHERE AP_Customer_Info_ID = @CustomerId                
 if(@EmpRole='Relationship Manager' and (@Prop_Status=2 or @Prop_Status=3 ))    
 begin   
   if Exists( SELECT * FROM TBL_OVI_Aprrover a WHERE a.Customer_Info_Id=@CustomerId and a.Status=4 and LevelNumber=1)  
   begin  
     update TBL_OVI_Aprrover set Status=0 where Customer_Info_Id=@CustomerId and LevelNumber=1   
   end  
   else  
   begin  
    if(@MaxLevelNo<=1)                  
    begin          
         update TBL_OVI_Aprrover set Status=0 where Customer_Info_Id=@CustomerId and LevelNumber=1         
    end          
    else          
    begin      
      update TBL_OVI_Aprrover set Status=1 where Customer_Info_Id=@CustomerId and LevelNumber=1       
         update TBL_OVI_Aprrover set Status=0 where Aprrover_Id=( select top 1 Aprrover_Id  from TBL_OVI_Aprrover where status=4 and Customer_Info_Id=@CustomerId)   
        
    end   
     
     end    
   
          if(@Prop_Status=2 )  
    begin  
       INSERT INTO tbl_OVI_Log                    
            VALUES (@CustomerId, 'Asset Pricing', 'Updated', @CreatedBy, GETDATE(), 0, 'Proposal updated', '', @Remark)     
   end  
  --      INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink,CustomerId,CommercialType)                                                          
  --      select 'Approval Request','Asset Pricing for '+@CommercialType+' approval sent by '+                        
  --      (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@CreatedBy),Request_Number+' request of '+Customer_Name,                        
  --      0,(select ApproverADID from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId and Status=0),@CreatedBy,GETDATE(),'/Home/Commercials',@CustomerId,'AP'                       
  --      from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId            
            
  --INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType)                                                
  --      values('Asset pricing for '+@CommercialType+' approval of '+(select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId),                                                
  --      'Asset pricing '+@CommercialType+' proposal request (Request No. AP-'+convert( varchar,@CustomerId)+') sent by '            
  --   +(select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId)+'(RM) for Approval',            
  --   0,(select ApproverADID from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId and Status=0),'/Home/Commercials',DATEADD(day, 1, Getdate()),1,                        
  --      @CreatedBy,GETDATE(),@CustomerId,'AP')            
            
  
  end  
else if(@EmpRole='Relationship Manager' and (@Prop_Status!=2 and @Prop_Status!=3 ))              
 begin              
 update TBL_OVI_Asset_Pricing_Customer_Info set [Status]=10 where AP_Customer_Info_ID=@CustomerId              
 end      
    
   if(@EmpRole='Cluster Head' and (@Prop_Status=2 or @Prop_Status=3 ))    
 begin        
    if(@MaxLevelNo=1)                  
    begin          
    update TBL_OVI_Aprrover set Status=0 where Customer_Info_Id=@CustomerId and LevelNumber=1              
    end          
    else          
    begin      
      update TBL_OVI_Aprrover set Status=1 where Customer_Info_Id=@CustomerId and LevelNumber=1    
   -- update TBL_OVI_Asset_Pricing_Customer_Info set [Status]=0 where AP_Customer_Info_ID=@CustomerId  
    if(@Prop_Status=2 )  
    begin  
       INSERT INTO tbl_OVI_Log                    
            VALUES (@CustomerId, 'Asset Pricing', 'Updated', @CreatedBy, GETDATE(), 0, 'Proposal updated', '', @Remark)     
   end  
    end   
     
      update TBL_OVI_Aprrover set Status=0 where Aprrover_Id=( select top 1 Aprrover_Id  from TBL_OVI_Aprrover where status=4 and Customer_Info_Id=@CustomerId)              
              
            
  --      INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink,CustomerId,CommercialType)                                                          
  --      select 'Approval Request','Asset Pricing for '+@CommercialType+' approval sent by '+                        
  --      (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@CreatedBy),Request_Number+' request of '+Customer_Name,                        
  --      0,(select ApproverADID from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId and Status=0),@CreatedBy,GETDATE(),'/Home/Commercials',@CustomerId,'AP'                       
  --      from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId            
            
  --INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType)                                                
  --      values('Asset pricing for '+@CommercialType+' approval of '+(select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId),                                                
  --      'Asset pricing '+@CommercialType+' proposal request (Request No. AP-'+convert( varchar,@CustomerId)+') sent by '            
  --   +(select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId)+'(RM) for Approval',            
  --   0,(select ApproverADID from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId and Status=0),'/Home/Commercials',DATEADD(day, 1, Getdate()),1,                        
  --      @CreatedBy,GETDATE(),@CustomerId,'AP')            
            
     end    
  else if(@EmpRole='Cluster Head' and (@Prop_Status!=2 and @Prop_Status!=3 ))              
 begin              
 update TBL_OVI_Asset_Pricing_Customer_Info set [Status]=10 where AP_Customer_Info_ID=@CustomerId              
 end   
  
   if(@EmpRole='Circle Head' and (@Prop_Status=2 or @Prop_Status=3 ))    
 begin        
    if(@MaxLevelNo=2)                  
    begin          
    update TBL_OVI_Aprrover set Status=0 where Customer_Info_Id=@CustomerId and LevelNumber=2              
    end          
    else          
    begin      
      update TBL_OVI_Aprrover set Status=1 where Customer_Info_Id=@CustomerId and LevelNumber=2    
  -- update TBL_OVI_Asset_Pricing_Customer_Info set [Status]=0 where AP_Customer_Info_ID=@CustomerId  
   if(@Prop_Status=2 )  
    begin  
       INSERT INTO tbl_OVI_Log                    
            VALUES (@CustomerId, 'Asset Pricing', 'Updated', @CreatedBy, GETDATE(), 0, 'Proposal updated', '', @Remark)     
   end  
    end   
     
      update TBL_OVI_Aprrover set Status=0 where Aprrover_Id=( select top 1 Aprrover_Id  from TBL_OVI_Aprrover where status=4 and Customer_Info_Id=@CustomerId)              
              
            
  --      INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink,CustomerId,CommercialType)                                                          
  --      select 'Approval Request','Asset Pricing for '+@CommercialType+' approval sent by '+                        
  --      (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@CreatedBy),Request_Number+' request of '+Customer_Name,                        
  --      0,(select ApproverADID from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId and Status=0),@CreatedBy,GETDATE(),'/Home/Commercials',@CustomerId,'AP'                       
  --      from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId            
            
  --INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType)                                                
  --      values('Asset pricing for '+@CommercialType+' approval of '+(select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId),                                                
