    BEGIN                    
      SET @IsProcess = (SELECT                    
        COUNT(AP_Customer_Info_ID)                    
      FROM TBL_OVI_Asset_Pricing_Customer_Info                    
      WHERE Proposal_Number = @ProposalNumber                    
      AND [Status] = 0);                    
      IF (@IsProcess = 0)                    
      BEGIN                    
        SET @WithOrWithoutProposal = 1;                    
      END                    
    END                    
    ELSE                    
    BEGIN                    
      SET @WithOrWithoutProposal = 1;                    
    END                    
    IF (@WithOrWithoutProposal > 0)                    
    BEGIN                    
      INSERT INTO TBL_OVI_Asset_Pricing_Customer_Info (Customer_Name, CommercialType, CustomerType, [Month], [Year],                    
      PSL, PSLType, IsWeakerSection, Justification, RAROC, [APR PFY], [APR YTD], CTI, Vintage, Clients_No, IP_Approval_No, [Status],                    
      CreatedOn, CreatedBy, IsMultipleBanking, IsFTB, CreditProtectWaived,flag)                    
        VALUES (@CustomerName, @CommercialType, @CustomerType, FORMAT(GETDATE(), 'MM'), FORMAT(GETDATE(), 'yyyy'), @IsPSL, @PSLType, @IsWeakerSection, @Justification, @RAROC, @APR_PFY, @APR_YTD, @CTI, @Vintage, @ClientId, @ApprovalNo, 10, GETDATE(), @CreatedBy, @Multiple_Banking, @IsFTB, @CreditProtectWaived,@flag);                    
                    
      SELECT                    
        @CustomerId = SCOPE_IDENTITY();                    
      IF (@ProposalNumber IS NULL                    
        OR @ProposalNumber = '')                    
      BEGIN                    
        UPDATE TBL_OVI_Asset_Pricing_Customer_Info                    
        SET Request_Number = 'AP-' + CONVERT(varchar(20), @CustomerId)                    
        WHERE AP_Customer_Info_ID = @CustomerId;                    
      END                    
      ELSE                    
      BEGIN                    
        UPDATE TBL_OVI_Asset_Pricing_Customer_Info                    
        SET Proposal_Number = @ProposalNumber,                    
 Request_Number = 'AP-' + CONVERT(varchar(20), @CustomerId)                    
        WHERE AP_Customer_Info_ID = @CustomerId;                    
      END          
           
    IF NOT EXISTS (        
                   SELECT Remark FROM tbl_OVI_Log  WHERE ActionBy = @CreatedBy AND  Remark= @Justification AND CustomerId=@CustomerId AND  Description='Approval request'         
                   AND Format(ActionDate,'dd/MM/yyyy')=Format( GetDate(),'dd/MM/yyyy')        
                 )         
           BEGIN              
        
              INSERT INTO tbl_OVI_Log                    
              VALUES (@CustomerId, 'Asset Pricing', 'Created', @CreatedBy, GETDATE(), 0, 'Approval request', '', @Justification)           
           
     END        
     ELSE         
           BEGIN        
         Select 2  As'DublicateMesgentry'        
    END        
    END                    
    ELSE                    
    BEGIN                    
      SET @CustomerId = -1;                    
    END                    
    SELECT                    
      @CustomerId AS CustomerId;                    
  END                    
END    
