/****** Object:  StoredProcedure [dbo].[SP_OVI_AssetPricing_GetAPRs]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_AssetPricing_GetAPRs](                      
@LsId int=null,                      
@UserId varchar(30)=null,                  
@Type varchar(50)=null,              
@APRCode int=null,              
@ProposalNo varchar(100)=null                  
)                      
AS                      
BEGIN                      
     IF(@Type='AssetPricing')                  
  BEGIN                 
  select A.CLIENTS_NO,A.CLIENTS_NAME,A.PROPOSAL_NO, B.[APR Code]  as APRCode ,B.RAROC , B.[APR PFY] as APR_PFY ,B.[APR YTD] as APR_YTD                      
  , B.CTI,B.VINTAGE from  client_details A INNER JOIN TBL_OVI_AssetPricing_APRs B on A.CLIENTS_NO=B.[Lasersoft Client Id] where A.PROPOSAL_NO=@LsId                
                
  END                  
  ELSE IF(@Type='ReversalApproval')                  
  BEGIN                  
  select A.CLIENTS_NO,A.CLIENTS_NAME, B.[APR Code]  as APRCode ,B.RAROC , B.[APR PFY] as APR_PFY ,B.[APR YTD] as APR_YTD                      
     ,B.VINTAGE,B.CTI,B.Limit from  client_details A INNER JOIN TBL_OVI_AssetPricing_APRs B on A.CLIENTS_NO=B.[Lasersoft Client Id] where A.CLIENTS_NO=@LsId                   
  END               
  ELSE IF(@Type='AccountCustomization')                  
  BEGIN              
  select top 1 A.[APR PFY] as APR_PFY,A.[APR YTD] as APR_YTD,A.[Lasersoft Client Id] as clientid,B.CLIENTS_NAME        
  from TBL_OVI_AssetPricing_APRs A inner join client_details B on A.[Lasersoft Client Id]=B.CLIENTS_NO        
  where A.[APR Code]=@APRCode             
  END         
  ELSE IF(@Type='TradePricing')                  
  BEGIN              
  select top 1 A.[APR PFY] as APR_PFY,A.[APR YTD] as APR_YTD,A.VINTAGE as vintage,A.[Lasersoft Client Id] as clientid,B.CLIENTS_NAME,B.PROPOSAL_NO as proposalNumber        
  from TBL_OVI_AssetPricing_APRs A inner join client_details B on A.[Lasersoft Client Id]=B.CLIENTS_NO        
  where A.[APR Code]=@APRCode             
  END          
                    
END
GO
