/****** Object:  StoredProcedure [dbo].[SP_OVI_CMAUR]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_CMAUR]  
	--declare 
	@IdentFlag varchar(50) = null,
	@CM_Emp_Code varchar(20) = null,
	@DelqFlag varchar(10) = null,
	@SelectedDate Datetime = null,
	@SelectedSegment varchar (max)=null,
	@SelectedLocation varchar (max)=null,
	@SelectedLSID varchar (max)=null
AS
BEGIN


DECLARE @EndDate DATE
DECLARE @StartDate DATE
DECLARE @EndDate1 DATE
DECLARE @StartDate1 DATE
--DECLARE @EndDate1 DATE
--DECLARE @StartDate1 DATE

--SET @EndDate = dateadd(month, datediff(month,0, @SelectedDate)-6,0);
--SET @StartDate = DATEADD(month, - 6, @EndDate)

SET @EndDate = dateadd(month, datediff(month,0, CONVERT(varchar, @SelectedDate, 23))-5,0);
SET @StartDate = DATEADD(month, - 1, cast(CONVERT(varchar, @SelectedDate, 23) as date))


if (@SelectedLSID = '')
begin
set @SelectedLSID = null
end


;WITH cte AS
(
    SELECT  @EndDate AS num
    UNION ALL
    SELECT  dateadd(mm, 1, num)
    FROM    cte
    WHERE dateadd(mm, 1, num) <= @StartDate
)
SELECT  
        datename(month, num) as MonthName
FROM    cte 
order by month(num) desc

	if(@IdentFlag ='CMAUR')
	BEGIN
		
		select  Month,count(*) as NOOFAccCount, CAST(Sum(CAST(Utilization As decimal(18,2)))/100 As decimal(18,2)) as Utilization,Segment,0 as Total
		from
		(
			Select FORMAT(Date,'MMMM') Month , Outstanding as Utilization,Segiment as Segment
			from tbl_OVI_AUR_Upload 
			
			where 
			(CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) 
			and FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
		
		) t  Group By Month,Segment order by Month asc 

if(@IdentFlag ='CMAUR' and isnull(@SelectedLocation,'') <> '' and isnull(@SelectedSegment,'') <> '' )
begin
	--Action Items
		Select LasterSoft_id as LSID,Cust_name as CustomerName,Segiment as Segment,City,CAST(Limit as DECIMAL(18,2)) as SANEXP ,CAST(Outstanding as DECIMAL(18,2)) as OSEXP,
		Regsonforexit as ReasonforExit, TypeOfPlan as TypeofPlan,Status as PlanStatus , PMG , TH_Name as TH, RM_Name as RM
		
		from tbl_OVI_AUR_Upload 
		
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
		--aur.Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
			 FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		and Segiment in (select Item from SplitString(@SelectedSegment, ','))	
		and State in (select Item from SplitString(@SelectedLocation, ','))
		and	LasterSoft_id = case when @SelectedLSID is not null then @SelectedLSID else LasterSoft_id end 

		
end
else if(@IdentFlag ='CMAUR' and isnull(@SelectedSegment,'') <> '')
begin
--Action Items
		Select LasterSoft_id as LSID,Cust_name as CustomerName,Segiment as Segment,City,CAST(Limit as DECIMAL(18,2)) as SANEXP ,CAST(Outstanding as DECIMAL(18,2)) as OSEXP,
		Regsonforexit as ReasonforExit, TypeOfPlan as TypeofPlan,Status as PlanStatus , PMG , TH_Name as TH, RM_Name as RM
		
		from tbl_OVI_AUR_Upload 
			
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and 
		--aur.Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
			 FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		and Segiment in (select Item from SplitString(@SelectedSegment, ',')) 
			and	LasterSoft_id = case when @SelectedLSID is not null then @SelectedLSID else LasterSoft_id end 

		
	   
end
else if(@IdentFlag ='CMAUR' and  isnull(@SelectedLocation,'') <> '')
begin
--Action Items
		Select LasterSoft_id as LSID,Cust_name as CustomerName,Segiment as Segment,City,CAST(Limit as DECIMAL(18,2)) as SANEXP ,CAST(Outstanding as DECIMAL(18,2)) as OSEXP,
		Regsonforexit as ReasonforExit, TypeOfPlan as TypeofPlan,Status as PlanStatus , PMG , TH_Name as TH, RM_Name as RM
		
		from tbl_OVI_AUR_Upload 
			
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and 
		Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and State in (select Item from SplitString(@SelectedLocation, ','))
			and	LasterSoft_id = case when @SelectedLSID is not null then @SelectedLSID else LasterSoft_id end 


end
else
begin
	--Action Items
		Select LasterSoft_id as LSID,Cust_name as CustomerName,Segiment as Segment,City,CAST(Limit as DECIMAL(18,2)) as SANEXP ,CAST(Outstanding as DECIMAL(18,2)) as OSEXP,
		Regsonforexit as ReasonforExit, TypeOfPlan as TypeofPlan,Status as PlanStatus , PMG , TH_Name as TH, RM_Name as RM
		
		from tbl_OVI_AUR_Upload 
		
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and 
		Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			--and ( SME_Client_ID =  @SelectedLSID OR @SelectedLSID = @SelectedLSID)
		and		LasterSoft_id = case when @SelectedLSID is not null then @SelectedLSID else LasterSoft_id end 
end
		---Summary count

		select COUNT (Segiment) TotalAURAcc ,CAST(Sum(CAST(Outstanding As decimal(18,2)))/100 As decimal(18,2)) as TotalAURAmount 


		from tbl_OVI_AUR_Upload 
			
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and 
		Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
		FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') 
		and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')


		-----------CM_Delinquency Month wise count
		select  Months,count(*) as NoOFAccount, CAST(Sum(CAST(UtilAmount As decimal(17,2)))/100 As decimal(18,2)) as UtilAmount
		from
		(

			Select FORMAT(Date,'MMMM') Months, Outstanding as  UtilAmount 
			from tbl_OVI_AUR_Upload 
			
			where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and 
				Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
			 FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			
		) t  Group By Months order by Months asc 



		--CM_Delinquency Segment Color Code
		select cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		--select distinct cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		INNER JOIN tbl_OVI_AUR_Upload aur on cc.Segment=aur.Segiment
		
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and 
		Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
		FORMAT(aur.Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM') 
		--order by cc.Segment desc
		and cc.Type='Segment' group by  cc.Segment ,Div ,BackgroundColor,HoverBackgroundColor 
		order by case  cc.Segment
		when 'BBG' then 1
		when 'EEG' then 2
		when 'SAB' then 3
		when 'CTG' then 4
		when 'CAP MKT' then 5
		when 'ECG' then 6
		when 'LAP' then 7
		else 8 end 


		---Location drop down bind
		select Distinct  State as 'ID' , State as 'Value' from  
		 tbl_OVI_AUR_Upload 
			
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and 
		FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		
		---Segment drop down bind
		select Distinct Segiment as 'ID' , Segiment as 'Value' from  
		 tbl_OVI_AUR_Upload 
			
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and 
		Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
		FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		order by Segiment desc


	

	--- Segment Wise Count
	select count(*) as NOOFAccCount, CAST(Sum(CAST(Utilization As decimal(18,2)))/100 As decimal(18,2)) as Utilization,Segment,0 as Total
		from
		(
			Select Outstanding as Utilization,Segiment as Segment
			from tbl_OVI_AUR_Upload 
			
			where 
			(CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code )  
			and FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
		
		) t  Group By Segment 

	 
		
	END

	
END



