-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_CMDelinquency] 
	--declare 
	@IdentFlag varchar(50) = null,
	@CM_Emp_Code varchar(20) = null,
	@DelqFlag varchar(10) = null,
	@SelectedDate Datetime = null,
	@SelectedSegment varchar (max)=null,
	@SelectedLocation varchar (max)=null,
	@SelectedLSID varchar (max)=null
AS
BEGIN


DECLARE @EndDate DATE
DECLARE @StartDate DATE
DECLARE @EndDate1 DATE
DECLARE @StartDate1 DATE
--DECLARE @EndDate1 DATE
--DECLARE @StartDate1 DATE

--SET @EndDate = dateadd(month, datediff(month,0, @SelectedDate)-6,0);
--SET @StartDate = DATEADD(month, - 6, @EndDate)

SET @EndDate = dateadd(month, datediff(month,0, CONVERT(varchar, @SelectedDate, 23))-5,0);
SET @StartDate = DATEADD(month, - 1, cast(CONVERT(varchar, @SelectedDate, 23) as date))


if (@SelectedLSID = '')
begin
set @SelectedLSID = null
end


;WITH cte AS
(
    SELECT  @EndDate AS num
    UNION ALL
    SELECT  dateadd(mm, 1, num)
    FROM    cte
    WHERE dateadd(mm, 1, num) <= @StartDate
)
SELECT  
        datename(month, num) as MonthName
FROM    cte 
order by month(num) desc

	if(@IdentFlag ='CMDelinquency')
	BEGIN
		
		select  Month,count(*) as NOOFAccCount, CAST(Sum(CAST(Utilization As decimal(18,2)))/100 As decimal(18,2)) as Utilization,Segment,0 as Total
		from
		(
			Select FORMAT(Date_of_tod,'MMMM') Month, Os_in_L as  Utilization , Segment 
			from TBL_OVI_CM_Delinquency 
			where --CM_EMP_Code=@CM_Emp_Code and
			(CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
			
			 Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			
		) t  Group By Month,Segment order by Month asc 

if(@IdentFlag ='CMDelinquency' and isnull(@SelectedLocation,'') <> '' and isnull(@SelectedSegment,'') <> '' )
begin
	--Action Items
		Select SME_Client_ID as LSID,Customer_Name as CustomerName,	Segment,City,PMG,CAST(Lim_in_L as DECIMAL(18,2)) as SANEXP ,CAST(Os_in_L as DECIMAL(18,2)) as OSEXP,
		[Total Overdue] as Overdue,DPD,RM_Name as RM,TH_Name as TH
		
		from TBL_OVI_CM_Delinquency 
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
		Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
			 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')		
		and Segment in (select Item from SplitString(@SelectedSegment, ','))
		and State in (select Item from SplitString(@SelectedLocation, ','))
		and	SME_Client_ID = case when @SelectedLSID is not null then @SelectedLSID else SME_Client_ID end 

		
end
else if(@IdentFlag ='CMDelinquency' and isnull(@SelectedSegment,'') <> '')
begin
--Action Items
		Select SME_Client_ID as LSID,Customer_Name as CustomerName,	Segment,City,PMG,CAST(Lim_in_L as DECIMAL(18,2)) as SANEXP ,CAST(Os_in_L as DECIMAL(18,2)) as OSEXP,
		[Total Overdue] as Overdue,DPD,RM_Name as RM,TH_Name as TH
		
		from TBL_OVI_CM_Delinquency 
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
		--Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and Segment in (select Item from SplitString(@SelectedSegment, ','))		
			and	SME_Client_ID = case when @SelectedLSID is not null then @SelectedLSID else SME_Client_ID end 

		
	   
end
else if(@IdentFlag ='CMDelinquency' and  isnull(@SelectedLocation,'') <> '')
begin
--Action Items
		Select SME_Client_ID as LSID,Customer_Name as CustomerName,	Segment,City,PMG,CAST(Lim_in_L as DECIMAL(18,2)) as SANEXP ,CAST(Os_in_L as DECIMAL(18,2)) as OSEXP,
		[Total Overdue] as Overdue,DPD,RM_Name as RM,TH_Name as TH
		
		from TBL_OVI_CM_Delinquency 
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
		Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and State in (select Item from SplitString(@SelectedLocation, ','))
			and	SME_Client_ID = case when @SelectedLSID is not null then @SelectedLSID else SME_Client_ID end 


end
else
begin
	--Action Items
		Select SME_Client_ID as LSID,Customer_Name as CustomerName,	Segment,City,PMG,CAST(Lim_in_L as DECIMAL(18,2)) as SANEXP ,CAST(Os_in_L as DECIMAL(18,2)) as OSEXP,
		[Total Overdue] as Overdue,DPD,RM_Name as RM,TH_Name as TH
		
		from TBL_OVI_CM_Delinquency 
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
		Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			--and ( SME_Client_ID =  @SelectedLSID OR @SelectedLSID = @SelectedLSID)
		and	SME_Client_ID = case when @SelectedLSID is not null then @SelectedLSID else SME_Client_ID end 
end
		---Summary count

		select COUNT (Segment) OverDueAccount ,CAST(Sum(CAST(Os_in_L As decimal(18,2)))/100 As decimal(18,2)) as OverDueAmount 
		from TBL_OVI_CM_Delinquency where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
		FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') 
		and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')

		-----------CM_Delinquency Month wise count
		select  MonthName,count(*) as NoOFAccount, CAST(Sum(CAST(UtilAmount As decimal(17,2)))/100 As decimal(18,2)) as UtilAmount
		from
		(
			Select FORMAT(Date_of_tod,'MMMM') MonthName, Os_in_L as  UtilAmount 
			from TBL_OVI_CM_Delinquency 
			where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
			 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			
		) t  Group By MonthName order by MonthName asc 



		--CM_Delinquency Segment Color Code
		select cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		--select distinct cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		INNER JOIN TBL_OVI_CM_Delinquency po on cc.Segment=po.Segment
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
		FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM') 
		--order by cc.Segment desc
		and cc.Type='Segment' group by  cc.Segment ,Div ,BackgroundColor,HoverBackgroundColor 
		order by case  cc.Segment
		when 'BBG' then 1
		when 'EEG' then 2
		when 'SAB' then 3
		when 'CTG' then 4
		when 'CAP MKT' then 5
		when 'ECG' then 6
		when 'LAP' then 7
		else 8 end 


		---Location drop down bind
		select Distinct  State as 'ID' , State as 'Value' from TBL_OVI_CM_Delinquency 
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
		FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		
		---Segment drop down bind
		select Distinct Segment as 'ID' , Segment as 'Value' from TBL_OVI_CM_Delinquency 
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
		FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		order by Segment desc


		--DPD count 


		select  count(*) as NOOFAccCount, CAST(Sum(CAST(Overdue_Amount As decimal(18,2)))/100 As decimal(18,2)) as Overdue_Amount,
		CAST(Sum(CAST(Overdue_Exposure As decimal(18,2)))/100 As decimal(18,2)) as Overdue_Exposure,Segment,   dpd_name
		

		from
		(
			Select Os_in_L as  Overdue_Amount,Lim_in_L as Overdue_Exposure , Segment,
			CASE WHEN DPD BETWEEN 0 AND 30 THEN '0 to 30' 
			WHEN DPD BETWEEN 31 AND 60 THEN '31 to 60'
			WHEN DPD BETWEEN 61 AND 90 THEN '61 to 90'
			WHEN DPD > 90 THEN 'Above 90'
			ELSE '' END AS dpd_name
			
			from TBL_OVI_CM_Delinquency 
			where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
			 Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
			 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		  
		) t  Group By Segment,dpd_name 


		------ DPD period------


		;WITH cte1 AS
(
    SELECT  '0 to 30' as DPD_NM
    UNION ALL
    SELECT  '31 to 60' as DPD_NM
	  UNION ALL
    SELECT  '61 to 90' as DPD_NM
	  UNION ALL
    SELECT  'Above 90' as DPD_NM    
)
SELECT * from  cte1


--------DPD Total ----
select  count(*) as NOOFAccCount, CAST(Sum(CAST(Overdue_Amount As decimal(18,2)))/100 As decimal(18,2)) as Overdue_Amount,
		CAST(Sum(CAST(Overdue_Exposure As decimal(18,2)))/100 As decimal(18,2)) as Overdue_Exposure,Segment
		from
		(
			Select Os_in_L as  Overdue_Amount,Lim_in_L as Overdue_Exposure , Segment 
			from TBL_OVI_CM_Delinquency 
			where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
			 Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		
		) t  Group By Segment 
       

--- Segment Wise Count
	

	select  count(*) as NOOFAccCount, CAST(Sum(CAST(Utilization As decimal(18,2)))/100 As decimal(18,2)) as Utilization,Segment,0 as Total
		from
		(
			Select  Os_in_L as  Utilization , Segment 
			from TBL_OVI_CM_Delinquency 
			where --CM_EMP_Code=@CM_Emp_Code and
			(CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code ) and
			
			 Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			
		) t  Group By Segment 


		
	END

	
END
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_CMLCHU]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
