-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_CMLCHU]
	--declare 
	@IdentFlag varchar(50) = null,
	@CM_Emp_Code varchar(20) = null,
	@DelqFlag varchar(10) = null,
	@SelectedDate Datetime = null,
	@SelectedSegment varchar (max)=null,
	@SelectedLocation varchar (max)=null,
	@SelectedLSID varchar (max)=null
AS
BEGIN


DECLARE @EndDate DATE
DECLARE @StartDate DATE
DECLARE @EndDate1 DATE
DECLARE @StartDate1 DATE
--DECLARE @EndDate1 DATE
--DECLARE @StartDate1 DATE

--SET @EndDate = dateadd(month, datediff(month,0, @SelectedDate)-6,0);
--SET @StartDate = DATEADD(month, - 6, @EndDate)

SET @EndDate = dateadd(month, datediff(month,0, CONVERT(varchar, @SelectedDate, 23))-5,0);
SET @StartDate = DATEADD(month, - 1, cast(CONVERT(varchar, @SelectedDate, 23) as date))


if (@SelectedLSID = '')
begin
set @SelectedLSID = null
end


IF OBJECT_ID('tempdb..#temp_DM') IS NOT NULL
DROP TABLE #temp_DM

create table #temp_DM (Month_Year varchar  (50))

;WITH cte AS
(
    SELECT  @EndDate AS num
    UNION ALL
    SELECT  dateadd(mm, 1, num)
    FROM    cte
    WHERE dateadd(mm, 1, num) <= @StartDate
)
SELECT  
        --datename(month, num) as MonthName
		 upper (substring (datename(MONTH, num),1,3)) as MonthName 
FROM    cte 
order by month(num) desc

;WITH CTE_DM AS
(
SELECT CONVERT(DATE, @EndDate) AS Dates
UNION ALL
SELECT DATEADD(mm, 1, Dates)
FROM CTE_DM
WHERE dateadd(mm, 1, Dates) <= @StartDate 
--WHERE CONVERT(DATE, Dates) <= CONVERT(DATE, @StartDate)
)

insert into #temp_DM  
--SELECT substring(DATENAME(YEAR, Dates),3,4) + '-' + upper (substring (datename(MONTH, Dates),1,3))  FROM CTE_DM
SELECT upper (substring (datename(MONTH, Dates),1,3)) + '-' + substring(DATENAME(YEAR, Dates),3,4)    FROM CTE_DM
OPTION (maxrecursion 0)


	if(@IdentFlag ='CMLCHU')
	BEGIN
		
		select  upper(Months) as Month,count(*) as NOOFAccCount, CAST(Sum(CAST(Utilization As decimal(18,2)))/100 As decimal(18,2)) as Utilization ,Segment,0 as Total
		from
		(
			Select ISNULL(substring(lcd.Month_Churn,1,3), '') Months, po.[Uti In L] as  Utilization , lcd.Segment 
			from tbl_OVI_LCHUDashboard lcd
			left join  tblPortfolio po on po.LSID=lcd.[LS ID] and (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			)
			where (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			) and	
			 lcd.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 --FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			 --lcd.Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		lcd.Month_Churn in (select * from #temp_DM )
		) t  Group By Months,Segment order by Months asc 

if(@IdentFlag ='CMLCHU' and isnull(@SelectedLocation,'') <> '' and isnull(@SelectedSegment,'') <> '' )
begin
	--Action Items
		Select lcd.[LS ID] as LSID,lcd.[Customer Name] as CustomerName,	lcd.Segment,lcd.City,lcd.PMG,lcd.No_of_times_in_LCHU,
		CAST(po.[Uti In L] as DECIMAL(18,2)) as SANEXP ,CAST(po.[Disbursed Limits In L] as DECIMAL(18,2)) as OSEXP,[RM Name] as RM,[TH Name] as TH
		
		from tbl_OVI_LCHUDashboard lcd
		left join  tblPortfolio po on po.LSID=lcd.[LS ID] and (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			)
		where --(po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code) 
		(po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			)
		
		and	
		lcd.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
		--	 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		 --lcd.Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		lcd.Month_Churn in (select * from #temp_DM ) 
		and lcd.Segment in (select Item from SplitString(@SelectedSegment, ','))	
		and lcd.State in (select Item from SplitString(@SelectedLocation, ','))
		and	lcd.[LS ID]  = case when @SelectedLSID is not null then @SelectedLSID else lcd.[LS ID] end 

	
end

else if(@IdentFlag ='CMLCHU' and isnull(@SelectedSegment,'') <> '')
begin
	--Action Items
		Select lcd.[LS ID] as LSID,lcd.[Customer Name] as CustomerName,	lcd.Segment,lcd.City,lcd.PMG,lcd.No_of_times_in_LCHU,
		CAST(po.[Uti In L] as DECIMAL(18,2)) as SANEXP ,CAST(po.[Disbursed Limits In L] as DECIMAL(18,2)) as OSEXP,[RM Name] as RM,[TH Name] as TH
		
		from tbl_OVI_LCHUDashboard lcd
		left join  tblPortfolio po on po.LSID=lcd.[LS ID] and (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			)
		where --(po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code) and	 
		(po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			) and 
		--lcd.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
		--	 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		 --lcd.Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		lcd.Month_Churn in (select * from #temp_DM ) 
		and lcd.Segment in (select Item from SplitString(@SelectedSegment, ','))		
		and	lcd.[LS ID]  = case when @SelectedLSID is not null then @SelectedLSID else lcd.[LS ID] end 

		
	
end

else if(@IdentFlag ='CMLCHU' and isnull(@SelectedLocation,'') <> '')
begin
	--Action Items
		Select lcd.[LS ID] as LSID,lcd.[Customer Name] as CustomerName,	lcd.Segment,lcd.City,lcd.PMG,lcd.No_of_times_in_LCHU,
		CAST(po.[Uti In L] as DECIMAL(18,2)) as SANEXP ,CAST(po.[Disbursed Limits In L] as DECIMAL(18,2)) as OSEXP,[RM Name] as RM,[TH Name] as TH
		
		from tbl_OVI_LCHUDashboard lcd
		left join  tblPortfolio po on po.LSID=lcd.[LS ID] and (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			)
		where (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			) and		 
		lcd.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
		--	 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		-- lcd.Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')						
		lcd.Month_Churn in (select * from #temp_DM ) 
		and lcd.State in (select Item from SplitString(@SelectedLocation, ',')) 
		and	lcd.[LS ID]  = case when @SelectedLSID is not null then @SelectedLSID else lcd.[LS ID] end 

		
	
end

else
begin
	--Action Items

	Select lcd.[LS ID] as LSID,lcd.[Customer Name] as CustomerName,	lcd.Segment,lcd.City,lcd.PMG,lcd.No_of_times_in_LCHU,
		CAST(po.[Uti In L] as DECIMAL(18,2)) as SANEXP ,CAST(po.[Disbursed Limits In L] as DECIMAL(18,2)) as OSEXP,[RM Name] as RM,[TH Name] as TH
		
		from tbl_OVI_LCHUDashboard lcd
		left join  tblPortfolio po on po.LSID=lcd.[LS ID] and (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			)
		where (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			) and	
		lcd.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
		--	 FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		 --lcd.Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')								
		lcd.Month_Churn in (select * from #temp_DM ) 
		and	lcd.[LS ID]  = case when @SelectedLSID is not null then @SelectedLSID else lcd.[LS ID] end 
		
end
		---Summary count

			Select COUNT (lcd.Segment) TotalLCHUAcc , CAST(Sum(CAST(po.[Uti In L] As decimal(18,2)))/100 As decimal(18,2)) as TotalLCHUAmount 
			
			from tbl_OVI_LCHUDashboard lcd
			left join  tblPortfolio po on po.LSID=lcd.[LS ID] and (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			)
			where (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			) and	
			 lcd.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 --FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			-- lcd.Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		lcd.Month_Churn in (select * from #temp_DM )


		-----------CM_Delinquency Month wise count

		select  upper(Months) as Months ,count(*) as NoOFAccount, CAST(Sum(CAST(UtilAmount As decimal(17,2)))/100 As decimal(17,2)) as UtilAmount
		from
		(
			Select ISNULL(substring(lcd.Month_Churn,1,3), '') Months, po.[Uti In L] as  UtilAmount
			from tbl_OVI_LCHUDashboard lcd
			left join  tblPortfolio po on po.LSID=lcd.[LS ID] and (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			)
			where (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			) and	
			 lcd.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 --FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			-- lcd.Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		lcd.Month_Churn in (select * from #temp_DM ) 
		) t  Group By Months order by Months asc 


		
		--CM_Delinquency Segment Color Code
		select cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		--select distinct cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		INNER JOIN tbl_OVI_LCHUDashboard lcd on cc.Segment=lcd.Segment		
		where --(lcd.[CM Code]=@CM_Emp_Code OR lcd.[ACM Code] = @CM_Emp_Code) and	
		(lcd.[CM Code]=@CM_Emp_Code OR lcd.[ACM Code] = @CM_Emp_Code OR 
			 lcd.[RM Code] = @CM_Emp_Code OR  lcd.[TH Code] = @CM_Emp_Code OR 
			lcd.[CH Code] = @CM_Emp_Code OR lcd.[UH Code] = @CM_Emp_Code OR lcd.[RH Code] = @CM_Emp_Code
			) and 

		--lcd.Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		lcd.Month_Churn in (select * from #temp_DM ) 
		--order by cc.Segment desc
		and cc.Type='Segment' group by  cc.Segment ,Div ,BackgroundColor,HoverBackgroundColor 
		order by case  cc.Segment
		when 'BBG' then 1
		when 'EEG' then 2
		when 'SAB' then 3
		when 'CTG' then 4
		when 'CAP MKT' then 5
		when 'ECG' then 6
		when 'LAP' then 7
		else 8 end 


		---Location drop down bind
		select Distinct  State as 'ID' , State as 'Value' from tbl_OVI_LCHUDashboard 
		where ([CM Code]=@CM_Emp_Code OR [ACM Code] = @CM_Emp_Code) and	
		--Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		 Month_Churn in (select * from #temp_DM )  
		---Segment drop down bind
		select Distinct Segment as 'ID' , Segment as 'Value' from tbl_OVI_LCHUDashboard 
		where --([CM Code]=@CM_Emp_Code OR [ACM Code] = @CM_Emp_Code) and	
		([CM Code]=@CM_Emp_Code OR [ACM Code] = @CM_Emp_Code OR 
			 [RM Code] = @CM_Emp_Code OR  [TH Code] = @CM_Emp_Code OR 
			[CH Code] = @CM_Emp_Code OR [UH Code] = @CM_Emp_Code OR [RH Code] = @CM_Emp_Code
			) and 
		--Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		Month_Churn in (select * from #temp_DM ) 
		order by Segment desc


		-----------LCHU Total Count
		select  count(*) as NOOFAccCount, CAST(Sum(CAST(LCHU_Amount As decimal(18,2)))/100 As decimal(18,2)) as LCHU_Amount,
		CAST(Sum(CAST(LCHU_Exposure As decimal(18,2)))/100 As decimal(18,2)) as LCHU_Exposure,Segment,   LCHU_name
		

		from
		(
			Select po.[Disbursed Limits In L] as  LCHU_Amount,po.[Exposure (Max of Limit & O/s)] as LCHU_Exposure , lcd.Segment,
			--CASE WHEN lcd.No_of_times_in_LCHU BETWEEN 0 AND 1 THEN 'First time LCHU' 
			CASE WHEN lcd.No_of_times_in_LCHU BETWEEN 4 AND 6 THEN '> 4 < 6  Months'
			WHEN lcd.No_of_times_in_LCHU BETWEEN 7 AND 9 THEN '> 6 < 9  Months'
			WHEN lcd.No_of_times_in_LCHU BETWEEN 10 AND 12 THEN '> 9 < 12  Months'
			WHEN lcd.No_of_times_in_LCHU > 12 then '> 12  Months'
			--ELSE ''
			END AS LCHU_name
			
			from tbl_OVI_LCHUDashboard lcd
			left join  tblPortfolio po on po.LSID=lcd.[LS ID] and (lcd.[CM Code]=@CM_Emp_Code OR lcd.[ACM Code] = @CM_Emp_Code OR 
			 lcd.[RM Code] = @CM_Emp_Code OR  lcd.[TH Code] = @CM_Emp_Code OR 
			lcd.[CH Code] = @CM_Emp_Code OR lcd.[UH Code] = @CM_Emp_Code OR lcd.[RH Code] = @CM_Emp_Code
			)
			where (lcd.[CM Code]=@CM_Emp_Code OR lcd.[ACM Code] = @CM_Emp_Code OR 
			 lcd.[RM Code] = @CM_Emp_Code OR  lcd.[TH Code] = @CM_Emp_Code OR 
			lcd.[CH Code] = @CM_Emp_Code OR lcd.[UH Code] = @CM_Emp_Code OR lcd.[RH Code] = @CM_Emp_Code
			) and	
			 lcd.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
			-- Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		  Month_Churn in (select * from #temp_DM ) 
		 and isnumeric( No_of_times_in_LCHU) > 0 

		) t where  LCHU_name is not null Group By Segment,LCHU_name 

		union 

		select  count(*) as NOOFAccCount, CAST(Sum(CAST(LCHU_Amount As decimal(18,2)))/100 As decimal(18,2)) as LCHU_Amount,
		CAST(Sum(CAST(LCHU_Exposure As decimal(18,2)))/100 As decimal(18,2)) as LCHU_Exposure,Segment,   LCHU_name
		

		from
		(
			Select po.[Disbursed Limits In L] as  LCHU_Amount,po.[Exposure (Max of Limit & O/s)] as LCHU_Exposure , lcd.Segment,
			CASE WHEN No_of_times_in_LCHU = 'First Time' THEN 'First time LCHU' 			
			--ELSE '' 
			END AS LCHU_name
			
			from tbl_OVI_LCHUDashboard lcd
			left join  tblPortfolio po on po.LSID=lcd.[LS ID] and (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			) 
			where (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			)  and	
			 lcd.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
			-- Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		 lcd.Month_Churn in (select * from #temp_DM ) 
		 and isnumeric( No_of_times_in_LCHU) <> 1 
		) t where  LCHU_name is not null  Group By Segment,LCHU_name 


		------ LCHU period------


		;WITH cte1 AS
(
    SELECT  'First time LCHU' as LCHU_NM
    UNION ALL
    SELECT  '> 4 < 6  Months' as LCHU_NM
	  UNION ALL
    SELECT  '> 6 < 9  Months' as LCHU_NM
	  UNION ALL
	   SELECT  '> 9 < 12  Months' as LCHU_NM
	  UNION ALL
    SELECT  '> 12  Months' as LCHU_NM    
)
SELECT * from  cte1


--------DPD Total ----
select  count(*) as NOOFAccCount, CAST(Sum(CAST(LCHU_Amount As decimal(18,2)))/100 As decimal(18,2)) as LCHU_Amount,
		CAST(Sum(CAST(LCHU_Exposure As decimal(18,2)))/100 As decimal(18,2)) as LCHU_Exposure,Segment
		from
		(
			Select po.[Disbursed Limits In L] as  LCHU_Amount,po.[Exposure (Max of Limit & O/s)] as LCHU_Exposure , lcd.Segment 
			from tbl_OVI_LCHUDashboard lcd
			left join  tblPortfolio po on po.LSID=lcd.[LS ID] and (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			) 
			where (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			)  and	
			 lcd.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			-- Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		lcd.Month_Churn in (select * from #temp_DM ) 
		) t  Group By Segment 
       

	--- Segment Wise Count

		select  count(*) as NOOFAccCount, CAST(Sum(CAST(Utilization As decimal(18,2)))/100 As decimal(18,2)) as Utilization ,Segment,0 as Total
		from
		(
			Select po.[Uti In L] as  Utilization , lcd.Segment 
			from tbl_OVI_LCHUDashboard lcd
			left join  tblPortfolio po on po.LSID=lcd.[LS ID] and (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			)
			where (po.[CM Code]=@CM_Emp_Code OR po.[ACM Code] = @CM_Emp_Code OR 
			po.[DR-ACM/RCM/UH Code] = @CM_Emp_Code OR po.[RM Code] = @CM_Emp_Code OR  po.[TH Code] = @CM_Emp_Code OR 
			po.[CH Code] = @CM_Emp_Code OR po.[ZH Code] = @CM_Emp_Code OR po.[RH Code] = @CM_Emp_Code
			) and	
			 lcd.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 --FORMAT(Date_of_tod, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			 --lcd.Month_Churn between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yy-MMM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yy-MMM')			
		lcd.Month_Churn in (select * from #temp_DM )
		) t  Group By Segment 
	
 
		
	END

	
END
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_CMViewDashboardData]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_CMViewDashboardData]  
	@IdentFlag varchar(50) = null,
	@CM_Code varchar(20) = null,
	@DelqFlag varchar(10) = null,
	@SelectedDate Datetime =null
AS
BEGIN

DECLARE @EndDate DATE
DECLARE @StartDate DATE

--DECLARE @EndDate1 DATE
--DECLARE @StartDate1 DATE

--SET @EndDate = dateadd(month, datediff(month,0, @SelectedDate)-6,0);
--SET @StartDate = DATEADD(month, - 6, @EndDate)

--SET @EndDate = dateadd(month, datediff(month,0, CONVERT(varchar, @SelectedDate, 23))-6,0);
--SET @StartDate = DATEADD(month, - 1, cast(CONVERT(varchar, @SelectedDate, 23) as date))

SET @EndDate = dateadd(month, datediff(month,0, CONVERT(varchar, CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23), 23))-6,0);
SET @StartDate = DATEADD(month, - 1, cast(CONVERT(varchar, CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23), 23) as date))

--SET @EndDate1 = @SelectedDate
--SET @StartDate1 = DATEADD(month, - 6, @EndDate1)

--;WITH cte AS
--(
--    SELECT  @StartDate1 AS num
--    UNION ALL
--    SELECT  dateadd(mm, 1, num)
--    FROM    cte
--    WHERE dateadd(mm, 1, num) < @EndDate1
--)

;WITH cte AS
(
    SELECT  @EndDate AS num
    UNION ALL
    SELECT  dateadd(mm, 1, num)
    FROM    cte
    WHERE dateadd(mm, 1, num) <= @StartDate
)

SELECT  
        datename(month, num) as MonthName
FROM    cte 
order by month(num) desc

	if(@IdentFlag ='Portfolio')
	BEGIN
		select  Segment,sCount No,CAST(Appr/100As decimal(17,2)) ApprLmt,CAST(Disbursed/100 As decimal(17,2)) Disbursed 
		from
		(
			Select Segment,Count(Segment) sCount, Sum(CAST([Disbursed Limits In L] As decimal(17,2))) Appr,Sum(CAST([Uti In L] As decimal(17,2))) Disbursed 
			from tblPortfolio 
			--where [CM Code]='M1934' and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate
			where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code)
			and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			--and FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate 
			and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			--and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate
			Group By Segment
		) PortFolio

		select Distinct cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		INNER JOIN tblPortfolio po on cc.Segment=po.Segment
		where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code)
		and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
		--and FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate 
			--and Type='Segment' and po.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			

	END
	else if(@IdentFlag ='LCUHData')
	BEGIN

		select  Segment,sCount No,CAST(Appr/100As decimal(17,2)) ApprLmt,CAST(Disbursed/100 As decimal(17,2)) Disbursed 
		from
		(
			Select po.Segment,Count(po.Segment) sCount, Sum(CAST([Disbursed Limits In L] As decimal(17,2))) Appr,Sum(CAST([Uti In L] As decimal(17,2))) Disbursed 
			from tblPortfolio po
			Right join  tbl_OVI_LCHUDashboard lcd on po.LSID=lcd.[LS ID] --and po.[CM Code]=lcd.[CM Code]
			where --po.[CM Code]=@CM_Code 
			(po.[CM Code]=@CM_Code OR po.[ACM Code]=@CM_Code OR po.[DR-ACM/RCM/UH Code] = @CM_Code OR po.[RM Code] = @CM_Code OR  po.[TH Code] = @CM_Code OR 
			po.[CH Code] = @CM_Code OR po.[ZH Code] = @CM_Code OR po.[RH Code] = @CM_Code)
			and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			and po.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			Group By po.Segment
		) LCHU

		select Distinct cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		INNER JOIN tblPortfolio po on cc.Segment=po.Segment
		where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code)
		and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')

	END

	else if(@IdentFlag ='HousekeepingData')
	BEGIN

	select  Segment,sCount,FileName1,Div,BackgroundColor,HoverBackgroundColor
		from
		(
			Select hk.Segment,Count(hk.Segment) sCount,hk.[File_Name] as FileName1
			,Div,BackgroundColor,HoverBackgroundColor
			from tblHouskeeping hk
			INNER JOIN tbl_OVI_ColorCode cc on cc.Segment=hk.Segment
			where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code) 
			and FORMAT(cast(DUE_DATE as date), 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			
			Group By hk.Segment,hk.[File_Name],Div,BackgroundColor,HoverBackgroundColor
		) HouseKeeping

		select Distinct cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		INNER JOIN tblHouskeeping po on cc.Segment=po.Segment
		where --[CM Code]=@CM_Code
		 ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code) 
		and FORMAT(cast(DUE_DATE as date), 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		and Type='Segment' and po.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')

	--select  Segment,sCount,FileName1
	--	from
	--	(
	--		Select Segment,Count(Segment) sCount,[File_Name] as FileName1
	--		from tblHouskeeping 
	--		--where [RM Code]=@CM_Code and dateadd(month, datediff(month,0, DUE_DATE)-6,0)>=@startdate and dateadd(month, datediff(month,0, DUE_DATE)-6,0)<@EndDate
	--		where [CM Code]=@CM_Code 
	--		--and dateadd(month, 0,  cast(DUE_DATE as date)) between @EndDate and @StartDate 
	--		and FORMAT(cast(DUE_DATE as date), 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
	--		--and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
	--		--and dateadd(month, datediff(month,0, DUE_DATE)-6,0)>=@startdate and dateadd(month, datediff(month,0, DUE_DATE)-6,0)<@EndDate
	--		Group By Segment,[File_Name]
	--	) HouseKeeping

	--	select Distinct cc.Segment,Div,BackgroundColor,HoverBackgroundColor,po.[File_Name] as fName from tbl_OVI_ColorCode cc
	--	INNER JOIN tblHouskeeping po on cc.Segment=po.Segment
	--	where [CM Code]=@CM_Code 
	--	--and dateadd(month, 0,  cast(DUE_DATE as date)) between @EndDate and @StartDate 
	--	and FORMAT(cast(DUE_DATE as date), 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
	--	and Type='Segment' and po.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')

	END
	else if(@IdentFlag ='GetPortfolioHubData')
	BEGIN
	select  City,AgriType,sCount
		from
		(
			Select City,[Agri/Non Agri] as AgriType,Count([Agri/Non Agri]) sCount
			from tblPortfolio 
			--where [RM Code]='M1934' and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate
			where --[CM Code]=@CM_Code 
			([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code) 
			and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			and [Agri/Non Agri] IN ('Agri', 'Non Agri')
			--and FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate 
			--and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			--and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate
			Group By City,[Agri/Non Agri]
		) p
	END

		else if(@IdentFlag ='GetLCHUHubData')
	BEGIN
	select  City,AgriType,sCount
		from
		(
			Select lcd.City,[Agri/Non Agri] as AgriType,Count([Agri/Non Agri]) sCount
			from tblPortfolio po
			Right join  tbl_OVI_LCHUDashboard lcd on po.LSID=lcd.[LS ID] --and po.[CM Code]=lcd.[CM Code]
			--where [RM Code]='M1934' and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate
			where --po.[CM Code]=@CM_Code 
			(po.[CM Code]=@CM_Code OR po.[ACM Code]=@CM_Code OR po.[DR-ACM/RCM/UH Code] = @CM_Code OR po.[RM Code] = @CM_Code OR  po.[TH Code] = @CM_Code OR 
			po.[CH Code] = @CM_Code OR po.[ZH Code] = @CM_Code OR po.[RH Code] = @CM_Code)
			and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			and po.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			and [Agri/Non Agri] IN ('Agri', 'Non Agri')
			--and FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate 
			--and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			--and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate
			Group By lcd.City,[Agri/Non Agri]
		) p

	END

	else if(@IdentFlag ='DelinquencyData')
	BEGIN
	

if(@DelqFlag='7P')
BEGIN

		select  Segment,sCount No,CAST(Appr/100As decimal(17,2)) ApprLmt,CAST(Disbursed/100 As decimal(17,2)) Disbursed 
		from
		(
			Select Segment,Count(Segment) sCount, Sum(CAST(Lim_in_L As decimal(17,2))) Appr,Sum(CAST(Os_in_L As decimal(17,2))) Disbursed 
			--from [repotdb].[dbo].[Tra_DDLHistory]
			FROM TBL_OVI_CM_Delinquency 
			where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
			and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			and DPD BETWEEN 7 AND 14 and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			Group By Segment
		) AUR

		select Distinct po.Segment,Div,BackgroundColor,HoverBackgroundColor 
		--from [repotdb].[dbo].[Tra_DDLHistory] po 
		FROM TBL_OVI_CM_Delinquency po
		LEFT JOIN tbl_OVI_ColorCode cc on cc.Segment=po.Segment
		where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
		and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
		and DPD BETWEEN 7 AND 14 and cc.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')

END

else if(@DelqFlag='15P')
BEGIN


		select  Segment,sCount No,CAST(Appr/100As decimal(17,2)) ApprLmt,CAST(Disbursed/100 As decimal(17,2)) Disbursed 
		from
		(
			Select Segment,Count(Segment) sCount, Sum(CAST(Lim_in_L As decimal(17,2))) Appr,Sum(CAST(Os_in_L As decimal(17,2))) Disbursed 
			--from [repotdb].[dbo].[Tra_DDLHistory]
			FROM TBL_OVI_CM_Delinquency 
			where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
			and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			and DPD BETWEEN 15 AND 29 and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			Group By Segment
		) AUR

		select Distinct po.Segment,Div,BackgroundColor,HoverBackgroundColor 
		--from [repotdb].[dbo].[Tra_DDLHistory]
			FROM TBL_OVI_CM_Delinquency po 
		LEFT JOIN tbl_OVI_ColorCode cc on cc.Segment=po.Segment
		where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
		and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
		and DPD BETWEEN 15 AND 29 and cc.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')

END

else if(@DelqFlag='30P')
BEGIN

		select  Segment,sCount No,CAST(Appr/100As decimal(17,2)) ApprLmt,CAST(Disbursed/100 As decimal(17,2)) Disbursed 
		from
		(
			Select Segment,Count(Segment) sCount, Sum(CAST(Lim_in_L As decimal(17,2))) Appr,Sum(CAST(Os_in_L As decimal(17,2))) Disbursed 
			--from [repotdb].[dbo].[Tra_DDLHistory]
			FROM TBL_OVI_CM_Delinquency 
			where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
			and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			and DPD BETWEEN 30 AND 59 and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			Group By Segment
		) AUR

		select Distinct po.Segment,Div,BackgroundColor,HoverBackgroundColor 
		--from [repotdb].[dbo].[Tra_DDLHistory]
			FROM TBL_OVI_CM_Delinquency po
		LEFT JOIN tbl_OVI_ColorCode cc on cc.Segment=po.Segment
		where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
		and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
		and DPD BETWEEN 30 AND 59 and cc.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')

END

else if(@DelqFlag='60P')
BEGIN

		select  Segment,sCount No,CAST(Appr/100As decimal(17,2)) ApprLmt,CAST(Disbursed/100 As decimal(17,2)) Disbursed 
		from
		(
			Select Segment,Count(Segment) sCount, Sum(CAST(Lim_in_L As decimal(17,2))) Appr,Sum(CAST(Os_in_L As decimal(17,2))) Disbursed 
			--from [repotdb].[dbo].[Tra_DDLHistory]
			FROM TBL_OVI_CM_Delinquency 
			where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
			and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			and DPD > 60 and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			Group By Segment
		) AUR

		select Distinct po.Segment,Div,BackgroundColor,HoverBackgroundColor 
		--from [repotdb].[dbo].[Tra_DDLHistory]
			FROM TBL_OVI_CM_Delinquency po
		LEFT JOIN tbl_OVI_ColorCode cc on cc.Segment=po.Segment
		where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
		and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
		and DPD > 60 and cc.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')

END
	END

else if(@IdentFlag='AURData')
BEGIN



		select  Segment,sCount No,CAST(Appr/100As decimal(17,2)) ApprLmt,CAST(Disbursed/100 As decimal(17,2)) Disbursed 
		from
		(
			Select aur.Segiment as Segment,Count(aur.Segiment) sCount, Sum(CAST(Limit As decimal(17,2))) Appr,Sum(CAST(Outstanding As decimal(17,2))) Disbursed 
			from tbl_OVI_AUR_Upload aur
			LEFT JOIN CM_upload cm on aur.LasterSoft_id = cm.LS_ID
			where --cm.CM_ID=@CM_Code
			(CM_ID = @CM_Code OR ACM_ID = @CM_Code OR RCH_ID = @CM_Code )
			and FORMAT(aur.Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			and aur.Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			Group By aur.Segiment
		) AUR

		select Distinct cc.Segment,Div,BackgroundColor,HoverBackgroundColor 
		from tbl_OVI_ColorCode cc
		INNER JOIN tbl_OVI_AUR_Upload po on cc.Segment=po.Segiment
		LEFT JOIN CM_upload cm on po.LasterSoft_id = cm.LS_ID
		where --cm.CM_ID=@CM_Code
		(CM_ID = @CM_Code OR ACM_ID = @CM_Code OR RCH_ID = @CM_Code )
		and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')

		

END

else if(@IdentFlag ='GetAURHubData')
	BEGIN
	select  City,AgriType,sCount
		from
		(
			Select City,[Agri/Non Agri] as AgriType,Count([Agri/Non Agri]) sCount
			from tbl_OVI_AUR_Upload aur
			LEFT JOIN CM_upload cm on aur.LasterSoft_id = cm.LS_ID
			where --cm.CM_ID=@CM_Code 
			(CM_ID = @CM_Code OR ACM_ID = @CM_Code OR RCH_ID = @CM_Code )
			and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			and aur.Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			and [Agri/Non Agri] IN ('Agri', 'Non Agri')
			--and FORMAT(cast(Date as date), 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate
			--and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate
			Group By City,[Agri/Non Agri]
		) p
	END

	else if(@IdentFlag ='GetDelinquencyHubData')
	BEGIN
	
if(@DelqFlag='7P')
BEGIN



select  City,AgriType,sCount
		from
		(
			Select td.City,pf.[Agri/Non Agri] as AgriType,Count(pf.[Agri/Non Agri]) sCount
			from tblPortfolio pf
			--INNER JOIN [repotdb].[dbo].[Tra_DDLHistory] td on pf.LSID=td.SME_Client_id
			INNER JOIN  TBL_OVI_CM_Delinquency td on pf.LSID=td.SME_Client_id 
			where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
			--where [CM Code]=@CM_Code
			and DPD BETWEEN 7 AND 14 and td.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			and pf.[Agri/Non Agri] IN ('Agri', 'Non Agri')
			--where [RM Code]='M1934' and DPD BETWEEN 7 AND 14 and td.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			--and (dateadd(month, datediff(month,0, Date_of_tod)-6,0)>=@sDate2 and dateadd(month, datediff(month,0, Date_of_tod)-6,0)<@eDate2)
			--and dateadd(month, 0,  cast(Date_of_tod as date)) between @EndDate and @StartDate
			--and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and FORMAT(Date_of_tod, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			Group By td.City,pf.[Agri/Non Agri]
		) p
END

else if(@DelqFlag='15P')
BEGIN


select  City,AgriType,sCount
		from
		(
			Select td.City,pf.[Agri/Non Agri] as AgriType,Count(pf.[Agri/Non Agri]) sCount
			from tblPortfolio pf
			--INNER JOIN [repotdb].[dbo].[Tra_DDLHistory] td on pf.LSID=td.SME_Client_id
			INNER JOIN  TBL_OVI_CM_Delinquency td on pf.LSID=td.SME_Client_id 
			where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
			--where [CM Code]=@CM_Code 
			and DPD BETWEEN 15 AND 29 and td.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			and pf.[Agri/Non Agri] IN ('Agri', 'Non Agri')
			--where [RM Code]='M1934' and DPD BETWEEN 15 AND 29 and td.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			--and (dateadd(month, datediff(month,0, Date_of_tod)-6,0)>=@sDate2 and dateadd(month, datediff(month,0, Date_of_tod)-6,0)<@eDate2)
			--and dateadd(month, 0,  cast(Date_of_tod as date)) between @EndDate and @StartDate
			--and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and FORMAT(Date_of_tod, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			Group By td.City,pf.[Agri/Non Agri]
		) p

END

else if(@DelqFlag='30P')
BEGIN



select  City,AgriType,sCount
		from
		(
			Select td.City,pf.[Agri/Non Agri] as AgriType,Count(pf.[Agri/Non Agri]) sCount
			from tblPortfolio pf
		--	INNER JOIN [repotdb].[dbo].[Tra_DDLHistory] td on pf.LSID=td.SME_Client_id
			INNER JOIN  TBL_OVI_CM_Delinquency td on pf.LSID=td.SME_Client_id 
			where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
			--where [CM Code]=@CM_Code 
			and DPD BETWEEN 30 AND 59 and td.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			and pf.[Agri/Non Agri] IN ('Agri', 'Non Agri')
			--where [RM Code]='M1934' and DPD BETWEEN 30 AND 59 and td.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			--and dateadd(month, 0,  cast(Date_of_tod as date)) between @EndDate and @StartDate
			--and (dateadd(month, datediff(month,0, Date_of_tod)-6,0)>=@sDate2 and dateadd(month, datediff(month,0, Date_of_tod)-6,0)<@eDate2)
			--and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and FORMAT(Date_of_tod, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			Group By td.City,pf.[Agri/Non Agri]
		) p
END

else if(@DelqFlag='60P')
BEGIN



select  City,AgriType,sCount
		from
		(
			Select td.City,pf.[Agri/Non Agri] as AgriType,Count(pf.[Agri/Non Agri]) sCount
			from tblPortfolio pf
			--INNER JOIN [repotdb].[dbo].[Tra_DDLHistory] td on pf.LSID=td.SME_Client_id
			INNER JOIN  TBL_OVI_CM_Delinquency td on pf.LSID=td.SME_Client_id 
			where (CM_EMP_Code = @CM_Code OR RM_Emp_Code = @CM_Code OR TH_Emp_Code = @CM_Code OR ACM_EMP_Code = @CM_Code) 
			--where [CM Code]=@CM_Code 
			and convert(int, DPD )> 60 and td.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			and pf.[Agri/Non Agri] IN ('Agri', 'Non Agri')
			--where [RM Code]='M1934' and DPD >60 and td.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			--and (dateadd(month, datediff(month,0, Date_of_tod)-6,0)>=@sDate2 and dateadd(month, datediff(month,0, Date_of_tod)-6,0)<@eDate2)
			--and dateadd(month, 0,  cast(Date_of_tod as date)) between @EndDate and @StartDate
			--and FORMAT(cast(Date_of_tod as date), 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and FORMAT(Date_of_tod, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			Group By td.City,pf.[Agri/Non Agri]
		) p
END
	
	END


END
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_CMWatchList]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_CMWatchList]
	--declare 
	@IdentFlag varchar(50) = null,
	@CM_Emp_Code varchar(20) = null,
	@DelqFlag varchar(10) = null,
	@SelectedDate Datetime = null,
	@SelectedSegment varchar (max)=null,
	@SelectedLocation varchar (max)=null,
	@SelectedLSID varchar (max)=null
AS
BEGIN


DECLARE @EndDate DATE
DECLARE @StartDate DATE
DECLARE @EndDate1 DATE
DECLARE @StartDate1 DATE
--DECLARE @EndDate1 DATE
--DECLARE @StartDate1 DATE

--SET @EndDate = dateadd(month, datediff(month,0, @SelectedDate)-6,0);
--SET @StartDate = DATEADD(month, - 6, @EndDate)

SET @EndDate = dateadd(month, datediff(month,0, CONVERT(varchar, @SelectedDate, 23))-5,0);
SET @StartDate = DATEADD(month, - 1, cast(CONVERT(varchar, @SelectedDate, 23) as date))


if (@SelectedLSID = '')
begin
set @SelectedLSID = null
end


;WITH cte AS
(
    SELECT  @EndDate AS num
    UNION ALL
    SELECT  dateadd(mm, 1, num)
    FROM    cte
    WHERE dateadd(mm, 1, num) <= @StartDate
)
SELECT  
        datename(month, num) as MonthName
FROM    cte 
order by month(num) desc

	if(@IdentFlag ='CMWatchList')
	BEGIN
		
		select  Month,count(*) as NOOFAccCount, CAST(Sum(CAST(Utilization As decimal(18,2)))/100 As decimal(18,2)) as Utilization,Segment,0 as Total
		from
		(
			Select FORMAT(Date,'MMMM') Month , [O/s in lacs] as Utilization, Segment
			from TBL_OVI_CM_WatchList 
			
			where 
			(CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code OR  RH_Emp_Code = @CM_Emp_Code OR  ZH_Emp_Code = @CM_Emp_Code  ) 
			and FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
		
		) t  Group By Month,Segment order by Month asc 

if(@IdentFlag ='CMWatchList' and isnull(@SelectedLocation,'') <> '' and isnull(@SelectedSegment,'') <> '' )
begin
	--Action Items
		Select  LSID,[Customer Name] as CustomerName, Segment,City,convert(decimal(18,2),CAST([Limit in lacs] as DECIMAL(18,2))/100) as SANEXP ,convert(decimal(18,2),CAST([O/s in lacs] as DECIMAL(18,2))/100) as OSEXP,
		 PMG , TH_Name as TH, RM_Name as RM
		
		from TBL_OVI_CM_WatchList 
		
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code OR  RH_Emp_Code = @CM_Emp_Code OR  ZH_Emp_Code = @CM_Emp_Code  ) 
		--aur.Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
		AND	 FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		and Segment in (select Item from SplitString(@SelectedSegment, ','))	
		and State in (select Item from SplitString(@SelectedLocation, ','))
		and	LSID = case when @SelectedLSID is not null then @SelectedLSID else LSID end 

		
end
else if(@IdentFlag ='CMWatchList' and isnull(@SelectedSegment,'') <> '')
begin
--Action Items
		Select  LSID,[Customer Name] as CustomerName, Segment,City,convert(decimal(18,2),CAST([Limit in lacs] as DECIMAL(18,2))/100) as SANEXP ,convert(decimal(18,2),CAST([O/s in lacs] as DECIMAL(18,2))/100) as OSEXP,
		 PMG , TH_Name as TH, RM_Name as RM
		
		from TBL_OVI_CM_WatchList 
			
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code OR  RH_Emp_Code = @CM_Emp_Code OR  ZH_Emp_Code = @CM_Emp_Code  ) 
		--aur.Segiment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
			and FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		and Segment in (select Item from SplitString(@SelectedSegment, ',')) 
			and	LSID = case when @SelectedLSID is not null then @SelectedLSID else LSID end 

		
	   
end
else if(@IdentFlag ='CMWatchList' and  isnull(@SelectedLocation,'') <> '')
begin
--Action Items
		Select  LSID,[Customer Name] as CustomerName, Segment,City,convert(decimal(18,2),CAST([Limit in lacs] as DECIMAL(18,2))/100) as SANEXP ,convert(decimal(18,2),CAST([O/s in lacs] as DECIMAL(18,2))/100) as OSEXP,
		 PMG , TH_Name as TH, RM_Name as RM
		
		from TBL_OVI_CM_WatchList 
			
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code OR  RH_Emp_Code = @CM_Emp_Code OR  ZH_Emp_Code = @CM_Emp_Code  ) 
		and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and State in (select Item from SplitString(@SelectedLocation, ','))
			and	LSID = case when @SelectedLSID is not null then @SelectedLSID else LSID end 


end
else
begin
	--Action Items
		Select  LSID,[Customer Name] as CustomerName, Segment,City,convert(decimal(18,2),CAST([Limit in lacs] as DECIMAL(18,2))/100) as SANEXP ,convert(decimal(18,2),CAST([O/s in lacs] as DECIMAL(18,2))/100) as OSEXP,
		 PMG , TH_Name as TH, RM_Name as RM
		
		from TBL_OVI_CM_WatchList 
		
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code OR  RH_Emp_Code = @CM_Emp_Code OR  ZH_Emp_Code = @CM_Emp_Code  ) 
		and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and
			 FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			--and ( SME_Client_ID =  @SelectedLSID OR @SelectedLSID = @SelectedLSID)
		and		LSID = case when @SelectedLSID is not null then @SelectedLSID else LSID end 
end
		---Summary count

		select COUNT (Segment) TotalWatchListAcc ,CAST(Sum(CAST([O/s in lacs] As decimal(18,2)))/100 As decimal(18,2)) as TotalWatchListAmount 


		from TBL_OVI_CM_WatchList 
			
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code OR  RH_Emp_Code = @CM_Emp_Code OR  ZH_Emp_Code = @CM_Emp_Code  ) 
		and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
		FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') 
		and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')


		-----------CM_Delinquency Month wise count
		select  Months,count(*) as NoOFAccount, CAST(Sum(CAST(UtilAmount As decimal(17,2)))/100 As decimal(18,2)) as UtilAmount
		from
		(

			Select FORMAT(Date,'MMMM') Months, [O/s in lacs] as  UtilAmount 
			from TBL_OVI_CM_WatchList 
			
			where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code OR  RH_Emp_Code = @CM_Emp_Code OR  ZH_Emp_Code = @CM_Emp_Code  ) 
			and	Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
			 FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			
		) t  Group By Months order by Months asc 



		--CM_Delinquency Segment Color Code
		select cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		--select distinct cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		INNER JOIN TBL_OVI_CM_WatchList aur on cc.Segment=aur.Segment
		
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code OR  RH_Emp_Code = @CM_Emp_Code OR  ZH_Emp_Code = @CM_Emp_Code  ) 
		and cc.Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
		FORMAT(aur.Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM') 
		--order by cc.Segment desc
		and cc.Type='Segment' group by  cc.Segment ,Div ,BackgroundColor,HoverBackgroundColor 
		order by case  cc.Segment
		when 'BBG' then 1
		when 'EEG' then 2
		when 'SAB' then 3
		when 'CTG' then 4
		when 'CAP MKT' then 5
		when 'ECG' then 6
		when 'LAP' then 7
		else 8 end 


		---Location drop down bind
		select Distinct  State as 'ID' , State as 'Value' from  
		 TBL_OVI_CM_WatchList 
			
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code OR  RH_Emp_Code = @CM_Emp_Code OR  ZH_Emp_Code = @CM_Emp_Code  ) 
		and FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		
		---Segment drop down bind
		select Distinct Segment as 'ID' , Segment as 'Value' from  
		 TBL_OVI_CM_WatchList 
			
		where (CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code OR  RH_Emp_Code = @CM_Emp_Code OR  ZH_Emp_Code = @CM_Emp_Code  ) 
		and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT') and 
		FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
		order by Segment desc


	

	--- Segment Wise Count
	select count(*) as NOOFAccCount, CAST(Sum(CAST(Utilization As decimal(18,2)))/100 As decimal(18,2)) as Utilization,Segment,0 as Total
		from
		(
			Select [O/s in lacs] as Utilization, Segment
			from TBL_OVI_CM_WatchList 
			
			where 
			(CM_EMP_Code=@CM_Emp_Code OR ACM_EMP_Code = @CM_Emp_Code  OR RM_Emp_Code = @CM_Emp_Code OR  TH_Emp_Code = @CM_Emp_Code OR  RH_Emp_Code = @CM_Emp_Code OR  ZH_Emp_Code = @CM_Emp_Code  )   
			and FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
		
		) t  Group By Segment 

	 
		
	END

	
END
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_Dashboard_Download]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Dashboard_Download] 
@UserId varchar(50) = NULL,  
@Flag varchar(50) = null    
AS    
BEGIN    
     DECLARE @table2 AS TABLE (                    
     EmpId varchar(20),                    
     EmpRole varchar(20)                    
  )                    
     INSERT INTO @table2 EXEC SP_OVI_GetRMListById @UserId;  
  if (@Flag = 'Portfolio')  
  Begin  
  select A.LSID,  
   A.Customer_name,  
   A.PAN,  
   A.Segment,  
   A.LS_Segment,  
   A.Group_Id,  
   A.CommonID_Status,  
   A.CommonID,    
            A.Fund_Limit,    
            A.Non_Fund_Limit,    
            A.Fund_Os,    
            A.Non_Fund_Os,  
   A.CAM_Amount,  
   A.Flexcube_CustID,  
   A.RM_name,  
   A.RM_code,  
   A.CH_name,  
   A.CH_code,  
   A.Circle_head_name,  
   A.Circle_head_code,  
   A.State_head_name,  
   A.State_head_code,  
   A.RH_name,  
   A.RH_code,  
   A.ZH_name,  
   A.ZH_code,  
   A.APR    from  TBL_OVI_Client_RM_Mapping B inner join TBL_OVI_Portfolio A on A.LSID=B.LSID                        
     where B.RM_ID in(select EmpId from @table2)   
  End  
  else if (@Flag = 'Customer')  
  Begin  
  Select    A.Customer_Name,    
   A.Os_In_Cr,    
   A.Primary_Dedupe,    
   A.DPD,    
   A.DPD_Bucket,    
   A.SME_Client_ID,    
   A.Os_in_L,    
   A.Lim_in_L,    
   A.Cards,    
   A.TOD_Overdue,    
   A.Loans_from_HDFC_Ltd,    
   A.TL_EMI_Bounce,    
   A.Treasury,    
   A.PDO_Loans_Overdue,    
   A.Total_Overdue,    
   A.RM_code,    
   A.RM_name from TBL_OVI_Delinquency_Customer A where RM_Code in(select EmpId from @table2);  
  End  
  else if (@Flag = 'Account')  
  Begin  
  Select A.Account_code,  
   A.Customer_Name,  
   A.SME_Client_ID,  
   A.Os_in_L,  
   A.Lim_in_L,  
   A.Date_of_TOD,  
   A.Overdue,  
   A.Facility_Ctg,  
   A.DPD,  
   A.Nature_of_Delq,  
   A.Part_of_Portfolio,  
   A.Asset_classification_code,  
   A.RM_code,  
   A.RM_name from TBL_OVI_Delinquency_Account A where RM_Code in(select EmpId from @table2);  
  End 
End  
GO
