/****** Object:  StoredProcedure [dbo].[SP_OVI_Fetch_Master_Data]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Fetch_Master_Data]                                          
 @IdenFlag varchar(100),                                        
 @UserId varchar(30)=null,                
 @SearchText varchar(50)=null                
 AS                                            
 BEGIN                                            
    if(@IdenFlag='Facility_Details')                                            
    BEGIN                                            
       Select FacilityName as [value], Fb_Nfb as[key] from TBL_OVI_Facility_Master                                            
    END            
 if(@IdenFlag='Facility_Instruction_Details')                                            
    BEGIN                                            
       Select FacilityInstruction as [value], FacilityInstruction as[key] from TBL_OVI_Facility_Instruction_Master                                            
    END             
    if(@IdenFlag='Charges_Types')                                            
    BEGIN                                            
       Select ChargesName as [value], ChargesCode as[key] from TBL_OVI_ChargesType_Master                                            
    END          
 if(@IdenFlag='Security_Types')                                            
    BEGIN                                            
       Select SecurityType as [value], SecurityType as[key] from TBL_OVI_Security_Type_Master                                            
    END           
    if(@IdenFlag='Get_All_Recepients')                                            
    BEGIN                                            
    select EmpCode,EmpName from TBL_OVI_RM_Hierarchy_Mapping where  EmpRole like '%Cluster Head%'                             
    select EmpCode,EmpName from TBL_OVI_RM_Hierarchy_Mapping where  EmpRole like '%Circle Head%'                             
    select EmpCode,EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpRole like '%Regional Head%'                                          
    select EmpCode,EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpRole like '%Zonal Head%'                                         
    select EmpCode,EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpRole like '%Business Head%'                                        
    select EmpCode,EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpRole like '%Group Head%'                               
    select EmpCode,EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpRole like '%State Head%'    
    select EmpCode,EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpRole like '%National Head%'    
    select EmpCode,EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpRole Not in ('Cluster Head','BBG Product','Relationship Manager','Operation Module')  
    END                                      
    if(@IdenFlag='Reversal_charges')                                            
    BEGIN                                            
       Select ChargesName as [value], ChargesCode as[key] from TBL_OVI_ChargesType_Master                                             
    END                                     
    if(@IdenFlag='WaiverType')                                            
    BEGIN                                            
       Select WaiverType as [value], WaiverCode as[key] from TBL_OVI_WaiverType_Master                                            
    END                            
    if(@IdenFlag='Business_Type')                                            
    BEGIN                           
    select distinct(Business) as [value] from TBL_OVI_RM_Hierarchy_Mapping  where Business!=''                                                         
    END                   
    if(@IdenFlag='SearchClients')                                            
    BEGIN                           
    select top 20 CLIENTS_NAME+'-'+CLIENTS_NO as CLIENTS_NAME from client_details where CLIENTS_NAME like '%'+@SearchText+'%' or CLIENTS_NO like '%'+@SearchText+'%'                     
    END                   
                      
 END 
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_Get_AccountCustomisationCustomerDetails]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Get_AccountCustomisationCustomerDetails]   
@CustomerId int=null,      
@UserId varchar(50)=null      
AS      
BEGIN      
  select *,(select EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId) as EmpRole,
    (select Top 1 isnull(ApprovalRemark,'') ApprovalRemark FROM TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID = A.Account_Customisation_Customer_Details_ID order by ApprovedDate desc) as [Comments]  
  from TBL_OVI_Account_Customisation_Customer_Details A where Account_Customisation_Customer_Details_ID=@CustomerId    
  select * from  TBL_OVI_Account_Customisation_Approver where  Account_Customisation_Customer_Details_ID=@CustomerId    
  select * from TBL_OVI_Account_Customisation_Waiver_Details where Account_Customisation_Customer_Details_ID=@CustomerId    
END 
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_Get_AccountCustomisationGridData]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Get_AccountCustomisationGridData]                              
@UserId varchar(50)=null,                            
@ProposalNumber varchar(100)=null,    
@LS_ClientID varchar(50)=null                   
AS                                 
BEGIN                                
 Declare @UserType varchar(100)=null,@fetchFor varchar(100)=null;                                
 SELECT @UserType = EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId                                
                                
  IF(@UserType  IS NULL)                                                  
   BEGIN                                                  
      IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='RM')                                                  
      BEGIN                                                  
       SET @UserType ='Relationship Manager';                                                  
      END                                                  
      ELSE IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='CM')                                                  
      BEGIN                                                  
       SET @UserType ='Cluster Head';                                             
      END                                                  
   END                                   
  IF(@UserType like '%Relationship Manager%')                                                
  BEGIN         
          
  select A.Account_Customisation_Customer_Details_ID as ID,STUFF((SELECT  distinct ', ' + CustomerName from TBL_OVI_Account_Customisation_Waiver_Details         
  where Account_Customisation_Customer_Details_ID=A.Account_Customisation_Customer_Details_ID        
         FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')        
         , 1, LEN(','), '') as CustomerName,                           
  ProposalNumber as Request_Number,A.CreatedBy,                                                
  dbo.AccountCustomisationApprovers(A.Account_Customisation_Customer_Details_ID) as [Sent To],                  
  (select Top 1 isnull(ApprovalRemark,'') ApprovalRemark FROM TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID = A.Account_Customisation_Customer_Details_ID order by ApprovedDate desc) as [Comments],                  
  
  CASE                                   
  when Status=10 then 'Pending'                                     
  when Status=0 then 'In Progress'                                                
  when Status=1 then 'Approved'                      
  when Status=2 then 'Sent Back'                      
  when Status=3 then 'Rejected'                                                
  END as [Status],                                                
  FORMAT(A.CreatedOn,'dd/MM/yy') as [Date],A.Ls_ClientId as ClientId,ISNULL(STUFF((SELECT  distinct ', ' + AccountNumber from TBL_OVI_Account_Customisation_Waiver_Details         
  where Account_Customisation_Customer_Details_ID=A.Account_Customisation_Customer_Details_ID        
         FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')        
         , 1, LEN(','), ''),'') as AccountNumber,  
   ISNULL(STUFF((SELECT  distinct ', ' + ClientId from TBL_OVI_Account_Customisation_Waiver_Details         
  where Account_Customisation_Customer_Details_ID=A.Account_Customisation_Customer_Details_ID        
         FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')        
         , 1, LEN(','), ''),'') as ClientIds   
  from TBL_OVI_Account_Customisation_Customer_Details A  where A.CreatedBy=@UserId            
                  
                                
  END                       
  ELSE                                               
  BEGIN                       
                              
    select A.Account_Customisation_Customer_Details_ID as ID, STUFF((SELECT  distinct ', ' + CustomerName from TBL_OVI_Account_Customisation_Waiver_Details         
  where Account_Customisation_Customer_Details_ID=A.Account_Customisation_Customer_Details_ID        
         FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')        
         , 1, LEN(','), '') as CustomerName,             
 A.ProposalNumber as Request_Number,A.CreatedBy, dbo.AccountCustomisationApprovers(A.Account_Customisation_Customer_Details_ID) as [Sent To],              
  (select Top 1 isnull(ApprovalRemark,'') ApprovalRemark FROM TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID = A.Account_Customisation_Customer_Details_ID order by ApprovedDate desc) as [Comments],               
     CASE                       
  when A.Status=10 then 'Pending'                                                 
     when A.Status=0 then 'In Progress'                                                
     when A.Status=1 then 'Approved'                      
     when A.Status=2 then 'Sent Back'                      
     when A.Status=3 then 'Rejected'                                                 
     END as [Status],                                                
     FORMAT(A.CreatedOn,'dd/MM/yy') as [Date],
	 A.Ls_ClientId as ClientId,
	 ISNULL(STUFF((SELECT  distinct ', ' + AccountNumber from TBL_OVI_Account_Customisation_Waiver_Details         
  where Account_Customisation_Customer_Details_ID=A.Account_Customisation_Customer_Details_ID        
         FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')        
         , 1, LEN(','), ''),'') as AccountNumber,
		 ISNULL(STUFF((SELECT  distinct ', ' + ClientId from TBL_OVI_Account_Customisation_Waiver_Details         
  where Account_Customisation_Customer_Details_ID=A.Account_Customisation_Customer_Details_ID        
         FOR XML PATH(''), TYPE).value('text()[1]','nvarchar(max)')        
         , 1, LEN(','), ''),'') as ClientIds
     from TBL_OVI_Account_Customisation_Customer_Details A inner join TBL_OVI_Account_Customisation_Approver B on                                 
     A.Account_Customisation_Customer_Details_ID=B.Account_Customisation_Customer_Details_ID                                           
     where B.ApproverADID=@UserId and (B.Status=0 )                  
                                                  
  END                    
END
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_Get_Aquisition_Data]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
   
CREATE PROCEDURE [dbo].[SP_OVI_Get_Aquisition_Data] --'S12179',10,2023,'mtd'              
@UserID varchar(22)=NULL,              
@Month int=NULL,              
@Year int=NULL,              
@MTD_YTD varchar(55)=NULL              
AS              
BEGIN              
DECLARE @Table2 AS TABLE (EmpID varchar(20), EmpRole varchar(20))              
              
DECLARE @MonthYear AS varchar(20)=CONCAT(@Year, '-', @Month);              
              
INSERT INTO @Table2 EXEC SP_OVI_GetRMListById @UserID              
              
IF (@MTD_YTD = 'mtd')              
 BEGIN              
 --************************* Assets *************************              
  select  A.ASSETS,sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (           
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=ABND' + '"><u>' + 'ABND' + '</u></a>' [ASSETS],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_ABND WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO],              
  (SELECT CASE WHEN SUM(CAST(CAM_AmtInCr AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(CAM_AmtInCr AS decimal(10, 2))) AS varchar) END) [IN CR],         
  --CAST(SUM(CAST(CAM_AmtInCr AS decimal(10, 2))) AS varchar) [IN CR],             
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_ABND              
  WHERE RM_Code IN (SELECT EmpID FROM @Table2)              
  AND ReportDate BETWEEN CONVERT(varchar, CONCAT(@MonthYear, '-', '01'), 23) AND CONVERT(varchar, GETDATE(), 23)        
    GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)         
    )as  A            
  GROUP BY A.ASSETS, A.UploadedDate        
            
  UNION              
              
  select  A.ASSETS,sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (        
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=Disbursed Pledge' + '"><u>' + 'Disbursed Pledge' + '</u></a>' [ASSETS],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_DisbursedPledge WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO],              
  (SELECT CASE WHEN SUM(CAST(AmtInCr AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(AmtInCr AS decimal(10, 2))) AS varchar) END) [IN CR],              
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_DisbursedPledge              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND ReportDate BETWEEN CONVERT(varchar, CONCAT(@MonthYear, '-', '01'), 23) AND CONVERT(varchar, GETDATE(), 23)              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)  )as  A         
  GROUP BY A.ASSETS, A.UploadedDate        
                
          
  UNION              
  select  A.ASSETS,sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (            
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=Disbursed WC' + '"><u>' + 'Disbursed WC' + '</u></a>' [ASSETS],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_DisbursedWC WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO],              
  (SELECT CASE WHEN SUM(CAST(NetDisbInCr AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(NetDisbInCr AS decimal(10, 2))) AS varchar) END) [IN CR],              
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_DisbursedWC              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND ReportDate BETWEEN CONVERT(varchar, CONCAT(@MonthYear, '-', '01'), 23) AND CONVERT(varchar, GETDATE(), 23)              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105) )as  A         
  GROUP BY A.ASSETS, A.UploadedDate        
                  
  UNION     
  select  A.ASSETS,sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (          
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=Lead Pipeline' + '"><u>' + 'Lead Pipeline' + '</u></a>' [ASSETS],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_LeadPipelineWIP WHERE RM_Code IN (SELECT EmpID FROM @Table2) AND LeadPipelineWIP='Lead Pipeline') [NO],              
  (SELECT CASE WHEN SUM(CAST(EstimatedAmt AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(EstimatedAmt AS decimal(10, 2))) AS varchar) END) [IN CR],              
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_LeadPipelineWIP              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND ReportDate BETWEEN CONVERT(varchar, CONCAT(@MonthYear, '-', '01'), 23) AND CONVERT(varchar, GETDATE(), 23)              
  AND LeadPipelineWIP='Lead Pipeline'              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)  )as  A         
  GROUP BY A.ASSETS,A.UploadedDate        
            
  UNION              
       select  A.ASSETS,sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (        
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=WIP' + '"><u>' + 'WIP' + '</u></a>' [ASSETS],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_LeadPipelineWIP WHERE RM_Code IN (SELECT EmpID FROM @Table2) AND LeadPipelineWIP='WIP') [NO],              
  (SELECT CASE WHEN SUM(CAST(EstimatedAmt AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(EstimatedAmt AS decimal(10, 2))) AS varchar) END) [IN CR],              
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_LeadPipelineWIP              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)              
  AND ReportDate BETWEEN CONVERT(varchar, CONCAT(@MonthYear, '-', '01'), 23) AND CONVERT(varchar, GETDATE(), 23)              
  AND LeadPipelineWIP='WIP'              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)  )as  A         
  GROUP BY A.ASSETS,A.UploadedDate            
              
  --************************* Liabilities *************************              
  select  A.[LIABILITIES],sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from ( SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=CA' + '"><u>' + 'CA' + '</u></
a>' [LIABILITIES],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_CA_SA_FD WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO],              
  (SELECT CASE WHEN SUM(CAST(((BalBook)/10000000) AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(((BalBook)/10000000) AS decimal(10, 2))) AS varchar) END) [IN CR],            
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_CA_SA_FD              
  WHERE RM_Code IN (SELECT EmpID FROM @Table2)              
  AND ReportDate BETWEEN CONVERT(varchar, CONCAT(@MonthYear, '-', '01'), 23) AND CONVERT(varchar, GETDATE(), 23)              
  AND Type='CA'              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)      )as  A         
  GROUP BY A.[LIABILITIES],A.UploadedDate         
             
  UNION              
      select  A.[LIABILITIES],sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (        
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=SA' + '"><u>' + 'SA' + '</u></a>' [LIABILITIES],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_CA_SA_FD WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO],              
  (SELECT CASE WHEN SUM(CAST(((BalBook)/10000000) AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(((BalBook)/10000000) AS decimal(10, 2))) AS varchar) END) [IN CR],            
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_CA_SA_FD              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND ReportDate BETWEEN CONVERT(varchar, CONCAT(@MonthYear, '-', '01'), 23) AND CONVERT(varchar, GETDATE(), 23)              
  AND Type='SA'              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)    )as  A         
  GROUP BY A.[LIABILITIES],A.UploadedDate            
              
  UNION              
    select  A.[LIABILITIES],sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (          
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=FD' + '"><u>' + 'FD' + '</u></a>' [LIABILITIES],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_CA_SA_FD WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO],              
(SELECT CASE WHEN SUM(CAST(((BalBook)/10000000) AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(((BalBook)/10000000) AS decimal(10, 2))) AS varchar) END) [IN CR],            
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_CA_SA_FD              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND ReportDate BETWEEN CONVERT(varchar, CONCAT(@MonthYear, '-', '01'), 23) AND CONVERT(varchar, GETDATE(), 23)              
  AND Type='FD'              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)    )as  A         
  GROUP BY A.[LIABILITIES],A.UploadedDate            
              
  UNION              
      select  A.[LIABILITIES],sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (        
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=COCO Code' + '"><u>' + 'COCO Code' + '</u></a>' [LIABILITIES],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_COCO_CodeAndSalaryAccount WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO], ('–') [IN CR],              
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_COCO_CodeAndSalaryAccount              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND ReportDate BETWEEN CONVERT(varchar, CONCAT(@MonthYear, '-', '01'), 23) AND CONVERT(varchar, GETDATE(), 23)              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)              
       )as  A         
  GROUP BY A.[LIABILITIES], A.UploadedDate            
    
  UNION              
  select  A.[LIABILITIES],sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (        
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=Salary Account' + '"><u>' + 'Salary Account' + '</u></a>' [LIABILITIES],            
  (SELECT CASE WHEN SUM(CAST(YTD_SF AS decimal(10, 0)))=0 THEN '–' ELSE  CAST(SUM(CAST(YTD_SF AS decimal(10, 0))) AS varchar) END) [NO], ('–') [IN CR],              
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_COCO_CodeAndSalaryAccount              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND ReportDate BETWEEN CONVERT(varchar, CONCAT(@MonthYear, '-', '01'), 23) AND CONVERT(varchar, GETDATE(), 23)              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105))as  A         
  GROUP BY A.[LIABILITIES], A.UploadedDate                
              
  SELECT TOP 1 *               
  FROM TBL_OVI_Acquisitions_SFR_SAL        WHERE EmpCode=@UserID              
  AND MTD_YTD=@MTD_YTD              
  AND MONTH([Date])=@Month              
  AND YEAR([Date])=@Year;              
 END              
              
ELSE              
 BEGIN              
  select  A.ASSETS,sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (           
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=ABND' + '"><u>' + 'ABND' + '</u></a>' [ASSETS],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_ABND WHERE RM_Code IN (SELECT EmpID FROM @Table2) ) [NO],              
  (SELECT CASE WHEN SUM(CAST(CAM_AmtInCr AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(CAM_AmtInCr AS decimal(10, 2))) AS varchar) END) [IN CR], CONVERT(varchar, ReportDate, 105) [UploadedDate]              
 FROM TBL_OVI_Acquisitions_ABND              
  WHERE RM_Code IN (SELECT EmpID FROM @Table2)              
  AND CONVERT(char(6), ReportDate, 112) BETWEEN CONCAT((@Year-1), (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND CONCAT(@Year, (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)              
  )as  A            
  GROUP BY A.ASSETS, A.UploadedDate        
              
  UNION              
   select  A.ASSETS,sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (           
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=Disbursed Pledge' + '"><u>' + 'Disbursed Pledge' + '</u></a>' [ASSETS],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_DisbursedPledge WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO],              
  (SELECT CASE WHEN SUM(CAST(AmtInCr AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(AmtInCr AS decimal(10, 2))) AS varchar) END) [IN CR],              
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_DisbursedPledge              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND CONVERT(char(6), ReportDate, 112) BETWEEN CONCAT((@Year-1), (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND CONCAT(@Year, (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)         
  )as  A            
  GROUP BY A.ASSETS, A.UploadedDate             
              
  UNION              
  select  A.ASSETS,sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (           
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=Disbursed WC' + '"><u>' + 'Disbursed WC' + '</u></a>' [ASSETS],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_DisbursedWC WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO],              
  (SELECT CASE WHEN SUM(CAST(NetDisbInCr AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(NetDisbInCr AS decimal(10, 2))) AS varchar) END) [IN CR],              
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_DisbursedWC              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND CONVERT(char(6), ReportDate, 112) BETWEEN CONCAT((@Year-1), (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND CONCAT(@Year, (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)              
    )as  A    GROUP BY A.ASSETS, A.UploadedDate             
  UNION              
      select  A.ASSETS,sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (          
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=Lead Pipeline' + '"><u>' + 'Lead Pipeline' + '</u></a>' [ASSETS],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_LeadPipelineWIP WHERE RM_Code IN (SELECT EmpID FROM @Table2) AND LeadPipelineWIP='Lead Pipeline') [NO],              
  (SELECT CASE WHEN SUM(CAST(EstimatedAmt AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(EstimatedAmt AS decimal(10, 2))) AS varchar) END) [IN CR],              
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_LeadPipelineWIP              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND CONVERT(char(6), ReportDate, 112) BETWEEN CONCAT((@Year-1), (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND CONCAT(@Year, (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND LeadPipelineWIP='Lead Pipeline'              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)              
      )as  A    GROUP BY A.ASSETS, A.UploadedDate         
  UNION              
       select  A.ASSETS,sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (          
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=WIP' + '"><u>' + 'WIP' + '</u></a>' [ASSETS],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_LeadPipelineWIP WHERE RM_Code IN (SELECT EmpID FROM @Table2) AND LeadPipelineWIP='WIP') [NO],              
  (SELECT CASE WHEN SUM(CAST(EstimatedAmt AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(EstimatedAmt AS decimal(10, 2))) AS varchar) END) [IN CR],              
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_LeadPipelineWIP              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)              
  AND CONVERT(char(6), ReportDate, 112) BETWEEN CONCAT((@Year-1), (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND CONCAT(@Year, (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND LeadPipelineWIP='WIP'              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)        
   )as  A    GROUP BY A.ASSETS, A.UploadedDate              
              
  --************************* Liabilities *************************              
      select  A.[LIABILITIES],sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (          
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=CA' + '"><u>' + 'CA' + '</u></a>' [LIABILITIES],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_CA_SA_FD WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO],              
  (SELECT CASE WHEN SUM(CAST(((BalBook)/10000000) AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(((BalBook)/10000000) AS decimal(10, 2))) AS varchar) END) [IN CR],            
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_CA_SA_FD              
  WHERE RM_Code IN (SELECT EmpID FROM @Table2)              
  AND CONVERT(char(6), ReportDate, 112) BETWEEN CONCAT((@Year-1), (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND CONCAT(@Year, (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND Type='CA'              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)              
       )as  A    GROUP BY A.[LIABILITIES], A.UploadedDate         
  UNION              
      select  A.[LIABILITIES],sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (          
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=SA' + '"><u>' + 'SA' + '</u></a>' [LIABILITIES],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_CA_SA_FD WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO],              
  (SELECT CASE WHEN SUM(CAST(((BalBook)/10000000) AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(((BalBook)/10000000) AS decimal(10, 2))) AS varchar) END) [IN CR],            
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_CA_SA_FD              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND CONVERT(char(6), ReportDate, 112) BETWEEN CONCAT((@Year-1), (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND CONCAT(@Year, (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))        
  AND Type='SA'              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)              
      )as  A    GROUP BY A.[LIABILITIES], A.UploadedDate         
  UNION              
      select  A.[LIABILITIES],sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (        
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=FD' + '"><u>' + 'FD' + '</u></a>' [LIABILITIES],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_CA_SA_FD WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO],              
  (SELECT CASE WHEN SUM(CAST(((BalBook)/10000000) AS decimal(10, 2)))=0 THEN '–' ELSE  CAST(SUM(CAST(((BalBook)/10000000) AS decimal(10, 2))) AS varchar) END) [IN CR],            
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_CA_SA_FD              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND CONVERT(char(6), ReportDate, 112) BETWEEN CONCAT((@Year-1), (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND CONCAT(@Year, (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND Type='FD'              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)             
  )as  A    GROUP BY A.[LIABILITIES], A.UploadedDate          
              
  UNION              
      select  A.[LIABILITIES],sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (        
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=COCO Code' + '"><u>' + 'COCO Code' + '</u></a>' [LIABILITIES],            
  (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Acquisitions_COCO_CodeAndSalaryAccount WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [NO], ('–') [IN CR],            
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_COCO_CodeAndSalaryAccount              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND CONVERT(char(6), ReportDate, 112) BETWEEN CONCAT((@Year-1), (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND CONCAT(@Year, (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)              
      )as  A    GROUP BY A.[LIABILITIES], A.UploadedDate          
  UNION              
      select  A.[LIABILITIES],sum(cast(A.NO as decimal(18,2))) as NO,sum(cast(Isnull(REPLACE(A.[IN CR], '–', 0),0) as decimal(18,2))) as [IN CR], A.UploadedDate from (        
  SELECT '<a href="'+ '/Home/DownloadAcquisitionsFile?FlagName=Salary Account' + '"><u>' + 'Salary Account' + '</u></a>' [LIABILITIES],            
  (SELECT CASE WHEN SUM(CAST(YTD_SF AS decimal(10, 0)))=0 THEN '–' ELSE  CAST(SUM(CAST(YTD_SF AS decimal(10, 0))) AS varchar) END) [NO], ('–') [IN CR],              
  CONVERT(varchar, ReportDate, 105) [UploadedDate]              
  FROM TBL_OVI_Acquisitions_COCO_CodeAndSalaryAccount              
  WHERE RM_Code IN (SELECT EmpID FROM @table2)                
  AND CONVERT(char(6), ReportDate, 112) BETWEEN CONCAT((@Year-1), (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  AND CONCAT(@Year, (RIGHT('00'+CAST(@Month AS varchar(3)), 2)))              
  GROUP BY RM_Code, CONVERT(varchar, ReportDate, 105)              
      )as  A    GROUP BY A.[LIABILITIES], A.UploadedDate         
        
        
  SELECT TOP 1 *               
  FROM TBL_OVI_Acquisitions_SFR_SAL              
  WHERE EmpCode=@UserID AND MTD_YTD=@MTD_YTD              
  AND CONVERT(char(6), [Date], 112) BETWEEN CONCAT((@Year-1), (RIGHT('00'+CAST(@month AS varchar(3)), 2)))               
  AND CONCAT(@Year, (RIGHT('00'+CAST(@Month AS varchar(3)), 2)));              
        
 END        
               
END
