-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[Sp_ovi_get_assetpricing_filterdetails]      
(      
@UserId VARCHAR(50)=NULL,      
@Month INT=NULL,      
@Year INT=NULL,      
@CustomerType VARCHAR(50)=NULL,      
@ClientId VARCHAR(50)=NULL,      
@selectedfiltervalue VARCHAR(100)=NULL  
)      
AS      
  BEGIN      
     
	       DECLARE @UserType VARCHAR(100)=NULL,      
              @fetchFor VARCHAR(100)=NULL;      
      declare @ApprovedDate datetime;
	  declare @ApprDateMonth int;
	   declare @ApprDateYear int;
set @ApprovedDate=
(select top 1 O.ApprovedDate from TBL_OVI_Aprrover O, tbl_ovi_asset_pricing_customer_info A where  O.Customer_Info_Id=A.AP_Customer_Info_ID and O.Status = 1 
 and CONVERT(date, ApprovedDate,102)=CONVERT(date,GETDATE(),102)
order by LevelNumber desc)



SELECT @ApprDateMonth = DATEPART(m, @ApprovedDate)
	
SELECT @ApprDateYear = DATEPART(YEAR, @ApprovedDate)


      SELECT @UserType = emprole      
      FROM   tbl_ovi_rm_hierarchy_mapping      
      WHERE  empcode = @UserId      
      
      IF( @UserType LIKE '%Operation Module%' )      
      BEGIN      
       IF( @ClientId = '0' )      
        BEGIN      
        IF( @selectedfiltervalue = 'Approved' )      
        BEGIN      
                        SELECT A.ap_customer_info_id                   AS ID,      
                               A.customer_name                         AS      
                               [Customer_Name],      
                               A.proposal_number,      
                               A.request_number,      
                               A.createdby                             AS      
                               [Initiated By]      
                               ,      
        dbo.Getapprovers(A.ap_customer_info_id) AS [Pending with],      
        A.justification                         AS [Remarks],      
        (SELECT TOP 1 Isnull(approvalremark, '') AS ApprovalRemark      
         FROM   tbl_ovi_aprrover      
         WHERE  customer_info_id = ap_customer_info_id      
         ORDER  BY approveddate DESC)           AS [Comments],      
        CASE      
          WHEN A.status = 10 THEN 'Pending'      
          WHEN A.status = 0 THEN 'In Progress'      
          WHEN A.status = 1 THEN 'Approved'      
          WHEN A.status = 2 THEN 'Sent Back'      
          WHEN A.status = 3 THEN 'Rejected'      
        END                                     AS [Status],      
        CASE      
          WHEN operation_status is NULL THEN '-'      
          WHEN operation_status = '1' THEN 'Pending1'      
          WHEN operation_status = '2' THEN 'Accept'      
          WHEN operation_status = '3' THEN 'Query'      
        END                                     AS [Operation_Status]      
        ,      
        Format(A.createdon, 'dd/MM/yy')      
        AS [Date],      
        A.clients_no                            AS ClientId      
        FROM   tbl_ovi_asset_pricing_customer_info A      
        --inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id             --shruti                                            
        --where A.CustomerType=@CustomerType and B.ApproverADID=@UserId and (B.Status=1)  and A.Status=1 and Month=@Month and Year=@Year  order by A.CreatedOn desc               
        WHERE  A.customertype = @CustomerType      
        AND ( A.status = 1 )      
        AND A.operation_status = 2     
        AND @ApprDateMonth = @Month      
        AND @ApprDateYear = @Year      
        ORDER  BY A.createdon DESC      
      
        SELECT Count(A.ap_customer_info_id) AS AssetPricing_Count      
        FROM   tbl_ovi_asset_pricing_customer_info A      
       -- INNER JOIN tbl_ovi_aprrover B      
             --   ON A.ap_customer_info_id = B.customer_info_id      
            WHERE  A.customertype = @CustomerType      
        AND ( A.status = 1 )      
        AND A.operation_status = 2    
        AND @ApprDateMonth = @Month      
        AND @ApprDateYear = @Year     
        --ORDER  BY A.createdon DESC    
        --WHERE  A.customertype = @CustomerType      
        --AND B.approveradid = @UserId      
        --AND month = @Month      
        --AND year = @Year      
        --AND ( B.status = 1 )      
        END      
        ELSE IF( @selectedfiltervalue = 'Pending' )      
        BEGIN   
	
        SELECT A.ap_customer_info_id                   AS ID,      
            A.customer_name                         AS      
            [Customer_Name],      
            A.proposal_number,      
            A.request_number,      
          A.createdby                             AS [Initiated By]      
   ,      
        dbo.Getapprovers(A.ap_customer_info_id) AS [Pending with],      
        A.justification                         AS [Remarks],      
        (SELECT TOP 1 Isnull(approvalremark, '') AS ApprovalRemark      
        FROM   tbl_ovi_aprrover      
        WHERE  customer_info_id = ap_customer_info_id      
        ORDER  BY approveddate DESC)           AS [Comments],      
        CASE      
        WHEN A.status = 10 THEN 'Pending'      
        WHEN A.status = 0 THEN 'In Progress'      
        WHEN A.status = 1 THEN 'Approved'      
        WHEN A.status = 2 THEN 'Sent Back'      
        WHEN A.status = 3 THEN 'Rejected'      
        END                                     AS [Status],      
        CASE      
        WHEN operation_status = NULL THEN '-'      
        WHEN operation_status = '1' THEN 'Pending'      
        WHEN operation_status = '2' THEN 'Accept'      
        WHEN operation_status = '3' THEN 'Query'      
        END                                     AS      
        [Operation_Status],      
        Format(A.createdon, 'dd/MM/yy')         AS [Date],      
        A.clients_no                            AS ClientId      
        FROM   tbl_ovi_asset_pricing_customer_info A      
        --inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id             --shruti                                            
        --where A.CustomerType=@CustomerType and B.ApproverADID=@UserId and (B.Status=1)  and A.Status=1 and Month=@Month and Year=@Year  order by A.CreatedOn desc               
        WHERE  A.customertype = @CustomerType      
        AND ( A.status = 1 )      
        AND A.operation_status = 1      
       AND @ApprDateMonth = @Month      
       AND @ApprDateYear = @Year  
		And @ApprovedDate BETWEEN GETDATE()-15 AND GETDATE()

        ORDER  BY A.createdon DESC      
      
        SELECT Count(A.ap_customer_info_id) AS AssetPricing_Count      
        FROM   tbl_ovi_asset_pricing_customer_info A      
        --INNER JOIN tbl_ovi_aprrover B      
        --ON A.ap_customer_info_id = B.customer_info_id     
  WHERE  A.customertype = @CustomerType      
        AND ( A.status = 1 )      
        AND A.operation_status = 1  
		And  @ApprovedDate BETWEEN GETDATE()-15 AND GETDATE()
        --------AND month = @Month      
        --------AND year = @Year      
        --ORDER  BY A.createdon DESC     
        --WHERE  A.customertype = @CustomerType      
        --AND B.approveradid = @UserId      
        --AND month = @Month      
        --AND year = @Year      
        --AND ( B.status = 1 )      
        END      
        ELSE IF( @selectedfiltervalue = 'Rejected' )      
        BEGIN      
        SELECT A.ap_customer_info_id                   AS ID,      
        A.customer_name                         AS [Customer_Name],      
        A.proposal_number,      
        A.request_number,      
        A.createdby                             AS [Initiated By],      
        dbo.Getapprovers(A.ap_customer_info_id) AS [Pending with],      
        A.justification                         AS [Remarks],      
        (SELECT TOP 1 Isnull(approvalremark, '') AS ApprovalRemark      
        FROM   tbl_ovi_aprrover      
        WHERE  customer_info_id = ap_customer_info_id      
        ORDER  BY approveddate DESC)           AS [Comments],      
        CASE      
        WHEN A.status = 10 THEN 'Pending'      
        WHEN A.status = 0 THEN 'In Progress'      
        WHEN A.status = 1 THEN 'Approved'      
        WHEN A.status = 2 THEN 'Sent Back'      
        WHEN A.status = 3 THEN 'Rejected'      
        END                                     AS [Status],      
        CASE      
        WHEN operation_status = NULL THEN '-'      
        WHEN operation_status = '1' THEN 'Pending'      
        WHEN operation_status = '2' THEN 'Accept'      
        WHEN operation_status = '3' THEN 'Query'      
        END                                     AS      
        [Operation_Status],      
        Format(A.createdon, 'dd/MM/yy')         AS [Date],      
        A.clients_no                            AS ClientId      
        FROM   tbl_ovi_asset_pricing_customer_info A      
        --inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id             --shruti                                            
        --where A.CustomerType=@CustomerType and B.ApproverADID=@UserId and (B.Status=1)  and A.Status=1 and Month=@Month and Year=@Year  order by A.CreatedOn desc               
        WHERE  A.customertype = @CustomerType      
        AND ( A.status = 1 )      
        AND A.operation_status = '3'      
        AND @ApprDateMonth = @Month      
       AND @ApprDateYear = @Year       
        ORDER  BY A.createdon DESC      
      
     --   SELECT Count(A.ap_customer_info_id) AS AssetPricing_Count      
     --   FROM   tbl_ovi_asset_pricing_customer_info A      
     --   INNER JOIN tbl_ovi_aprrover B      
     --ON A.ap_customer_info_id = B.customer_info_id      
     --   WHERE  A.customertype = @CustomerType      
     --   AND B.approveradid = @UserId      
     --   AND month = @Month      
     --   AND year = @Year      
     --   AND ( B.status = 1 )     
    
  
   SELECT Count(A.ap_customer_info_id) AS AssetPricing_Count      
        FROM   tbl_ovi_asset_pricing_customer_info A      
 WHERE  A.customertype = @CustomerType      
        AND ( A.status = 1 )      
        AND A.operation_status = '3'      
         AND @ApprDateMonth = @Month      
       AND @ApprDateYear = @Year         
        --ORDER  BY A.createdon DESC   
  
        END      
        ELSE IF( @selectedfiltervalue = 'All' )      
        BEGIN      
        (SELECT A.ap_customer_info_id                   AS ID,      
        A.customer_name                         AS [Customer_Name],      
        A.proposal_number,      
        A.request_number,      
        A.createdby                             AS [Initiated By],      
        dbo.Getapprovers(A.ap_customer_info_id) AS [Pending with],      
        A.justification                         AS [Remarks],      
        (SELECT TOP 1 Isnull(approvalremark, '') AS ApprovalRemark      
        FROM   tbl_ovi_aprrover      
        WHERE  customer_info_id = ap_customer_info_id      
        ORDER  BY approveddate DESC)           AS [Comments],      
        CASE      
        WHEN A.status = 10 THEN 'Pending'      
        WHEN A.status = 0 THEN 'In Progress'      
        WHEN A.status = 1 THEN 'Approved'      
        WHEN A.status = 2 THEN 'Sent Back'      
        WHEN A.status = 3 THEN 'Rejected'      
        END                                     AS [Status],      
        CASE      
        WHEN operation_status = NULL THEN '-'      
        WHEN operation_status = '1' THEN 'Pending'      
        WHEN operation_status = '2' THEN 'Accept'      
        WHEN operation_status = '3' THEN 'Query'      
        END                                     AS      
        [Operation_Status],      
        Format(A.createdon, 'dd/MM/yy')         AS [Date],      
        A.clients_no                            AS ClientId      
        FROM   tbl_ovi_asset_pricing_customer_info A      
        --inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id             --shruti                                            
        --where A.CustomerType=@CustomerType and B.ApproverADID=@UserId and (B.Status=1)  and A.Status=1 and Month=@Month and Year=@Year  order by A.CreatedOn desc               
        WHERE  A.customertype = @CustomerType      
             AND ( A.status = 1 )      
          AND (A.operation_status = 2  or A.operation_status =3)-- or A.operation_status = 3)  
        AND @ApprDateMonth = @Month      
       AND @ApprDateYear = @Year  )
		union
		(
		SELECT A.ap_customer_info_id                   AS ID,      
        A.customer_name                         AS [Customer_Name],      
        A.proposal_number,      
        A.request_number,      
        A.createdby                             AS [Initiated By],      
        dbo.Getapprovers(A.ap_customer_info_id) AS [Pending with],      
