        (SELECT TOP 1 Isnull(approvalremark, '') AS ApprovalRemark      
        FROM   tbl_ovi_aprrover      
        WHERE  customer_info_id = ap_customer_info_id      
        ORDER  BY approveddate DESC)           AS [Comments],      
        CASE      
        WHEN A.status = 10 THEN 'Pending'      
        WHEN A.status = 0 THEN 'In Progress'      
        WHEN A.status = 1 THEN 'Approved'      
        WHEN A.status = 2 THEN 'Sent Back'      
        WHEN A.status = 3 THEN 'Rejected'      
        END                                     AS [Status],      
        CASE      
        WHEN operation_status = NULL THEN '-'      
        WHEN operation_status = '1' THEN 'Pending'      
        WHEN operation_status = '2' THEN 'Accept'      
        WHEN operation_status = '3' THEN 'Query'      
        END                                     AS      
        [Operation_Status],      
        Format(A.createdon, 'dd/MM/yy')         AS [Date],      
        A.clients_no                            AS ClientId      
        FROM   tbl_ovi_asset_pricing_customer_info A      
        --inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id             --shruti                                            
        --where A.CustomerType=@CustomerType and B.ApproverADID=@UserId and (B.Status=1)  and A.Status=1 and Month=@Month and Year=@Year  order by A.CreatedOn desc               
        WHERE  A.customertype = @CustomerType      
             AND ( A.status = 1 )      
          AND (A.operation_status = 1 )-- or A.operation_status =3)-- or A.operation_status = 3)  
        AND @ApprDateMonth = @Month      
       AND @ApprDateYear = @Year  
		 AND  @ApprovedDate BETWEEN GETDATE()-15 AND GETDATE()
		)
        --ORDER  BY A.createdon DESC      
      
        select Sum(AssetPricing_Count) as AssetPricing_Count from
		(
        SELECT Count(A.ap_customer_info_id) AS AssetPricing_Count      
        FROM   tbl_ovi_asset_pricing_customer_info A        
           WHERE  A.customertype = @CustomerType      
                AND ( A.status = 1 )      
          AND ( A.operation_status = 2 or A.operation_status = 3)     
       AND @ApprDateMonth = @Month      
       AND @ApprDateYear = @Year  
		Union
		    SELECT Count(A.ap_customer_info_id) AS AssetPricing_Count      
        FROM   tbl_ovi_asset_pricing_customer_info A        
           WHERE  A.customertype = @CustomerType      
