	 ----or A.Status=3)     
  --          -- AND ( A.status = 1 or A.Status=3)      
  --      AND (A.operation_status = 1  or A.operation_status = 2 or A.operation_status = 3)      
  --      AND month = @Month      
  --      AND year = @Year      
  --   --   ORDER  BY A.createdon DESC       
      
               --ORDER  BY A.createdon DESC      
       
        END      
        END      
        ELSE      
        BEGIN      
        SELECT A.ap_customer_info_id                   AS ID,      
