AS BEGIN                            
       Declare @UserType varchar(100)=null,@fetchFor varchar(100)=null;                                                        
                                                        
  SELECT @UserType = EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId      
  if(@UserType='Operation Module')      
  begin      
   select (select EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId) as EmpRole,*,[APR PFY] as APRPFY,                      
