   END as Status,Customer_Name,Proposal_Number,Request_Number from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId and CustomerType=@CustomerType and Status=1                     
   select * from TBL_OVI_Facility_Details where AP_Customer_Info_ID=@CustomerId                            
   select * from TBL_OVI_Collateral_Details where AP_Customer_Info_ID=@CustomerId                            
   select * from TBL_OVI_Other_Charges where AP_Customer_Info_ID=@CustomerId                            
   select * from TBL_OVI_Promoter where AP_Customer_Info_ID=@CustomerId                            
   select * from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId                         
   select * from TBL_OVI_MultipleBanks where AP_Customer_Info_ID=@CustomerId                     
   select  CONCAT(A.EmpCode,' - ', A.EmpName) as [Action Taken By],B.Remark, B.Activity,Format(B.ActionDate,'dd/MM/yyyy HH:mm') as [Date]  from TBL_OVI_RM_Hierarchy_Mapping A inner join                       
   tbl_OVI_Log B on A.EmpCode= B.ActionBy where B.CustomerId=@CustomerId order by B.ActionDate desc;                    
   select top 1 (FileName) from TBL_OVI_Facility_Details where AP_Customer_Info_ID=@CustomerId and FileName!=''                     
  -- select  (A.ActionBy+' - '+B.EmpName) as username,B.EmpRole as user_role,                    
  -- CASE        
  -- -- when ActionStatus=10 then 'Pending'                                         
  ---- when ActionStatus=0 then 'In Progress'                                                    
  -- when ActionStatus=1 then 'Approved'                          
  -- when ActionStatus=2 then 'Sent Back'                          
  -- when ActionStatus=3 then 'Rejected'        
  -- -----------old  case  --star---------------------        
  -- --when EmpRole='Relationship Manager' then 'Initiator'                                           
  -- --when EmpRole='Cluster Head' then 'Recommender'                    
  -- --ELSE 'Approver'   ------End ------------hky                                  
  -- END as actiontaken,A.Remark,Format(A.ActionDate,'dd/MM/yyyy HH:mm') as [Date]                        
  -- from tbl_OVI_Log A inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ActionBy=B.EmpCode                
  -- where A.CustomerId=@CustomerId and (A.Activity!='Updated' and A.Activity!='update')    and ActionStatus=1            
  -- order by A.ActionDate desc  
   

     select  (A.ActionBy+' - '+B.EmpName) as username,B.EmpRole as user_role,    
	   --shruti changes31072023 for Operation module
  -- CASE 
     --shruti changes31072023 for Operation module
   -- when ActionStatus=10 then 'Pending'                                         
  -- when ActionStatus=0 then 'In Progress'
  --shruti changes31072023 for Operation module
   --when ActionStatus=1 then 'Approved'                          
   --when ActionStatus=2 then 'Sent Back'                          
   --when ActionStatus=3 then 'Rejected'   
     --shruti changes31072023 for Operation module
   -----------old  case  --star---------------------        
   --when EmpRole='Relationship Manager' then 'Initiator'                                           
   --when EmpRole='Cluster Head' then 'Recommender'                    
   --ELSE 'Approver'   ------End ------------hky   
     --shruti changes31072023 for Operation module
  -- END as actiontaken
     --shruti changes31072023 for Operation module
    CASE      
    when A.Activity='Updated' then 'Response'                                                
 ELSE A.Activity  End as actiontaken, 
    A.Remark,  
  -- B.Activity as actiontaken,  
   
   Format(A.ActionDate,'dd/MM/yyyy HH:mm') as [Date]                        
   from tbl_OVI_Log A inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ActionBy=B.EmpCode                
   where A.CustomerId=@CustomerId and ( A.Activity!='update')             
   order by A.ActionDate desc
  end      
  else      
  begin      
   select (select EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId) as EmpRole, CASE                                       
   when Status=10 then 'Pending'                                         
   when Status=0 then 'In Progress'                                        when Status=1 then 'Approved'                          
   when Status=2 then 'Sent Back'           
   when Status=3 then 'Rejected'                                                    
   END as Status,*,[APR PFY] as APRPFY,                      
   [APR YTD] as APRYTD,Customer_Name,Proposal_Number,Request_Number from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId and CustomerType=@CustomerType                      
   select * from TBL_OVI_Facility_Details where AP_Customer_Info_ID=@CustomerId                            
   select * from TBL_OVI_Collateral_Details where AP_Customer_Info_ID=@CustomerId                            
   select * from TBL_OVI_Other_Charges where AP_Customer_Info_ID=@CustomerId                            
   select * from TBL_OVI_Promoter where AP_Customer_Info_ID=@CustomerId                            
   select * from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId                         
   select * from TBL_OVI_MultipleBanks where AP_Customer_Info_ID=@CustomerId                     
   select  CONCAT(A.EmpCode,' - ', A.EmpName) as [Action Taken By],B.Remark,
  CASE      
    when B.Activity='Updated' then 'Response'                                                
 ELSE B.Activity End as Activity,
   Format(B.ActionDate,'dd/MM/yyyy HH:mm') as [Date]  from TBL_OVI_RM_Hierarchy_Mapping A inner join                       
   tbl_OVI_Log B on A.EmpCode= B.ActionBy where B.CustomerId=@CustomerId order by B.ActionDate desc;                    
   select top 1 (FileName) from TBL_OVI_Facility_Details where AP_Customer_Info_ID=@CustomerId and FileName!=''         
         
   ----------------AuditTril---------hk---------      
   --Shruti before changes    
  -- select        
