      select        
   CONCAT(A.EmpCode,' - ', A.EmpName) as [username],      
   A.EmpRole as user_role,      
    CASE      
    when B.Activity='Updated' then 'Response'                                                
 ELSE B.Activity  End as actiontaken,       
  -- B.Activity as actiontaken,      
   B.Remark,       
   Format(B.ActionDate,'dd/MM/yyyy HH:mm') as [Date]        
   from TBL_OVI_RM_Hierarchy_Mapping A inner join                       
   tbl_OVI_Log B on A.EmpCode= B.ActionBy where B.CustomerId=@CustomerId and  (B.Activity!='update')  order by B.ActionDate desc;      
   --shruti after changes    
   --select top 1 (FileName) from TBL_OVI_Facility_Details where AP_Customer_Info_ID=@CustomerId and FileName!=''       
      
      
      
      
   ---------------------------------------------------old Audit Trail-----------------------------------------      
  -- select  (A.ActionBy+' - '+B.EmpName) as username,B.EmpRole as user_role,                    
