  -- when ActionStatus=3 then 'Rejected'        
  -- -----------old  case  --star---------------------        
  -- --when EmpRole='Relationship Manager' then 'Initiator'                                           
  -- --when EmpRole='Cluster Head' then 'Recommender'                    
  -- --ELSE 'Approver'   ------End ------------hky                                  
  -- END as actiontaken,A.Remark,Format(A.ActionDate,'dd/MM/yyyy HH:mm') as [Date]                        
