/****** Object:  StoredProcedure [dbo].[SP_OVI_Get_AssetPricingDetails]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Get_AssetPricingDetails](                                                                
@UserId varchar(50)=null,                                                          
@Month int=null,                                                          
@Year int=null,                                                          
@CustomerType varchar(50)=null,                                                
@ClientId VARCHAR(50)=null                                                
)                                                                
AS BEGIN                                                                
                                                                
  Declare @UserType varchar(100)=null,@fetchFor varchar(100)=null;                                                                      
  declare @ApprovedDate datetime,@ApproveDate1 datetime;                                                                 
  SELECT @UserType = EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId                                                                 
         
set @ApprovedDate=(select top 1 ApprovedDate from TBL_OVI_Aprrover O, tbl_ovi_asset_pricing_customer_info A where  O.Customer_Info_Id=A.AP_Customer_Info_ID and O.Status = 1 order by LevelNumber desc)  
--set @ApproveDate1=(select top 1 ApprovedDate from TBL_OVI_Aprrover O, tbl_ovi_asset_pricing_customer_info A where O.Customer_Info_Id=A.AP_Customer_Info_ID and O.Status = 1 and  A.Operation_Status = '1' and  order by LevelNumber desc)  
                                                          
  IF(@UserType  IS NULL)                                                                      
   BEGIN                                                                      
      IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='RM')                                                            
      BEGIN                                                                      
       SET @UserType ='Relationship Manager';                                                                      
      END                                                                      
      ELSE IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='CM')                                                                      
      BEGIN                                                                      
       SET @UserType ='Cluster Head';                                                                 
      END                                                                      
   END                                                                 
  IF(@UserType like '%Relationship Manager%')                                                                    
  BEGIN                                             
      IF(@ClientId='0')                           
   BEGIN      
   if(@CustomerType='IP')  
   begin  
     select AP_Customer_Info_ID AS ID, Customer_Name as [Customer_Name],Proposal_Number, Request_Number,CreatedBy as [Initiated By],                                                                    
      dbo.GetApprovers(AP_Customer_Info_ID) as [Pending with],Justification as [Remarks],(select top 1 isnull(ApprovalRemark,'') as ApprovalRemark from TBL_OVI_Aprrover where Customer_Info_Id = AP_Customer_Info_ID order by ApprovedDate desc               
  
  )     as [Comments],                                                                     
      CASE    
      when Status=10 and Flag=1 then 'Pending'     
      when Status=10 and Flag=0 then 'Draft'     
      when Status=0 then 'In Progress'                                                                    
      when Status=1 then 'Approved'                                                  
      when Status=2 then 'Sent Back'                                                  
      when Status=3 then 'Rejected'                                                  
      END as [Status],   
   --CASE  
   --when Flag=1 then 'No'  
   --when Flag=0 then 'Yes'  
   --END as [IsDraft],  
                
   --   CASE                
   --when Operation_Status=Null then '-'                
   --When Operation_Status='1' then 'Pending From Operation'                
   --When Operation_Status='2' then 'Approved'                
   --When Operation_Status='3' then 'Rejected'                
   --END as [Operation_Status],                
             
      FORMAT(CreatedOn,'dd/MM/yy') as [Date],Clients_No as ClientId                                 
      from TBL_OVI_Asset_Pricing_Customer_Info where CustomerType=@CustomerType and CreatedBy=@UserId and Month=@Month and Year=@Year  
     order by ID desc                            
    select count(AP_Customer_Info_ID) as AssetPricing_Count from TBL_OVI_Asset_Pricing_Customer_Info where CustomerType=@CustomerType and CreatedBy=@UserId --and Month=@Month and Year=@Year -- and ([Status] in (1,3))    
   end   
   else  
   begin  
     select AP_Customer_Info_ID AS ID, Customer_Name as [Customer_Name],Proposal_Number, Request_Number,CreatedBy as [Initiated By],                                                                    
      dbo.GetApprovers(AP_Customer_Info_ID) as [Pending with],Justification as [Remarks],(select top 1 isnull(ApprovalRemark,'') as ApprovalRemark from TBL_OVI_Aprrover where Customer_Info_Id = AP_Customer_Info_ID order by ApprovedDate desc               
  
  )     as [Comments],                                                                     
     CASE    
      when Status=10 and Flag=1 then 'Pending'     
      when Status=10 and Flag=0 then 'Draft'     
      when Status=0 then 'In Progress'                                                                    
      when Status=1 then 'Approved'                                                  
      when Status=2 then 'Sent Back'                                                  
      when Status=3 then 'Rejected'                                                  
      END as [Status],              
           
      CASE                
   when Operation_Status=Null then '-'                
  When Operation_Status='1' then 'Pending From Operation'   

   --When Operation_Status='1' And @ApprovedDate BETWEEN GETDATE()-15 AND GETDATE() then 'Pending From Operation'          
   --When Operation_Status='1' And @ApprovedDate Not BETWEEN GETDATE()-15 AND GETDATE() then 'Pending From RM To Revalidate'                
   When Operation_Status='2' then 'Accept'                
   When Operation_Status='3' then 'Query'                
   END as [Operation_Status],  
  
             
      FORMAT(CreatedOn,'dd/MM/yy') as [Date]  
   --,Clients_No as ClientId                                 
      from TBL_OVI_Asset_Pricing_Customer_Info where CustomerType=@CustomerType and CreatedBy=@UserId and Month=@Month and Year=@Year order by ID desc                            
    select count(AP_Customer_Info_ID) as AssetPricing_Count from TBL_OVI_Asset_Pricing_Customer_Info where CustomerType=@CustomerType and CreatedBy=@UserId --and Month=@Month and Year=@Year-- and ([Status] in (1,3))    
   end  
                           
   END                          
   else                    
   BEGIN                          
   select a.AP_Customer_Info_ID AS ID, a.Customer_Name as [Customer_Name],a.Proposal_Number, a.Request_Number,a.CreatedBy as [Initiated By],                                                                    
      dbo.GetApprovers(a.AP_Customer_Info_ID) as [Pending with],a.Justification as [Remarks],(select top 1 isnull(ApprovalRemark,'') as ApprovalRemark from TBL_OVI_Aprrover where Customer_Info_Id = a.AP_Customer_Info_ID order by ApprovedDate desc         
  
 )     as [Comments],                                                                     
    CASE    
      when Status=10 and Flag=1 then 'Pending'     
      when Status=10 and Flag=0 then 'Draft'     
      when Status=0 then 'In Progress'                                                                    
      when Status=1 then 'Approved'                                                  
      when Status=2 then 'Sent Back'                                                  
      when Status=3 then 'Rejected'                                                  
      END as [Status],              
            
      FORMAT(a.CreatedOn,'dd/MM/yy') as [Date],a.Clients_No as ClientId                                                                    
      from TBL_OVI_Asset_Pricing_Customer_Info a inner join client_details b on a.Proposal_Number=b.PROPOSAL_NO where a.CustomerType=@CustomerType and a.CreatedBy=@UserId  and b.CLIENTS_NO=@ClientId order by ID desc   ----and a.Month=@Month and a.Year=@Year                          
                             
   select count(AP.AP_Customer_Info_ID) as AssetPricing_Count from TBL_OVI_Asset_Pricing_Customer_Info AP inner join client_details CD on AP.Proposal_Number=CD.PROPOSAL_NO where AP.CustomerType=@CustomerType and AP.CreatedBy=@UserId  
   and (AP.[Status]    in (1,3))  
      
  and CD.CLIENTS_NO=@ClientId  ---and Month=@Month and Year=@Year                          
   END                                
  END                                                                 
  ELSE   if(@UserType like '%Operation Module%')                  
    BEGIN                            
    IF(@ClientId='0')                         
   BEGIN                        
   select A.AP_Customer_Info_ID as ID,A.Customer_Name as [Customer_Name], A.Proposal_Number, A.Request_Number,A.CreatedBy as [Initiated By],                                                                    
      dbo.GetApprovers(A.AP_Customer_Info_ID) as [Pending with],      
   A.Justification as [Remarks],(select top 1 isnull(ApprovalRemark,'') as ApprovalRemark from TBL_OVI_Aprrover where Customer_Info_Id = AP_Customer_Info_ID order by ApprovedDate desc)     as [Comments],                                                    
  
    
                 
      CASE                                                         
      when A.Status=10 then 'Pending'                                                               
      when A.Status=0 then 'In Progress'                                                                    
      when A.Status=1 then 'Approved'                                      
      when A.Status=2 then 'Sent Back'                                                  
      when A.Status=3 then 'Rejected'                                 
      END as [Status],                
       CASE                
   when Operation_Status IS NULL  then '-'             
   When Operation_Status='1' then 'Pending'                
   When Operation_Status='2' then 'Approved'                
   When Operation_Status='3' then 'Rejected'                
   END as [Operation_Status],              
      FORMAT(A.CreatedOn,'dd/MM/yy') as [Date],A.Clients_No as ClientId                                                                   
      from TBL_OVI_Asset_Pricing_Customer_Info A               
   --inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id             --shruti                                           
      --where A.CustomerType=@CustomerType and B.ApproverADID=@UserId and (B.Status=1)  and A.Status=1 and Month=@Month and Year=@Year  order by A.CreatedOn desc                     
        where A.CustomerType=@CustomerType  and (A.Status=1)  and A.Operation_Status=1 and Month=@Month and Year=@Year  order by A.CreatedOn desc                      
                                                            
      select count(A.AP_Customer_Info_ID) as AssetPricing_Count  from TBL_OVI_Asset_Pricing_Customer_Info A       
   --inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id                                                               
      where A.CustomerType=@CustomerType  and Month=@Month and Year=@Year and (A.Status=1)  and A.Operation_Status=1                       
   END                        
   ELSE                        
   BEGIN                        
                        
   select A.AP_Customer_Info_ID as ID,A.Customer_Name as [Customer_Name], A.Proposal_Number, A.Request_Number,A.CreatedBy as [Initiated By],                                                                    
      dbo.GetApprovers(A.AP_Customer_Info_ID) as [Pending with],A.Justification as [Remarks],(select top 1 isnull(ApprovalRemark,'') as ApprovalRemark from TBL_OVI_Aprrover where Customer_Info_Id = AP_Customer_Info_ID order by ApprovedDate desc) as [Comments],                      
                                       
      CASE                                                  
      when A.Status=10 then 'Pending'                                                               
      when A.Status=0 then 'In Progress'                                                                    
      when A.Status=1 then 'Approved'                                      
      when A.Status=2 then 'Sent Back'                                                  
      when A.Status=3 then 'Rejected'                                                                 
      END as [Status],                  
       CASE                
   when Operation_Status=Null then '-'                
   When Operation_Status='1' then 'Pending'                
   When Operation_Status='2' then 'Approved'                
