      FORMAT(A.CreatedOn,'dd/MM/yy') as [Date],A.Clients_No as ClientId                                                                 
      from TBL_OVI_Asset_Pricing_Customer_Info A inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id                      
   INNER JOIN client_details C ON A.Proposal_Number=C.PROPOSAL_NO                      
      where A.CustomerType=@CustomerType and B.ApproverADID=@UserId  and (B.Status=0) and C.CLIENTS_NO=@ClientId order by A.CreatedOn desc --and Month=@Month and Year=@Year                           
                      
   select count(A.AP_Customer_Info_ID) as AssetPricing_Count  from TBL_OVI_Asset_Pricing_Customer_Info A inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id                      
   INNER JOIN client_details C ON A.Proposal_Number=C.PROPOSAL_NO                      
      where A.CustomerType=@CustomerType AND B.ApproverADID=@UserId  and (B.Status=0) and C.CLIENTS_NO=@ClientId ---and Month=@Month and Year=@Year                      
   END                                   
  END     
		
		   else

		         BEGIN                          
    IF(@ClientId='0')                       
   BEGIN          
   select A.AP_Customer_Info_ID as ID,A.Customer_Name as [Customer_Name], A.Proposal_Number, A.Request_Number,A.CreatedBy as [Initiated By],                                                                  
      dbo.GetApprovers(A.AP_Customer_Info_ID) as [Pending with],A.Justification as [Remarks],(select top 1 isnull(ApprovalRemark,'') as ApprovalRemark from TBL_OVI_Aprrover where Customer_Info_Id = AP_Customer_Info_ID order by ApprovedDate desc) as [Comme
  
nts],                                                                   
      CASE                                                       
      when A.Status=10 then 'Pending'                                                             
      when A.Status=0 then 'In Progress'                                                                  
      when A.Status=1 then 'Approved'                                    
      when A.Status=2 then 'Sent Back'                                                
      when A.Status=3 then 'Rejected'                                                               
      END as [Status],
	       CASE              
   when Operation_Status=Null then '-'              
   When Operation_Status='1' then 'Pending From Operation'              
   When Operation_Status='2' then 'Accept'              
   When Operation_Status='3' then 'Query'              
   END as [Operation_Status], 
      FORMAT(A.CreatedOn,'dd/MM/yy') as [Date],A.Clients_No as ClientId                                                                 
      from TBL_OVI_Asset_Pricing_Customer_Info A inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id                                                             
      where A.CustomerType=@CustomerType and B.ApproverADID=@UserId and Month=@Month and Year=@Year and (B.Status=0) order by A.CreatedOn desc                                                         
                             
      select count(A.AP_Customer_Info_ID) as AssetPricing_Count  from TBL_OVI_Asset_Pricing_Customer_Info A inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id                                                             
      where A.CustomerType=@CustomerType AND B.ApproverADID=@UserId and Month=@Month and Year=@Year and (B.Status=0)                      
   END                      
   ELSE                      
   BEGIN                                
   select A.AP_Customer_Info_ID as ID,A.Customer_Name as [Customer_Name], A.Proposal_Number, A.Request_Number,A.CreatedBy as [Initiated By],                                                                  
      dbo.GetApprovers(A.AP_Customer_Info_ID) as [Pending with],A.Justification as [Remarks],(select top 1 isnull(ApprovalRemark,'') as ApprovalRemark from TBL_OVI_Aprrover where Customer_Info_Id = AP_Customer_Info_ID order by ApprovedDate desc) as [Comme
  
nts],                                          
      CASE                                                       
      when A.Status=10 then 'Pending'                                                             
      when A.Status=0 then 'In Progress'                                                                  
      when A.Status=1 then 'Approved'                                    
      when A.Status=2 then 'Sent Back'                                                
      when A.Status=3 then 'Rejected'                                                               
      END as [Status],
	       CASE              
   when Operation_Status=Null then '-'              
   When Operation_Status='1' then 'Pending From Operation'              
   When Operation_Status='2' then 'Accept'              
   When Operation_Status='3' then 'Query'              
   END as [Operation_Status], 
      FORMAT(A.CreatedOn,'dd/MM/yy') as [Date],A.Clients_No as ClientId                                                                 
      from TBL_OVI_Asset_Pricing_Customer_Info A inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id                      
   INNER JOIN client_details C ON A.Proposal_Number=C.PROPOSAL_NO                      
      where A.CustomerType=@CustomerType and B.ApproverADID=@UserId  and (B.Status=0) and C.CLIENTS_NO=@ClientId order by A.CreatedOn desc --and Month=@Month and Year=@Year                           
                      
   select count(A.AP_Customer_Info_ID) as AssetPricing_Count  from TBL_OVI_Asset_Pricing_Customer_Info A inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id                      
   INNER JOIN client_details C ON A.Proposal_Number=C.PROPOSAL_NO                      
      where A.CustomerType=@CustomerType AND B.ApproverADID=@UserId  and (B.Status=0) and C.CLIENTS_NO=@ClientId ---and Month=@Month and Year=@Year                      
   END                      
                        
  END     

                                                       
       end                                      
  else
  BEGIN                          
    IF(@ClientId='0')                       
   BEGIN          
   select A.AP_Customer_Info_ID as ID,A.Customer_Name as [Customer_Name], A.Proposal_Number, A.Request_Number,A.CreatedBy as [Initiated By],                                                                  
      dbo.GetApprovers(A.AP_Customer_Info_ID) as [Pending with],A.Justification as [Remarks],(select top 1 isnull(ApprovalRemark,'') as ApprovalRemark from TBL_OVI_Aprrover where Customer_Info_Id = AP_Customer_Info_ID order by ApprovedDate desc) as [Comme
  
nts],                                                                   
      CASE                                                       
      when A.Status=10 then 'Pending'                                                             
      when A.Status=0 then 'In Progress'                                                                  
      when A.Status=1 then 'Approved'                                    
      when A.Status=2 then 'Sent Back'                                                
      when A.Status=3 then 'Rejected'                                                               
      END as [Status],                                                   
      FORMAT(A.CreatedOn,'dd/MM/yy') as [Date],A.Clients_No as ClientId                                                                 
      from TBL_OVI_Asset_Pricing_Customer_Info A inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id                                                             
      where A.CustomerType=@CustomerType and B.ApproverADID=@UserId and Month=@Month and Year=@Year and (B.Status=0) order by A.CreatedOn desc                                                         
                             
      select count(A.AP_Customer_Info_ID) as AssetPricing_Count  from TBL_OVI_Asset_Pricing_Customer_Info A inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id                                                             
      where A.CustomerType=@CustomerType AND B.ApproverADID=@UserId and Month=@Month and Year=@Year and (B.Status=0)                      
   END                      
   ELSE                      
   BEGIN                                
   select A.AP_Customer_Info_ID as ID,A.Customer_Name as [Customer_Name], A.Proposal_Number, A.Request_Number,A.CreatedBy as [Initiated By],                                                                  
      dbo.GetApprovers(A.AP_Customer_Info_ID) as [Pending with],A.Justification as [Remarks],(select top 1 isnull(ApprovalRemark,'') as ApprovalRemark from TBL_OVI_Aprrover where Customer_Info_Id = AP_Customer_Info_ID order by ApprovedDate desc) as [Comme
  
nts],                                          
      CASE                                                       
      when A.Status=10 then 'Pending'                                                             
      when A.Status=0 then 'In Progress'                                                                  
      when A.Status=1 then 'Approved'                                    
      when A.Status=2 then 'Sent Back'                                                
      when A.Status=3 then 'Rejected'                                                               
      END as [Status],                                                   
      FORMAT(A.CreatedOn,'dd/MM/yy') as [Date],A.Clients_No as ClientId                                                                 
      from TBL_OVI_Asset_Pricing_Customer_Info A inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id                      
   INNER JOIN client_details C ON A.Proposal_Number=C.PROPOSAL_NO                      
      where A.CustomerType=@CustomerType and B.ApproverADID=@UserId  and (B.Status=0) and C.CLIENTS_NO=@ClientId order by A.CreatedOn desc --and Month=@Month and Year=@Year                           
                      
   select count(A.AP_Customer_Info_ID) as AssetPricing_Count  from TBL_OVI_Asset_Pricing_Customer_Info A inner join TBL_OVI_Aprrover B on A.AP_Customer_Info_ID=B.Customer_Info_Id                      
   INNER JOIN client_details C ON A.Proposal_Number=C.PROPOSAL_NO                      
      where A.CustomerType=@CustomerType AND B.ApproverADID=@UserId  and (B.Status=0) and C.CLIENTS_NO=@ClientId ---and Month=@Month and Year=@Year                      
