/****** Object:  StoredProcedure [dbo].[SP_OVI_Get_Dashboard_Records]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Get_Dashboard_Records](                      
 @UserId varchar(30)=null,                      
 @IdentFlag varchar(100)=null                      
 )                      
 AS                       
 BEGIN              
     DECLARE @table2 AS TABLE (                  
     EmpId varchar(20),                  
     EmpRole varchar(20)                  
  )                  
     INSERT INTO @table2 EXEC SP_OVI_GetRMListById @UserId              
              
              
     select COUNT(A.LSID) as LeadCount,    
     APRs_Count=(select count(distinct(L.APR_Code )) from TBL_OVI_APRs L inner join TBL_OVI_Client_RM_Mapping M on L.LSID=M.LSID where M.RM_ID in(select EmpId from @table2)),                       
     cast((SUM(A.Fund_Limit)/10000000 ) as decimal(10,0))as Fund_Limit,                  
     cast((SUM(A.Non_Fund_Limit)/10000000) as decimal(10,0)) as Non_Fund_Limit,                  
     cast((SUM(A.Fund_Os)/10000000)as decimal(10,0)) as Fund_Os,                            
     cast((SUM(A.Non_Fund_Os)/10000000)as decimal(10,0)) as Non_Fund_Os,                   
     Total_Limits= cast((SUM(A.Fund_Limit)+SUM(A.Non_Fund_Limit))/10000000 as decimal(10,0)),                          
     Total_Os=cast((SUM(A.Fund_Os)+SUM(A.Non_Fund_Os))/10000000 as decimal(10,0)),                         
     FB_Percentage=IIF(SUM(A.Fund_Limit)=0,0,ROUND(SUM(A.Fund_Os) * 100.0 / SUM(A.Fund_Limit), 1)) ,                          
     NFB_percentage= IIF(cast((SUM(A.Non_Fund_Limit)/10000000) as decimal(10,1)) > 0 , ROUND(SUM(A.Non_Fund_Os) * 100.0 / SUM(A.Non_Fund_Limit), 1),0),                          
     Total_percentage=IIF((SUM(A.Fund_Limit)+SUM(A.Non_Fund_Limit))=0,0,ROUND((SUM(A.Fund_Os)+SUM(A.Non_Fund_Os)) * 100.0 / (SUM(A.Fund_Limit)+SUM(A.Non_Fund_Limit)), 1)),      
     UploadedDate = CONVERT(varchar,A.UploadedDate,105)                        
     from  TBL_OVI_Client_RM_Mapping B inner join TBL_OVI_Portfolio A on A.LSID=B.LSID                      
     where B.RM_ID in(select EmpId from @table2) group by CONVERT(varchar,A.UploadedDate,105)               
              
     select COUNT(Lead_No) as Fresh_Leads from TBL_OVI_Fresh_Leads where RM_code in(select EmpId from @table2)            
              
 END
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_Get_FacilityDetails]    Script Date: 21-09-2024 20:36:55 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Get_FacilityDetails](    
@LsId int=null,    
@Type varchar(50)=null,    
@ProposalNo varchar(100)=null    
)    
AS    
BEGIN    
   IF(@Type='ReversalApproval')    
   BEGIN    
     SELECT distinct B.PRODUCT_NAME, B.EXIST_LIMIT FROM client_details A INNER JOIN facility_details B ON A.PROPOSAL_NO=B.PROPOSAL_NO right join TBL_OVI_Facility_Master C on B.PRODUCT_NAME=C.FacilityName where A.PROPOSAL_NO=@ProposalNo    
   END  
   ELSE IF(@Type='AssetPricingExisting')  
   BEGIN  
     SELECT distinct B.PRODUCT_NAME, B.EXIST_LIMIT,B.PROPOSED_LIMIT FROM client_details A INNER JOIN facility_details B ON A.PROPOSAL_NO=B.PROPOSAL_NO right join TBL_OVI_Facility_Master C on B.PRODUCT_NAME=C.FacilityName where A.CLIENTS_NO=@LsId    
   END                                                                                                                                                                                 
END
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_Get_IP_AssetPricingDetails]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE procedure [dbo].[SP_OVI_Get_IP_AssetPricingDetails](  
@UserId varchar(50)=null  
)  
AS BEGIN  
  
  Declare @UserType varchar(100)=null,@fetchFor varchar(100)=null;      
      
  SELECT @UserType = EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId  
  
  IF(@UserType  IS NULL)        
   BEGIN        
      IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='RM')        
      BEGIN        
       SET @UserType ='Relationship Manager';        
      END        
      ELSE IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='CM')        
      BEGIN        
       SET @UserType ='Cluster Head';   
      END        
   END   
  IF(@UserType like '%Relationship Manager%')      
  BEGIN      
      select Customer_Name as [Customer_Name],AP_Customer_Info_ID as [Proposal_Number],CreatedBy as [Initiated By],      
      dbo.GetApprovers(AP_Customer_Info_ID) as [Sent To],Justification as [Remarks],       
      CASE       
      when Status=0 then 'In Progress'      
      when Status=1 then 'Submitted'      
      END as [Status],      
      FORMAT(CreatedOn,'dd/MM/yy') as [Date]      
      from TBL_OVI_Asset_Pricing_Customer_Info where CustomerType='IP' and CreatedBy=@UserId  
  END   
  ELSE IF(@UserType like '%Cluster Head%')      
  BEGIN      
      CREATE TABLE #tmpCHTable (EmpId varchar(50),EmpName varchar(250), [Role] varchar(100))        
      INSERT INTO #tmpCHTable        
      select EmpCode,EmpName,EmpRole                                               
      from TBL_OVI_RM_Hierarchy_Mapping                             
      where  SupervisorCode=@UserId;      
         
      select Customer_Name as [Customer_Name],AP_Customer_Info_ID as [Proposal_Number],CreatedBy as [Initiated By],      
      dbo.GetApprovers(AP_Customer_Info_ID) as [Sent To],Justification as [Remarks],       
      CASE       
      when Status=0 then 'In Progress'      
      when Status=1 then 'Submitted'      
      END as [Status],      
      FORMAT(CreatedOn,'dd/MM/yy') as [Date]      
      from TBL_OVI_Asset_Pricing_Customer_Info   
      where CustomerType='IP' and CreatedBy IN(select EmpId from #tmpCHTable) AND   
      @UserId IN(SELECT ApproverADID from TBL_OVI_Aprrover where CommercialType='IP'   
      and CreatedBy IN(select EmpId from #tmpCHTable))  
         
      drop table #tmpCHTable;          
         
  END  
  ELSE IF(@UserType like '%Circle Head%')      
  BEGIN      
     select EmpCode,EmpName,EmpRole,SupervisorCode                            
     Into #tmpClusterHeadTable                            
     from TBL_OVI_RM_Hierarchy_Mapping                            
     where SupervisorCode=@UserId;       
           
     select EmpCode,EmpName,EmpRole,SupervisorCode                            
     INTO #tmpRMTable                            
     from TBL_OVI_RM_Hierarchy_Mapping                        
     where SupervisorCode in (                            
     select EmpCode from #tmpClusterHeadTable                            
     )      
        
     select Customer_Name as [Customer_Name],AP_Customer_Info_ID as [Proposal_Number],CreatedBy as [Initiated By],      
      dbo.GetApprovers(AP_Customer_Info_ID) as [Sent To],Justification as [Remarks],       
      CASE       
      when Status=0 then 'In Progress'      
      when Status=1 then 'Submitted'      
      END as [Status],      
      FORMAT(CreatedOn,'dd/MM/yy') as [Date]      
      from TBL_OVI_Asset_Pricing_Customer_Info   
      where CustomerType='IP' and CreatedBy IN(select EmpCode from #tmpRMTable) AND   
      @UserId IN(SELECT ApproverADID from TBL_OVI_Aprrover where CommercialType='IP'   
      and CreatedBy IN(select EmpCode from #tmpRMTable))   
      
     drop table #tmpClusterHeadTable;                            
     drop table #tmpRMTable;         
  END    
  ELSE IF(@UserType like '%Unit Head%')      
  BEGIN      
           
     CREATE TABLE #tmpClusterHeadTable1 (EmpCode Varchar(25), EmpName VARCHAR(100),EmpRole varchar(50),SupervisorCode varchar(25))      
           
     select EmpCode,EmpName,EmpRole,SupervisorCode                            
     INTO #tmpCHTable1                            
     from TBL_OVI_RM_Hierarchy_Mapping                             
     where SupervisorCode=@UserId        
           
     INSERT INTO #tmpClusterHeadTable1                             
     select EmpCode,EmpName,EmpRole,SupervisorCode                             
     from TBL_OVI_RM_Hierarchy_Mapping                     
     where SupervisorCode in (                            
      select EmpCode from #tmpCHTable1 where EmpRole like'%Circle Head%'                             
     )      
           
     IF EXISTS(select EmpCode from #tmpCHTable1 where EmpRole like'%Cluster Head%')                            
     BEGIN                            
       INSERT INTO #tmpClusterHeadTable1                             
       Select EmpCode ,EmpName,EmpRole,SupervisorCode from                             
       #tmpCHTable1 where EmpRole like'%Cluster Head%'                            
     END       
         
     SELECT EmpCode , EmpName,EmpRole, SupervisorCode                            
     INTO #tmpRMTable1                            
     FROM TBL_OVI_RM_Hierarchy_Mapping                  
     where SupervisorCode in (select EmpCode from #tmpClusterHeadTable1)       
      
      select Customer_Name as [Customer_Name],AP_Customer_Info_ID as [Proposal_Number],CreatedBy as [Initiated By],      
      dbo.GetApprovers(AP_Customer_Info_ID) as [Sent To],Justification as [Remarks],       
      CASE       
      when Status=0 then 'In Progress'      
      when Status=1 then 'Submitted'      
      END as [Status],      
      FORMAT(CreatedOn,'dd/MM/yy') as [Date]      
      from TBL_OVI_Asset_Pricing_Customer_Info   
      where CustomerType='IP' and CreatedBy IN(select EmpCode from #tmpRMTable1) AND   
      @UserId IN(SELECT ApproverADID from TBL_OVI_Aprrover where CommercialType='IP'   
      and CreatedBy IN(select EmpCode from #tmpRMTable1))   
      
     drop table #tmpClusterHeadTable1                            
     drop table #tmpCHTable1                            
     drop table #tmpRMTable1        
      
  END   
  IF(@UserType='Business Head')      
  BEGIN      
     Select * INTO #tmpUnitHeadTable                             
     from TBL_OVI_RM_Hierarchy_Mapping where SupervisorCode = @UserId and EmpRole='Unit Head'       
      
     select EmpCode,EmpName,EmpRole,SupervisorCode                            
     INTO #tmpCHTable2                            
     from TBL_OVI_RM_Hierarchy_Mapping                         
     where SupervisorCode In(                            
     select EmpCode from #tmpUnitHeadTable)        
                        
     select EmpCode,EmpName,EmpRole,SupervisorCode       
  INTO #tmpClusterHeadTable2      
     from TBL_OVI_RM_Hierarchy_Mapping                        
     where SupervisorCode in (                            
     select EmpCode from #tmpCHTable2 where EmpRole like'%Circle Head%')      
      
  IF EXISTS(select EmpCode from #tmpCHTable2 where EmpRole like'%Cluster Head%')                            
     BEGIN                            
       INSERT INTO #tmpClusterHeadTable2                             
       Select EmpCode , EmpName ,EmpRole,SupervisorCode from                             
       #tmpCHTable2 where EmpRole like'%Cluster Head%'       
  END       
          
     SELECT EmpCode , EmpName,EmpRole, SupervisorCode                            
     INTO #tmpRMTable2                            
     FROM TBL_OVI_RM_Hierarchy_Mapping                            
     where SupervisorCode in (select EmpCode from #tmpClusterHeadTable2)      
      
     select Customer_Name as [Customer_Name],AP_Customer_Info_ID as [Proposal_Number],CreatedBy as [Initiated By],      
      dbo.GetApprovers(AP_Customer_Info_ID) as [Sent To],Justification as [Remarks],       
      CASE       
      when Status=0 then 'In Progress'      
      when Status=1 then 'Submitted'      
      END as [Status],      
      FORMAT(CreatedOn,'dd/MM/yy') as [Date]      
      from TBL_OVI_Asset_Pricing_Customer_Info   
      where CustomerType='IP' and CreatedBy IN(select EmpCode from #tmpRMTable2) AND   
      @UserId IN(SELECT ApproverADID from TBL_OVI_Aprrover where CommercialType='IP'   
      and CreatedBy IN(select EmpCode from #tmpRMTable2))    
      
     drop table #tmpClusterHeadTable2                            
     drop table #tmpCHTable2                            
     drop table #tmpRMTable2                            
     drop table #tmpUnitHeadTable        
           
  END      
END  
GO
