CREATE procedure [dbo].[SP_OVI_Get_Links]
@ID int=null,
@Type varchar(100)=null,
@ServerType varchar(50)=null
AS 
BEGIN
  IF(@ServerType='Local')
  BEGIN
   SELECT [Local] as Link from TBL_OVI_PMS_LINKS where [Type]=@Type
  END
  ELSE IF(@ServerType='UAT')
  BEGIN
  SELECT UAT as Link from TBL_OVI_PMS_LINKS where [Type]=@Type
  END
  ELSE
  BEGIN
  SELECT Live as Link from TBL_OVI_PMS_LINKS where [Type]=@Type
  END
END
GO
