/****** Object:  StoredProcedure [dbo].[SP_OVI_Get_NotificationDetails]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Get_NotificationDetails]             
@Emp_Id varchar(50)=null,              
@Identflag varchar(100)=null,
@Id int=null
AS              
BEGIN              
  IF(@Identflag='GetCount')              
  BEGIN              
  select COUNT(ID) as NotificationCount from TBL_OVI_Notification where EmpCode=@Emp_Id and Status=0             
  END              
  IF(@Identflag='GetAllNotifications')              
  BEGIN              
  select * into #temp1 from       
  (select * from  TBL_OVI_Notification where EmpCode=@Emp_Id and Status=0  union select top 20 * from  TBL_OVI_Notification where EmpCode=@Emp_Id and Status=1 order by ID desc) A      
          
  update TBL_OVI_Notification set Status=1 where ID IN(select ID from #temp1)            
  select * from #temp1            
            
  drop table #temp1            
  END   
  IF(@Identflag='DeleteNotification')
  BEGIN
  DELETE FROM TBL_OVI_Notification WHERE ID=@Id
  END
END
GO
