CREATE procedure [dbo].[SP_OVI_Get_Reversal_Approval_CustomerDetail]                                      
@CustomerType varchar(50)=null,                                      
@CustomerId int=null,                                  
@UserId varchar(50)=null,      
@ClientId varchar(50)=null                                 
                                      
AS BEGIN                                      
               
   select b.RequestNumber,b.LS_ClientID,b.CustomerName,b.ProposalNumber,b.Vintage,b.RAROC,b.[APR PFY] as APRPFY,b.[APR YTD] as APRYTD,                      
   b.CTI,b.Limit,(select EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId) as EmpRole from                     
   TBL_OVI_Reversal_Approval_Customer_Details b where LS_ClientID=@ClientId and b.Status=1 order by b.Reversal_Approval_Customer_Details_ID desc       
          
   select * from TBL_OVI_Reversal_Approval_Facility_Details a, TBL_OVI_Reversal_Approval_Customer_Details b      
   where a.Reversal_Approval_Customer_Details_ID=b.Reversal_Approval_Customer_Details_ID and b.LS_ClientID=@ClientId and b.Status=1 order by b.Reversal_Approval_Customer_Details_ID desc     
       
   select * from TBL_OVI_Reversal_Approval_Reversal_Details a, TBL_OVI_Reversal_Approval_Customer_Details b , TBL_OVI_ChargesType_Master C    
   where a.Reversal_Approval_Customer_Details_ID=b.Reversal_Approval_Customer_Details_ID and
   a.NatureofReversal=c.ChargesCode
   and b.LS_ClientID=@ClientId and b.Status=1 order by b.Reversal_Approval_Customer_Details_ID desc     
         
   select RequestNumber,Limit_OS,Reversal_Amount_Breakdown_Details_ID,FORMAT(From_Date,'dd/MM/yyyy') as From_Date,                      
   FORMAT(To_Date,'dd/MM/yyyy') as To_Date,NoOfDays,Actual_Int,Penal_Int_Amount,Account_No                      
   from TBL_OVI_Reversal_Amount_Breakdown_Details a, TBL_OVI_Reversal_Approval_Customer_Details b      
   where a.Reversal_Approval_Customer_Details_ID=b.Reversal_Approval_Customer_Details_ID and b.LS_ClientID=@ClientId and b.Status=1 order by b.Reversal_Approval_Customer_Details_ID desc            
                       
  -- select * from TBL_OVI_Reversal_Aprrover a, TBL_OVI_Reversal_Approval_Customer_Details b      
   --where a.Reversal_Approval_Customer_Details_ID=b.Reversal_Approval_Customer_Details_ID and b.LS_ClientID=@ClientId  and b.Status=1 order by b.Reversal_Approval_Customer_Details_ID desc          
          
 Select * from (select                       
  c.RequestNumber, CONCAT(A.EmpCode,' - ', A.EmpName) as [username],                      
   A.EmpRole as user_role,                      
   CASE when B.Activity='Updated' then 'Response' ELSE B.Activity  End as actiontaken,B.Remark,                       
   Format(B.ActionDate,'dd/MM/yyyy HH:mm') as [Date]  ,--d.LevelNumber,              
   row_number() over(Partition by b.CustomerId, A.EmpCode order by  B.ActionDate,c.Reversal_Approval_Customer_Details_ID desc ) rn                    
   from TBL_OVI_RM_Hierarchy_Mapping A inner join                                       
   tbl_OVI_Log B on A.EmpCode= B.ActionBy     
   inner join TBL_OVI_Reversal_Approval_Customer_Details c    
   on b.CustomerId=c.Reversal_Approval_Customer_Details_ID and c.LS_ClientID=@ClientId  and c.Status=1     
  -- Inner join TBL_OVI_Reversal_Aprrover d  
   --On  c.Reversal_Approval_Customer_Details_ID=d.Reversal_Approval_Customer_Details_ID  
   where (B.Activity!='update') and B.MasterId='Reversal Approval'          
   ) a where rn=1;      
END    
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_Get_ReversalApproval_Details]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Get_ReversalApproval_Details]                    
@UserId varchar(50)=null,                
@ProposalNumber varchar(50)=null ,
@ClientId varchar(50)=null                
AS                     
BEGIN                    
 Declare @UserType varchar(100)=null,@fetchFor varchar(100)=null;                    
 SELECT @UserType = EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId                    
                    
  IF(@UserType  IS NULL)                                      
   BEGIN                                      
      IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='RM')                                      
      BEGIN                                      
       SET @UserType ='Relationship Manager';                                      
      END                                      
      ELSE IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='CM')                                      
      BEGIN                                      
       SET @UserType ='Cluster Head';                                 
      END                                      
   END                       
  IF(@UserType like '%Relationship Manager%')                                    
  BEGIN                 
     select Reversal_Approval_Customer_Details_ID as ID, CustomerName as [Customer_Name],LS_ClientID as [Client_ID], RequestNumber as [Request_Number],CreatedBy as [Initiated By],                                    
      dbo.ReversalApprovers(Reversal_Approval_Customer_Details_ID) as [Pending with],Remarks,(select top 1 isnull(ApprovalRemark,'') ApprovalRemark  from TBL_OVI_Reversal_Aprrover  where Reversal_Approval_Customer_Details_ID = A.Reversal_Approval_Customer_Details_ID order by ApprovedDate desc            
) as Comments,                                     
      CASE                           
    when Status=10 then 'Pending'                            
      when Status=0 then 'In Progress'                                    
      when Status=1 then 'Approved'                
      when Status=2 then 'Sent Back'                
      when Status=3 then 'Rejected'                                    
      END as [Status],                                    
      FORMAT(CreatedOn,'dd/MM/yy') as [Date],LS_ClientID as ClientId                                    
      from TBL_OVI_Reversal_Approval_Customer_Details A where CreatedBy=@UserId                 
  END                     
  ELSE                                    
  BEGIN                 
  select A.Reversal_Approval_Customer_Details_ID as ID, A.CustomerName as [Customer_Name],A.LS_ClientID as [Client_ID], RequestNumber  as [Request_Number],A.CreatedBy as [Initiated By],                                    
     dbo.ReversalApprovers(A.Reversal_Approval_Customer_Details_ID) as [Pending with], A.Remarks,(select top 1 isnull(ApprovalRemark,'') ApprovalRemark  from TBL_OVI_Reversal_Aprrover  where Reversal_Approval_Customer_Details_ID = A.Reversal_Approval_Customer_Details_ID order by ApprovedDate desc            
) as Comments,                                     
      CASE                  
    when A.Status=10 then 'Pending'                                     
      when A.Status=0 then 'In Progress'                                    
      when A.Status=1 then 'Approved'                
      when A.Status=2 then 'Sent Back'                
      when A.Status=3 then 'Rejected'                               
      END as [Status],                                    
      FORMAT(A.CreatedOn,'dd/MM/yy') as [Date],LS_ClientID as ClientId                                    
      from TBL_OVI_Reversal_Approval_Customer_Details A inner join TBL_OVI_Reversal_Aprrover B on                     
      A.Reversal_Approval_Customer_Details_ID=B.Reversal_Approval_Customer_Details_ID                               
      where B.ApproverADID=@UserId and (B.Status=0)             
                    
  END                       
                
END
GO
