-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Get_ReversalApprovalCustomerDetails]                    
@CustomerId int=null,                    
@UserId varchar(50)=null                    
AS                    
BEGIN                    
   select LS_ClientID,CustomerName,ProposalNumber,Vintage,RAROC,[APR PFY] as APRPFY,[APR YTD] as APRYTD,                    
   CTI,Limit,(select EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId) as EmpRole,Status,Remarks from                   
   TBL_OVI_Reversal_Approval_Customer_Details where Reversal_Approval_Customer_Details_ID=@CustomerId                
       
   select * from TBL_OVI_Reversal_Approval_Facility_Details where Reversal_Approval_Customer_Details_ID=@CustomerId                    
      
   select * from TBL_OVI_Reversal_Approval_Reversal_Details a      
   inner join      
   TBL_OVI_ChargesType_Master b      
   on a.NatureofReversal=b.ChargesCode      
   where Reversal_Approval_Customer_Details_ID=@CustomerId                    
                  
   select Limit_OS,Reversal_Amount_Breakdown_Details_ID,FORMAT(From_Date,'dd/MM/yyyy') as From_Date,                    
   FORMAT(To_Date,'dd/MM/yyyy') as To_Date,NoOfDays, cast(Actual_Int as decimal(10,2)) Actual_Int,cast(Penal_Int_Amount as decimal(10,2)) Penal_Int_Amount,Account_No                    
   from TBL_OVI_Reversal_Amount_Breakdown_Details where Reversal_Approval_Customer_Details_ID=@CustomerId                    
                  
   select * from TBL_OVI_Reversal_Aprrover where Reversal_Approval_Customer_Details_ID=@CustomerId                    
                       
   select RequestNumber,Doc_File_Name,Doc_File_ID,CreatedBy,convert(varchar, CreatedOn, 103) as CreatedOn from TBL_OVI_Reversal_Upload_Docs where Reversal_Approval_Customer_Details_ID=@CustomerId                
            
   Select * from (select                           
   CONCAT(A.EmpCode,' - ', A.EmpName) as [username],                          
   A.EmpRole as user_role,                          
   CASE                          
    when B.Activity='Updated' then 'Response' ELSE B.Activity  End as actiontaken,B.Remark,                           
   Format(B.ActionDate,'dd/MM/yyyy HH:mm') as [Date],                 
   row_number() over(Partition by A.EmpCode order by B.ActionDate desc ) rn                        
   from TBL_OVI_RM_Hierarchy_Mapping A inner join                                           
   tbl_OVI_Log B           
   on A.EmpCode= B.ActionBy         
--   inner join TBL_OVI_Reversal_Aprrover c        
  -- on c.Reversal_Approval_Customer_Details_ID=b.CustomerId        
   where B.CustomerId=@CustomerId and  (B.Activity!='update') and B.MasterId='Reversal Approval'             
   ) a where rn=1;             
END         
  
GO
