/****** Object:  StoredProcedure [dbo].[SP_OVI_Get_TraderPricingDetails]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Get_TraderPricingDetails] 
(                                      
@TradeType varchar(150)=null                                    
,@CustomerId int = null                            
,@UserId varchar(50)=null                            
                            
)                                      
AS                                      
BEGIN                                  
 If(@TradeType='GetAll')                              
 BEGIN                              
 Declare @UserType varchar(100)=null,@fetchFor varchar(100)=null;                                
 SELECT @UserType = EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId                                
                                
  IF(@UserType  IS NULL)                                                  
   BEGIN                                                  
      IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='RM')                                                  
      BEGIN                                                  
       SET @UserType ='Relationship Manager';                                                  
      END                                                  
      ELSE IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @UserId AND UserType ='CM')                                                  
      BEGIN                                                  
       SET @UserType ='Cluster Head';                                             
      END                                                  
   END                                   
  IF(@UserType like '%Relationship Manager%')                                                
  BEGIN                             
  Select TP_Customer_Info_ID as Id,CustomerName as [Customer Name] ,ProposalNumber as [Proposal Number], RequestNumber as[Request Number]                              
  ,CreatedBy as [Initiated By],ApproverADID as [Sent To],Remark,ApproverRemark as [Comments],[Status],format(CreatedOn,'dd-MM-yyyy') as Date,ClientId                            
  from TBL_OVI_Trade_Pricing_Customer_Info where CreatedBy=@UserId                            
  End                            
  ELSE                                               
  BEGIN        

	 Select TP_Customer_Info_ID as Id,CustomerName as [Customer Name] ,ProposalNumber as [Proposal Number], RequestNumber as[Request Number]                              
         ,CreatedBy as [Initiated By],ApproverADID as [Sent To],Remark,ApproverRemark as [Comments],[Status],format(CreatedOn,'dd-MM-yyyy') as Date,ClientId                            
         from TBL_OVI_Trade_Pricing_Customer_Info                             
         where  Status IN('Pending At L2','Pending')  and  IIF(Status='Pending At L2', ApproverADID2,ApproverADID) = @UserId
 END                            
                             
 END                              
 ELSE If(@TradeType='GetCustomerDetails')                              
 BEGIN                              
 print 11                              
   Select TP_Customer_Info_ID as Id ,ProposalNumber,(select EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@UserId) as EmpRole,                               
   CustomerName , CustomerType ,[Status],PANNumber,Remark,ApproverRemark as [Comments],ApproverADID,APR_Code,APR_PFY,APR_YTD,Vintage,ClientId,ProposalNumber,CustomerType,ApproverADID2                    
   from TBL_OVI_Trade_Pricing_Customer_Info                               
   where TP_Customer_Info_ID=@CustomerId         
 END                        
 ELSE IF(@TradeType='GetTradePricingTableStatus')        
                     
 BEGIN                        
 SELECT * FROM TBL_OVI_TradePricing_Tables WHERE TradePricing_Customer_Info_Id=@CustomerId                        
 END                        
 ELSE IF(@TradeType='GetTradePricingAuditTrail')        
 BEGIN    
  Select * from     
(select             
   CONCAT(A.EmpCode,' - ', A.EmpName) as [username],            
   A.EmpRole as user_role,            
   CASE            
    when B.Activity='Updated' then 'Response'                                                      
 ELSE B.Activity  End as actiontaken,             
  -- B.Activity as actiontaken,            
   B.Remark,             
   Format(B.ActionDate,'dd/MM/yyyy HH:mm') as [Date]  ,    
   row_number() over(Partition by A.EmpCode order by B.ActionDate desc ) rn          
   from TBL_OVI_RM_Hierarchy_Mapping A inner join                             
   tbl_OVI_Log B on A.EmpCode= B.ActionBy where B.CustomerId=@CustomerId and  (B.Activity!='update') and B.MasterId='Trade Pricing'    
   ) a    
   where rn=1;      
 END    
 ELSE                              
 BEGIN                              
   select Distinct a.TBL_OVI_Trade_Pricing_Item_Master_ID as Id ,a.PricingCategory as[Pricing_Category]                                  
   ,a.ChargesAndCommission as [Charges_Commission],a.StandardPricing as [Standard_Pricing]                                  
   ,b.ExistingPrice as [Existing_Pricing], b.ProposedPrice as [Proposed_Pricing]                                  
   from TBL_OVI_Trade_Pricing_Item_Master a                                     
   left join TBL_OVI_Trade_Pricing_Proposal b                                      
  on a.TBL_OVI_Trade_Pricing_Item_Master_ID = b.TBL_OVI_Trade_Pricing_Item_Master_ID                              
  and b.TBL_OVI_Trade_Pricing_Customer_Info_ID = @CustomerId                                
  where  a.TradeType = @TradeType                                    
  END                    
END 
GO
