-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_GetApprovalStatus]     
@ApproverADId varchar(50)=null,      
@CustomerId int=null,      
@IdentFlag varchar(200)      
      
AS      
BEGIN      
  IF(@IdentFlag='check_Approver_Status')      
  BEGIN      
  SELECT Status FROM TBL_OVI_Aprrover where ApproverADID=@ApproverADId and Customer_Info_Id=@CustomerId      
  END     
  IF(@IdentFlag='check_Reversal_Approver_Status')      
  BEGIN      
  SELECT Status FROM TBL_OVI_Reversal_Aprrover where ApproverADID=@ApproverADId and Reversal_Approval_Customer_Details_ID=@CustomerId      
  END   
  IF(@IdentFlag='check_AccountCustomisation_Approver_Status')      
  BEGIN      
  SELECT Status FROM TBL_OVI_Account_Customisation_Approver where ApproverADID=@ApproverADId and Account_Customisation_Customer_Details_ID=@CustomerId      
  END   
END 
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_GetComplianceList]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE  PROCEDURE [dbo].[SP_OVI_GetComplianceList]    
@UserID AS varchar(50)    
AS    
BEGIN    
DECLARE @table2 AS TABLE (EmpID varchar(20), EmpRole varchar(20))    
    
INSERT INTO @table2 EXEC SP_OVI_GetRMListById @UserID    

SELECT 'AML' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_AML WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_CAD_Deferrals    
UNION    
SELECT 'CAD Deferrals' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_CAD_Deferrals WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_CAD_Deferrals    
UNION    
SELECT 'Call Memo' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_CallMemo WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_CallMemo    
UNION    
SELECT 'CAM Expiry' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_CAM_Expiry WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_CAM_Expiry    
UNION    
SELECT 'Deferrals' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_Deferrals WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_Deferrals    
UNION    
SELECT 'EDPMS' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_EDPMS WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_EDPMS    
UNION    
SELECT 'IDPMS' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_IDPMS WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_IDPMS    
UNION    
SELECT 'LAD' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_LAD WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_LAD    
UNION    
SELECT 'Out of Order' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_OutofOrder WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_OutofOrder    
UNION    
SELECT 'Plant And Machinery' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_PlantAndMachinery WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_PlantAndMachinery    
UNION    
SELECT 'Property Insurance' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_PropertyInsurance WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_PropertyInsurance    
UNION    
SELECT 'Stock Insurance' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_StockInsurance WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_StockInsurance    
UNION    
SELECT 'Stock Statement' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_StockStatement WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_StockStatement    
UNION    
SELECT 'UFCE' [Compliance_Item], (SELECT DISTINCT COUNT(*) FROM TBL_OVI_Compliance_UFCE WHERE RM_Code IN (SELECT EmpID FROM @Table2)) [Cnt],    
CONVERT(varchar, [ReportDate], 105) [ItemDate]    
FROM TBL_OVI_Compliance_UFCE    
WHERE RM_Code IN (SELECT EmpID FROM @table2)    
AND ReportDate <= GETDATE()    
GROUP BY CONVERT(varchar,[ReportDate],105)   
ORDER BY [Compliance_Item];    
END  
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_GetDelinquencyDashboardCount]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[SP_OVI_GetDelinquencyDashboardCount](@UserID AS varchar(50))      
AS      
BEGIN      
  Declare @percent decimal(10,2)    
  Declare @customers_count decimal(18,2)      
  DECLARE @table2 AS TABLE (                
    EmpId varchar(20),                
    EmpRole varchar(20)                
  )                
  INSERT INTO @table2 EXEC SP_OVI_GetRMListById  @UserID     
       
  --select @customers_count= count(distinct A.LSID) from TBL_OVI_Client_RM_Mapping A inner join TBL_OVI_Delinquency_new B on A.RM_ID=B.RM_Code      
  --where A.RM_ID in(SELECT                
  --  EmpId FROM @table2)      
    
  
  select @customers_count = round((isnull(SUM(B.Fund_Os + b.Non_Fund_Os),0)/10000000),2)  from TBL_OVI_Client_RM_Mapping A inner join TBL_OVI_Portfolio B on A.LSID=B.LSID      
  where A.RM_ID in(SELECT                
  EmpId FROM @table2)    
    
  select CONVERT(varchar,UploadedDate,105) as UploadedDate,  DPD_Bucket as Items,  
  COUNT(1) as [No],   
  Round((Sum(Os_In_Cr)),2) as [value],   
  --Round(((Sum(Os_In_Cr)/@customers_count)*100),2) as [Percent]  Commented By Sachin Bcoz Of Divide by Zero exception
  Round(((ISNULL(NULLIF(Sum(Os_In_Cr),@customers_count), 1))*100),2)as [Percent] 
  from TBL_OVI_Delinquency_Customer   
  where RM_Code in(SELECT                
  EmpId FROM @table2) and UploadedDate <= GETDATE()  group by DPD_Bucket,UploadedDate  
  
   
  
    
