/****** Object:  StoredProcedure [dbo].[SP_OVI_GetDelinquencyDaysCount]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE proc [dbo].[SP_OVI_GetDelinquencyDaysCount] (@UserID AS varchar(50))        
AS        
BEGIN        
  DECLARE @table2 AS TABLE (        
    EmpId varchar(20),        
    EmpRole varchar(20)        
  )        
  INSERT INTO @table2 EXEC SP_OVI_GetRMListById @UserID     
   
    SELECT     
    CONVERT(varchar,UploadedDate,105) as UploadedDate,  
    CASE    
    WHEN (Sum([15_Plus])<1 or Sum([15_Plus])=NULL) THEN '-'    
    ELSE  CAST(Sum(ISNULL([15_Plus], 0)) AS varchar)     
    END as Days_15,    
 CASE    
    WHEN Sum(ISNULL([30_Plus], 0))<1 THEN '-'    
    ELSE  CAST(Sum(ISNULL([30_Plus], 0) ) AS varchar)     
    END as Days_30,    
 CASE    
    WHEN Sum(ISNULL([60_Plus], 0))<1 THEN '-'    
    ELSE  CAST(Sum(ISNULL([60_Plus], 0)) AS varchar)     
    END as Days_60   
   
  FROM TBL_OVI_Delinquency  
  WHERE RM_Code IN (SELECT        
    EmpId        
  FROM @table2) and Date <= GETDATE()
   group by UploadedDate
        
END
GO
