-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_GetProposalApprovalDateDetails] 
@AP_Customer_Info_ID int=null

AS  
BEGIN  
  
select DATEDIFF(DAY, ApprovedDate, GETDATE()) AS daysDiff, ApprovedDate from TBL_OVI_Aprrover   
where Customer_Info_Id=@AP_Customer_Info_ID  
and LevelNumber=(select MAX(LevelNumber) from TBL_OVI_Aprrover where Customer_Info_Id=@AP_Customer_Info_ID)  
and Status=1  
  
END
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_GetRMListById]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
 

CREATE proc [dbo].[SP_OVI_GetRMListById] (  
@UserId as varchar(50) )  
AS  
Begin  
DECLARE @table1 AS TABLE (  
  ID int,  
  EmpId varchar(20),  
  EmpRole varchar(20)  
)  
  
DECLARE @table2 AS TABLE (  
  EmpId varchar(20),  
  EmpRole varchar(20)  
)  
  
DECLARE @cnt AS int = 0;  
  
SET @cnt = (SELECT  
  COUNT(*)  
FROM TBL_OVI_RM_Hierarchy_Mapping  
WHERE SupervisorCode = @UserId  
OR EmpCode = @UserId);  
INSERT INTO @table1  
  SELECT  
    @cnt,  
    EmpCode,  
    EmpRole  
  FROM TBL_OVI_RM_Hierarchy_Mapping  
  WHERE SupervisorCode = @UserId  
  OR EmpCode = @UserId;  
  
  
WHILE @cnt > 0  
BEGIN  
  DECLARE @innerCntNotRM AS int = 0;  
  DECLARE @innerCntRM AS int = 0;  
  
  INSERT INTO @table1  
    SELECT  
      @cnt + 1,  
      EmpCode,  
      EmpRole  
    FROM TBL_OVI_RM_Hierarchy_Mapping  
    WHERE SupervisorCode IN (SELECT  
      EmpId  
    FROM @table1  
    WHERE ID = @cnt)  
    AND EmpRole NOT LIKE '%Relationship Manager%';  
  SELECT  
    @innerCntNotRM = (SELECT  
      COUNT(*)  
    FROM TBL_OVI_RM_Hierarchy_Mapping  
    WHERE SupervisorCode IN (SELECT  
      EmpId  
    FROM @table1  
    WHERE ID = @cnt)  
    AND EmpRole NOT LIKE '%Relationship Manager%');  
  
  INSERT INTO @table2  
    SELECT  
      EmpCode,  
      EmpRole  
    FROM TBL_OVI_RM_Hierarchy_Mapping  
    WHERE SupervisorCode IN (SELECT  
      EmpId  
    FROM @table1  
    WHERE ID = @cnt)  
    ;  -- AND EmpRole LIKE '%Relationship Manager%'
  INSERT INTO @table2  
    SELECT  
      EmpCode,  
      EmpRole  
    FROM TBL_OVI_RM_Hierarchy_Mapping  
    WHERE EmpCode IN (SELECT  
      EmpId  
    FROM @table1  
    WHERE ID = @cnt)  
    ;  -- AND EmpRole LIKE '%Relationship Manager%'
  SELECT  
    @innerCntRM = COUNT(*)  
  FROM @table2;  
  
  SET @cnt = IIF(@innerCntNotRM != 0, @cnt + 1, 0);  
END  
  
--SELECT * FROM @table1;  
SELECT distinct  
  *  
FROM @table2;  
End
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_Getsendbackflow]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SP_OVI_Getsendbackflow]  
 -- Add the parameters for the stored procedure here  
 @CustomerId int=null,  
 @EmpCode varchar(50)= null,  
 @Role  varchar(50)= null  
   
AS  
BEGIN  
 -- SET NOCOUNT ON added to prevent extra result sets from  
 -- interfering with SELECT statements.  
 SET NOCOUNT ON;  
  
 Set @Role= (select distinct EmpRole from TBL_OVI_RM_Hierarchy_Mapping Where EmpCode=@EmpCode)  
 print @Role  
 --Declare @RoleName varchar(50)  
 declare @RoleName table  
    (  
       RoleName varchar(1000)  
    )  
  
 if(@Role='Group Head')  
 BEGIN  
    insert into @RoleName values ('Relationship Manager')  
    insert into @RoleName values ('Cluster Head')  
    insert into @RoleName values ('Circle Head')  
    insert into @RoleName values ('State Head')  
       insert into @RoleName values ('Regional Head')  
       insert into @RoleName values ('Zonal Head')  
       insert into @RoleName values ('National Head')  
       insert into @RoleName values ('Business Head')  
 END   
 ELSE IF(@Role='Business Head')  
 BEGIN  
    insert into @RoleName values ('Relationship Manager')  
    insert into @RoleName values ('Cluster Head')  
    insert into @RoleName values ('Circle Head')  
    insert into @RoleName values ('State Head')  
       insert into @RoleName values ('Regional Head')  
       insert into @RoleName values ('Zonal Head')  
       insert into @RoleName values ('National Head')  
         
 END   
  
 ELSE IF(@Role='National Head')  
 BEGIN  
    insert into @RoleName values ('Relationship Manager')  
    insert into @RoleName values ('Cluster Head')  
    insert into @RoleName values ('Circle Head')  
    insert into @RoleName values ('State Head')  
       insert into @RoleName values ('Regional Head')  
       insert into @RoleName values ('Zonal Head')  
         
         
 END   
  
 ELSE IF(@Role='Zonal Head')  
 BEGIN  
    insert into @RoleName values ('Relationship Manager')  
    insert into @RoleName values ('Cluster Head')  
    insert into @RoleName values ('Circle Head')  
    insert into @RoleName values ('State Head')  
       insert into @RoleName values ('Regional Head')  
 END  
  
 ELSE IF(@Role='Regional Head')  
 BEGIN  
    insert into @RoleName values ('Relationship Manager')  
    insert into @RoleName values ('Cluster Head')  
    insert into @RoleName values ('Circle Head')  
    insert into @RoleName values ('State Head')  
         
         
 END  
 ELSE IF(@Role='State Head')  
 BEGIN  
    insert into @RoleName values ('Relationship Manager')  
    insert into @RoleName values ('Cluster Head')  
    insert into @RoleName values ('Circle Head')  
 END  
 ELSE IF(@Role='Circle Head')  
 BEGIN  
    insert into @RoleName values ('Relationship Manager')  
    insert into @RoleName values ('Cluster Head')  
 END  
  
 ELSE IF(@Role='Cluster Head')  
 BEGIN  
    insert into @RoleName values ('Relationship Manager')  
      
 END  
 --ELSE IF(@Role='Relationship Manager')  
 --BEGIN  
 --   insert into @RoleName values ('Cluster Head')  
      
 --END  
  
   
    -- Insert statements for procedure here  
  
If(@Role ='Cluster Head')  
BEGIN  
select  
 '- Select- -' as EmpName,  
 '' as EmpCode  
 UNION  
select   
 Distinct  
 EmpName,  
 TOV.ActionBy 'EmpCode'  
 --EmpRole  
 --ID  
 From    
 TBL_OVI_log  TOV  
 Left Join TBL_OVI_RM_Hierarchy_Mapping as UM On Um.EmpCode=TOV.ActionBy-- where TOV.EmpCode='A36545'  
 where CustomerId=@CustomerId and EmpRole = 'Relationship Manager'  
END  
ELSE  
select  
 '- Select- -' as EmpName,  
 '' as EmpCode  
 UNION  
  
 select   
 Distinct  
 EmpName,  
 TOV.ActionBy 'EmpCode'  
 --EmpRole  
 --ID  
 From    
 TBL_OVI_log  TOV  
 Left Join TBL_OVI_RM_Hierarchy_Mapping as UM On Um.EmpCode=TOv.ActionBy-- where TOV.EmpCode='A36545'  
 where CustomerId=@CustomerId and EmpRole in(select RoleName from @RoleName)  
 ----where CustomerId=313 and Status=2 order by TOV.CreatedOn asc  
 ----where CustomerId=@CustomerId and Status=2  and EmpRole in(select RoleName from @RoleName)  
 ----where CustomerId=@CustomerId and Status in(1,2)  and EmpRole in(select RoleName from @RoleName)  
   
 -- by ID asc  
   
   
  
END  
GO
