CREATE PROCEDURE [dbo].[SP_OVI_GetSupervisors]   
@Empcode varchar(100)=null      
AS       
BEGIN      
Declare @level1 varchar(50),@level2 varchar(50),@level3 varchar(50),@level4 varchar(50),      
@level5 varchar(50),@level6 varchar(50),@level7 varchar(50),@level8 varchar(50),    
@l1 varchar(50),@l2 varchar(50),@l3 varchar(50),@l4 varchar(50),      
@l5 varchar(50),@l6 varchar(50),@l7 varchar(50),@l8 varchar(50)   
      
create table #Temp      
(Level1 Varchar(50),Level2 Varchar(50),Level3 Varchar(50),Level4 Varchar(50),      
Level5 Varchar(50),Level6 Varchar(50),Level7 Varchar(50),Level8 Varchar(50) )      
      
select @level1= dbo.fn_GetSupervisor(@Empcode,'Cluster Head')    
set @l1=@level1    
select @level2= dbo.fn_GetSupervisor(@level1,'Circle Head')     
set @l2=@level2    
if(@level2 is null)    
begin    
set @level2=@level1    
end    
select @level3= dbo.fn_GetSupervisor(@level2,'State Head')    
set @l3=@level3    
if(@level3 is null)    
begin    
set @level3=@level2    
end    
select @level4= dbo.fn_GetSupervisor(@level3,'Regional Head')     
set @l4=@level4    
if(@level4 is null)    
begin    
set @level4=@level3    
end    
select @level5= dbo.fn_GetSupervisor(@level4,'Zonal Head')    
set @l5=@level5    
if(@level5 is null)    
begin    
set @level5=@level4    
end    
select @level6= dbo.fn_GetSupervisor(@level5,'National Head')     
set @l6=@level6    
if(@level6 is null)    
begin    
set @level6=@level5    
end    
select @level7= dbo.fn_GetSupervisor(@level6,'Business Head')     
set @l7=@level7    
if(@level7 is null)    
begin    
set @level7=@level6   
end    
select @level8= dbo.fn_GetSupervisor(@level7,'Group Head')     
set @l8=@level8   
      
insert into #Temp values(@l1,@l2,@l3,@l4,@l5,@l6,@l7,@l8)      
      
select * from #Temp      
      
drop table #Temp      
END 
GO
