@NumberofTransactions int=null,                                
@AMBCommitment varchar(100)=null,                                
@Idenflag varchar(100),                  
@AccountNumber varchar(100)=null,                  
@ProductCode varchar(100)=null,                  
@CustomerName varchar(100)=null,                  
@CommercialTypeMain  varchar(50)=null,              
@CustomerId int=null,        
@WaiverId int=null,  
@ClientId varchar(100)=null  
AS                                   
BEGIN                             
Declare @ToName varchar(100),@customers_names varchar(100),                            
  @ReferenceNo varchar(100),@CreatedById varchar(100),@ApproverRemark varchar(max)                            
                               
  IF(@Idenflag='InsertApproverDetails')                                  
  BEGIN       
   IF EXISTS(Select * from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@Account_Customisation_Customer_Details_ID and LevelNumber=@LevelNumber)    
   BEGIN    
    UPDATE TBL_OVI_Account_Customisation_Approver SET ApproverADID=@ApproverADID                                  
      WHERE Account_Customisation_Customer_Details_ID=@Account_Customisation_Customer_Details_ID    
   and LevelNumber=@LevelNumber                                  
      select 1 as msg       
   END    
   ELSE    
   BEGIN    
    INSERT INTO TBL_OVI_Account_Customisation_Approver(Account_Customisation_Customer_Details_ID,ApproverADID,LevelNumber,                                  
    [Status],CreatedBy,CreatedOn)                                        
    VALUES(@Account_Customisation_Customer_Details_ID,@ApproverADID,@LevelNumber,@Status,@CreatedBy,GETDATE())    
     
  IF(@LevelNumber=1)                        
  BEGIN                        
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)                                          
  VALUES('Approval Request','Account Customisation Proposal Request','Proposal Sent by Relationship Manager',                                  
  'Account Customisation proposal request sent by '+@CreatedBy+'(RM) for Approval',0,@ApproverADID,@CreatedBy,GETDATE(),'/Home/Commercials')                                
                              
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag)                              
  values('Account Customisation proposal request sent by '+@CreatedBy+'(RM) for Approval',                              
  'Account Customisation proposal request sent by '+@CreatedBy+'(RM) for Approval',0,                              
  @ApproverADID,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@CreatedBy,GETDATE(),'0')         
   END    
                        
  END                        
                        
  select C.CustomerName,B.EmpEmail as ReceipientEmail,B.EmpName as ReceipentName,C.ProposalNumber,D.EmpEmail as RM_Email ,                            
   'Request' Action,A.CreatedBy                            
   into #tempAcc5                            
   from TBL_OVI_Account_Customisation_Approver A                             
   inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                             
   inner join TBL_OVI_Account_Customisation_Customer_Details C on C.Account_Customisation_Customer_Details_ID=A.Account_Customisation_Customer_Details_ID                            
  inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                              
   where A.ApproverADID=@ApproverADID and A.LevelNumber=@LevelNumber and A.Account_Customisation_Customer_Details_ID=@Account_Customisation_Customer_Details_ID                            
                            
   select @ToName=ReceipentName,@customers_names=CustomerName,@ReferenceNo=ProposalNumber,@CreatedById=CreatedBy from #tempAcc5                              
                            
   select * from #tempAcc5                            
                      
 Exec SP_OVI_GetEmailContent 'Request',@ToName,@customers_names,@ReferenceNo,@CommercialTypeMain,@CreatedById,@ApproverRemark                            
                            
 SELECT * FROM temp2                            
                            
 Drop table #tempAcc5                            
                          
                                
  END                                 
  IF(@Idenflag='InsertWaiverDetails')                                  
  BEGIN            
  IF(@CustomerId=null or @CustomerId=0)            
  BEGIN            
  IF EXISTS(select Account_Customisation_Waiver_Details_Temp_ID from TBL_OVI_Account_Customisation_Waiver_Details_temp where Account_Customisation_Waiver_Details_Temp_ID=@RowId)                    
  BEGIN                  
  update TBL_OVI_Account_Customisation_Waiver_Details_temp SET ChargesType=@ChargesType,TypeOfWaiver=@TypeOfWaiver,                     
  [Value]=@Value,NumberofTransactions=@NumberofTransactions,AMBCommitment=@AMBCommitment,AccountNumber=@AccountNumber,ProductCode=@ProductCode,  
  CustomerName=@CustomerName,ClientId=@ClientId  
  where Account_Customisation_Waiver_Details_Temp_ID=@RowId                              
  select 1 as msg                              
  END                              
  ELSE                              
  BEGIN             
  INSERT INTO TBL_OVI_Account_Customisation_Waiver_Details_temp(                                
  ChargesType,TypeOfWaiver,[Value],NumberofTransactions,AMBCommitment,AccountNumber,                  
  ProductCode,CustomerName,CreatedBy,ClientId)                                        
  VALUES(@ChargesType,@TypeOfWaiver,@Value,@NumberofTransactions,                                
  @AMBCommitment,@AccountNumber,@ProductCode,@CustomerName,@CreatedBy,@ClientId)                    
                  
  select 1 as msg              
  END            
                    
  END             
  ELSE            
  BEGIN            
  IF EXISTS(select Account_Customisation_Waiver_Details_ID from TBL_OVI_Account_Customisation_Waiver_Details where Account_Customisation_Waiver_Details_ID=@RowId)                    
  BEGIN                  
  update TBL_OVI_Account_Customisation_Waiver_Details SET ChargesType=@ChargesType,TypeOfWaiver=@TypeOfWaiver,                     
  [Value]=@Value,NumberofTransactions=@NumberofTransactions,AMBCommitment=@AMBCommitment,AccountNumber=@AccountNumber,ProductCode=@ProductCode,          
  CustomerName=@CustomerName,ClientId=@ClientId                              
  where Account_Customisation_Waiver_Details_ID=@RowId                              
  select 1 as msg                              
  END                              
  ELSE                              
  BEGIN             
  INSERT INTO TBL_OVI_Account_Customisation_Waiver_Details(Account_Customisation_Customer_Details_ID,                                
  ChargesType,TypeOfWaiver,[Value],NumberofTransactions,AMBCommitment,AccountNumber,                  
  ProductCode,CustomerName,CreatedBy,CreatedOn,ClientId)                                        
  VALUES(@CustomerId,@ChargesType,@TypeOfWaiver,@Value,@NumberofTransactions,                                
  @AMBCommitment,@AccountNumber,@ProductCode,@CustomerName,@CreatedBy,GETDATE(),@ClientId)               
                  
  select 1 as msg              
  END            
  END            
  END                   
  IF(@Idenflag='GetWaiverAccordingToAccountNumber')                  
  BEGIN              
                
  IF(@CustomerId = null or @CustomerId = 0)              
  BEGIN              
  select @CreatedBy as createdBy, COUNT(Account_Customisation_Waiver_Details_Temp_ID) as TotalCharges,AccountNumber,CustomerName,sum([Value])as totalValue                  
  from TBL_OVI_Account_Customisation_Waiver_Details_temp                  
  where CreatedBy=@CreatedBy                   
  group by AccountNumber,CustomerName                
  END              
  ELSE              
  BEGIN              
  select @CreatedBy as createdBy, COUNT(Account_Customisation_Waiver_Details_ID) as TotalCharges,AccountNumber,CustomerName,sum([Value])as totalValue                  
  from TBL_OVI_Account_Customisation_Waiver_Details                 
  where Account_Customisation_Customer_Details_ID=@CustomerId                   
  group by AccountNumber,CustomerName              
  END              
              
  END                
  IF(@Idenflag='Geteditbeforesave')                  
  BEGIN                 
  select * from TBL_OVI_Account_Customisation_Waiver_Details_temp where AccountNumber=@AccountNumber and CreatedBy=@CreatedBy                
  END             
   IF(@Idenflag='GeteditAftersave')                  
  BEGIN                 
  select * from TBL_OVI_Account_Customisation_Waiver_Details where AccountNumber=@AccountNumber and CreatedBy=@CreatedBy                
  END              
  IF(@Idenflag='Deletebeforesave')                  
  BEGIN                 
  Delete from TBL_OVI_Account_Customisation_Waiver_Details_temp where AccountNumber=@AccountNumber and CreatedBy=@CreatedBy                
   select 1 as msg                 
  END              
  IF(@Idenflag='DeleteAftersave')                  
  BEGIN                 
  Delete from TBL_OVI_Account_Customisation_Waiver_Details where AccountNumber=@AccountNumber and CreatedBy=@CreatedBy                
   select 1 as msg                 
  END           
  IF(@Idenflag='DeleteWaiverById')                  
  BEGIN                 
  Delete from TBL_OVI_Account_Customisation_Waiver_Details where Account_Customisation_Waiver_Details_ID=@WaiverId         
  END       
   IF(@Idenflag='DeleteTempRecords')                  
  BEGIN                 
  Delete from TBL_OVI_Account_Customisation_Waiver_Details_temp where CreatedBy=@CreatedBy        
  END        
END    
GO
