       INSERT INTO TBL_OVI_Collateral_Details(AP_Customer_Info_ID,SecurityType,SecurityDescription,SecurityOwner,SecurityValue,CreatedBy,CreatedOn)                                                              
          values(@AP_Customer_Info_ID,@SecurityType,@SecurityDescription,@SecurityOwner,@SecurityValue,(select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID),GETDATE())                                  
  
    
      
         
         
            
                            
                                                       
          select 1 as msg                                                       
    --END                                                      
                                                             
    END                                                            
    IF(@Idenflag='InsertMultipleBanking')                                                            
