       values(@AP_Customer_Info_ID,@FacilityType,@BankName,@Sanctioned,@Outstanding,@ROI,(select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID),GETDATE())                                       
                                                             
