        AP_Customer_Info_ID=@AP_Customer_Info_ID),GETDATE(),'/Home/Commercials',@AP_Customer_Info_ID,'AP'                   
        from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID  
                                          
     --   INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType)                                            
     --   values('Asset pricing for '+@CommercialType+' approval of '+(select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID),                                            
     --   'Asset pricing '+@CommercialType+' proposal request (Request No. AP-'+convert( varchar,@AP_Customer_Info_ID)+') sent by '        
     --+(select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID)+'(RM) for Approval',        
     --0,(select ApproverADID from TBL_OVI_Aprrover where status=0 and Customer_Info_Id=@AP_Customer_Info_ID),'/Home/Commercials',DATEADD(day, 1, Getdate()),1,                    
     --   (select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID),GETDATE(),@AP_Customer_Info_ID,'AP')     

	    INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType,ToDoListCount_Flag)                                            
        values('Asset pricing for '+@CommercialType+' approval of '+(select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID),                                            
        'Asset pricing '+@CommercialType+' proposal request (Request No. AP-'+convert( varchar,@AP_Customer_Info_ID)+') sent by '        
     +(select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID)+'(RM) for Approval',        
     0,@Id,'/Home/Commercials',DATEADD(day, 1, Getdate()),1,                    
        (select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID),GETDATE(),@AP_Customer_Info_ID,'AP','0')   
	 
         end
        select C.Customer_Name,B.EmpEmail as ReceipientEmail,B.EmpName as ReceipentName,C.Request_Number,      
  D.EmpEmail+', '+(select Y.EmpEmail from TBL_OVI_Aprrover X inner join       
  TBL_OVI_RM_Hierarchy_Mapping Y on X.ApproverADID=Y.EmpCode where X.Customer_Info_Id=@AP_Customer_Info_ID and X.LevelNumber=1) as RM_Email ,                                          
          'Request' Action,A.CreatedBy,C.CustomerType                                          
          into #temp5                                          
          from TBL_OVI_Aprrover A                          
          inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                                           
          inner join TBL_OVI_Asset_Pricing_Customer_Info C on C.AP_Customer_Info_ID=A.Customer_Info_Id                                          
          inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                                            
          where A.Status=0 and A.Customer_Info_Id=@AP_Customer_Info_ID                                          
                                               
          select @ToName=ReceipentName,@customer_name=Customer_Name,@ReferenceNo=Request_Number,@CreatedById=CreatedBy,@AssetType=CustomerType from #temp5                                            
                                               
          select * from #temp5                                          
                                              
          Exec SP_OVI_GetEmailContent 'Request',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,@ApproverRemark,'',@AssetType                                          
                                               
          SELECT * FROM temp2                                          
                                               
          Drop table #temp5         
 end         
 --else        
 --begin 
 ----Update TBL_OVI_Asset_Pricing_Customer_Info set status=0 where AP_Customer_Info_ID=@AP_Customer_Info_ID 
 --  --INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink,CustomerId,CommercialType)                                                      
 --  --     select 'Response','Asset Pricing for '+@CommercialType+' Response sent by '+                    
 --  --     (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@CreatedBy),Request_Number+' response of '+Customer_Name,                    
 --  --     0,@ApproverADID,(select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where                     
 --  --     AP_Customer_Info_ID=@AP_Customer_Info_ID),GETDATE(),'/Home/Commercials',@AP_Customer_Info_ID,'AP'                   
 --  --     from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID                                   
                                          
 --  --     INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType)                                            
 --  --     values('Asset pricing for '+@CommercialType+' Response of '+(select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID),                                            
 --  --     'Asset pricing '+@CommercialType+' proposal response (Response No. AP-'+convert( varchar,@AP_Customer_Info_ID)+') sent by '        
 --  --     +(select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID)+'(RM) for Approval',        
 --  --      0,@ApproverADID,'/Home/Commercials',DATEADD(day, 1, Getdate()),1,                    
 --  --     (select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID),GETDATE(),@AP_Customer_Info_ID,'AP')        
          
 --select 1 as msg        
 --end        
        
 end   
      --end
 else        
 begin        
  INSERT INTO TBL_OVI_Aprrover(CommercialType,Customer_Info_Id,ApproverADID,LevelNumber,Status,CreatedBy,CreatedOn)                                
  VALUES(@CommercialType,@AP_Customer_Info_ID,@ApproverADID,@LevelNumber,@Status,(select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID),GETDATE())                  
         
  if(@EmpRole='Relationship Manager')                    
  begin                    
     IF(@LevelNumber=1)                                    
     BEGIN                       
        update TBL_OVI_ToDoList set Status=1 where CustomerId=@AP_Customer_Info_ID and CommercialType='AP'                    
        update TBL_OVI_Notification set Status=2 where CustomerId=@AP_Customer_Info_ID and CommercialType='AP'                     
                        
        INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink,CustomerId,CommercialType)                                                      
        select 'Approval Request','Asset Pricing for '+@CommercialType+' approval sent by '+                    
        (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@CreatedBy),Request_Number+' request of '+Customer_Name,                    
        0,@ApproverADID,(select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where                     
        AP_Customer_Info_ID=@AP_Customer_Info_ID),GETDATE(),'/Home/Commercials',@AP_Customer_Info_ID,'AP'                   
        from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID                                   
                                          
        INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType,ToDoListCount_Flag)                                            
        values('Asset pricing for '+@CommercialType+' approval of '+(select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID),                                            
        'Asset pricing '+@CommercialType+' proposal request (Request No. AP-'+convert( varchar,@AP_Customer_Info_ID)+') sent by '        
        +(select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID)+'(RM) for Approval',        
         0,@ApproverADID,'/Home/Commercials',DATEADD(day, 1, Getdate()),1,                    
        (select CreatedBy from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID),GETDATE(),@AP_Customer_Info_ID,'AP','0')        
          
          --IF NOT EXISTS(Select * from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@AP_Customer_Info_ID)                   
          --BEGIN              
          select C.Customer_Name,B.EmpEmail as ReceipientEmail,B.EmpName as ReceipentName,C.Request_Number,D.EmpEmail as RM_Email ,                                          
          'Request' Action,A.CreatedBy,c.CustomerType                                          
          into #temp6                                          
          from TBL_OVI_Aprrover A                                           
          inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                                           
          inner join TBL_OVI_Asset_Pricing_Customer_Info C on C.AP_Customer_Info_ID=A.Customer_Info_Id                                          
          inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                                            
          where A.LevelNumber=1 and A.Customer_Info_Id=@AP_Customer_Info_ID                                          
                                               
          select @ToName=ReceipentName,@customer_name=Customer_Name,@ReferenceNo=Request_Number,@CreatedById=CreatedBy,@AssetType=CustomerType from #temp6                                            
                                               
          select * from #temp6                                          
                                              
          Exec SP_OVI_GetEmailContent 'Request',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,@ApproverRemark,'',@AssetType                                          
                                               
          SELECT * FROM temp2                                          
                                               
          Drop table #temp6            
      --END        
                                      
     END                         
  end         
         
 end        
                                               
                                                         
 END    
 End
