CREATE PROCEDURE [dbo].[SP_OVI_Insert_Other_Reversal_Approval]                      
@Reversal_Approval_Customer_Details_ID int=null,                          
@NatureofReversal varchar(100) =null,                          
@AmountofReversal float=null,                          
@Limit_OS float=null,                          
@From_Date datetime =null,                          
@To_Date datetime =null,                          
@NoOfDays int=null,                          
@Actual_Int float=null,                          
@Penal_Int_Amount float=null,                          
@CreatedBy varchar(50)=null,                          
@FacilityDetails VARCHAR(100)=NULL,                          
@Amount FLOAT=NULL,                          
@ApproverADID varchar(50)=null,                          
@LevelNumber int=null,                          
@Status int=null,                        
@RowId int=null,                        
@Idenflag varchar(100)=null,                
@CommercialTypeMain  varchar(50)=null,  
@Base_Reversal_Amount FLOAT=NULL,        
@Percentage  FLOAT=NULL,                   
@Reversal_Remark VARCHAR(500)=NULL  ,
@Account_No VARCHAR(15)=NULL,
@EmpRole VARCHAR(25)=NULL
AS                          
BEGIN                 
  Declare @ToName varchar(100),@customer_name varchar(100),                  
  @ReferenceNo varchar(100),@CreatedById varchar(100),@ApproverRemark varchar(max)  ,@ApproveADIdName varchar(100)    
    select @ApproveADIdName= EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@CreatedBy
  IF(@Idenflag='InsertReversalDetails')                          
  BEGIN                          
  --IF EXISTS(select Reversal_Approval_Reversal_Details_ID from TBL_OVI_Reversal_Approval_Reversal_Details where Reversal_Approval_Reversal_Details_ID=@RowId)                        
  --BEGIN                        
  --UPDATE TBL_OVI_Reversal_Approval_Reversal_Details SET NatureofReversal=@NatureofReversal,                        
  --AmountofReversal=@AmountofReversal WHERE Reversal_Approval_Reversal_Details_ID=@RowId                        
  --select 1 as Msg                         
  --END                        
  --ELSE                        
  --BEGIN                        
  INSERT INTO TBL_OVI_Reversal_Approval_Reversal_Details(Reversal_Approval_Customer_Details_ID,                          
  NatureofReversal,AmountofReversal,Base_Reversal_Amount,Percentage,Remark,CreatedBy,CreatedOn)                          
  VALUES(@Reversal_Approval_Customer_Details_ID,@NatureofReversal,@AmountofReversal,@Base_Reversal_Amount,@Percentage,@Reversal_Remark,@CreatedBy,GETDATE())                        
  select 1 as Msg                          
  --END                        
   
  END                          
  IF(@Idenflag='InsertReversalAmountBreakdown')                          
  BEGIN                         
  --IF EXISTS(select Reversal_Amount_Breakdown_Details_ID from TBL_OVI_Reversal_Amount_Breakdown_Details where Reversal_Amount_Breakdown_Details_ID=@RowId)                        
  --BEGIN                        
  --UPDATE TBL_OVI_Reversal_Amount_Breakdown_Details SET Limit_OS=@Limit_OS,From_Date=@From_Date,To_Date=@To_Date,                        
  --NoOfDays=@NoOfDays,Actual_Int=@Actual_Int, Penal_Int_Amount=@Penal_Int_Amount WHERE Reversal_Amount_Breakdown_Details_ID=@RowId                        
                        
  --select 1 as Msg                         
                        
  --END                        
  --ELSE                        
  --BEGIN                        
  INSERT INTO TBL_OVI_Reversal_Amount_Breakdown_Details(Reversal_Approval_Customer_Details_ID,                          
  Limit_OS,From_Date,To_Date,NoOfDays,Actual_Int,Penal_Int_Amount,Account_No,CreatedBy,CreatedOn)                          
  VALUES(@Reversal_Approval_Customer_Details_ID,@Limit_OS,@From_Date,@To_Date,@NoOfDays,@Actual_Int,                          
  @Penal_Int_Amount,@Account_No,@CreatedBy,GETDATE())                         
  select 1 as Msg                         
  --END                        
                          
  END                          
  IF(@Idenflag='InsertReversal_FacilityDetails')                          
  BEGIN                   
  --IF EXISTS(select Reversal_Approval_Facility_Details_ID from TBL_OVI_Reversal_Approval_Facility_Details where Reversal_Approval_Facility_Details_ID=@RowId)                  
  --BEGIN                  
  -- UPDATE TBL_OVI_Reversal_Approval_Facility_Details SET FacilityDetails=@FacilityDetails,                        
  --Amount=@Amount WHERE Reversal_Approval_Facility_Details_ID=@RowId                        
  --END                  
  --ELSE                  
  --BEGIN                  
  INSERT INTO TBL_OVI_Reversal_Approval_Facility_Details(Reversal_Approval_Customer_Details_ID,FacilityDetails,Amount,CreatedBy,CreatedOn)                          
  VALUES(@Reversal_Approval_Customer_Details_ID,@FacilityDetails,@Amount,@CreatedBy,GETDATE())                  
  --END                 
                          
  select 1 as Msg                          
                          
  END                          
  IF(@Idenflag='Insert_Reversal_ApproverDetails')                          
  BEGIN                         
  --IF EXISTS(Select * from TBL_OVI_Reversal_Aprrover where Reversal_Approval_Customer_Details_ID=@Reversal_Approval_Customer_Details_ID and LevelNumber=@LevelNumber)                        
  --BEGIN                         
  --UPDATE TBL_OVI_Reversal_Aprrover SET ApproverADID=@ApproverADID                         
  --WHERE Reversal_Approval_Customer_Details_ID=@Reversal_Approval_Customer_Details_ID and LevelNumber=@LevelNumber                        
                        
  --select 1 as Msg                          
  --END                        
  --ELSE                        
  --BEGIN                        
                        
  INSERT INTO TBL_OVI_Reversal_Aprrover(Reversal_Approval_Customer_Details_ID,ApproverADID,LevelNumber,                          
  Status,CreatedBy,CreatedOn)                          
  values(@Reversal_Approval_Customer_Details_ID,@ApproverADID,@LevelNumber,@Status,@CreatedBy,GETDATE())              
  
  IF(@LevelNumber=1 and  @EmpRole='Relationship Manager')                
  BEGIN 
 -- @ApproveADIdName
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)                                
  VALUES('Approval Request','Reversal Approval Proposal Request','Proposal Sent by Relationship Manager',                        
  'Reversal Approval proposal request sent by '+@ApproveADIdName+'('+@CreatedBy+') for Approval',0,@ApproverADID,@CreatedBy,GETDATE(),'/Home/Commercials')                      
                    
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag,CustomerId,CommercialType)                    
  values('Reversal Approval proposal request sent by '+@ApproveADIdName+'('+@CreatedBy+') for Approval',                    
  'Reversal Approval proposal request sent by '+@ApproveADIdName+'('+@CreatedBy+') for Approval',0,                    
  @ApproverADID,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@CreatedBy,GETDATE(),'0',@Reversal_Approval_Customer_Details_ID,'RA')          
       
  END               
                          
  select C.CustomerName,B.EmpEmail as ReceipientEmail,B.EmpName as ReceipentName,C.ProposalNumber,D.EmpEmail as RM_Email ,                  
  'Request' Action,A.CreatedBy                  
  into #temp5                  
  from TBL_OVI_Reversal_Aprrover A                   
  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                   
  inner join TBL_OVI_Reversal_Approval_Customer_Details C on C.Reversal_Approval_Customer_Details_ID=A.Reversal_Approval_Customer_Details_ID                  
  inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                    
  where A.ApproverADID=@ApproverADID and A.LevelNumber=@LevelNumber and A.Reversal_Approval_Customer_Details_ID=@Reversal_Approval_Customer_Details_ID                  
                  
  select @ToName=ReceipentName,@customer_name=CustomerName,@ReferenceNo=ProposalNumber,@CreatedById=CreatedBy from #temp5                    
                  
  select * from #temp5                  
                   
  Exec SP_OVI_GetEmailContent 'Request',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,@ApproverRemark                 
  SELECT * FROM temp2                  
                  
  Drop table #temp5                  
  --END                     
  END                          
END
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_LinkMaster]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SP_OVI_LinkMaster](              
@Action varchar(50),              
@Name varchar(100)=null,              
@Link varchar(500)=null,              
@Link_Description varchar(max)=null,              
@RecordId int =null,
@IsFrequentlyUsed int=null,
@CreatedBy varchar(100)=null  
)              
AS              
BEGIN              
 IF(@Action = 'AddEdit')              
 BEGIN              
   IF NOT EXISTS(select RecordId from TBL_OVI_LinkMaster where RecordId = @RecordId)              
   BEGIN              
   INSERT INTO TBL_OVI_LinkMaster (              
    Name              
    ,Link              
    ,Link_Description              
    ,CreatedOn
	,IsFrequentlyUsed
	,CreatedBy
   )VALUES              
   (              
    @Name              
    ,@Link              
    ,@Link_Description              
    ,GETDATE()
	,@IsFrequentlyUsed
	,@CreatedBy
   )              
          
   SET @RecordId = SCOPE_IDENTITY();          
   select @RecordId as RecordId;          
   END              
   ELSE              
   BEGIN              
  UPDATE TBL_OVI_LinkMaster               
  SET Name = @Name               
  ,Link = @Link              
  ,Link_Description = @Link_Description,
         IsFrequentlyUsed=@IsFrequentlyUsed       
  where RecordId = @RecordId              
          
  select @RecordId as RecordId;          
   END              
 END              
 ELSE IF(@Action = 'Delete')              
 BEGIN              
  DELETE FROM TBL_OVI_LinkMaster where RecordId = @RecordId         
  Select 'RecordDeleted' as Msg;        
 END              
 ELSE IF(@Action ='getAll')              
 BEGIN              
  select * FROM TBL_OVI_LinkMaster   
  select * from TBL_OVI_LinkMaster where IsFrequentlyUsed=1  
 END       
 ELSE IF(@Action ='getBySearch')      
 BEGIN      
 select * from TBL_OVI_LinkMaster where [Name] like '%'+@Name+'%'   
 select * from TBL_OVI_LinkMaster where IsFrequentlyUsed=1  
 END      
 ELSE IF(@Action ='isUrlExists')              
 BEGIN        
   IF EXISTS(select RecordId FROM TBL_OVI_LinkMaster where RecordId != @RecordId and Link = @Link)          
   BEGIN          
   select 'Exists' as Msg;          
   END          
   ELSE          
   BEGIN          
  select 'NotExists' as Msg;          
   END          
 END            
END
GO
