/****** Object:  StoredProcedure [dbo].[SP_OVI_PortFolioData]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_PortFolioData]
	@IdentFlag varchar(50) = null,
	@CM_Code varchar(20) = null,
	@DelqFlag varchar(10) = null,
	@SelectedDate Datetime =null
AS
BEGIN


DECLARE @EndDate DATE
DECLARE @StartDate DATE
DECLARE @EndDate1 DATE
DECLARE @StartDate1 DATE
--DECLARE @EndDate1 DATE
--DECLARE @StartDate1 DATE

--SET @EndDate = dateadd(month, datediff(month,0, @SelectedDate)-6,0);
--SET @StartDate = DATEADD(month, - 6, @EndDate)

SET @EndDate = dateadd(month, datediff(month,0, CONVERT(varchar, @SelectedDate, 23))-6,0);
SET @StartDate = DATEADD(month, - 1, cast(CONVERT(varchar, @SelectedDate, 23) as date))

--SET @EndDate1 = dateadd(month, datediff(month,0, CONVERT(varchar, @SelectedDate, 23))-6,0);
--SET @StartDate1 = DATEADD(month, - 1, cast(CONVERT(varchar, @SelectedDate, 23) as date))

;WITH cte AS
(
    SELECT  @EndDate AS num
    UNION ALL
    SELECT  dateadd(mm, 1, num)
    FROM    cte
    WHERE dateadd(mm, 1, num) <= @StartDate
)
SELECT  
        datename(month, num) as MonthName
FROM    cte 
order by month(num) asc

	if(@IdentFlag ='PortfolioPageData')
	BEGIN

		--Segment
		select  Segment,sCount No,CAST(Appr/100As decimal(17,2)) ApprLmt,CAST(Disbursed/100 As decimal(17,2)) Disbursed 
		from
		(
			Select Segment,Count(Segment) sCount, Sum(CAST([Disbursed Limits In L] As decimal(17,2))) Appr,Sum(CAST([Uti In L] As decimal(17,2))) Disbursed 
			from tblPortfolio 
			--where [RM Code]='M1934' 
			where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code)
			--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate
			--and FORMAT (Date, 'yyyy-MM') =FORMAT (@SelectedDate, 'yyyy-MM')
			and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			and Segment IN ('BBG','EEG','SAB','CTG','LAP','ECG','CAP MKT')
			Group By Segment
		) PortFolio



		--Summary
		Select LSID,[Name of Customer] as Name,	Segment,City,State as State,CAST([Disbursed Limits In L] as DECIMAL(17,2)) as [Exposure (In L)],u.EmpName as RM ,'Coming Soon ...' as CAM 
		
		from tblPortfolio p
		Left join UserMaster u on p.[RM Code] = u.EmpCode
		
		--where [CM Code]='M1934' and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate

		where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code) 
		--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate
		and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')

		
		--Trend

		SET @EndDate1 = dateadd(month, datediff(month,0, CONVERT(varchar, @SelectedDate, 23))-12,0);
		SET @StartDate1 = DATEADD(month, - 1, cast(CONVERT(varchar, @SelectedDate, 23) as date))

		select  MonthName,count(*) as sCount,CAST(Sum(CAST(Exposure As decimal(17,2)))/100 As decimal(17,2)) as Exposure
		from
		(
			Select FORMAT(Date,'MMMM') MonthName, [Exposure (Max of Limit & O/s)] as Exposure
			from tblPortfolio 
			where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code)
			and FORMAT(Date, 'yyyy-MM') between Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @EndDate, 105), 23) as datetime),'yyyy-MM') and Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @StartDate, 105), 23) as datetime),'yyyy-MM')
			--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate
			--where [RM Code]='M1934' 
			--where [CM Code]=@CM_Code
			--and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate
		
		) t  Group By MonthName order by MonthName asc 

		-- ABC Categories
		select  abcCategories as Categories,sCount No,CAST(Exposure/100 As decimal(17,2)) Exposure,CAST(Utilization/100 As decimal(17,2)) Utilization 
		from
		(
			Select [ABC Jan 21] abcCategories,Count([ABC Jan 21]) sCount, Sum(CAST([Disbursed Limits In L] As decimal(17,2))) Exposure,Sum(CAST([Uti In L] As decimal(17,2))) Utilization 
			from tblPortfolio 
			where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code)
			and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate
			--where [RM Code]='M1934' 
			--and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate
			Group By [ABC Jan 21]
		) abc

		--Risk Categories
		IF OBJECT_ID(N'tempdb..#temp') IS NOT NULL
		BEGIN
			DROP TABLE #temp
		END

	    create table #temp
		(
		RiskType varchar(20) null,
		BehavScore varchar(10) null,
		No varchar(10) null,
		Exposure varchar(20) null,
		Utilization varchar(20) null
		)
		insert into #temp
		select  RiskType,BehavScore,sCount No,CAST(Exposure/100 As decimal(17,2)) Exposure,CAST(Utilization/100 As decimal(17,2)) Utilization 
		from
		(
			Select case 
		
			when cast([Behav Score Jan 21] as int) >= 3 and cast([Behav Score Jan 21] as int) <= 5 then 'Medium' 
			 
				when cast([Behav Score Jan 21] as int) >= 1 and cast([Behav Score Jan 21] as int) <= 2 then 'Low' 
				when cast([Behav Score Jan 21] as int) >= 6 and cast([Behav Score Jan 21] as int) <= 10 then 'High'
			else 'NA'
			END RiskType,
			[Behav Score Jan 21] BehavScore,Count([Behav Score Jan 21]) sCount, Sum(CAST([Disbursed Limits In L] As decimal(17,2))) Exposure,Sum(CAST([Uti In L] As decimal(17,2))) Utilization 
			from tblPortfolio 
			where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code)
			and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate
			--where [RM Code]='M1934' 
			--and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate
			Group By [Behav Score Jan 21]
		) abc

		select RiskType,Sum(CAST(No As int)) As No,Sum(CAST(Exposure As decimal(17,2))) As Exposure,Sum(CAST(Utilization As decimal(17,2))) As Utilization
		from #temp
		Group By RiskType

		--Industry Wise Exposure

		select  BroadIndustry,sCount No,CAST(Disbursed/100 As decimal(17,2)) Value
		from
		(
			Select [Broad Industry] As BroadIndustry,Count([Broad Industry]) sCount, Sum(CAST([Disbursed Limits In L] As decimal(17,2))) Disbursed
			from tblPortfolio 
			where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code)
			and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
			--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate
			--where [RM Code]='M1934' 
			--and dateadd(month, datediff(month,0, Date)-6,0)>=@startdate and dateadd(month, datediff(month,0, Date)-6,0)<@EndDate
			Group By [Broad Industry]
		) PortFolio

		--Portfolio Color Code
		select Distinct cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		INNER JOIN tblPortfolio po on cc.Segment=po.Segment
		where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code)
		and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
		--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate and Type='Segment'

		--Broad Industry Color Code
		select Distinct cc.Segment,Div,BackgroundColor,HoverBackgroundColor from tbl_OVI_ColorCode cc
		INNER JOIN tblPortfolio po on cc.Segment=po.[Broad Industry]
		where ([CM Code]=@CM_Code OR [ACM Code]=@CM_Code OR [DR-ACM/RCM/UH Code] = @CM_Code OR [RM Code] = @CM_Code OR  [TH Code] = @CM_Code OR 
			[CH Code] = @CM_Code OR [ZH Code] = @CM_Code OR [RH Code] = @CM_Code)
		and FORMAT(Date, 'yyyy-MM') = Format(cast(CONVERT(VARCHAR(10), CONVERT(date, @SelectedDate, 105), 23) as datetime),'yyyy-MM')
		--and dateadd(month, 0,  cast(Date as date)) between @EndDate and @StartDate and Type='Industry'

	END
END
GO
