/****** Object:  StoredProcedure [dbo].[SP_OVI_Update_AccountCustomisation_ApproveStatus]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Update_AccountCustomisation_ApproveStatus]                           
@CustomerId int=null,                              
@Action varchar(50)=null,                            
@Remark varchar(max)=null,                            
@ApproverADId varchar(50)=null,          
@CommercialTypeMain varchar(50)=null                                
AS                              
BEGIN                            
Declare @levelNo int,@NextLevelNo int,@CreatedBy varchar(100),@Remarks varchar(max),          
@MaxLvl int,@ToName varchar(100),@customer_name varchar(100),          
  @ReferenceNo varchar(100),@CreatedById varchar(100),@ApproverRemark varchar(max) ,@NextLevelApprover varchar(100)                         
  IF(@Action='Approve')                            
  BEGIN                            
  UPDATE TBL_OVI_Account_Customisation_Approver SET Status=1,ApprovalRemark=@Remark,ApprovedDate=GETDATE()                              
  where Account_Customisation_Customer_Details_ID=@CustomerId and ApproverADID=@ApproverADId      
      
  INSERT INTO tbl_OVI_Log VALUES(@CustomerId,'Account Customisation','Approved',    
  @ApproverADId,GETDATE(),1,'Proposal Approved','',@Remark)    
                          
  select @CreatedBy=CreatedBy,@levelNo = LevelNumber from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@CustomerId and ApproverADID=@ApproverADId          
          
  IF(@levelNo=1)        
  BEGIN        
  --update TBL_OVI_Account_Customisation_Approver set Status=0 where Account_Customisation_Customer_Details_ID=@CustomerId       
   update TBL_OVI_Account_Customisation_Customer_Details set Status=0 where Account_Customisation_Customer_Details_ID=@CustomerId             
  END         
              
                 
     -- IF exists(select min(LevelNumber) from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber>@levelNo)                          
     -- BEGIN                          
     --select @NextLevelNo= (select min(LevelNumber) from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber>@levelNo)                          
     --   UPDATE TBL_OVI_Account_Customisation_Approver SET Status=0                               
     --   where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber=(@NextLevelNo)                          
                               
     --IF not exists(select ApproverADID from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber>@levelNo)                          
     --BEGIN                          
     --update TBL_OVI_Account_Customisation_Customer_Details set Status=1 where Account_Customisation_Customer_Details_ID=@CustomerId                          
     --END                          
     -- END                          
              
  select @NextLevelNo= (select min(LevelNumber) from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber>@levelNo)          
  select @NextLevelApprover=(select ApproverADID from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber=@NextLevelNo)                      
               
          
     select @MaxLvl=(select max(LevelNumber) from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@CustomerId)          
          
 IF(@MaxLvl=@levelNo)          
 BEGIN          
          
 update TBL_OVI_Account_Customisation_Customer_Details set Status=1 where Account_Customisation_Customer_Details_ID=@CustomerId            
         
 INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)                    
 values('Supervisor approve the request','Supervisor approved Account Customisation proposal',                 
 'Proposal Approved','Account Customisation proposal Approved by '+@ApproverADId+' - L'+cast(@levelNo as varchar(100))+' Approver.',0,@CreatedBy,@ApproverADId,GETDATE(),'/Home/Commercials')     
     
      
        
 select C.CustomerName,D.EmpEmail as ReceipientEmail,D.EmpName as ReceipentName,          
 C.ProposalNumber,B.EmpEmail as RM_Email,dbo.Get_CC_EmailID(@CustomerId,@levelNo,'Approved','AccountType') as CCEmailId,'Approved' Action,A.ApproverADID          
 into #tempAcc1          
 from TBL_OVI_Account_Customisation_Approver A           
 inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode           
 inner join TBL_OVI_Account_Customisation_Customer_Details C on C.Account_Customisation_Customer_Details_ID=A.Account_Customisation_Customer_Details_ID          
 inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode            
 where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Account_Customisation_Customer_Details_ID=@CustomerId          
           
 select @ToName=ReceipentName,@customer_name=CustomerName,@ReferenceNo=ProposalNumber,@CreatedById=ApproverADID from #tempAcc1            
          
 select * from #tempAcc1          
          
 Exec SP_OVI_GetEmailContent 'Approved',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,''          
 SELECT * FROM temp2          
 Drop table #tempAcc1          
 END          
  ELSE          
  BEGIN          
          
  UPDATE TBL_OVI_Account_Customisation_Approver SET Status=0                           
  where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber=(@NextLevelNo)        
          
   INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)                          
   VALUES('Approval Request','Account Customisation Proposal Request','Proposal Sent by Relationship Manager',                  
  'Account Customisation proposal request sent by '+@CreatedBy+'(RM) for Approval',0,@NextLevelApprover,@ApproverADId,GETDATE(),'/Home/Commercials')         
      
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag)                  
  values('Account Customisation Proposal Request','Account Customisation proposal request sent by '+@CreatedBy+'(RM) for Approval',0,                  
  @NextLevelApprover,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0')      
       
      
  select C.CustomerName,(select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@NextLevelApprover) as ReceipentName,          
  (select EmpEmail  from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@NextLevelApprover) as ReceipientEmail,          
  C.ProposalNumber,D.EmpEmail as RM_Email,           
  dbo.Get_CC_EmailID(@CustomerId,@NextLevelNo,'Request','AccountType') as CCEmailId,'Request' Action,A.CreatedBy          
  into #tempAcc2          
  from TBL_OVI_Account_Customisation_Approver A           
  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode           
  inner join TBL_OVI_Account_Customisation_Customer_Details C on C.Account_Customisation_Customer_Details_ID=A.Account_Customisation_Customer_Details_ID          
  inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode            
  where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Account_Customisation_Customer_Details_ID=@CustomerId            
          
  select @ToName=ReceipentName,@customer_name=CustomerName,@ReferenceNo=ProposalNumber,@CreatedById=CreatedBy from #tempAcc2            
          
  select * from #tempAcc2          
          
 --@ToName varchar(100),@customer_name varchar(100),          
 -- @ReferenceNo varchar(100),@CreatedById varchar(100)          
  Exec SP_OVI_GetEmailContent 'Request',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,''          
          
          
  SELECT * FROM temp2          
          
  Drop table #tempAcc2          
  END                
                              
  END                            
  ELSE IF(@Action='Send_Back')                            
  BEGIN               
                  
  UPDATE TBL_OVI_Account_Customisation_Approver SET Status=0,ApprovalRemark=@Remark,ApprovedDate=GETDATE()                             
  where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber=1         
        
  UPDATE TBL_OVI_Account_Customisation_Approver SET Status=4,ApprovalRemark=@Remark,ApprovedDate=GETDATE()                             
  where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber>1        
          
  update TBL_OVI_Account_Customisation_Customer_Details set Status=2 where Account_Customisation_Customer_Details_ID=@CustomerId                  
            
  select @CreatedBy=CreatedBy,@levelNo = LevelNumber,@Remarks=ApprovalRemark from                   
  TBL_OVI_Account_Customisation_Approver                   
  where Account_Customisation_Customer_Details_ID=@CustomerId and ApproverADID=@ApproverADId            
        
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn)         
  select 'Supervisor sends back the request ' NotificationType,'Supervisor sends back Account Customisation proposal' Title,        
  'Proposal sent back' Subtitle,'Account Customisation proposal sent back by '+@ApproverADId+' - L'+cast(@levelNo as varchar(100))+' Approver with Remark - '+@Remarks,        
  0 ,ApproverADID, '/Home/Commercials',@ApproverADId,GETDATE()        
  from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber<@levelNo        
          
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)                    
  values('Supervisor sends back the request ','Supervisor sends back Account Customisation proposal',                    
  'Proposal sent back','Account Customisation proposal sent back by '+@ApproverADId+' - L'+cast(@levelNo as varchar(100))+' Approver with Remark - '+@Remarks,0,@CreatedBy,@ApproverADId,GETDATE(),'/Home/Commercials')                 
              
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag)                  
  values(@ApproverADId +' - L'+cast(@levelNo as varchar(100))+' sends back Account Customisation proposal with Queries - '+@Remarks,                  
  @ApproverADId+' - L'+cast(@levelNo as varchar(100))+' sends back Account Customisation proposal with Queries - '+@Remarks,0,                  
  @CreatedBy,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0')       
      
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag)                  
  select @ApproverADId +' - L'+cast(@levelNo as varchar(100))+' sends back Account Customisation proposal with Queries - '+@Remarks,                  
  @ApproverADId+' - L'+cast(@levelNo as varchar(100))+' sends back Account Customisation proposal with Queries - '+@Remarks,0,                  
  ApproverADID,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0'      
  from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber=1        
        
  INSERT INTO tbl_OVI_Log VALUES(@CustomerId,'Account Customisation','sent back',    
  @ApproverADId,GETDATE(),0,'Proposal sent back','',@Remark)    
             
  select C.CustomerName,D.EmpEmail as ReceipientEmail,D.EmpName as ReceipentName,          
  C.ProposalNumber,B.EmpEmail as RM_Email,           
  dbo.Get_CC_EmailID(@CustomerId,@levelNo,'SentBack','AccountType') as CCEmailId,'Sent Back' Action,A.ApproverADID          
  into #tempAcc3          
  from TBL_OVI_Account_Customisation_Approver A           
  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode           
  inner join TBL_OVI_Account_Customisation_Customer_Details C on C.Account_Customisation_Customer_Details_ID=A.Account_Customisation_Customer_Details_ID          
  inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode            
  where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Account_Customisation_Customer_Details_ID=@CustomerId            
          
   select @ToName=ReceipentName,@customer_name=CustomerName,@ReferenceNo=ProposalNumber,@CreatedById=ApproverADID from #tempAcc3            
          
 select * from #tempAcc3          
          
 --@ToName varchar(100),@customer_name varchar(100),          
 -- @ReferenceNo varchar(100),@CreatedById varchar(100)          
 Exec SP_OVI_GetEmailContent 'Send_Back',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById          
 SELECT * FROM temp2          
  Drop table #tempAcc3          
                
  END                              
  ELSE IF(@Action='Reject')                
  BEGIN             
                  
  UPDATE TBL_OVI_Account_Customisation_Approver SET Status=0,ApprovalRemark=@Remark                              
  where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber=1        
        
  UPDATE TBL_OVI_Account_Customisation_Approver SET Status=4,ApprovalRemark=@Remark                              
  where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber>1        
          
  update TBL_OVI_Account_Customisation_Customer_Details set Status=3 where Account_Customisation_Customer_Details_ID=@CustomerId                    
            
  select @CreatedBy=CreatedBy,@levelNo = LevelNumber,@Remarks=ApprovalRemark from                   
  TBL_OVI_Account_Customisation_Approver                   
  where Account_Customisation_Customer_Details_ID=@CustomerId and ApproverADID=@ApproverADId            
          
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn)         
  select 'Supervisor rejects the request ' NotificationType,'Supervisor rejects Account Customisation proposal' Title,        
  'Proposal rejected' Subtitle,'Account Customisation proposal rejected by '+@ApproverADId+' - L'+cast(@levelNo as varchar(100))+' Approver with Remark - '+@Remarks,        
  0,ApproverADID, '/Home/Commercials',@ApproverADId,GETDATE()        
  from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber<@levelNo        
        
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)                    
  values('Supervisor rejects the request ','Supervisor rejects Account Customisation proposal',                    
  'Proposal rejected','Account Customisation proposal rejected by '+@ApproverADId+' - L'+cast(@levelNo as varchar(100))+' Approver with Remark - '+@Remarks,0,@CreatedBy,@ApproverADId,GETDATE(),'/Home/Commercials')                  
               
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag)                  
  values(@ApproverADId +' - L'+cast(@levelNo as varchar(100))+' rejects Account Customisation proposal with comments - '+@Remarks,                  
  @ApproverADId+' - L'+cast(@levelNo as varchar(100))+' rejects Account Customisation proposal with comments - '+@Remarks,0,                  
  @CreatedBy,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0')       
        
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag)                  
  select @ApproverADId +' - L'+cast(@levelNo as varchar(100))+' rejects Account Customisation proposal with Queries - '+@Remarks,                  
  @ApproverADId+' - L'+cast(@levelNo as varchar(100))+' rejects Account Customisation proposal with Queries - '+@Remarks,0,                  
  ApproverADID,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0'      
  from TBL_OVI_Account_Customisation_Approver where Account_Customisation_Customer_Details_ID=@CustomerId and LevelNumber=1        
      
  INSERT INTO tbl_OVI_Log VALUES(@CustomerId,'Account Customisation','Rejected',    
  @ApproverADId,GETDATE(),0,'Proposal Rejected','',@Remark)    
    
  select C.CustomerName,D.EmpEmail as ReceipientEmail,D.EmpName as ReceipentName,          
    C.ProposalNumber,B.EmpEmail as RM_Email,A.ApprovalRemark,           
    dbo.Get_CC_EmailID(@CustomerId,@levelNo,'SentBack','AccountType') as CCEmailId,'Reject' Action,A.ApproverADID          
  into #temp4          
    from TBL_OVI_Account_Customisation_Approver A           
    inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode           
    inner join TBL_OVI_Account_Customisation_Customer_Details C on C.Account_Customisation_Customer_Details_ID=A.Account_Customisation_Customer_Details_ID          
    inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode            
    where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Account_Customisation_Customer_Details_ID=@CustomerId            
          
 select @ToName=ReceipentName,@customer_name=CustomerName,@ReferenceNo=ProposalNumber,@CreatedById=ApproverADID,@ApproverRemark=ApprovalRemark from #temp4            
          
 select * from #temp4          
 --@ToName varchar(100),@customer_name varchar(100),          
 -- @ReferenceNo varchar(100),@CreatedById varchar(100)          
 Exec SP_OVI_GetEmailContent 'Reject',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,@ApproverRemark          
 SELECT * FROM temp2          
          
 Drop table #temp4          
          
  END                            
                              
END  
