CREATE PROCEDURE [dbo].[SP_OVI_Update_Reversal_ApproveStatus]                                
@CustomerId int=null,                                  
@Action varchar(50)=null,                                
@Remark varchar(max)=null,                                
@ApproverADId varchar(50)=null,              
@CommercialTypeMain varchar(50)=null,
@ReceiveApprovalId varchar(50)=null,
@ReceipentName varchar(75)=null  
AS                                  
BEGIN                                
  Declare @levelNo int,@NextLevelNo int,@NextLevelApprover varchar(100),@CreatedBy varchar(100),@Remarks varchar(max),              
  @MaxLvl int,@ToName varchar(100),@customer_name varchar(100),                
  @ReferenceNo varchar(100),@CreatedById varchar(100),@ApproverRemark varchar(max),@ApproveADIdName varchar(100) ,
  @EmpRole varchar(100),@RMRole varchar(100) ,@ApproverADIdName varchar(100),@ReceiveApprovalIdName varchar(100),@ClientName varchar(100)
    select @EmpRole=EmpRole,@ApproverADIdName=EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ApproverADId
	select @RMRole = EmpRole,@ReceiveApprovalIdName=EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ReceiveApprovalId 
	select @ClientName=CustomerName from TBL_OVI_Reversal_Approval_Customer_Details where Reversal_Approval_Customer_Details_ID=@CustomerId

  IF(@Action='Approve')                                
  BEGIN                                
  UPDATE TBL_OVI_Reversal_Aprrover SET Status=1,ApprovalRemark=@Remark,ApprovedDate=GETDATE()                                   
  where Reversal_Approval_Customer_Details_ID=@CustomerId and ApproverADID=@ApproverADId         
  INSERT INTO tbl_OVI_Log VALUES(@CustomerId,'Reversal Approval','Approved',@ApproverADId,GETDATE(),1,'proposal approved','',@Remark)          
                        
  select @CreatedBy=CreatedBy,@levelNo = LevelNumber from TBL_OVI_Reversal_Aprrover where Reversal_Approval_Customer_Details_ID=@CustomerId and ApproverADID=@ApproverADId  
  select @ApproveADIdName= a.EmpName from TBL_OVI_RM_Hierarchy_Mapping a Inner join TBL_OVI_Reversal_Aprrover b
  on b.ApproverADID=a.EmpCode where b.ApproverADID=@ApproverADId

  --select * from TBL_OVI_RM_Hierarchy_Mapping
   update TBL_OVI_Reversal_Approval_Customer_Details set Status=0 where Reversal_Approval_Customer_Details_ID=@CustomerId     

                          
  IF(@levelNo=1)            
  BEGIN            
  update TBL_OVI_Reversal_Approval_Customer_Details set Status=0 where Reversal_Approval_Customer_Details_ID=@CustomerId            
  END                        
                
  select @NextLevelNo= (select min(LevelNumber) from TBL_OVI_Reversal_Aprrover where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber>@levelNo)              
  select @NextLevelApprover=(select ApproverADID from TBL_OVI_Reversal_Aprrover where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber=@NextLevelNo)               
  select @MaxLvl=(select max(LevelNumber) from TBL_OVI_Reversal_Aprrover where Reversal_Approval_Customer_Details_ID=@CustomerId)              
             
  IF(@MaxLvl=@levelNo)              
  BEGIN  
  
  --select @ApproveADIdName= a.EmpName from TBL_OVI_RM_Hierarchy_Mapping a Inner join TBL_OVI_Reversal_Approval_Customer_Details b
  --on b.CreatedBy=a.EmpCode where b.CreatedBy=(select CreatedBy from TBL_OVI_Reversal_Approval_Customer_Details where Reversal_Approval_Customer_Details_ID=@CustomerId)
            
  update TBL_OVI_Reversal_Approval_Customer_Details set Status=1 where Reversal_Approval_Customer_Details_ID=@CustomerId             
              
  --INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)                              
  --VALUES('Proposal Approved','Reversal Approval Proposal Approved','Reversal Approval Proposal Approved by supervisor',                      
  --'Reversal Approval proposal request approved by '+@ApproverADId+' .',0,@CreatedBy,@ApproverADId,GETDATE(),'/Home/Commercials')             
  --       INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)            VALUES('Approval Request','Reversal Approval Proposal Request','Proposal Sent by Relationship Manager',                      
  --'Reversal Approval proposal request sent by '+@ApproveADIdName+'('+@ApproverADId+') for Approval',0,(select CreatedBy from TBL_OVI_Reversal_Approval_Customer_Details where Reversal_Approval_Customer_Details_ID=@CustomerId),@ApproverADId,GETDATE(),'/Home/Commercials')    
           
         INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)            VALUES('Approval Request','Reversal Approval Proposal Request','Proposal Sent by Relationship Manager',                      
  'Reversal Approval proposal request ('+CONVERT(varchar(50), @CustomerId)+') has been approved.',0,(select CreatedBy from TBL_OVI_Reversal_Approval_Customer_Details where Reversal_Approval_Customer_Details_ID=@CustomerId),@ApproverADId,GETDATE(),'/Home/Commercials')    
            
  --INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag,CustomerId,CommercialType)       values('Reversal Approval proposal request sent by '+@ApproveADIdName+'('+@ApproverADId+') for Approval',                  
  --'Reversal Approval proposal request sent by '+ (select CreatedBy from TBL_OVI_Reversal_Approval_Customer_Details where Reversal_Approval_Customer_Details_ID=@CustomerId)+'(RM) for Approval',0,                  
  --(select CreatedBy from TBL_OVI_Reversal_Approval_Customer_Details where Reversal_Approval_Customer_Details_ID=@CustomerId),'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0',@CustomerId,'RA')   

  --    INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag,CustomerId,CommercialType)       values('Reversal Approval proposal request sent by '+@ApproveADIdName+'('+@ApproverADId+') for Approval',                  
  --'Reversal Approval proposal request sent by '+ @ApproveADIdName+'('+@ApproverADId+') for Approval',0,                  
  --(select CreatedBy from TBL_OVI_Reversal_Approval_Customer_Details where Reversal_Approval_Customer_Details_ID=@CustomerId),'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0',@CustomerId,'RA')   


    INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag,CustomerId,CommercialType)       values('Reversal Approval request ('+ CONVERT(varchar(50), @CustomerId)+') has been approved.',                  
  'Reversal Approval request ( '+CONVERT(varchar(50), @CustomerId)+') has been approved.',0,                  
  (select CreatedBy from TBL_OVI_Reversal_Approval_Customer_Details where Reversal_Approval_Customer_Details_ID=@CustomerId),'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0',@CustomerId,'RA')   
           
          
  select C.CustomerName,D.EmpEmail as ReceipientEmail,D.EmpName as ReceipentName,                
  C.ProposalNumber,B.EmpEmail as RM_Email,                 
  dbo.Get_ReversalApproval_CC_EmailID(@CustomerId,@levelNo,'Approved') as CCEmailId,'Approved' Action,A.ApproverADID                
  into #temp1                
  from TBL_OVI_Reversal_Aprrover A                 
  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                 
  inner join TBL_OVI_Reversal_Approval_Customer_Details C on C.Reversal_Approval_Customer_Details_ID=A.Reversal_Approval_Customer_Details_ID               
  inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                  
  where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Reversal_Approval_Customer_Details_ID=@CustomerId               
       
  select @ToName=ReceipentName,@customer_name=CustomerName,@ReferenceNo=ProposalNumber,@CreatedById=ApproverADID from #temp1                  
  select * from #temp1               
              
  Exec SP_OVI_GetEmailContent 'Approved',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,''               
                
   SELECT * FROM temp2                
   Drop table #temp1                
  END      
  


  ELSE              
  BEGIN              
  UPDATE TBL_OVI_Reversal_Aprrover SET Status=0                                 
  where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber=(@NextLevelNo)              
            
  --INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)            VALUES('Approval Request','Reversal Approval Proposal Request','Proposal Sent by Relationship Manager',                      
  --'Reversal Approval proposal request sent by '+(select CreatedBy from TBL_OVI_Reversal_Approval_Customer_Details where Reversal_Approval_Customer_Details_ID=@CustomerId)+'(RM) for Approval',0,@NextLevelApprover,@ApproverADId,GETDATE(),'/Home/Commercials')    
    INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)            VALUES('Approval Request','Reversal Approval Proposal Request','Proposal Sent by Relationship Manager',                      
  'Reversal Approval proposal request sent by '+@ApproveADIdName+'('+@ApproverADId+') for Approval',0,@NextLevelApprover,@ApproverADId,GETDATE(),'/Home/Commercials') 
            
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag,CustomerId,CommercialType)       values('Reversal Approval request sent by '+@ApproveADIdName+'('+@ApproverADId+') for '+ @ClientName,                  
  'Reversal Approval request sent by '+@ApproveADIdName+'('+@ApproverADId+') for '+ @ClientName ,0,                  
  @NextLevelApprover,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0',@CustomerId,'RA')    
    
   
  
  select C.CustomerName,(select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@NextLevelApprover) as ReceipentName,        (select EmpEmail  from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@NextLevelApprover) as ReceipientEmail,                
  C.ProposalNumber,D.EmpEmail as RM_Email,                 
  dbo.Get_ReversalApproval_CC_EmailID(@CustomerId,@NextLevelNo,'Request') as CCEmailId,'Request' Action,A.CreatedBy                
  into #temp2                
  from TBL_OVI_Reversal_Aprrover A                 
  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                 
  inner join TBL_OVI_Reversal_Approval_Customer_Details C on C.Reversal_Approval_Customer_Details_ID=A.Reversal_Approval_Customer_Details_ID                
  inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                  
  where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Reversal_Approval_Customer_Details_ID=@CustomerId              
                
  select @ToName=ReceipentName,@customer_name=CustomerName,@ReferenceNo=ProposalNumber,@CreatedById=CreatedBy from #temp2                  
                
  select * from #temp2               
                
  Exec SP_OVI_GetEmailContent 'Request',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,''                
                
                
  SELECT * FROM temp2                
                
  Drop table #temp2                
  END              
                                    
  END                                
  ELSE IF(@Action='Send_Back')                                
  BEGIN             
         IF(@RMRole='Relationship Manager') 
    BEGIN
       --UPDATE TBL_OVI_Reversal_Aprrover SET Status=0 
       --where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber=1  
	    update TBL_OVI_Reversal_Approval_Customer_Details set Status_SendBack='1' where Reversal_Approval_Customer_Details_ID=@CustomerId   
   END 
    ELSE
    BEGIN
       UPDATE TBL_OVI_Reversal_Aprrover SET Status=0     
       where Reversal_Approval_Customer_Details_ID=@CustomerId and ApproverADID=@ReceiveApprovalId
    END                         
        
  update TBL_OVI_Reversal_Approval_Customer_Details set Status=2 where Reversal_Approval_Customer_Details_ID=@CustomerId        
  update TBL_OVI_Reversal_Aprrover SET Status=4                                                       
  where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber=@levelNo                     

  update TBL_OVI_Reversal_Aprrover set ApprovalRemark=@Remark,ApprovedDate=GETDATE()                                                 where Reversal_Approval_Customer_Details_ID=@CustomerId and ApproverADID=@ApproverADId          
            
  --UPDATE TBL_OVI_Reversal_Aprrover SET Status=0,ApprovalRemark=@Remark,ApprovedDate=GETDATE()                                  
  --where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber=1            
              
  --UPDATE TBL_OVI_Reversal_Aprrover SET Status=4,ApprovalRemark=@Remark,ApprovedDate=GETDATE()                                  
  --where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber>1            
                          
  select @CreatedBy=CreatedBy,@levelNo = LevelNumber,                          
  @Remarks=ApprovalRemark from TBL_OVI_Reversal_Aprrover                           
  where Reversal_Approval_Customer_Details_ID=@CustomerId and ApproverADID=@ApproverADId              
              
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn)             
  select 'Supervisor sends back the request ' NotificationType,'Supervisor sends back Reversal Approval             
  proposal' Title,'Proposal sent back' Subtitle,'Reversal Approval proposal sent back by '+@ApproverADId+' - L'+cast(@levelNo as varchar(100))+' Approver with Remark - '+@Remarks,            
  0 ,ApproverADID, '/Home/Commercials',@ApproverADId,GETDATE()            
  from TBL_OVI_Reversal_Aprrover where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber<@levelNo           
                          
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)                          
  values('Supervisor sends back the request ','Supervisor sends back Reversal Approval proposal',                          
  'Proposal sent back','Reversal Approval proposal sent back by '+@ApproverADId+' - L'+cast(@levelNo as varchar(100))+' Approver with Remark - '+@Remarks,0,@CreatedBy,@ApproverADId,GETDATE(),'/Home/Commercials')                     
                      
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag,CustomerId,CommercialType)                    
  values(@ApproverADIdName +' - L'+cast(@levelNo as varchar(100))+' sends back Reversal Approval with Queries - '+@Remarks,                    
  @ApproverADIdName+' - L'+cast(@levelNo as varchar(100))+' sends back Reversal Approval with Queries - '+@Remarks,0,                    
  (select CreatedBy from TBL_OVI_Reversal_Approval_Customer_Details where Reversal_Approval_Customer_Details_ID=@CustomerId),'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0',@CustomerId,'RA') 
   -- insert into tbl_log_New(request,response,hittime,serviceName)Values(@levelNo,@ApproverADId,GETDATE(),'To_Do_list')   
         if(@levelNo=2 OR @levelNo=3 OR @levelNo=4 OR  @levelNo=5 OR @levelNo=6)
			begin
        --  insert into tbl_log_New(request,response,hittime,serviceName)Values(@levelNo,@ApproverADId,GETDATE(),'To_Do_list1')    


  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag,CustomerId,CommercialType)   Values                 
 ( @ReceiveApprovalIdName +' - L'+cast(@levelNo as varchar(100))+' sends back Reversal Approval with Queries - '+@Remarks,                    
  @ReceiveApprovalIdName+' - L'+cast(@levelNo as varchar(100))+' sends back Reversal Approval with Queries - '+@Remarks,0,                    
  @ReceiveApprovalId,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0',@CustomerId,'RA'  )  
  

 --- from TBL_OVI_Reversal_Aprrover where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber=1--   and ApproverADID=@ApproverADId       
   --- insert into tbl_log_New(request,response,hittime,serviceName)Values(@levelNo,@ApproverADId,GETDATE(),'To_Do_list2')
	end
          
 --- INSERT INTO tbl_OVI_Log VALUES(@CustomerId,'Reversal Approval','Sent back',@ApproverADId,GETDATE(),2,'Sent back','',@Remarks)          
                
  select C.CustomerName,b.EmpEmail as ReceipientEmail,b.EmpName as ReceipentName,             
  C.ProposalNumber,E.EmpEmail as RM_Email,                   
   dbo.Get_ReversalApproval_CC_EmailID(@CustomerId,@levelNo,'SentBack') as CCEmailId,'Sent Back' Action,A.ApproverADID ,A.ApprovalRemark 
  into #temp3                
  from TBL_OVI_Reversal_Aprrover A                 
  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                 
  inner join TBL_OVI_Reversal_Approval_Customer_Details C on C.Reversal_Approval_Customer_Details_ID=A.Reversal_Approval_Customer_Details_ID                
  inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode   
    inner join TBL_OVI_RM_Hierarchy_Mapping E on C.CreatedBy=E.EmpCode
  where A.ApproverADID=@ReceiveApprovalId  and A.Reversal_Approval_Customer_Details_ID=@CustomerId    -- and A.LevelNumber=@levelNo and A.Reversal_Approval_Customer_Details_ID=@CustomerId                
                
  select @ToName=@ReceipentName,@customer_name=CustomerName,@ReferenceNo=ProposalNumber,@CreatedById=ApproverADID,@ApproverRemark=ApprovalRemark from #temp3                  
                
  select * from #temp3                
               
  Exec SP_OVI_GetEmailContent 'Send_Back',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,@ApproverRemark,@ApproverADId               
  SELECT * FROM temp2                
  Drop table #temp3                  
  END    
 ELSE IF(@Action='Reject')                                
  BEGIN                                
             
  UPDATE TBL_OVI_Reversal_Aprrover SET Status=0,ApprovalRemark=@Remark,ApprovedDate=GETDATE()                                  
  where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber=1            
              
  UPDATE TBL_OVI_Reversal_Aprrover SET Status=4,ApprovalRemark=@Remark,ApprovedDate=GETDATE()                                  
  where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber>1            
            
                             
  update TBL_OVI_Reversal_Approval_Customer_Details set Status=3 where Reversal_Approval_Customer_Details_ID=@CustomerId                          
                          
  select @CreatedBy=CreatedBy,@levelNo = LevelNumber,                          
  @Remarks=ApprovalRemark from TBL_OVI_Reversal_Aprrover                           
  where Reversal_Approval_Customer_Details_ID=@CustomerId and ApproverADID=@ApproverADId            
              
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn)             
  select 'Supervisor rejects the request ' NotificationType,'Supervisor rejects Reversal Approval proposal' Title,            
  'Proposal rejected' Subtitle,'Reversal Approval proposal rejected by '+@ApproverADId+' - L'+cast(@levelNo as varchar(100))+' Approver with Remark - '+@Remarks,            
  0,ApproverADID, '/Home/Commercials',@ApproverADId,GETDATE()            
  from TBL_OVI_Reversal_Aprrover where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber<@levelNo            
                            
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)                          
  values('Supervisor rejects the request','Supervisor rejects Reversal Approval proposal',                          
  'Proposal rejected','Reversal Approval proposal rejected by '+@ApproverADId+' - L'+cast(@levelNo as varchar(100))+' Approver with Remark - '+@Remarks,0,@CreatedBy,@ApproverADId,GETDATE(),'/Home/Commercials')                       
                     
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag,CustomerId,CommercialType)                    
  values(@ApproverADId +' - L'+cast(@levelNo as varchar(100))+' rejects Reversal Approval with comments - '+@Remarks,                    
  @ApproverADId+' - L'+cast(@levelNo as varchar(100))+' rejects Reversal Approval with comments - '+@Remarks,0,                    
  @CreatedBy,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0',@CustomerId,'RA')  

   --         if(@levelNo=1)
			--begin
			--  insert into tbl_log_New(request,response,hittime,serviceName)Values(@levelNo,@ApproverADId,GETDATE(),'To_Do_list1')
			   if(@levelNo=2 OR @levelNo=3 OR @levelNo=4 OR  @levelNo=5 OR @levelNo=6)
			begin
			  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,ToDoListCount_Flag,CustomerId,CommercialType)                    
  select @ApproverADId +' - L'+cast(@levelNo as varchar(100))+' rejects Reversal Approval with comments - '+@Remarks,                    
  @ApproverADId+' - L'+cast(@levelNo as varchar(100))+' rejects Reversal Approval with comments - '+@Remarks,0,                    
  ApproverADID,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'0',@CustomerId,'RA'          
  from TBL_OVI_Reversal_Aprrover where Reversal_Approval_Customer_Details_ID=@CustomerId and LevelNumber=1
			end
			
  -- and ApproverADID=@ApproverADId         
                
    --- INSERT INTO tbl_OVI_Log VALUES(@CustomerId,'Reversal Approval','Rejected',@ApproverADId,GETDATE(),3,'Rejected','',@Remarks)          
          
  select C.CustomerName,D.EmpEmail as ReceipientEmail,D.EmpName as ReceipentName,                
  C.ProposalNumber,B.EmpEmail as RM_Email,A.ApprovalRemark,                 
  dbo.Get_ReversalApproval_CC_EmailID(@CustomerId,@levelNo,'SentBack') as CCEmailId,'Reject' Action,A.ApproverADID                
  into #temp4                
  from TBL_OVI_Reversal_Aprrover A                 
  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                 
  inner join TBL_OVI_Reversal_Approval_Customer_Details C on C.Reversal_Approval_Customer_Details_ID=A.Reversal_Approval_Customer_Details_ID                
  inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                  
  where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Reversal_Approval_Customer_Details_ID=@CustomerId               
                
  select @ToName=ReceipentName,@customer_name=CustomerName,@ReferenceNo=ProposalNumber,@CreatedById=ApproverADID,@ApproverRemark=ApprovalRemark from #temp4                  
                
  select * from #temp4                
               
  Exec SP_OVI_GetEmailContent 'Reject',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,@ApproverRemark                
  SELECT * FROM temp2                
                
  Drop table #temp4               
  END                                
                                  
END
GO
