CREATE PROCEDURE [dbo].[SP_OVI_UpdateApproveStatus]                                                                  
@CustomerId int=null,                                                                    
@Action varchar(50)=null,                                                                  
@Remark varchar(max)=null,                                                                  
@ApproverADId varchar(50)=null,                                                    
@CommercialTypeMain varchar(50)=null,            
@ReceiveApprovalId varchar(50)=null,             
@ReceipentName varchar(50)=null   
AS                                                                    
BEGIN  
   Declare @levelNo int,@NextLevelNo int,@NextLevelApprover varchar(100),@CommercialType varchar(100),                                        
  @CreatedBy varchar(100),@Remarks varchar(max),@MaxLvl int,@ToName varchar(100),@customer_name varchar(100),                                        
  @ReferenceNo varchar(100),@CreatedById varchar(100),@ApproverRemark varchar(max),@EmpRole varchar(100),@AssetType varchar(100) ,@RMRole varchar(100)  ,@Prop_Status int               

  select @EmpRole=EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ApproverADId

     select @Prop_Status=[Status] from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId  

  select @RMRole = EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ReceiveApprovalId --Relationship Manager
  --Declare @levelNo int,@NextLevelNo int,@NextLevelApprover varchar(100),@CommercialType varchar(100),                                                    
  --@CreatedBy varchar(100),@Remarks varchar(max),@MaxLvl int,@ToName varchar(100),@customer_name varchar(100),                                                    
  --@ReferenceNo varchar(100),@CreatedById varchar(100),@ApproverRemark varchar(max),@EmpRole varchar(100),@AssetType varchar(100)                                   
                                    
  --select @EmpRole=EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ApproverADId                                  
                                  
  IF(@Action='Approve')                                                                  
  BEGIN            
 if(@EmpRole='Operation Module')        
 begin      
 Update TBL_OVI_Asset_Pricing_Customer_Info set Operation_Status='2' where AP_Customer_Info_ID=@CustomerId        
   select @MaxLvl=(select max(LevelNumber) from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId)           
   select @CommercialType= CommercialType,@CreatedBy=CreatedBy from TBL_OVI_Aprrover     where Customer_Info_Id=@CustomerId                
insert TBL_OVI_Aprrover (CommercialType,Customer_Info_Id,ApproverADID,LevelNumber,Status,ApprovedDate,ApprovalRemark,CreatedBy,CreatedOn)Values(@CommercialType,@CustomerId,@ApproverADId,@MaxLvl+1,1,GETDATE(),@Remark,@CreatedBy,GETDATE())        
  UPDATE TBL_OVI_Aprrover SET Status=1,ApprovalRemark=@Remark,ApprovedDate=GETDATE()                                                                     
  where Customer_Info_Id=@CustomerId and ApproverADID=@ApproverADId                                   
                                    
  update TBL_OVI_ToDoList set Status=1 where CustomerId=@CustomerId and CommercialType='AP'                                  
                                  
  update TBL_OVI_Notification set Status=2 where CustomerId=@CustomerId and CommercialType='AP'                                  
                                                
                                                  
  INSERT INTO tbl_OVI_Log VALUES(@CustomerId,'Asset Pricing','Accept',@ApproverADId,GETDATE(),1,'Approved','',@Remark)                                              
                                                          
  select @CommercialType= CommercialType,@CreatedBy=CreatedBy,@levelNo = LevelNumber from TBL_OVI_Aprrover                                                         
  where Customer_Info_Id=@CustomerId and ApproverADID=@ApproverADId                                                    
                                                    
  select @NextLevelNo= (select min(LevelNumber) from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId and LevelNumber>@levelNo and Status=4)                                                    
  select @NextLevelApprover=(select ApproverADID from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId and LevelNumber=@NextLevelNo and Status=4)                                                                
                                                  
  IF(@levelNo=1)              
  BEGIN                                                  
  update TBL_OVI_Asset_Pricing_Customer_Info set Status=0 where AP_Customer_Info_ID=@CustomerId                                                  
  END                         
                                                   
                                                  
  --INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)                                                        
  --values('Supervisor approve the request','Supervisor approved asset pricing proposal',                                                        
  --'Proposal Approved','Asset pricing '+@CommercialType+                                                        
  --' proposal Approved by '+@ApproverADId+' - L '+cast(@levelNo as varchar(100))+' Approver.',0,@CreatedBy,@ApproverADId,GETDATE(),'/Home/Commercials')                                                        
            
                           
                                                                 
  select @MaxLvl=(select max(LevelNumber) from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId)                            
                                                    
 if(@MaxLvl=@levelNo)                           
 BEGIN                                                   
                                                  
 --update TBL_OVI_Asset_Pricing_Customer_Info set Status=1,Operation_Status='1' where AP_Customer_Info_ID=@CustomerId                                                  
                                    
