  from TBL_OVI_Aprrover A inner join TBL_OVI_Asset_Pricing_Customer_Info B on A.Customer_Info_Id=B.AP_Customer_Info_ID                                 
  where A.Customer_Info_Id=@CustomerId and A.LevelNumber=@levelNo                                
                                  
   INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn,CustomerId,CommercialType)                                                
  select 'Proposal Accept','Asset Pricing for '+@CommercialType+' request Accept by '+                                
  (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ApproverADId),                                                            
  B.Request_Number+' request of '+B.Customer_Name ,0,A.ApproverADID,'/Home/Commercials',@ApproverADId,GETDATE(),@CustomerId,'AP'                                                 
  from TBL_OVI_Aprrover A inner join TBL_OVI_Asset_Pricing_Customer_Info B on A.Customer_Info_Id=B.AP_Customer_Info_ID                                 
  where A.Customer_Info_Id=@CustomerId and A.LevelNumber=1                                
                                              
                                                    
 select C.Customer_Name,D.EmpEmail as ReceipientEmail,D.EmpName as ReceipentName,                                                    
 C.Request_Number,B.EmpEmail as RM_Email,C.CustomerType,                                                     
 dbo.Get_CC_EmailID(@CustomerId,@levelNo,'Approved','Asset Pricing') as CCEmailId,'Approved' Action,A.ApproverADID                                                    
 into #temp1                                                    
 from TBL_OVI_Aprrover A                          
 inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                                                     
 inner join TBL_OVI_Asset_Pricing_Customer_Info C on C.AP_Customer_Info_ID=A.Customer_Info_Id                                                    
inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                                                      
 where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Customer_Info_Id=@CustomerId                                                    
                                                     
 select @ToName=ReceipentName,@customer_name=Customer_Name,@ReferenceNo=Request_Number,@ApproverADId=ApproverADID,@AssetType=CustomerType from #temp1                                                      
                                                    
 select * from #temp1                                                    
 --@ToName varchar(100),@customer_name varchar(100),                                                    
 -- @ReferenceNo varchar(100),@CreatedById varchar(100)                                                    
 Exec SP_OVI_GetEmailContent 'Approved',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,'','',@ApproverADId,@AssetType                                                   
 SELECT * FROM temp2                                                    
 Drop table #temp1                                           
 END                                                    
 ELSE                                                
 BEGIN                                     
                                                    
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn,CustomerId,CommercialType)                                                
  select 'Approval Request','Asset pricing for '+@CommercialType+' approval recommend by '+                                
  (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ApproverADId),B.Request_Number+' request of '+B.Customer_Name ,0,                                
  @NextLevelApprover,'/Home/Commercials',@ApproverADId,GETDATE(),@CustomerId,'AP'                                                 
  from TBL_OVI_Aprrover A inner join TBL_OVI_Asset_Pricing_Customer_Info B on A.Customer_Info_Id=B.AP_Customer_Info_ID where A.Customer_Info_Id=@CustomerId and A.LevelNumber=@NextLevelNo                                                  
                                                  
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType,ToDoListCount_Flag)                                                          
  values('Asset pricing for '+@CommercialType+' approval of '+ (select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId),                                                          
  'Asset pricing '+@CommercialType+' proposal request with Request No.: AP-'+convert(varchar,@CustomerId)+' sent by '+@CreatedBy+'(RM) for Approval',0,                                                          
  @NextLevelApprover,'/Home/Commercials',DATEADD(day, 1, Getdate()),1,@ApproverADId,GETDATE(),@CustomerId,'AP','0')                                                 
                                                
                                              
  UPDATE TBL_OVI_Aprrover SET Status=0                                                                     
  where Customer_Info_Id=@CustomerId and LevelNumber=(@NextLevelNo)                                    
                                                    
  select C.Customer_Name,(select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@NextLevelApprover) as ReceipentName,                                                    
  (select EmpEmail  from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@NextLevelApprover) as ReceipientEmail,                            
  C.Request_Number,D.EmpEmail as RM_Email,C.CustomerType,                                                    
  dbo.Get_CC_EmailID(@CustomerId,@NextLevelNo,'Request','Asset Pricing') as CCEmailId,'Request' Action,A.CreatedBy                                                    
  into #temp2                                                    
  from TBL_OVI_Aprrover A                                                     
  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                                                     
  inner join TBL_OVI_Asset_Pricing_Customer_Info C on C.AP_Customer_Info_ID=A.Customer_Info_Id                                     
  inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                                                      
  where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Customer_Info_Id=@CustomerId                                                      
                                                    
                                                      
                                                    
 select @ToName=ReceipentName,@customer_name=Customer_Name,@ReferenceNo=Request_Number,@AssetType=CustomerType from #temp2                                                      
                                                    
    select * from #temp2                                                    
                                                    
 --@ToName varchar(100),@customer_name varchar(100),                                  
 -- @ReferenceNo varchar(100),@CreatedById varchar(100)                                                    
  Exec SP_OVI_GetEmailContent 'ApproverRequest',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,'','',@ApproverADId,@AssetType                                                  
                                                    
                                                    
  SELECT * FROM temp2                                                    
                                                    
 Drop table #temp2                                                    
 END       
 end  
 else      
 begin    
 
   insert into tbl_log_New(serviceName,userID,hittime)Values(CONVERT(varchar(10), @Prop_Status),'testProp_Status3',GETDATE())   
