  end
                                                          
  select @CommercialType= CommercialType,@CreatedBy=CreatedBy,@levelNo = LevelNumber from TBL_OVI_Aprrover                                                         
  where Customer_Info_Id=@CustomerId and ApproverADID=@ApproverADId                                                    
                                                    
  select @NextLevelNo= (select min(LevelNumber) from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId and LevelNumber>@levelNo and Status=4)                                                    
  select @NextLevelApprover=(select ApproverADID from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId and LevelNumber=@NextLevelNo and Status=4)                                                                
                                                  
  IF(@levelNo=1)                                                  
  BEGIN                         
  update TBL_OVI_Asset_Pricing_Customer_Info set Status=0 where AP_Customer_Info_ID=@CustomerId                                                  
  END                         
                                                   
                                                  
  --INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink)                                                        
  --values('Supervisor approve the request','Supervisor approved asset pricing proposal',                                                        
  --'Proposal Approved','Asset pricing '+@CommercialType+                                                        
  --' proposal Approved by '+@ApproverADId+' - L '+cast(@levelNo as varchar(100))+' Approver.',0,@CreatedBy,@ApproverADId,GETDATE(),'/Home/Commercials')                                                        
            
                           
                                                                 
  select @MaxLvl=(select max(LevelNumber) from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId)                            
                                                    
 if(@MaxLvl=@levelNo)                           
 BEGIN                                                   
                                                  
 update TBL_OVI_Asset_Pricing_Customer_Info set Status=1,Operation_Status='1' where AP_Customer_Info_ID=@CustomerId                                                  
                                    
 INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn,CustomerId,CommercialType)                                                
  select 'Proposal Approved','Asset Pricing for '+@CommercialType+' request approved by '+                                
  (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ApproverADId),                                           
