  from TBL_OVI_Aprrover A inner join TBL_OVI_Asset_Pricing_Customer_Info B on A.Customer_Info_Id=B.AP_Customer_Info_ID                                 
  where A.Customer_Info_Id=@CustomerId and A.LevelNumber=@levelNo                                
                                  
   INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn,CustomerId,CommercialType)                                                
  select 'Proposal Approved','Asset Pricing for '+@CommercialType+' request approved by '+                                
  (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ApproverADId),                                                            
  B.Request_Number+' request of '+B.Customer_Name ,0,A.ApproverADID,'/Home/Commercials',@ApproverADId,GETDATE(),@CustomerId,'AP'                                                 
