 dbo.Get_CC_EmailID(@CustomerId,@levelNo,'Approved','Asset Pricing') as CCEmailId,'Approved' Action,A.ApproverADID                                                    
 into #temp5                                                    
 from TBL_OVI_Aprrover A                                                     
