inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                                                      
 where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Customer_Info_Id=@CustomerId                                                    
                                                     
 select @ToName=ReceipentName,@customer_name=Customer_Name,@ReferenceNo=Request_Number,@ApproverADId=ApproverADID,@AssetType=CustomerType from #temp5                                                      
            
 select * from #temp5                                                    
 --@ToName varchar(100),@customer_name varchar(100),                                                    
