  --------------------------------------------Value Insert RM-------------------------------------------------------  
  
   INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink,CustomerId,CommercialType)                                              
