  from TBL_OVI_Aprrover A inner join TBL_OVI_Asset_Pricing_Customer_Info B on A.Customer_Info_Id=B.AP_Customer_Info_ID where A.Customer_Info_Id=@CustomerId  
  
  
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType,ToDoListCount_Flag)                                            
