  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType,ToDoListCount_Flag)                                            
  select 'Asset pricing for '+@CommercialType+' approval of '+ (select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId)+' sent back',                                            
  @ApproverADId+' sends back Asset pricing '+@CommercialType+' proposal with Queries - '+@Remarks,0,                                      
