  from TBL_OVI_Aprrover A inner join TBL_OVI_Asset_Pricing_Customer_Info B on A.Customer_Info_Id=B.AP_Customer_Info_ID where A.Customer_Info_Id=@CustomerId  
  
  
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType,ToDoListCount_Flag)                                            
  values('Asset pricing for '+@CommercialType+' approval of '+ (select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId)+' sent back',                                            
  @ApproverADId+' sends back Asset pricing '+@CommercialType+' proposal with Queries - '+@Remarks,0,                                            
  @RMRAPP,'/Home/Commercials',DATEADD(day, 1, Getdate()),1,@ApproverADId,GETDATE(),@CustomerId,'AP','0')   
  
  END  ----------------------------Hk 20072023 end  
  
  
  --INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType)                                            
  --select 'Asset pricing for '+@CommercialType+' approval of '+ (select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId)+' sent back',                                            
  --@ApproverADId+' sends back Asset pricing '+@CommercialType+' proposal with Queries - '+@Remarks,0,                                      
