  ----changing  LevelNumber=1 to ApproverADID=@ReceiveApprovalId  
    
 --ELSE IF(@RMRole !='Relationship Manager')  
 -- BEGIN  
  
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType,ToDoListCount_Flag)                                            
  select 'Asset pricing for '+@CommercialType+' approval of '+ (select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId)+' sent back',                                            
  @ApproverADId+' sends back Asset pricing '+@CommercialType+' proposal with Queries - '+@Remarks,0,                                      
  ApproverADID,'/Home/Commercials',DATEADD(day, 1, Getdate()),1,@ApproverADId,GETDATE(),@CustomerId,'AP','0'                                      
  from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId and ApproverADID=@ReceiveApprovalId   
                        
  --INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn,CustomerId,CommercialType)                                         
  --select 'Supervisor sends back the request','Asset pricing for '+@CommercialType+' approval sent back by '+                       
  --(select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ApproverADId),B.Request_Number+' request of '+B.Customer_Name,                                        
  --0 ,A.ApproverADID, '/Home/Commercials',@ApproverADId,GETDATE(),@CustomerId,'AP'                                        
  --from TBL_OVI_Aprrover A inner join TBL_OVI_Asset_Pricing_Customer_Info B on A.Customer_Info_Id=B.AP_Customer_Info_ID where A.Customer_Info_Id=@CustomerId and A.LevelNumber=1      
    
----changing  LevelNumber=1 to ApproverADID=@ReceiveApprovalId  
  
  
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn,CustomerId,CommercialType)                                         
  select 'Supervisor sends back the request','Asset pricing for '+@CommercialType+' approval sent back by '+                       
  (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ApproverADId),B.Request_Number+' request of '+B.Customer_Name,                                        
  0 ,A.ApproverADID, '/Home/Commercials',@ApproverADId,GETDATE(),@CustomerId,'AP'                                        
  from TBL_OVI_Aprrover A inner join TBL_OVI_Asset_Pricing_Customer_Info B on A.Customer_Info_Id=B.AP_Customer_Info_ID where A.Customer_Info_Id=@CustomerId and ApproverADID=@ReceiveApprovalId --A.LevelNumber=1      
    
  --END  
 END                              
                                    
  INSERT INTO tbl_OVI_Log VALUES(@CustomerId,'Asset Pricing','Sent back',@ApproverADId,GETDATE(),2,'Sent back','',@Remark)                                    
                                            
  select C.Customer_Name,D.EmpEmail as ReceipientEmail,D.EmpName as ReceipentName,                                          
  C.Request_Number,B.EmpEmail as RM_Email,C.CustomerType,A.ApprovalRemark,                                            
  dbo.Get_CC_EmailID(@CustomerId,@levelNo,'SentBack','Asset Pricing') as CCEmailId,'Sent Back' Action,A.ApproverADID                                          
  into #temp3                                          
  from TBL_OVI_Aprrover A                                           
  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                                           
  inner join TBL_OVI_Asset_Pricing_Customer_Info C on C.AP_Customer_Info_ID=A.Customer_Info_Id                                         
  inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                                            
  where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Customer_Info_Id=@CustomerId                                            
             
     
  -- select @ToName=ReceipentName,@customer_name=Customer_Name,@ReferenceNo=Request_Number,@AssetType=CustomerType,@ApproverRemark=ApprovalRemark from #temp3                                       
    select @ToName=@ReceipentName,@customer_name=Customer_Name,@ReferenceNo=Request_Number,@AssetType=CustomerType,@ApproverRemark=ApprovalRemark from #temp3                                       
                                                                      
 select * from #temp3                                          
                                          
 --@ToName varchar(100),@customer_name varchar(100),                                          
 -- @ReferenceNo varchar(100),@CreatedById varchar(100)                                          
 Exec SP_OVI_GetEmailContent 'Send_Back',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,'',@ApproverRemark,@ApproverADId,@AssetType                                         
 SELECT * FROM temp2                                          
  Drop table #temp3                                          
  END                                                        
  ELSE IF(@Action='Reject')                                                        
  BEGIN                                          
                
  select @CommercialType= CommercialType,@CreatedBy=CreatedBy,@levelNo = LevelNumber,                                              
  @Remarks=ApprovalRemark from TBL_OVI_Aprrover                                               
  where Customer_Info_Id=@CustomerId and ApproverADID=@ApproverADId               
              
  UPDATE TBL_OVI_Aprrover SET Status=0                                                         
  where Customer_Info_Id=@CustomerId and LevelNumber=1                                        
                                          
  UPDATE TBL_OVI_Aprrover SET Status=4                                
  where Customer_Info_Id=@CustomerId and LevelNumber=@levelNo                         
                        
  UPDATE TBL_OVI_Aprrover set ApprovalRemark=@Remark,ApprovedDate=GETDATE()                                            
  where Customer_Info_Id=@CustomerId and ApproverADID=@ApproverADId                       
                                        
  --UPDATE TBL_OVI_Aprrover SET Status=3,ApprovalRemark=@Remark,ApprovedDate=GETDATE()                                                         
  --where Customer_Info_Id=@CustomerId and ApproverADID=@ApproverADId                                                 
                                                  
  update TBL_OVI_Asset_Pricing_Customer_Info set Status=3 where AP_Customer_Info_ID=@CustomerId                                               
                                      
                              
                          
  update TBL_OVI_ToDoList set Status=1 where CustomerId=@CustomerId and CommercialType='AP'                        
  update TBL_OVI_Notification set Status=2 where CustomerId=@CustomerId and CommercialType='AP'                        
                                         
                                              
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,CreatedBy,CreatedOn,ActionLink,CustomerId,CommercialType)                                              
  Select distinct 'Supervisor rejects the request ','Asset pricing for '+@CommercialType+' approval rejectd by '+                      
  (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ApproverADId),B.Request_Number+' request of '+B.Customer_Name,                      
  0,A.CreatedBy,@ApproverADId,GETDATE(),'/Home/Commercials',@CustomerId,'AP' from                       
  TBL_OVI_Aprrover A inner join TBL_OVI_Asset_Pricing_Customer_Info B on A.Customer_Info_Id=B.AP_Customer_Info_ID where A.Customer_Info_Id=@CustomerId                       
                                              
  --select ApproverADID,LevelNumber into #tmp from  TBL_OVI_Aprrover where LevelNumber<@levelNo and Customer_Info_Id=@CustomerId                                             
                                            
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType,ToDoListCount_Flag)     
  values('Asset pricing for '+@CommercialType+' approval of '+ (select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId)+' rejected',                                            
  @ApproverADId+' rejects Asset pricing '+@CommercialType+' proposal with comments - '+@Remarks,0,                                            
  @CreatedBy,'/Home/Commercials',DATEADD(day, 1, Getdate()),1,@ApproverADId,GETDATE(),@CustomerId,'AP','0')                                      
                          
  if(@EmpRole!='Cluster Head')                        
  begin                        
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType,ToDoListCount_Flag)                                 
  select 'Asset pricing for '+@CommercialType+' approval of '+ (select Customer_Name from TBL_OVI_Asset_Pricing_Customer_Info where AP_Customer_Info_ID=@CustomerId)+' rejected',                                            
  @ApproverADId+' rejects  Asset pricing '+@CommercialType+' proposal with comments - '+@Remarks,0,                                            
  ApproverADID,'/Home/Commercials',DATEADD(day, 1, Getdate()),1,@ApproverADId,GETDATE(),@CustomerId,'AP','0'                                      
  from TBL_OVI_Aprrover where Customer_Info_Id=@CustomerId and LevelNumber=1                          
                      
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn,CustomerId,CommercialType)                                         
  select 'Supervisor rejects the request ','Asset pricing for '+@CommercialType+' approval rejected by '+                      
  (select EmpName from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@ApproverADId),B.Request_Number+' request of '+B.Customer_Name,                                       
  0 ,A.ApproverADID, '/Home/Commercials',@ApproverADId,GETDATE(),@CustomerId,'AP'                                        
  from TBL_OVI_Aprrover A inner join TBL_OVI_Asset_Pricing_Customer_Info B on A.Customer_Info_Id=B.AP_Customer_Info_ID                      
  where A.Customer_Info_Id=@CustomerId and A.LevelNumber=1                      
  end                        
                              
                                      
  INSERT INTO tbl_OVI_Log VALUES(@CustomerId,'Asset Pricing','Rejected',@ApproverADId,GETDATE(),2,'Rejected','',@Remark)                                    
                                             
    select C.Customer_Name,D.EmpEmail as ReceipientEmail,D.EmpName as ReceipentName,C.Request_Number,B.EmpEmail as RM_Email,A.ApprovalRemark,C.CustomerType,                                           
    dbo.Get_CC_EmailID(@CustomerId,@levelNo,'Reject','Asset Pricing') as CCEmailId,'Reject' Action,A.ApproverADID                                          
    into #temp4                                          
    from TBL_OVI_Aprrover A                                           
    inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                                           
    inner join TBL_OVI_Asset_Pricing_Customer_Info C on C.AP_Customer_Info_ID=A.Customer_Info_Id                                          
    inner join TBL_OVI_RM_Hierarchy_Mapping D on A.CreatedBy=D.EmpCode                   
    where A.ApproverADID=@ApproverADId and A.LevelNumber=@levelNo and A.Customer_Info_Id=@CustomerId                                            
                                          
 select @ToName=ReceipentName,@customer_name=Customer_Name,@ReferenceNo=Request_Number,@ApproverRemark=ApprovalRemark,@AssetType=CustomerType from #temp4                                            
                                          
 select * from #temp4                                          
 --@ToName varchar(100),@customer_name varchar(100),                                     
 -- @ReferenceNo varchar(100),@CreatedById varchar(100)                                          
 Exec SP_OVI_GetEmailContent 'Reject',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,'',@ApproverRemark,@ApproverADId,@AssetType         
       
 SELECT * FROM temp2                                          
                                          
 Drop table #temp4                                          
                                          
  END                                        
                                                          
