/****** Object:  StoredProcedure [dbo].[SP_OVI_UpdateTradePricingApprovalStatus]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_UpdateTradePricingApprovalStatus]                                
@CustomerId int=null,                                  
@Action varchar(50)=null,                                  
@Remark varchar(max)=null,                                  
@ApproverADId varchar(100)=null,                        
@CommercialTypeMain varchar(50)=null                          
                                  
AS                                  
BEGIN                                 
  Declare @CreatedBy varchar(100),@Remarks varchar(max),@ToName varchar(100),@customer_name varchar(100),                            
  @ReferenceNo varchar(100),@CreatedById varchar(100),@ApproverRemark varchar(max) ,@ChkApproverAdLevel1 varchar(10),@ChkApproverAdLevel2 varchar(10)            
        
        
      
  select @ChkApproverAdLevel1=case when ApproverADID=@ApproverADId then 'True' else  'False' end  ,      
        @ChkApproverAdLevel2= case when ApproverADID2=@ApproverADId then 'True' else  'False' end        
  from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId --and ApproverADID=@ApproverADId        
      
       
                              
  IF(@Action='Approve')                                  
  BEGIN           
      
  if (@ChkApproverAdLevel1='True' And @ChkApproverAdLevel2<>'True')      
  BEGIN                             
     UPDATE TBL_OVI_Trade_Pricing_Customer_Info SET [Status]='Pending At L2',ApproverDate=GETDATE(),ApproverRemark=@Remark                                  
     where TP_Customer_Info_ID=@CustomerId and ApproverADID=@ApproverADId      

   INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType,ToDoListCount_Flag)                                                        
        values('Trade pricing approval of '+(select CustomerName from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId),                                                        
        'Trade pricing proposal request (Request No. TP-'+convert( varchar,@CustomerId)+') sent by '                    
        +(select CreatedBy from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId)+'(RM) for Approval',                    
         0,(select ApproverADID2 from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId),'/Home/Commercials',DATEADD(day, 1, Getdate()),1,                                
    (select CreatedBy from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId),GETDATE(),@CustomerId,'TP','0')                    
                      
	                       
  END      
      
  if (@ChkApproverAdLevel2='True' ANd @ChkApproverAdLevel1<>'True')      
  BEGIN                       
     UPDATE TBL_OVI_Trade_Pricing_Customer_Info SET [Status]='Appoved',ApproverDate2=GETDATE(),ApproverRemark2=@Remark                                  
     where TP_Customer_Info_ID=@CustomerId and ApproverADID2=@ApproverADId  
	 
	  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CustomerId,CommercialType,ToDoListCount_Flag)                                                        
        values('Trade pricing approval of '+(select CustomerName from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId),                                                        
        'Trade pricing proposal request (Request No. TP-'+convert( varchar,@CustomerId)+') sent by '                    
        +(select CreatedBy from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId)+'(RM) for Approval',                    
         0,(select ApproverADID from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId),'/Home/Commercials',DATEADD(day, 1, Getdate()),1,                                
    (select CreatedBy from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId),GETDATE(),@CustomerId,'TP','0')                    
                                        
  END      
                                
  select @CreatedBy=CreatedBy from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId --and ApproverADID=@ApproverADId                                
                                  
                   
  
    IF((select Status from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId) ='Appoved' )                
   BEGIN 
  
       INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,ActionLink)                                  
       values('Supervisor approve the request','Supervisor approved Trade Pricing proposal',                                  
       'Proposal Approved','Trade Pricing proposal Approved by '+@ApproverADId+' - L1',0,@CreatedBy,'/Home/Commercials')                      
                             
         
  
        update TBL_OVI_ToDoList set Status=1 where CustomerId=@CustomerId and CommercialType='TP'        
   End
    INSERT INTO tbl_OVI_Log VALUES(@CustomerId,'Trade Pricing','Approved',@ApproverADId,GETDATE(),1,'Proposal Approved','',@Remark)

  select A.CustomerName,C.EmpEmail as ReceipientEmail,C.EmpName as ReceipentName,A.RequestNumber,                        
  B.EmpEmail as RM_Email,'Approved' Action,A.ApproverADID                        
  into #temp5                        
  from TBL_OVI_Trade_Pricing_Customer_Info A                         
  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                         
  inner join TBL_OVI_RM_Hierarchy_Mapping C on A.CreatedBy=C.EmpCode                         
  WHERE TP_Customer_Info_ID=@CustomerId                        
                        
  select @ToName=ReceipentName,@customer_name=CustomerName,@ReferenceNo=RequestNumber,@CreatedById=ApproverADID from #temp5                              
                     
  select * from #temp5                            
                           
  Exec SP_OVI_GetEmailContent 'Approved',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,Null,@ApproverADId,'Trade Pricing'                       
                           
  SELECT * FROM temp2                            
                           
  Drop table #temp5                        
                              
  END                                  
  IF(@Action='Reject')                                  
  BEGIN           
         
  if (@ChkApproverAdLevel1='True' And @ChkApproverAdLevel2<>'True')      
  BEGIN                             
      UPDATE TBL_OVI_Trade_Pricing_Customer_Info SET [Status]='Rejected',ApproverDate=GETDATE(),ApproverRemark=@Remark                                  
      where TP_Customer_Info_ID=@CustomerId and ApproverADID=@ApproverADId     
	                              
  END      
        
  if (@ChkApproverAdLevel2='True' And @ChkApproverAdLevel1<>'True')      
  BEGIN                             
      UPDATE TBL_OVI_Trade_Pricing_Customer_Info SET [Status]='Rejected',ApproverDate2=GETDATE(),ApproverRemark2=@Remark                                  
     where TP_Customer_Info_ID=@CustomerId and ApproverADID2=@ApproverADId                                    
  END      
                          
  select @CreatedBy=CreatedBy,@Remarks=ApproverRemark from TBL_OVI_Trade_Pricing_Customer_Info where TP_Customer_Info_ID=@CustomerId and ApproverADID=@ApproverADId                                
                                
  INSERT INTO TBL_OVI_Notification(NotificationType,Title,Subtitle,Body,Status,EmpCode,ActionLink,CreatedBy,CreatedOn,CommercialType,CustomerId)                                  
  values('Supervisor rejects the request','Supervisor rejects Trade Pricing proposal',                                  
  'Proposal Rejected','Trade Pricing proposal Rejected by '+@ApproverADId+' - L1 with comments - '+@Remarks,0,@CreatedBy,'/Home/Commercials',@ApproverADId,GETDATE()              
  ,'TP',@CustomerId)                              
                              
  update TBL_OVI_ToDoList set Status=1 where CustomerId=@CustomerId and CommercialType='TP'                       
              
  INSERT INTO TBL_OVI_ToDoList(Title,Body,Status,EmpCode,ActionLink,DueOn,DueInDays,CreatedBy,CreatedOn,CommercialType,CustomerId,ToDoListCount_Flag)                            
  values(@ApproverADId+' - L1 Rejects Trade Pricing proposal with comments - '+@Remarks,                            
  @ApproverADId+' - L1 Rejectes Trade Pricing proposal with comments - '+@Remarks,0,                            
  @CreatedBy,'/Home/Commercials',DATEADD(day, 2, Getdate()),2,@ApproverADId,GETDATE(),'TP',@CustomerId,'0')                        
                        
  INSERT INTO tbl_OVI_Log VALUES(@CustomerId,'Trade Pricing','Rejected',@ApproverADId,GETDATE(),2,'Proposal Rejected','',@Remark)                  
              
                
                          
  select A.CustomerName,C.EmpEmail as ReceipientEmail,C.EmpName as ReceipentName,A.RequestNumber,                        
  B.EmpEmail as RM_Email,'Reject' Action,A.ApproverADID,A.ApproverRemark                        
  into #temp6                        
  from TBL_OVI_Trade_Pricing_Customer_Info A                         
  inner join TBL_OVI_RM_Hierarchy_Mapping B on A.ApproverADID=B.EmpCode                         
  inner join TBL_OVI_RM_Hierarchy_Mapping C on A.CreatedBy=C.EmpCode                         
  WHERE TP_Customer_Info_ID=@CustomerId                        
                        
  select @ToName=ReceipentName,@customer_name=CustomerName,@ReferenceNo=RequestNumber,@CreatedById=ApproverADID,@ApproverRemark=ApproverRemark from #temp6                              
                            
  select * from #temp6                            
                           
  --Exec SP_OVI_GetEmailContent 'Reject',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@ApproverADId,@ApproverRemark                            
  Exec SP_OVI_GetEmailContent 'Reject',@ToName,@customer_name,@ReferenceNo,@CommercialTypeMain,@CreatedById,@ApproverRemark,@ApproverADId,'Trade Pricing'        
  SELECT * FROM temp2                            
                           
  Drop table #temp6                        
                            
  END                                  
END
GO
