-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_Urgent_Bulletin]                                         
(                                            
@Identflag varchar(100)=null,                                            
@subject varchar(max)=null,                                            
@body varchar(max)=null,                                            
@expiry_date date=null,                                          
@from_date date=null,                                          
@Recipients varchar(50)=null,                                          
@FileType varchar(100)=null,                                            
@Filename varchar(200)=null,                                            
@FilePath varchar(100)=null,                                        
@CreatedBy varchar(50)=null,                                            
@CreatedOn datetime=null,                                            
@id int=null,                         
@Business varchar(max)=null,                        
@UserRole varchar(100)=null,                          
@Emp_Id varchar(50)=null,    
@Action varchar(100)=null    
)                                            
                                            
 AS                                             
 BEGIN                            
    Declare @UserType varchar(100)=null,@UserBusiness varchar(100)=null                                             
                                              
    SELECT @UserType = EmpRole from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@Emp_Id                           
 SELECT @UserBusiness = Business from TBL_OVI_RM_Hierarchy_Mapping where EmpCode=@Emp_Id                        
    IF(@UserType  IS NULL)                                                
    BEGIN                                                
    IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @Emp_Id AND UserType ='RM')                                                
    BEGIN                                                
    SET @UserType ='Relationship Manager';                                                
    END                                                
    ELSE IF EXISTS(select TOP(1) EmployeeCode from EmployeeMaster where SupervisorEmployeeCode = @Emp_Id AND UserType ='CM')                                                
    BEGIN                                                
    SET @UserType ='Cluster Head';                                           
    END                                                
    END                           
    IF(@Identflag='UploadBulletin')                                            
 BEGIN                                            
   INSERT into TBL_OVI_Urgent_Bulletin(Subject,Recipients,From_Date,Expiry_Date,CreatedBy,CreatedOn,Body,Business)                                             
   values(@subject,@Recipients,GETDATE(),@expiry_date,@CreatedBy,GETDATE(),@body,@Business)                                            
                                            
   set @id = SCOPE_IDENTITY()                                            
   select @id as bulletin_id                                            
 END                                            
 IF(@Identflag='Update_File_Details')                                            
 BEGIN                                            
  update TBL_OVI_Urgent_Bulletin set FileName=@Filename where Urgent_Bulletin_Id=@id                                            
                                            
  select 1 as msg                                            
 END                                            
 IF(@Identflag='fetch_Urgent_bulletin_data')                                            
 BEGIN                          
                            
   IF(@UserType like '%Relationship Manager%')                          
   BEGIN                          
   select A.Body,A.Expiry_Date,A.Urgent_Bulletin_Id,A.FileName,A.Subject,FORMAT (A.CreatedOn, 'dd MMMM') as create_date,B.EmpName,B.EmpRole                                        
   into #temp                                        
from TBL_OVI_Urgent_Bulletin A inner join TBL_OVI_RM_Hierarchy_Mapping B on A.CreatedBy=B.EmpCode                        
   where A.Business=@UserBusiness and A.Urgent_Bulletin_Id not in(select Urgent_Bulletin_Id from TBL_OVI_Urgent_Bulletin_log where EmpCode=@Emp_Id)                                
   and CONVERT(date,GETDATE(),105) <= CONVERT(date,A.Expiry_Date,105) AND (A.Recipients like '%Relationship Manager%' or A.Recipients like '%RM and Supervisor%')                   
   order by CreatedOn desc                          
                          
   insert into TBL_OVI_Urgent_Bulletin_log(Urgent_Bulletin_Id,EmpCode,CreatedOn)                                        
   select Urgent_Bulletin_Id,Emp_Id=@Emp_Id,GETDATE() from #temp where Expiry_Date<GETDATE()                            
                          
   select * from #temp                              
   END                 
   ELSE IF(@UserType like '%Business Head%' or @UserType like '%Group Head%')                
   BEGIN                
   select A.Body,A.Expiry_Date,A.Urgent_Bulletin_Id,A.FileName,A.Subject,FORMAT (A.CreatedOn, 'dd MMMM') as create_date,B.EmpName,B.EmpRole                                     
   into #temp3                                        
   from TBL_OVI_Urgent_Bulletin A inner join TBL_OVI_RM_Hierarchy_Mapping B on A.CreatedBy=B.EmpCode                                        
   where A.CreatedBy=@Emp_Id and A.Urgent_Bulletin_Id not in(select Urgent_Bulletin_Id from TBL_OVI_Urgent_Bulletin_log where EmpCode=@Emp_Id)                                
   and CONVERT(date,GETDATE(),105) <= CONVERT(date,A.Expiry_Date,105)                           
   order by CreatedOn desc                          
                          
   insert into TBL_OVI_Urgent_Bulletin_log(Urgent_Bulletin_Id,EmpCode,CreatedOn)                                        
   select Urgent_Bulletin_Id,Emp_Id=@Emp_Id,GETDATE() from #temp3 where Expiry_Date<GETDATE()                            
                          
   select * from #temp3                
   END                
   ELSE                          
   BEGIN                          
   select A.Body,A.Expiry_Date,A.Urgent_Bulletin_Id,A.FileName,A.Subject,FORMAT (A.CreatedOn, 'dd MMMM') as create_date,B.EmpName,B.EmpRole                                     
   into #temp1                                        
   from TBL_OVI_Urgent_Bulletin A inner join TBL_OVI_RM_Hierarchy_Mapping B on A.CreatedBy=B.EmpCode                                        
   where A.Business=@UserBusiness and A.Urgent_Bulletin_Id not in(select Urgent_Bulletin_Id from TBL_OVI_Urgent_Bulletin_log where EmpCode=@Emp_Id)                                
   and CONVERT(date,GETDATE(),105) <= CONVERT(date,A.Expiry_Date,105) AND (A.Recipients like '%Supervisor%' or A.Recipients like '%RM and Supervisor%')                             
   order by CreatedOn desc                          
                          
   insert into TBL_OVI_Urgent_Bulletin_log(Urgent_Bulletin_Id,EmpCode,CreatedOn)                                        
   select Urgent_Bulletin_Id,Emp_Id=@Emp_Id,GETDATE() from #temp1 where Expiry_Date<GETDATE()                            
                          
   select * from #temp1                         
   END                                    
                                      
   drop table #temp                           
   drop table #temp1                          
 END                                            
 IF(@Identflag='Delete_Bulletin')                                            
 BEGIN                                            
  delete from TBL_OVI_Urgent_Bulletin where Urgent_Bulletin_Id=@id                                            
  select 1 as msg                                            
 END                                         
 ELSE IF(@Identflag='Take_UrgentBulletinCount')                                        
 BEGIN        
     
   declare @BulletineCount int=null        
      declare @ToDoListCount int=null      
 if(@Action='GetCount')    
