    IF(@UserType like '%Relationship Manager%')                          
   BEGIN        
      
  -- select @ToDoListCount=COUNT(CustomerId) from  TBL_OVI_ToDoList where Status=0 and ToDoListCount_Flag='0'    
      select @BulletineCount = count(A.Urgent_Bulletin_Id) from  TBL_OVI_Urgent_Bulletin A inner join TBL_OVI_RM_Hierarchy_Mapping B on A.CreatedBy=B.EmpCode                                       
      where A.Business=@UserBusiness and Urgent_Bulletin_Id not in(select Urgent_Bulletin_Id from TBL_OVI_Urgent_Bulletin_log where EmpCode=@Emp_Id)                            
     and CONVERT(date,GETDATE(),105) <= CONVERT(date,A.Expiry_Date,105)  AND (A.Recipients like '%Relationship Manager%' or A.Recipients like '%RM and Supervisor%')                    
                    
      IF(@BulletineCount=0)                    
      BEGIN                    
      SELECT TOP 3 Title,FORMAT(DueOn,'MMM dd') as DueOn ,ActionLink ,CustomerId,CommercialType FROM TBL_OVI_ToDoList WHERE EmpCode=@Emp_Id and Status=0 order by ID desc                    
      END                    
      ELSE                    
      BEGIN                    
      SELECT TOP 2 Title,FORMAT(DueOn,'MMM dd') as DueOn,ActionLink ,CustomerId,CommercialType FROM TBL_OVI_ToDoList WHERE EmpCode=@Emp_Id and Status=0 order by ID desc                    
      END         
      select COUNT(CustomerId) as ToDoList_Count from  TBL_OVI_ToDoList where Status=0 and ToDoListCount_Flag='0' and EmpCode=@Emp_Id    
      select count(A.Urgent_Bulletin_Id) as Bulletin_count from  TBL_OVI_Urgent_Bulletin A inner join TBL_OVI_RM_Hierarchy_Mapping B on A.CreatedBy=B.EmpCode                                       
      where A.Business=@UserBusiness and Urgent_Bulletin_Id not in(select Urgent_Bulletin_Id from TBL_OVI_Urgent_Bulletin_log where EmpCode=@Emp_Id)                            
      and CONVERT(date,GETDATE(),105) <= CONVERT(date,A.Expiry_Date,105) AND (A.Recipients like '%Relationship Manager%' or A.Recipients like '%RM and Supervisor%')                    
                    
   END                      
   ELSE IF(@UserType like '%Business Head%' or @UserType like '%Group Head%')                       
   BEGIN        
     select @ToDoListCount=COUNT(CustomerId) from  TBL_OVI_ToDoList where Status=0 and ToDoListCount_Flag='0' and EmpCode=@Emp_Id    
