/****** Object:  StoredProcedure [dbo].[SP_OVI_ValidateUser]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	SP_OVI_ValidateUser '1001'
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_ValidateUser]           
@UserId as varchar(50)=null             
AS             
BEGIN            
--select top(1) EmpCode,EmpName,EmpRole as [EMPRole] from TBL_OVI_RM_Hierarchy_Mapping  where EmpCode=@UserId          
select Top 1 'RM' as Business, EmpCode,EmpName,EmpRole as [EMPRole], ISNULL(CentralTeam,'No') as  CentralTeam from TBL_OVI_RM_Hierarchy_Mapping          
where EmpCode = @UserId          
union          
select Top 1 'CM' as Business, EmpId as EmpCode,Name as EmpName,Role as [EMPRole], 'No' as CentralTeam  from Mst_Wb_Emp          
where  Segment='Credit' and EmpId=@UserId        
union          
select Top 1 'PMS' as Business, EmpCode as EmpCode,EmpName as EmpName,EmpDesignation as [EMPRole], 'No' as CentralTeam from  tbl_PMS_Hierarchy_Master          
where EmpCode = @UserId          
            
END
GO
/****** Object:  StoredProcedure [dbo].[SP_OVI_View]    Script Date: 21-09-2024 20:36:56 ******/
SET ANSI_NULLS ON
