-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[SP_OVI_View]   
@IdentFlag varchar(100)=null,    
 @SearchText varchar(100)= null,    
 @EmpCode varchar(20)= null,    
 @LSID varchar(20)=null    
AS    
BEGIN    
 declare @query varchar(max)=null    
 
  
    
  -- DECLARE @USERROLE VARCHAR(200)    
  --Declare @State varchar(500),@statecode varchar(500),@Segment varchar(100)     
  --SET @USERROLE=(SELECT PROFILEDESCRIPTION FROM USERMASTER(nolock) WHERE EMPCODE=@EMPID)    
  -- set @Segment=(select b.Segment from UserMaster a inner join Mst_Wb_Emp b on a.EmpCode=b.EmpId where a.EmpCode=@EMPID)    
  --set @statecode=(select State_Code from Mst_Wb_Emp where EmpId=@EMPID)      
if(@IdentFlag='GetCustomerTable')    
BEGIN    
 if(@SearchText ='' or @SearchText =null)    
 BEGIN    
  SELECT distinct top 50  Name_as_per_access as CustomerName ,[SME_Client_ID] as LSID    
  FROM dbo.Mst_Name_Match_Dtl where [SME_Client_ID]=null or [SME_Client_ID]!='NULL' ORDER BY [Name_as_per_access]  

 END    
 ELSE    
 BEGIN  
 SET @SearchText =''''+ '%' + @SearchText + '%' + '''' 
  set @query='SELECT distinct top 50  Name_as_per_access as CustomerName ,[SME_Client_ID] as LSID    
  FROM dbo.Mst_Name_Match_Dtl    
  WHERE  ( [Name_as_per_access] LIKE '+@SearchText+'  OR   [SME_Client_ID] LIKE '+@SearchText+' )    
  ORDER BY [Name_as_per_access]'    
  print (@query)    
  exec (@query)    
 END    
END    
ELSE IF(@IdentFlag='AllDataByLSID')    
BEGIN    
    
-----------------declare variable         
declare @First_time_7_dpd_date varchar(100)        
declare @First_time_30_dpd_date varchar(100)         
declare @First_time_Pot_NPA varchar(100)         
declare @Current_Watchlist varchar(100)         
declare @No_of_times_last_6_Watchlist varchar(100)        
declare @Watchlist_Months varchar(800)        
declare @Current_Low_Churning varchar(100)          
declare @No_times_Last_6_Churn varchar(100)        
declare @Low_Churn_Months varchar(100)        
declare @Exit1 varchar(100)          
declare @Plan_Avb varchar(100)        
declare @Plan1 varchar(500)         
declare @Current_Pot_NPA varchar(100)         
declare @No_times_last_6_NPA varchar(100)         
declare @Pot_NPA_Months varchar(100)       
DECLARE @Record_Id numeric(18)        
--Demographic_Report    
Create Table #TblOneViewInd_Demographic_Report        
(        
[City] varchar(200),        
[Region] varchar(200),        
[Lasersoft_Id] varchar(200)        
)        
    
INSERT INTO #TblOneViewInd_Demographic_Report        
([City],[Region],[Lasersoft_Id] )        
select Distinct City as 'City',        
Region as 'Region',[SME_Client_ID] as 'Lasersoft Id'         
from  dbo.Mst_Name_Match_Dtl where [SME_Client_ID] = @LSID        
    
SELECT [City],[Region],[Lasersoft_Id] FROM #TblOneViewInd_Demographic_Report    
    
--FaciltyDtl_Report    
Create Table #TblOneViewInd_FaciltyDtl_Report        
(        
[Facility] varchar(200),        
[Limit] varchar(200),        
[OS] varchar(200),        
[AC_Limit_Set_Date] varchar(100),        
[Initial_Limit_Set_Date] varchar(100)        
)        
    
INSERT INTO #TblOneViewInd_FaciltyDtl_Report([Facility],[Limit],[OS],[AC_Limit_Set_Date],[Initial_Limit_Set_Date])        
select Facility as 'Facility',        
convert(Decimal(18,2), Limits_In_Rs_L) as 'Limit',        
convert(Decimal(18,2), Uti_in_RS_L) as 'OS',        
Replace( convert(varchar(50), convert(Datetime,substring(Limit_set_date,0,11)),106),' ','-') as 'A/C Limit Set Date',        
Replace( convert(varchar(50), convert(Datetime,substring(All_Lmt_Dt_Cust_Basis,0,11)),106),' ','-') as 'Initial Limit Set Date'         
From [repotdb].[dbo].Tra_Account_Status Where [LASERSOFT_ID]  =@LSID    
    
SELECT [Facility],[Limit],[OS],[AC_Limit_Set_Date],[Initial_Limit_Set_Date] FROM #TblOneViewInd_FaciltyDtl_Report        
 
--Pending Housekeeping Report    
Create Table #TblOneViewInd_PndHouse_Report        
(        
[Doc_Name] varchar(100),        
[Due_Date] varchar(100)        
)     
    
INSERT INTO #TblOneViewInd_PndHouse_Report([Doc_Name],[Due_Date])        
select Doc_Name,Replace(substring(convert(varchar(20),cast( Due_Date as datetime),113),1,11),' ','-') as 'Due_Date'          
from [repotdb].[dbo].Mst_Wb_Housekeeping where Client_Number = @LSID           
    
SELECT [Doc_Name] as 'HouseKeeping Items ( Doc_Name )',[Due_Date] FROM #TblOneViewInd_PndHouse_Report      
    
--OneViewInd_report    
    
CREATE TABLE #TblOneViewInd_report        
(        
[First_time_7_dpd_date] varchar(100),        
[First_time_30_dpd_date] varchar(100),         
[First_time_Pot_NPA] varchar(100),         
[Current_Watchlist] varchar(100),         
[No_of_times_last_6_Watchlist] varchar(100),        
[Watchlist_Months] varchar(100),        
[Current_Low_Churning] varchar(100),          
[No_times_Last_6_Churn] varchar(100),        
[Low_Churn_Months] varchar(100),        
[Exit1] varchar(100),          
[Plan_Avb] varchar(100),        
[Plan1] varchar(500),         
[Current_Pot_NPA] varchar(100),         
[No_times_last_6_NPA] varchar(100),         
[Pot_NPA_Months] varchar(100),         
[Field1] varchar(100)        
)       
    
INSERT INTO #TblOneViewInd_report([Field1]) VALUES('0')        
    
set @First_time_7_dpd_date=(select Replace(Substring(convert(varchar(50),min(convert(datetime,DATE_OF_TOD,101)),113),0,12),' ','/')as 'DATE OF TOD'            
From [repotdb].dbo.Tra_DDLHistory  where convert(numeric(18),DPD)>=7 and SME_Client_ID=@LSID)        
    
set @First_time_30_dpd_date =(select Replace(Substring(convert(varchar(50),min(convert(datetime,DATE_OF_TOD,101)),113),0,12),' ','/')as 'DATE OF TOD'            
From [repotdb].dbo.Tra_DDLHistory  where convert(numeric(18),DPD)>=30 and SME_Client_ID=@LSID )        
    
set @First_time_Pot_NPA=(select  Replace(Substring(convert(varchar(50),min(convert(datetime,[PotNPAMonth],101)),113),0,12),' ','/')        
from [repotdb].dbo.TbleUpload_PotNPA WHERE [SMEClientID]= @LSID )    
    
if @First_time_Pot_NPA is not null        
 begin        
  set @First_time_Pot_NPA = datename(month,convert(varchar(50),@First_time_Pot_NPA,103))+' - '+        
  datename(year,convert(varchar(50),@First_time_Pot_NPA,103))        
 end        
    
 set @Current_Watchlist = (SELECT top 1 'Y' AS [status] FROM [repotdb].dbo.TbleUpload_WatchList WHERE convert(dateTIME,Month1,101) IN        
(select max(convert(datetime,Month1,101)) as mnt  from [repotdb].dbo.TbleUpload_WatchList)        
AND [SME_Client_ID]= @LSID)        
        
if  @Current_Watchlist IS  null        
         
 BEGIN        
         
  set @Current_Watchlist='N'        
         
 END       
    
 set @No_of_times_last_6_Watchlist = (SELECT count(*) as [Count] FROM [repotdb].dbo.TbleUpload_WatchList WHERE convert(datetime,Month1,101) IN        
(select distinct top 6 (convert(datetime,Month1,101)) as mnt  from [repotdb].dbo.TbleUpload_WatchList order by mnt desc )        
AND [SME_Client_ID]= @LSID)        
        
if  @No_of_times_last_6_Watchlist IS  null        
        
 BEGIN        
         
  set @No_of_times_last_6_Watchlist='0'        
         
 END     
     
    
 SELECT  DATENAME(MONTH,CONVERT(VARCHAR(50),(convert(datetime,Month1,101))))+ '-'+DATENAME(year,CONVERT(VARCHAR(50),(convert(datetime,Month1,101))))  AS mnt        
 INTO #TEMPWatchList FROM [repotdb].dbo.TbleUpload_WatchList         
 WHERE convert(datetime,Month1,101) IN        
 (select distinct top 6 (convert(datetime,Month1,101)) as mnt  from [repotdb].dbo.TbleUpload_WatchList order by mnt desc )        
 AND [SME_Client_ID]= @LSID        
    
 SELECT @Watchlist_Months = COALESCE(@Watchlist_Months + ', ', '') + mnt FROM #TEMPWatchList        
    
    
 set @Current_Low_Churning = (SELECT top 1 'Y' AS [status] FROM [repotdb].dbo.TbleUpload_LowChurn WHERE convert(datetime,[Month_Churn],101) IN        
(select max(convert(datetime,[Month_Churn],101)) as mnt  from [repotdb].dbo.TbleUpload_LowChurn)        
AND [LASERSOFT_ID]= @LSID)        
        
if  @Current_Low_Churning IS  null        
 begin         
  set @Current_Low_Churning='N'        
 end       
    
 set @No_times_Last_6_Churn = (SELECT count(*) as [Count] FROM [repotdb].dbo.TbleUpload_LowChurn WHERE convert(datetime,[Month_Churn],101) IN        
(select distinct top 6 (convert(datetime,[Month_Churn],101)) as mnt  from [repotdb].dbo.TbleUpload_LowChurn order by mnt desc )        
AND [LASERSOFT_ID]= @LSID)        
        
if  @No_times_Last_6_Churn IS  null        
 begin         
  set @No_times_Last_6_Churn='0'        
 end        
    
  SELECT DATENAME(MONTH,CONVERT(VARCHAR(50),(convert(datetime,[Month_Churn],101))))+ '-'+DATENAME(year,CONVERT(VARCHAR(50),(convert(datetime,[Month_Churn],101))))  AS mnt        
 INTO #TEMCHURN FROM [repotdb].dbo.TbleUpload_LowChurn         
 WHERE convert(datetime,[Month_Churn],101) IN        
 (select distinct top 6 (convert(datetime,[Month_Churn],101)) as mnt  from [repotdb].dbo.TbleUpload_LowChurn order by mnt desc )        
 AND [LASERSOFT_ID]= @LSID        
         
         
 SELECT @Low_Churn_Months = COALESCE(@Low_Churn_Months + ', ', '') + mnt FROM #TEMCHURN        
    
    
       IF EXISTS(SELECT top 1 * FROM [repotdb].dbo.Mst_Exit WHERE [LasterSoft_id] =@LSID and [Status] IN ('Pending for Exit','DOD Approved'))        
  BEGIN        
   SET @Exit1='YES'        
   SELECT top 1 @Record_Id=ID FROM [repotdb].dbo.Mst_Exit WHERE [LasterSoft_id] =@LSID        
  END        
 ELSE if EXISTS(SELECT top 1 * FROM [repotdb].dbo.Mst_Exit WHERE [LasterSoft_id] =@LSID and [Status] NOT IN ('Pending for Exit','DOD Approved') AND VISIBLE='0')   --aDDED BY ASMITA H ON 9-APR-18    
 BEGIN    
    SET @Exit1='YES'        
   SELECT top 1 @Record_Id=ID FROM [repotdb].dbo.Mst_Exit WHERE [LasterSoft_id] =@LSID        
  END     
  ELSE    
  BEGIN        
   SET @Exit1='NO'        
   SET @Plan_Avb='NO'        
   SET @Plan1='NO'        
          
  END     
    
    
   IF @Exit1='YES'        
  begin        
    IF EXISTS(SELECT top 1 * FROM [repotdb].dbo.[Tra_planOfAction] WHERE [Record_Id] =@Record_Id)        
     BEGIN        
      SET @Plan_Avb='YES'        
      SET @Plan1=(select top 1 [Plan_Of_Action] from [repotdb].dbo.[Tra_planOfAction] where [Record_Id]=@Record_Id order by sr_no desc)        
           
     END        
    ELSE        
     BEGIN        
      SET @Plan_Avb='NO'        
      SET @Plan1='NO'        
     END         
  end      
    
  set @Current_Pot_NPA = (SELECT top 1 'Y' AS [status] FROM [repotdb].dbo.TbleUpload_PotNPA WHERE convert(datetime,[PotNPAMonth],101) IN        
(select max(convert(datetime,[PotNPAMonth],101)) as mnt  from [repotdb].dbo.TbleUpload_PotNPA)        
AND [SMEClientID]= @LSID)        
        
if  @Current_Pot_NPA IS  null        
 begin         
  set @Current_Pot_NPA='N'        
 end        
    
 set @No_times_last_6_NPA = (SELECT count(*) as [Count] FROM [repotdb].dbo.TbleUpload_PotNPA WHERE convert(datetime,[PotNPAMonth],101) IN        
(select distinct top 6 (convert(datetime,[PotNPAMonth],101)) as mnt  from [repotdb].dbo.TbleUpload_PotNPA order by mnt desc )        
AND [SMEClientID]= @LSID)        
        
if  @No_times_last_6_NPA IS  null        
 begin         
  set @No_times_last_6_NPA='0'        
 end        
    
 SELECT DATENAME(MONTH,CONVERT(VARCHAR(50),(convert(datetime,[PotNPAMonth],101))))+ '-'+DATENAME(year,CONVERT(VARCHAR(50),(convert(datetime,[PotNPAMonth],101))))  AS mnt        
INTO #TEMPNPA FROM [repotdb].dbo.TbleUpload_PotNPA         
WHERE convert(datetime,[PotNPAMonth],101) IN        
(select distinct top 6 (convert(datetime,[PotNPAMonth],101)) as mnt  from [repotdb].dbo.TbleUpload_PotNPA order by mnt desc )        
AND [SMEClientID]= @LSID        
         
SELECT @Pot_NPA_Months = COALESCE(@Pot_NPA_Months + ', ', '') + mnt FROM #TEMPNPA        
    
UPDATE #TblOneViewInd_report        
SET First_time_7_dpd_date  =@First_time_7_dpd_date        
,First_time_30_dpd_date   =@First_time_30_dpd_date        
,First_time_Pot_NPA    =@First_time_Pot_NPA        
,Current_Watchlist    =@Current_Watchlist        
,No_of_times_last_6_Watchlist =@No_of_times_last_6_Watchlist        
,Watchlist_Months    =@Watchlist_Months        
,Current_Low_Churning   =@Current_Low_Churning        
,No_times_Last_6_Churn   =@No_times_Last_6_Churn     
,Low_Churn_Months    =@Low_Churn_Months        
,Exit1       =@Exit1        
,Plan_Avb      =@Plan_Avb        
,Plan1       =@Plan1        
,Current_Pot_NPA    =@Current_Pot_NPA        
,No_times_last_6_NPA   =@No_times_last_6_NPA        
,Pot_NPA_Months     =@Pot_NPA_Months        
    
SELECT [First_time_7_dpd_date],[First_time_30_dpd_date],[First_time_Pot_NPA],[Current_Watchlist],        
[No_of_times_last_6_Watchlist],[Watchlist_Months],[Current_Low_Churning],        
[No_times_Last_6_Churn],[Low_Churn_Months],[Exit1],[Plan_Avb],[Plan1],        
[Current_Pot_NPA],[No_times_last_6_NPA],[Pot_NPA_Months],[Field1] FROM #TblOneViewInd_report        
    
--Delinquency    
    
    Create Table #temp            
  (            
