  )            
              
           
   insert into #Temp             
      ( AC_Contract_No,            
       Customer_Name,            
       SME_Client_ID,            
       Prior_Book,            
       Segment,            
        Limit_Rs_in_L ,            
        Os_Rs_in_L ,            
       Customer_Vintage,            
       DATE_OF_TOD,            
       Curr_Overdue_AMT,            
       Facility_Ctg,            
       DPD,            
       Nature_of_Delq,            
       City  ,            
       Region ,            
       State ,            
       Industry ,            
       ACM ,            
       RM_Proposed_by ,            
       TH_Name ,            
       CH_Name ,            
       ZH_Name ,            
       NPA            
                    
      )            
        
    select             
     fn.COD_ACCT_NO,            
     nw.Name_as_per_access,             
     nw.SME_Client_ID  ,             
     nw.Prior_Book ,            
     nw.Segment ,            
     abs(nw.Limit_Rs) ,            
     abs(nw.Os_Rs ),            
     substring(DATENAME (MM,nw.Customer_Vintage),0,4) + ' - '+  DATENAME(yy, nw.Customer_Vintage ) as 'Customer_Vintage',            
     convert(Datetime,fn.DAT_ARREARS_DUE,105) as 'Date_of_Tod',            
     abs(fn.AMT_ARREARS_DUE),            
     nw.Facility,            
     DATEDIFF(day,convert(Datetime,fn.DAT_ARREARS_DUE,105), (getdate()-1))  as 'DPD',            
     'Interest Servicing',            
     nw.City   ,            
     nw.Region ,            
     nw.State ,            
     nw.Industry ,            
     nw.ACM ,            
     nw.RM_Proposed_by ,            
     nw.TH_Name ,            
     nw.CH_Name ,            
     nw.ZH_Name ,            
     nw.npa            
   from [repotdb].dbo.Mst_Arrears_Int_ServiceBkp as fn inner join [repotdb].dbo.Mst_Name_Match_Dtl as nw            
   on fn.COD_ACCT_NO = nw.Account_No            
   where nw.check_for_interest_servicing = 'yes'        
   and nw.SME_Client_ID=@LSID           
            
   insert into #Temp             
      ( AC_Contract_No,            
       Customer_Name,            
       SME_Client_ID,            
       Prior_Book,            
       Segment,            
       Limit_Rs_in_L,            
       Os_Rs_in_L,            
       Customer_Vintage,            
       DATE_OF_TOD,            
       Curr_Overdue_AMT,            
       Facility_Ctg,            
       DPD,            
       Nature_of_Delq,            
       City  ,            
       Region ,            
       State ,            
       Industry ,            
       ACM ,            
       RM_Proposed_by ,            
       TH_Name ,            
       CH_Name ,            
       ZH_Name ,            
       NPA            
      )            
            
      select             
     fn.Account_No,             
     nw.Name_as_per_access,            
     nw.SME_Client_ID  ,             
     nw.Prior_Book ,            
     nw.Segment ,            
     abs(nw.Limit_Rs) ,            
     abs(nw.Os_Rs ),            
substring(DATENAME (MM,nw.Customer_Vintage),0,4) + ' - '+  DATENAME(yy, nw.Customer_Vintage ) as 'Customer_Vintage',            
     convert(Datetime,fn.DATE_Of_TOD,105) as 'Date_of_Tod',             
     abs(fn.TOD_Amount),            
     fn.Facility_CTG,              
     DATEDIFF(day,fn.DATE_OF_TOD , GETDATE()-1) as 'DPD',           
