     nw.City   ,            
     nw.Region ,            
     nw.State ,            
     nw.Industry ,            
     nw.ACM ,            
     nw.RM_Proposed_by ,            
     nw.TH_Name ,            
     nw.CH_Name ,            
     nw.ZH_Name ,             
     nw.npa             
   from [repotdb].dbo.tblFinWare as fn inner join [repotdb].dbo.Mst_Name_Match_Dtl as nw            
   on fn.Account_no = nw.Account_No        
   where nw.SME_Client_ID=@LSID                
        
   insert into #Temp             
      ( AC_Contract_No,            
       Customer_Name,            
       SME_Client_ID,            
       Prior_Book,            
       Segment,            
       Limit_Rs_in_L,            
       Os_Rs_in_L,            
       Customer_Vintage,            
       DATE_OF_TOD,            
       Curr_Overdue_AMT,            
       Facility_Ctg,            
       DPD,            
