     nw.Segment ,            
     abs(nw.Limit_Rs) ,            
     abs(nw.Os_Rs ),            
     substring(DATENAME (MM,nw.Customer_Vintage),0,4) + ' - '+  DATENAME(yy, nw.Customer_Vintage ) as 'Customer_Vintage',            
