 SME_Client_ID as 'SME Client ID',            
 Substring(convert(varchar(50),DATE_OF_TOD,113),0,12) as 'DATE OF TOD',            
 Curr_Overdue_AMT  as 'Curr Overdue AMT',            
 DPD as 'DPD',            
