select * from [repotdb].dbo.ACR_data_SMA_tran where [LSID] = @LSID    
select * from [repotdb].dbo.ACR_data_GST_tran where [LSID] = @LSID    
    
if(@SearchText ='')    
 BEGIN    
  SELECT distinct top 50  [Name_as_per_access] as CustomerName ,[SME_Client_ID] as LSID    
  FROM  [repotdb].dbo.[Mst_Name_Match_Dtl]    
 END    
 ELSE    
 BEGIN    
 set @query='SELECT distinct top 50  [Name_as_per_access] as CustomerName ,[SME_Client_ID] as LSID    
  FROM  [repotdb].dbo.[Mst_Name_Match_Dtl]      
  WHERE  ( [Name_as_per_access] LIKE '''+@SearchText+'''  OR   [SME_Client_ID] LIKE '''+@SearchText+''' )    
  ORDER BY [Name_as_per_access]'    
  print (@query)    
  exec (@query)    
 END    
    
    
END    
