CREATE PROCEDURE [dbo].[Sp_SaveFeedback]
@LUSR varchar(20) =null,
	@Remarks varchar(max) =null,
	@ModuleID int=0,
	@Application varchar(20)=null,
	@UI int =null,
	@Perfomance  int =null,
	@Userfreindly  int=null,
	@Experience int=null,
	@Revelvance int=null,
	@ApplicationVersion varchar(20)=null

AS
BEGIN
	Insert into Tbl_feedback (Remarks,ModuleID,ApplicationName,UI,Performance,Userfreindly,Experience,Revelvance,ApplicationVersion,LUSR,insertedon) 
	values (@Remarks,@ModuleID,@Application,@UI,@Perfomance,@Userfreindly,@Experience,@Revelvance,@ApplicationVersion,@LUSR,GETDATE())
END
